/* QB_CHEMISTRY — compact curated bank (source of truth). Row {i,g,u,d,t,q,o[4],c,e}. */
window.QB_CHEMISTRY = [
  {"i":"chem-g12-atom-001","g":11,"u":"Atomic Structure & Periodic Properties","d":"easy","t":"conceptual","q":"Which subatomic particle carries a negative charge?","o":["Proton","Neutron","Electron","Positron"],"c":2,"e":"The electron carries a charge of −1; the proton is +1 and the neutron is neutral."},
  {"i":"chem-g12-atom-002","g":11,"u":"Atomic Structure & Periodic Properties","d":"easy","t":"definition","q":"What is the maximum number of electrons that can occupy a single p subshell?","o":["2","6","10","14"],"c":1,"e":"A p subshell has 3 orbitals, and each orbital holds 2 electrons, so 3 × 2 = 6."},
  {"i":"chem-g12-atom-003","g":11,"u":"Atomic Structure & Periodic Properties","d":"easy","t":"conceptual","q":"Across a period from left to right, atomic radius generally:","o":["Increases","Decreases","Stays constant","Doubles"],"c":1,"e":"Nuclear charge increases across a period while electrons enter the same shell, pulling them in, so the radius decreases."},
  {"i":"chem-g12-peri-004","g":11,"u":"Atomic Structure & Periodic Properties","d":"easy","t":"conceptual","q":"Elements in the same group of the periodic table have the same number of:","o":["Neutrons","Valence electrons","Protons","Energy levels"],"c":1,"e":"A group shares the same valence-electron count, which gives the members similar chemical properties."},
  {"i":"chem-g12-bond-005","g":9,"u":"Chemical Bonding","d":"easy","t":"conceptual","q":"A bond formed by the transfer of electrons from a metal to a non-metal is called:","o":["Covalent bond","Metallic bond","Ionic bond","Hydrogen bond"],"c":2,"e":"Electron transfer produces oppositely charged ions held by electrostatic attraction — an ionic bond."},
  {"i":"chem-g12-bond-006","g":9,"u":"Chemical Bonding","d":"easy","t":"conceptual","q":"What type of bond exists between the two atoms in a chlorine molecule, Cl₂?","o":["Ionic","Non-polar covalent","Polar covalent","Metallic"],"c":1,"e":"Two identical atoms share electrons equally (ΔEN = 0), giving a non-polar covalent bond."},
  {"i":"chem-g12-mole-007","g":10,"u":"Chemical Reactions & Stoichiometry","d":"easy","t":"definition","q":"Approximately how many particles are in one mole of a substance (Avogadro's number)?","o":["6.02 × 10²³","3.01 × 10²³","1.66 × 10⁻²⁴","6.02 × 10²²"],"c":0,"e":"One mole contains Avogadro's number of particles, 6.02 × 10²³."},
  {"i":"chem-g12-mole-008","g":10,"u":"Chemical Reactions & Stoichiometry","d":"easy","t":"calculation","q":"What is the molar mass of water, H₂O? (H = 1, O = 16 g/mol)","o":["16 g/mol","17 g/mol","18 g/mol","20 g/mol"],"c":2,"e":"M = 2(1) + 16 = 18 g/mol."},
  {"i":"chem-g12-mole-009","g":10,"u":"Chemical Reactions & Stoichiometry","d":"easy","t":"calculation","q":"How many moles are in 64 g of methane, CH₄? (C = 12, H = 1 g/mol)","o":["1 mol","2 mol","4 mol","8 mol"],"c":2,"e":"M(CH₄) = 12 + 4 = 16 g/mol; n = 64 ÷ 16 = 4 mol."},
  {"i":"chem-g12-states-010","g":11,"u":"Physical States of Matter","d":"easy","t":"conceptual","q":"The direct change of a solid to a gas without passing through the liquid state is called:","o":["Condensation","Sublimation","Evaporation","Fusion"],"c":1,"e":"Solid → gas directly is sublimation (e.g. dry ice, iodine)."},
  {"i":"chem-g12-states-011","g":11,"u":"Physical States of Matter","d":"easy","t":"conceptual","q":"According to the kinetic theory, the pressure of a gas is caused by:","o":["Gas particles attracting each other","Collisions of particles with the container walls","The mass of the container","Particles staying still"],"c":1,"e":"Gas pressure results from the force of countless particle collisions against the walls of the container."},
  {"i":"chem-g12-kin-012","g":11,"u":"Chemical Kinetics","d":"easy","t":"conceptual","q":"A catalyst speeds up a reaction by:","o":["Increasing the temperature","Lowering the activation energy","Increasing the concentration of products","Shifting the equilibrium right"],"c":1,"e":"A catalyst provides an alternative pathway with lower activation energy, so more collisions are successful; it does not shift the equilibrium position."},
  {"i":"chem-g12-kin-013","g":11,"u":"Chemical Kinetics","d":"easy","t":"conceptual","q":"Which factor generally increases the rate of a chemical reaction?","o":["Lower temperature","Larger solid particle size","Higher reactant concentration","Removing the catalyst"],"c":2,"e":"Higher concentration means more particles per unit volume and more frequent effective collisions, raising the rate."},
  {"i":"chem-g12-eqm-014","g":11,"u":"Chemical Equilibrium","d":"easy","t":"conceptual","q":"At dynamic equilibrium, the rates of the forward and reverse reactions are:","o":["Both zero","Equal","Forward greater than reverse","Reverse greater than forward"],"c":1,"e":"Dynamic equilibrium means the forward and reverse rates are equal, so concentrations stay constant."},
  {"i":"chem-g12-acid-015","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"definition","q":"According to Arrhenius, an acid is a substance that produces which ion in water?","o":["OH⁻","H⁺ (H₃O⁺)","Na⁺","Cl⁻"],"c":1,"e":"An Arrhenius acid ionizes in water to give hydrogen ions, H⁺ (hydronium, H₃O⁺)."},
  {"i":"chem-g12-acid-016","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"calculation","q":"What is the pH of a 0.01 M solution of HCl, a strong acid?","o":["1","2","12","0.01"],"c":1,"e":"HCl fully dissociates, so [H⁺] = 0.01 = 10⁻² M and pH = −log(10⁻²) = 2."},
  {"i":"chem-g12-echem-017","g":12,"u":"Electrochemistry","d":"easy","t":"definition","q":"Oxidation is best defined as the:","o":["Gain of electrons","Loss of electrons","Gain of protons","Loss of neutrons"],"c":1,"e":"Oxidation Is Loss of electrons (OIL); reduction is gain (RIG)."},
  {"i":"chem-g12-echem-018","g":12,"u":"Electrochemistry","d":"easy","t":"conceptual","q":"In any electrochemical cell, oxidation always occurs at the:","o":["Anode","Cathode","Salt bridge","Voltmeter"],"c":0,"e":"By definition, oxidation occurs at the anode and reduction at the cathode in every electrochemical cell."},
  {"i":"chem-g12-org-019","g":10,"u":"Hydrocarbons","d":"easy","t":"conceptual","q":"What is the general formula of an alkane?","o":["CₙH₂ₙ","CₙH₂ₙ₊₂","CₙH₂ₙ₋₂","CₙHₙ"],"c":1,"e":"Saturated open-chain alkanes follow CₙH₂ₙ₊₂ (e.g. methane CH₄, ethane C₂H₆)."},
  {"i":"chem-g12-org-020","g":11,"u":"Oxygen-Containing Organic Compounds","d":"easy","t":"definition","q":"The functional group –OH characterizes which class of organic compounds?","o":["Aldehydes","Carboxylic acids","Alcohols","Ketones"],"c":2,"e":"The hydroxyl group (–OH) attached to a carbon is the functional group of alcohols (e.g. ethanol, C₂H₅OH)."},
  {"i":"chem-g12-org-021","g":10,"u":"Hydrocarbons","d":"easy","t":"conceptual","q":"Which is the simplest alkene?","o":["Methane","Ethene","Ethyne","Propene"],"c":1,"e":"Alkenes (CₙH₂ₙ) need at least 2 carbons for a C=C bond; ethene (C₂H₄) is the simplest."},
  {"i":"chem-g12-poly-022","g":12,"u":"Polymers","d":"easy","t":"definition","q":"A polymer is a large molecule built from many repeating small units called:","o":["Isotopes","Monomers","Isomers","Catalysts"],"c":1,"e":"Monomers are the small repeating units that join (polymerize) to form a polymer (e.g. ethene → polyethene)."},
  {"i":"chem-g12-env-023","g":12,"u":"Introduction to Environmental Chemistry","d":"easy","t":"conceptual","q":"Which gas is the main contributor to the greenhouse effect from burning fossil fuels?","o":["Oxygen, O₂","Nitrogen, N₂","Carbon dioxide, CO₂","Helium, He"],"c":2,"e":"Combustion of fossil fuels releases CO₂, the principal greenhouse gas driving global warming."},
  {"i":"chem-g12-atom-101","g":11,"u":"Atomic Structure & Periodic Properties","d":"medium","t":"conceptual","q":"An element has the electron configuration 1s² 2s² 2p⁶ 3s² 3p⁴. To which group and period does it belong?","o":["Group IVA, Period 3","Group VIA, Period 3","Group IIA, Period 3","Group VIA, Period 2"],"c":1,"e":"The highest principal quantum number is 3 (Period 3); valence electrons 3s²3p⁴ = 6, so Group VIA. The element is sulfur."},
  {"i":"chem-g12-atom-102","g":11,"u":"Atomic Structure & Periodic Properties","d":"medium","t":"calculation","q":"An atom has 17 protons, 18 neutrons and 17 electrons. What is its mass number?","o":["17","18","35","52"],"c":2,"e":"Mass number = protons + neutrons = 17 + 18 = 35 (this is chlorine-35)."},
  {"i":"chem-g12-peri-103","g":11,"u":"Atomic Structure & Periodic Properties","d":"medium","t":"conceptual","q":"Which of the following has the largest first ionization energy?","o":["Na","Mg","Al","Cl"],"c":3,"e":"Ionization energy increases across a period; Cl is farthest right of these Period-3 elements, so it holds its outer electron most tightly."},
  {"i":"chem-g12-bond-104","g":11,"u":"Chemical Bonding","d":"medium","t":"conceptual","q":"What is the molecular geometry of methane, CH₄, according to VSEPR theory?","o":["Trigonal planar","Bent","Tetrahedral","Linear"],"c":2,"e":"Carbon has 4 bonding pairs and no lone pairs, so the four C–H bonds point to the corners of a tetrahedron (≈109.5°)."},
  {"i":"chem-g12-bond-105","g":11,"u":"Chemical Bonding","d":"medium","t":"conceptual","q":"Why does water (H₂O) have a much higher boiling point than hydrogen sulfide (H₂S)?","o":["Water has a larger molar mass","Water forms hydrogen bonds","H₂S is ionic","Water is non-polar"],"c":1,"e":"O is small and very electronegative, so H₂O forms strong hydrogen bonds; H₂S cannot, so despite its larger mass H₂S boils lower."},
  {"i":"chem-g12-mole-106","g":10,"u":"Chemical Reactions & Stoichiometry","d":"medium","t":"calculation","q":"What volume does 0.5 mol of an ideal gas occupy at STP (molar volume 22.4 L/mol)?","o":["11.2 L","22.4 L","44.8 L","5.6 L"],"c":0,"e":"V = n × 22.4 = 0.5 × 22.4 = 11.2 L at STP."},
  {"i":"chem-g12-mole-107","g":10,"u":"Chemical Reactions & Stoichiometry","d":"medium","t":"calculation","q":"How many grams of NaOH are needed to make 250 mL of a 2.0 M solution? (NaOH = 40 g/mol)","o":["10 g","20 g","40 g","80 g"],"c":1,"e":"n = M × V = 2.0 × 0.250 = 0.5 mol; mass = 0.5 × 40 = 20 g."},
  {"i":"chem-g12-mole-108","g":10,"u":"Chemical Reactions & Stoichiometry","d":"medium","t":"calculation","q":"Balance: __ H₂ + __ O₂ → __ H₂O. What is the coefficient of H₂O in the balanced equation (smallest whole numbers)?","o":["1","2","3","4"],"c":1,"e":"2H₂ + O₂ → 2H₂O balances 4 H and 2 O on each side; the coefficient of H₂O is 2."},
  {"i":"chem-g12-mole-109","g":10,"u":"Chemical Reactions & Stoichiometry","d":"medium","t":"calculation","q":"What is the percentage by mass of nitrogen in ammonium nitrate, NH₄NO₃? (N=14, H=1, O=16)","o":["17.5%","28%","35%","50%"],"c":2,"e":"M = 2(14) + 4(1) + 3(16) = 80 g/mol; N mass = 28; %N = 28/80 × 100 = 35%."},
  {"i":"chem-g12-states-110","g":11,"u":"Physical States of Matter","d":"medium","t":"calculation","q":"A gas occupies 4.0 L at 2.0 atm. At constant temperature, what volume does it occupy at 1.0 atm? (Boyle's law)","o":["2.0 L","4.0 L","8.0 L","16 L"],"c":2,"e":"P₁V₁ = P₂V₂ → V₂ = (2.0 × 4.0)/1.0 = 8.0 L."},
  {"i":"chem-g12-states-111","g":11,"u":"Physical States of Matter","d":"medium","t":"calculation","q":"A gas at 300 K and 1.0 atm is heated to 600 K at constant volume. What is the new pressure? (Gay-Lussac's law)","o":["0.5 atm","1.0 atm","2.0 atm","4.0 atm"],"c":2,"e":"P₁/T₁ = P₂/T₂ → P₂ = 1.0 × (600/300) = 2.0 atm."},
  {"i":"chem-g12-kin-112","g":11,"u":"Chemical Kinetics","d":"medium","t":"conceptual","q":"For a reaction with rate law rate = k[A][B], what happens to the rate if [A] is doubled and [B] is held constant?","o":["Stays the same","Doubles","Quadruples","Halves"],"c":1,"e":"Rate is first order in A, so doubling [A] doubles the rate (2¹ = 2)."},
  {"i":"chem-g12-eqm-113","g":11,"u":"Chemical Equilibrium","d":"medium","t":"application","q":"For N₂(g) + 3H₂(g) ⇌ 2NH₃(g) + heat, what happens to the yield of NH₃ when pressure is increased?","o":["Decreases","Increases","No change","NH₃ decomposes completely"],"c":1,"e":"Higher pressure shifts equilibrium toward the side with fewer gas moles (4 mol → 2 mol), i.e. toward NH₃, increasing its yield."},
  {"i":"chem-g12-eqm-114","g":11,"u":"Chemical Equilibrium","d":"medium","t":"application","q":"For the exothermic reaction 2SO₂ + O₂ ⇌ 2SO₃ + heat, increasing temperature will:","o":["Shift equilibrium toward SO₃","Shift equilibrium toward SO₂ and O₂","Not affect the equilibrium","Stop the reaction"],"c":1,"e":"Adding heat to an exothermic reaction shifts equilibrium in the endothermic (reverse) direction, favouring the reactants SO₂ and O₂."},
  {"i":"chem-g12-acid-115","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"What is the pH of a 0.001 M NaOH solution at 25 °C?","o":["3","11","10","12"],"c":1,"e":"[OH⁻] = 10⁻³, so pOH = 3; pH = 14 − 3 = 11."},
  {"i":"chem-g12-acid-116","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"conceptual","q":"In the reaction NH₃ + H₂O ⇌ NH₄⁺ + OH⁻, which species acts as a Brønsted–Lowry acid?","o":["NH₃","H₂O","NH₄⁺","OH⁻"],"c":1,"e":"A Brønsted acid donates a proton; here H₂O donates H⁺ to NH₃, becoming OH⁻."},
  {"i":"chem-g12-echem-117","g":12,"u":"Electrochemistry","d":"medium","t":"calculation","q":"What is the oxidation number of manganese in the permanganate ion, MnO₄⁻?","o":["+2","+4","+6","+7"],"c":3,"e":"Oxygen is −2 (total −8); the ion charge is −1, so Mn + (−8) = −1 → Mn = +7."},
  {"i":"chem-g12-echem-118","g":12,"u":"Electrochemistry","d":"medium","t":"calculation","q":"Given E°(Zn²⁺/Zn) = −0.76 V and E°(Cu²⁺/Cu) = +0.34 V, what is the standard EMF of the Zn–Cu cell?","o":["0.42 V","1.10 V","−0.42 V","−1.10 V"],"c":1,"e":"E°cell = E°cathode − E°anode = 0.34 − (−0.76) = 1.10 V (Cu²⁺ is reduced, Zn is oxidized)."},
  {"i":"chem-g12-org-119","g":10,"u":"Hydrocarbons","d":"medium","t":"calculation","q":"An alkyne has 4 carbon atoms. Using the general formula CₙH₂ₙ₋₂, how many hydrogen atoms does it have?","o":["6","8","10","4"],"c":0,"e":"For n = 4: H = 2n − 2 = 2(4) − 2 = 6, so C₄H₆ (e.g. but-1-yne)."},
  {"i":"chem-g12-org-120","g":11,"u":"Oxygen-Containing Organic Compounds","d":"medium","t":"definition","q":"What is the IUPAC name of CH₃–CH₂–CH₂–OH?","o":["Propanal","Propan-1-ol","Propanoic acid","Propanone"],"c":1,"e":"A 3-carbon chain with –OH on the end carbon is propan-1-ol (an alcohol)."},
  {"i":"chem-g12-org-121","g":11,"u":"Oxygen-Containing Organic Compounds","d":"medium","t":"conceptual","q":"Dehydration of ethanol (C₂H₅OH) with concentrated H₂SO₄ at about 170 °C produces:","o":["Ethane","Ethene","Ethanoic acid","Ethyne"],"c":1,"e":"Acid-catalysed dehydration removes H₂O from ethanol, forming the alkene ethene: C₂H₅OH → C₂H₄ + H₂O."},
  {"i":"chem-g12-poly-122","g":12,"u":"Polymers","d":"medium","t":"conceptual","q":"Polyethene is formed from ethene by which type of polymerization?","o":["Condensation","Addition","Hydrolysis","Neutralization"],"c":1,"e":"Ethene's C=C double bond opens and monomers add together with no small molecule lost — addition polymerization."},
  {"i":"chem-g12-env-123","g":12,"u":"Introduction to Environmental Chemistry","d":"medium","t":"conceptual","q":"Acid rain is mainly caused by atmospheric oxides of:","o":["Carbon and hydrogen","Sulfur and nitrogen","Sodium and potassium","Helium and neon"],"c":1,"e":"SO₂ and NOₓ dissolve in rainwater to form sulfuric and nitric acids, lowering rain pH (acid rain)."},
  {"i":"chem-g12-mole-201","g":10,"u":"Chemical Reactions & Stoichiometry","d":"hard","t":"calculation","q":"For 2H₂ + O₂ → 2H₂O, how many grams of water form from 8.0 g of H₂ reacting with excess O₂? (H=1, O=16)","o":["36 g","72 g","18 g","144 g"],"c":1,"e":"n(H₂) = 8/2 = 4 mol; ratio H₂:H₂O is 2:2 = 1:1, so 4 mol H₂O; mass = 4 × 18 = 72 g."},
  {"i":"chem-g12-mole-202","g":10,"u":"Chemical Reactions & Stoichiometry","d":"hard","t":"calculation","q":"A compound contains 40% C, 6.7% H and 53.3% O by mass. What is its empirical formula? (C=12, H=1, O=16)","o":["CH₂O","C₂H₄O","CHO","C₂H₆O"],"c":0,"e":"Moles: C 40/12=3.33, H 6.7/1=6.7, O 53.3/16=3.33; divide by 3.33 → 1:2:1, so CH₂O."},
  {"i":"chem-g12-mole-203","g":10,"u":"Chemical Reactions & Stoichiometry","d":"hard","t":"calculation","q":"When 4.0 g of CH₄ is burned completely (CH₄ + 2O₂ → CO₂ + 2H₂O), what volume of CO₂ forms at STP? (C=12, H=1; molar volume 22.4 L/mol)","o":["5.6 L","11.2 L","22.4 L","44.8 L"],"c":0,"e":"n(CH₄) = 4/16 = 0.25 mol; 1:1 gives 0.25 mol CO₂; V = 0.25 × 22.4 = 5.6 L."},
  {"i":"chem-g12-mole-204","g":10,"u":"Chemical Reactions & Stoichiometry","d":"hard","t":"calculation","q":"In N₂ + 3H₂ → 2NH₃, 2 mol N₂ react with 4 mol H₂. Which is the limiting reagent and how many mol NH₃ form?","o":["N₂ limiting, 4 mol NH₃","H₂ limiting, 2.67 mol NH₃","H₂ limiting, 4 mol NH₃","N₂ limiting, 2 mol NH₃"],"c":1,"e":"H₂ needed for 2 mol N₂ is 6 mol, but only 4 mol present, so H₂ limits; NH₃ = 4 × (2/3) = 2.67 mol."},
  {"i":"chem-g12-acid-205","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"A weak acid HA has Ka = 1.0 × 10⁻⁵ and concentration 0.10 M. What is the approximate pH? (assume x ≪ 0.10)","o":["1.0","3.0","5.0","2.5"],"c":1,"e":"[H⁺] ≈ √(Ka·C) = √(10⁻⁵ × 10⁻¹) = √(10⁻⁶) = 10⁻³; pH = 3.0."},
  {"i":"chem-g12-acid-206","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"25.0 mL of HCl is exactly neutralized by 50.0 mL of 0.10 M NaOH. What is the concentration of the HCl?","o":["0.05 M","0.10 M","0.20 M","0.40 M"],"c":2,"e":"mol NaOH = 0.050 × 0.10 = 0.005 mol; 1:1 reaction → mol HCl = 0.005; M = 0.005/0.025 = 0.20 M."},
  {"i":"chem-g12-acid-207","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"What is the pH of a solution made by mixing 50 mL of 0.20 M HCl with 50 mL of 0.10 M HCl? (volumes additive)","o":["0.82","1.0","0.70","1.5"],"c":0,"e":"Total mol H⁺ = 0.050×0.20 + 0.050×0.10 = 0.015 mol in 0.100 L → 0.15 M; pH = −log(0.15) ≈ 0.82."},
  {"i":"chem-g12-echem-208","g":12,"u":"Electrochemistry","d":"hard","t":"calculation","q":"How many grams of copper are deposited when 2.0 A flows for 965 s through CuSO₄ solution? (Cu = 64, F = 96500 C/mol, Cu²⁺ + 2e⁻ → Cu)","o":["0.32 g","0.64 g","1.28 g","2.56 g"],"c":1,"e":"Q = It = 2.0 × 965 = 1930 C; mol e⁻ = 1930/96500 = 0.02; mol Cu = 0.02/2 = 0.01; mass = 0.01 × 64 = 0.64 g."},
  {"i":"chem-g12-echem-209","g":12,"u":"Electrochemistry","d":"hard","t":"calculation","q":"What is the oxidation number of chromium in the dichromate ion, Cr₂O₇²⁻?","o":["+3","+6","+7","+12"],"c":1,"e":"O is −2 (total −14); ion charge −2, so 2Cr − 14 = −2 → 2Cr = +12 → Cr = +6 each."},
  {"i":"chem-g12-kin-210","g":11,"u":"Chemical Kinetics","d":"hard","t":"calculation","q":"For rate = k[A]²[B], if [A] is tripled and [B] is doubled, by what factor does the rate change?","o":["×6","×12","×18","×9"],"c":2,"e":"Rate ∝ [A]²[B], so factor = 3² × 2¹ = 9 × 2 = 18."},
  {"i":"chem-g12-kin-211","g":11,"u":"Chemical Kinetics","d":"hard","t":"calculation","q":"A first-order reaction has a half-life of 10 minutes. What fraction of the reactant remains after 30 minutes?","o":["1/2","1/4","1/8","1/16"],"c":2,"e":"30 min = 3 half-lives; fraction remaining = (1/2)³ = 1/8."},
  {"i":"chem-g12-eqm-212","g":11,"u":"Chemical Equilibrium","d":"hard","t":"calculation","q":"For H₂ + I₂ ⇌ 2HI, at equilibrium [H₂] = 0.20 M, [I₂] = 0.20 M, [HI] = 0.80 M. What is Kc?","o":["4","8","16","2"],"c":2,"e":"Kc = [HI]² / ([H₂][I₂]) = (0.80)² / (0.20 × 0.20) = 0.64 / 0.04 = 16."},
  {"i":"chem-g12-eqm-213","g":11,"u":"Chemical Equilibrium","d":"hard","t":"application","q":"For the endothermic reaction N₂O₄(g) ⇌ 2NO₂(g), which change increases the amount of NO₂ at equilibrium?","o":["Increasing pressure","Decreasing temperature","Increasing temperature","Adding a catalyst"],"c":2,"e":"Heat favours the endothermic (forward) direction, so raising temperature shifts equilibrium toward NO₂; a catalyst does not change the position."},
  {"i":"chem-g12-atom-214","g":11,"u":"Atomic Structure & Periodic Properties","d":"hard","t":"calculation","q":"Chlorine has two isotopes: ³⁵Cl (75%) and ³⁷Cl (25%). What is its relative atomic mass?","o":["35.0","35.5","36.0","37.0"],"c":1,"e":"Ar = (35 × 0.75) + (37 × 0.25) = 26.25 + 9.25 = 35.5."},
  {"i":"chem-g12-bond-215","g":11,"u":"Chemical Bonding","d":"hard","t":"conceptual","q":"Which molecule is non-polar overall despite containing polar bonds?","o":["H₂O","NH₃","CO₂","HCl"],"c":2,"e":"CO₂ is linear (O=C=O), so the two equal C=O bond dipoles point opposite and cancel; H₂O and NH₃ are bent/pyramidal and stay polar."},
  {"i":"chem-g12-mole-216","g":10,"u":"Chemical Reactions & Stoichiometry","d":"hard","t":"calculation","q":"A hydrocarbon has empirical formula CH₂ and molar mass 42 g/mol. What is its molecular formula? (C=12, H=1)","o":["C₂H₄","C₃H₆","C₃H₈","CH₂"],"c":1,"e":"Empirical mass CH₂ = 14; 42/14 = 3, so molecular formula = (CH₂)₃ = C₃H₆ (propene)."},
  {"i":"chem-g12-org-217","g":10,"u":"Hydrocarbons","d":"hard","t":"conceptual","q":"How many structural isomers have the molecular formula C₄H₁₀?","o":["1","2","3","4"],"c":1,"e":"C₄H₁₀ has two isomers: n-butane (straight chain) and 2-methylpropane (isobutane, branched)."},
  {"i":"chem-g12-org-218","g":10,"u":"Hydrocarbons","d":"hard","t":"conceptual","q":"Complete combustion of 1 mole of propane (C₃H₈) requires how many moles of O₂? (C₃H₈ + 5O₂ → 3CO₂ + 4H₂O)","o":["3","4","5","7"],"c":2,"e":"Balancing C₃H₈ + 5O₂ → 3CO₂ + 4H₂O gives 5 mol O₂ per mole of propane (10 O on each side)."},
  {"i":"chem-g12-org-219","g":10,"u":"Hydrocarbons","d":"hard","t":"conceptual","q":"Benzene (C₆H₆) does NOT readily undergo addition reactions with bromine in the dark because:","o":["It has no hydrogen atoms","Its delocalized π electrons give aromatic stability","It is an alkane","It is ionic"],"c":1,"e":"The six delocalized π electrons form a stable aromatic ring, so benzene favours substitution over addition, preserving that stability."},
  {"i":"chem-g12-poly-220","g":12,"u":"Polymers","d":"hard","t":"conceptual","q":"Which polymer is formed by condensation polymerization, releasing a small molecule such as water?","o":["Polyethene","Polypropene","Nylon (a polyamide)","PVC"],"c":2,"e":"Nylon forms when a diamine and a diacid join, releasing water at each amide link — condensation polymerization; the others are addition polymers of alkenes."},
  {"i":"chem-g12-env-221","g":12,"u":"Industrial Chemistry","d":"hard","t":"conceptual","q":"In the Contact process for making sulfuric acid, the key catalysed step 2SO₂ + O₂ ⇌ 2SO₃ uses which catalyst?","o":["Iron","Vanadium(V) oxide, V₂O₅","Nickel","Platinum only"],"c":1,"e":"The Contact process uses vanadium(V) oxide (V₂O₅) to catalyse the oxidation of SO₂ to SO₃."},
  {"i":"chem-g12-atom-222","g":11,"u":"Atomic Structure & Periodic Properties","d":"hard","t":"calculation","q":"How many unpaired electrons are in a ground-state nitrogen atom (Z = 7)?","o":["1","2","3","0"],"c":2,"e":"N is 1s² 2s² 2p³; by Hund's rule the three 2p electrons occupy separate orbitals singly, giving 3 unpaired electrons."},
  {"i":"chem-g12-acid-301","g":12,"u":"Acid–Base Equilibria","d":"impossible","t":"calculation","q":"A buffer contains 0.20 M CH₃COOH and 0.20 M CH₃COONa. Ka(acetic) = 1.8 × 10⁻⁵. What is the pH? (log 1.8 ≈ 0.26)","o":["4.74","5.00","4.20","9.26"],"c":0,"e":"Henderson–Hasselbalch: pH = pKa + log([salt]/[acid]); equal concentrations make the log term 0, so pH = pKa = −log(1.8×10⁻⁵) = 5 − 0.26 = 4.74."},
  {"i":"chem-g12-acid-302","g":12,"u":"Acid–Base Equilibria","d":"impossible","t":"calculation","q":"50 mL of 0.10 M HCl is mixed with 30 mL of 0.10 M NaOH. What is the pH of the resulting solution? (volumes additive)","o":["1.60","2.00","1.90","7.00"],"c":0,"e":"mol H⁺ = 0.005, mol OH⁻ = 0.003; excess H⁺ = 0.002 mol in 0.080 L = 0.025 M; pH = −log(0.025) ≈ 1.60."},
  {"i":"chem-g12-acid-303","g":12,"u":"Acid–Base Equilibria","d":"impossible","t":"calculation","q":"What is the pH of a 1.0 × 10⁻⁸ M HCl solution at 25 °C? (water autoionization matters)","o":["8.0","6.98","7.0","6.0"],"c":1,"e":"Acid is so dilute that water's H⁺ matters: [H⁺] = ½(10⁻⁸ + √(10⁻¹⁶ + 4×10⁻¹⁴)) ≈ 1.05×10⁻⁷; pH ≈ 6.98 (just below 7, never above for an acid)."},
  {"i":"chem-g12-mole-304","g":10,"u":"Chemical Reactions & Stoichiometry","d":"impossible","t":"calculation","q":"A 1.00 g sample of CaCO₃ is heated: CaCO₃ → CaO + CO₂. What volume of CO₂ is released at STP? (Ca=40, C=12, O=16; molar volume 22.4 L/mol)","o":["0.112 L","0.224 L","0.448 L","1.00 L"],"c":1,"e":"M(CaCO₃) = 100 g/mol; n = 1.00/100 = 0.01 mol; 1:1 gives 0.01 mol CO₂; V = 0.01 × 22.4 = 0.224 L."},
  {"i":"chem-g12-mole-305","g":10,"u":"Chemical Reactions & Stoichiometry","d":"impossible","t":"calculation","q":"Aluminium reacts as 2Al + 3Cl₂ → 2AlCl₃. If 5.4 g Al reacts with 21.3 g Cl₂, what mass of AlCl₃ forms? (Al=27, Cl=35.5)","o":["26.7 g","13.35 g","26.6 g","40.05 g"],"c":0,"e":"n(Al)=5.4/27=0.20, n(Cl₂)=21.3/71=0.30; Cl₂/Al ratio needed 1.5, available 1.5, so both fully react; AlCl₃ = 0.20 mol × 133.5 = 26.7 g."},
  {"i":"chem-g12-echem-306","g":12,"u":"Electrochemistry","d":"impossible","t":"calculation","q":"The same charge is passed through cells of AgNO₃ and CuSO₄ in series. If 10.8 g of Ag (108 g/mol) is deposited, what mass of Cu (64 g/mol) deposits? (Ag⁺+e⁻→Ag; Cu²⁺+2e⁻→Cu)","o":["6.4 g","3.2 g","12.8 g","1.6 g"],"c":1,"e":"mol Ag = 10.8/108 = 0.10 = mol e⁻; Cu needs 2 e⁻ each, so mol Cu = 0.10/2 = 0.05; mass = 0.05 × 64 = 3.2 g."},
  {"i":"chem-g12-echem-307","g":12,"u":"Electrochemistry","d":"impossible","t":"calculation","q":"Balance in acid: MnO₄⁻ + Fe²⁺ → Mn²⁺ + Fe³⁺. How many moles of Fe²⁺ are oxidized per mole of MnO₄⁻?","o":["1","2","5","8"],"c":2,"e":"Mn goes +7→+2 (gains 5 e⁻); each Fe²⁺→Fe³⁺ loses 1 e⁻, so 5 Fe²⁺ are needed to balance the 5 electrons."},
  {"i":"chem-g12-eqm-308","g":11,"u":"Chemical Equilibrium","d":"impossible","t":"calculation","q":"For A(g) ⇌ 2B(g), 1.0 mol A is placed in a 1.0 L flask and 50% dissociates at equilibrium. What is Kc?","o":["0.5","1.0","2.0","0.25"],"c":2,"e":"A reacted = 0.5 mol, so [A] = 0.5 M and [B] = 2 × 0.5 = 1.0 M; Kc = [B]²/[A] = (1.0)²/0.5 = 2.0."},
  {"i":"chem-g12-eqm-309","g":11,"u":"Chemical Equilibrium","d":"impossible","t":"calculation","q":"For PCl₅ ⇌ PCl₃ + Cl₂, 2.0 mol PCl₅ in a 2.0 L vessel reaches equilibrium with 0.50 mol Cl₂ formed. What is Kc?","o":["0.083","0.17","0.33","0.042"],"c":0,"e":"At eqm (in M): Cl₂=0.25, PCl₃=0.25, PCl₅=(2.0−0.5)/2=0.75; Kc=(0.25×0.25)/0.75=0.0625/0.75=0.083."},
  {"i":"chem-g12-kin-310","g":11,"u":"Chemical Kinetics","d":"impossible","t":"calculation","q":"Experiments give: doubling [A] doubles the rate; doubling [B] quadruples the rate. What is the overall reaction order?","o":["2","3","1","4"],"c":1,"e":"Order in A = 1 (rate ×2), order in B = 2 (rate ×4 = 2²); overall order = 1 + 2 = 3."},
  {"i":"chem-g12-mole-311","g":10,"u":"Chemical Reactions & Stoichiometry","d":"impossible","t":"calculation","q":"A 4.0 L sample of gas at STP has a mass of 5.0 g. What is its molar mass? (molar volume 22.4 L/mol)","o":["22.4 g/mol","28 g/mol","44 g/mol","11.2 g/mol"],"c":1,"e":"n = 4.0/22.4 = 0.1786 mol; M = mass/n = 5.0/0.1786 ≈ 28 g/mol (e.g. N₂ or CO)."},
  {"i":"chem-g12-org-312","g":10,"u":"Hydrocarbons","d":"impossible","t":"conceptual","q":"How many structural isomers (including positional) have the molecular formula C₅H₁₂?","o":["2","3","4","5"],"c":1,"e":"C₅H₁₂ has three isomers: n-pentane, 2-methylbutane (isopentane) and 2,2-dimethylpropane (neopentane)."},
  {"i":"chem-g12-org-313","g":10,"u":"Hydrocarbons","d":"impossible","t":"calculation","q":"A hydrocarbon contains 85.7% carbon by mass and has molar mass 56 g/mol. What is its molecular formula? (C=12, H=1)","o":["C₄H₈","C₃H₆","C₄H₁₀","C₄H₆"],"c":0,"e":"C: 85.7/12 = 7.14, H: 14.3/1 = 14.3; ratio 1:2 → empirical CH₂ (mass 14); 56/14 = 4 → C₄H₈ (a butene)."},
  {"i":"chem-g12-org-314","g":10,"u":"Hydrocarbons","d":"impossible","t":"conceptual","q":"Which compound exhibits cis–trans (geometric) isomerism?","o":["But-1-ene","But-2-ene","Propene","2-methylpropene"],"c":1,"e":"Geometric isomerism needs each doubly-bonded carbon to carry two different groups; in but-2-ene (CH₃–CH=CH–CH₃) each =C has H and CH₃, giving cis and trans forms."},
  {"i":"chem-g12-bond-315","g":11,"u":"Chemical Bonding","d":"impossible","t":"conceptual","q":"What is the hybridization of the central carbon atoms in ethyne (C₂H₂, H–C≡C–H)?","o":["sp³","sp²","sp","sp³d"],"c":2,"e":"Each carbon in the triple bond has two sigma regions (one C–H, one C–C) and two π bonds, so it is sp hybridized (linear, 180°)."},
  {"i":"chem-g12-atom-316","g":11,"u":"Atomic Structure & Periodic Properties","d":"impossible","t":"calculation","q":"An electron transitions in a hydrogen atom from n = 3 to n = 2. Using ΔE = −13.6(1/n_f² − 1/n_i²) eV, what energy is emitted?","o":["1.89 eV","13.6 eV","10.2 eV","3.40 eV"],"c":0,"e":"ΔE = 13.6(1/2² − 1/3²) = 13.6(0.25 − 0.1111) = 13.6 × 0.1389 ≈ 1.89 eV emitted."},
  {"i":"chem-g12-mole-317","g":10,"u":"Chemical Reactions & Stoichiometry","d":"impossible","t":"calculation","q":"How many oxygen atoms are present in 0.50 mol of Al₂(SO₄)₃? (Avogadro = 6.02 × 10²³)","o":["3.6 × 10²⁴","6.0 × 10²³","1.2 × 10²⁴","7.2 × 10²⁴"],"c":0,"e":"Each formula unit has 12 O atoms (3 SO₄); O moles = 0.50 × 12 = 6.0 mol; atoms = 6.0 × 6.02×10²³ = 3.6 × 10²⁴."},
  {"i":"chem-g12-acid-318","g":12,"u":"Acid–Base Equilibria","d":"impossible","t":"calculation","q":"A 0.10 M solution of a weak base B has Kb = 1.0 × 10⁻⁵. What is its pH at 25 °C? (assume x ≪ 0.10)","o":["3.0","11.0","9.0","5.0"],"c":1,"e":"[OH⁻] = √(Kb·C) = √(10⁻⁵ × 0.10) = √(10⁻⁶) = 10⁻³; pOH = 3, pH = 14 − 3 = 11."},
  {"i":"chem-g12-echem-319","g":12,"u":"Electrochemistry","d":"impossible","t":"calculation","q":"How long must a current of 5.0 A flow to deposit 0.50 mol of Al from molten Al₂O₃? (Al³⁺ + 3e⁻ → Al, F = 96500 C/mol)","o":["9650 s","28950 s","19300 s","4825 s"],"c":1,"e":"mol e⁻ = 0.50 × 3 = 1.5; Q = 1.5 × 96500 = 144750 C; t = Q/I = 144750/5.0 = 28950 s."},
  {"i":"chem-g12-eqm-320","g":11,"u":"Chemical Equilibrium","d":"impossible","t":"application","q":"For 2NO₂(g) ⇌ N₂O₄(g) at equilibrium in a sealed rigid flask, an inert gas (argon) is added at constant volume. The equilibrium position will:","o":["Shift toward N₂O₄","Shift toward NO₂","Not shift","Shift then reverse"],"c":2,"e":"At constant volume, adding inert gas does not change the partial pressures or concentrations of NO₂ or N₂O₄, so the equilibrium position is unchanged."},
  {"i":"chem-g12-org-321","g":10,"u":"Hydrocarbons","d":"impossible","t":"calculation","q":"Complete combustion of an alkane gives 4 mol CO₂ and 5 mol H₂O per mole of fuel. What is the alkane?","o":["Butane, C₄H₁₀","Propane, C₃H₈","Pentane, C₅H₁₂","Butene, C₄H₈"],"c":0,"e":"Carbons = mol CO₂ = 4; hydrogens = 2 × mol H₂O = 10; so C₄H₁₀ (butane), which fits the alkane formula CₙH₂ₙ₊₂."},
  {"i":"chem-g12-poly-322","g":12,"u":"Polymers","d":"impossible","t":"calculation","q":"A sample of polyethene, (C₂H₄)ₙ, has an average molar mass of 28,000 g/mol. What is the average degree of polymerization n? (C₂H₄ = 28 g/mol)","o":["100","500","1000","2000"],"c":2,"e":"Each repeat unit C₂H₄ is 28 g/mol; n = 28000 / 28 = 1000 repeat units."},
  {"i":"chem-b3-0001","g":9,"u":"Chemistry & Its Importance","d":"easy","t":"definition","q":"Which branch of chemistry deals mainly with the study of compounds that contain carbon, such as those found in injera and other foods?","o":["Inorganic chemistry","Organic chemistry","Physical chemistry","Analytical chemistry"],"c":1,"e":"Organic chemistry is the study of carbon-containing compounds; most food substances are organic."},
  {"i":"chem-b3-0002","g":9,"u":"Chemistry & Its Importance","d":"easy","t":"conceptual","q":"A chemist at an Ethiopian sugar factory determines the percentage of sucrose in a sample. Which branch of chemistry is mainly applied?","o":["Analytical chemistry","Organic synthesis","Nuclear chemistry","Biochemistry"],"c":0,"e":"Analytical chemistry deals with determining the composition and amount of substances in a sample."},
  {"i":"chem-b3-0003","g":9,"u":"Chemistry & Its Importance","d":"easy","t":"conceptual","q":"Which of the following is an example of how chemistry improves agriculture in Ethiopia?","o":["Producing fertilizers to increase crop yield","Translating documents into Amharic","Building roads between towns","Composing traditional music"],"c":0,"e":"Chemistry contributes to agriculture chiefly through fertilizers, pesticides and soil treatment that raise crop yields."},
  {"i":"chem-b3-0004","g":9,"u":"Measurements & Scientific Methods","d":"easy","t":"definition","q":"What is the SI base unit of the amount of substance?","o":["Gram","Mole","Litre","Kilogram"],"c":1,"e":"The mole (mol) is the SI base unit for amount of substance."},
  {"i":"chem-b3-0005","g":9,"u":"Measurements & Scientific Methods","d":"easy","t":"calculation","q":"A length is measured as 250 cm. What is this length expressed in metres?","o":["0.25 m","2.5 m","25 m","2500 m"],"c":1,"e":"Since 100 cm = 1 m, 250 cm ÷ 100 = 2.5 m."},
  {"i":"chem-b3-0006","g":9,"u":"Measurements & Scientific Methods","d":"easy","t":"calculation","q":"The density of a substance is 2 g/cm³. What is the mass of 5 cm³ of this substance?","o":["2.5 g","7 g","10 g","3 g"],"c":2,"e":"Mass = density × volume = 2 g/cm³ × 5 cm³ = 10 g."},
  {"i":"chem-b3-0007","g":9,"u":"Measurements & Scientific Methods","d":"easy","t":"conceptual","q":"In the scientific method, what is the correct name for a tested, proposed explanation that can be supported or rejected by experiment?","o":["Conclusion","Hypothesis","Observation","Measurement"],"c":1,"e":"A hypothesis is a testable proposed explanation that experiments can support or reject."},
  {"i":"chem-b3-0008","g":9,"u":"Measurements & Scientific Methods","d":"easy","t":"calculation","q":"A temperature is recorded as 27 °C. What is this temperature in kelvin?","o":["246 K","300 K","254 K","327 K"],"c":1,"e":"K = °C + 273, so 27 + 273 = 300 K."},
  {"i":"chem-b3-0009","g":9,"u":"Structure of the Atom","d":"easy","t":"definition","q":"Which subatomic particle carries a negative electric charge?","o":["Proton","Neutron","Electron","Nucleus"],"c":2,"e":"The electron is the negatively charged subatomic particle."},
  {"i":"chem-b3-0010","g":9,"u":"Structure of the Atom","d":"easy","t":"calculation","q":"An atom has 17 protons and 18 neutrons. What is its mass number?","o":["17","18","35","1"],"c":2,"e":"Mass number = protons + neutrons = 17 + 18 = 35."},
  {"i":"chem-b3-0011","g":9,"u":"Structure of the Atom","d":"easy","t":"calculation","q":"A neutral atom has 11 protons. How many electrons does it have?","o":["10","11","12","22"],"c":1,"e":"A neutral atom has equal numbers of protons and electrons, so 11 electrons."},
  {"i":"chem-b3-0012","g":9,"u":"Structure of the Atom","d":"easy","t":"conceptual","q":"Two atoms have the same number of protons but different numbers of neutrons. They are called:","o":["Isotopes","Ions","Isomers","Allotropes"],"c":0,"e":"Isotopes are atoms of the same element (same protons) with different numbers of neutrons."},
  {"i":"chem-b3-0013","g":9,"u":"Structure of the Atom","d":"easy","t":"calculation","q":"What is the maximum number of electrons that the second energy level (n = 2) can hold?","o":["2","6","8","18"],"c":2,"e":"The maximum electrons in a level is 2n²; for n = 2 this is 2(2²) = 8."},
  {"i":"chem-b3-0014","g":9,"u":"Structure of the Atom","d":"easy","t":"application","q":"The electron configuration of an atom is 2, 8, 1. How many valence (outermost) electrons does it have?","o":["1","2","8","11"],"c":0,"e":"The outermost shell holds 1 electron, so there is 1 valence electron."},
  {"i":"chem-b3-0015","g":9,"u":"Periodic Classification of Elements","d":"easy","t":"definition","q":"In the periodic table, the horizontal rows are called:","o":["Groups","Periods","Families","Blocks"],"c":1,"e":"Horizontal rows are periods; vertical columns are groups."},
  {"i":"chem-b3-0016","g":9,"u":"Periodic Classification of Elements","d":"easy","t":"conceptual","q":"To which group of the periodic table do the very unreactive noble gases belong?","o":["Group IA","Group IIA","Group VIIA","Group VIIIA"],"c":3,"e":"The noble gases occupy Group VIIIA (Group 18) and are chemically very unreactive."},
  {"i":"chem-b3-0017","g":9,"u":"Periodic Classification of Elements","d":"easy","t":"application","q":"An element has the electron configuration 2, 8, 7. In which group is it found?","o":["Group IIA","Group VA","Group VIIA","Group VIIIA"],"c":2,"e":"With 7 valence electrons, the element belongs to Group VIIA (the halogens)."},
  {"i":"chem-b3-0018","g":9,"u":"Periodic Classification of Elements","d":"easy","t":"conceptual","q":"Which of the following is a general property of metals?","o":["They are good conductors of electricity","They are brittle in the solid state","They gain electrons easily","They are poor heat conductors"],"c":0,"e":"Metals are typically good conductors of electricity and heat and tend to lose electrons."},
  {"i":"chem-b3-0019","g":9,"u":"Chemical Bonding","d":"easy","t":"definition","q":"The type of bond formed by the transfer of electrons from a metal to a non-metal is called:","o":["Covalent bond","Ionic bond","Metallic bond","Hydrogen bond"],"c":1,"e":"An ionic bond forms when electrons are transferred from a metal to a non-metal, producing oppositely charged ions."},
  {"i":"chem-b3-0020","g":9,"u":"Chemical Bonding","d":"easy","t":"application","q":"In a water molecule (H₂O), the hydrogen and oxygen atoms are joined by what kind of bond?","o":["Ionic bond","Metallic bond","Covalent bond","Ionic and metallic bonds"],"c":2,"e":"Water is formed by covalent bonds in which non-metal atoms share electrons."},
  {"i":"chem-b3-0021","g":9,"u":"Chemical Bonding","d":"easy","t":"application","q":"When sodium (Na) reacts with chlorine (Cl) to form NaCl, the sodium atom:","o":["Gains one electron","Loses one electron","Shares one electron","Loses two electrons"],"c":1,"e":"Sodium loses its single valence electron to become Na⁺, forming an ionic bond with chloride."},
  {"i":"chem-b3-0022","g":9,"u":"Chemistry & Its Importance","d":"easy","t":"definition","q":"Which branch of chemistry deals mainly with the study of carbon-containing compounds, such as the sugars found in Ethiopian honey?","o":["Inorganic chemistry","Organic chemistry","Analytical chemistry","Physical chemistry"],"c":1,"e":"Organic chemistry is the branch that studies carbon-containing compounds, including sugars and other biomolecules."},
  {"i":"chem-b3-0023","g":9,"u":"Measurements & Scientific Methods","d":"easy","t":"calculation","q":"A sample of teff flour has a mass of 250 g and a volume of 500 cm³. What is its density in g/cm³?","o":["0.5 g/cm³","2.0 g/cm³","1.5 g/cm³","0.25 g/cm³"],"c":0,"e":"Density = mass ÷ volume = 250 g ÷ 500 cm³ = 0.5 g/cm³."},
  {"i":"chem-b3-0024","g":9,"u":"Measurements & Scientific Methods","d":"easy","t":"definition","q":"Which of the following is the SI base unit used to measure the amount of a substance?","o":["Kilogram (kg)","Mole (mol)","Litre (L)","Gram (g)"],"c":1,"e":"The mole (mol) is the SI base unit for the amount of substance; the kilogram is the base unit for mass."},
  {"i":"chem-b3-0025","g":9,"u":"Structure of the Atom","d":"easy","t":"conceptual","q":"An atom of sodium has 11 protons and 12 neutrons. What is its mass number?","o":["11","12","23","1"],"c":2,"e":"Mass number = number of protons + number of neutrons = 11 + 12 = 23."},
  {"i":"chem-b3-0026","g":9,"u":"Structure of the Atom","d":"easy","t":"definition","q":"Which subatomic particle carries a negative charge and has a negligible mass?","o":["Proton","Neutron","Electron","Nucleus"],"c":2,"e":"The electron carries a negative charge and has a mass about 1/1836 that of a proton, so it is negligible."},
  {"i":"chem-b3-0027","g":9,"u":"Periodic Classification of Elements","d":"easy","t":"conceptual","q":"In the modern periodic table, the elements are arranged in order of increasing what?","o":["Atomic mass","Atomic (proton) number","Number of neutrons","Density"],"c":1,"e":"The modern periodic table arranges elements by increasing atomic (proton) number, following Moseley's work."},
  {"i":"chem-b3-0028","g":9,"u":"Chemical Bonding","d":"easy","t":"conceptual","q":"What type of chemical bond forms when a metal transfers electrons to a non-metal, as in sodium chloride (NaCl)?","o":["Covalent bond","Ionic bond","Metallic bond","Hydrogen bond"],"c":1,"e":"In NaCl, sodium transfers an electron to chlorine, forming oppositely charged ions held by an ionic bond."},
  {"i":"chem-b3-0029","g":9,"u":"Chemistry & Its Importance","d":"medium","t":"conceptual","q":"A farmer near Ziway stores urea fertilizer to enrich soil nitrogen. Classifying chemistry into its main branches, the study of how urea is synthesized from ammonia and carbon dioxide falls primarily under which branch?","o":["Analytical chemistry","Inorganic chemistry","Organic chemistry","Physical chemistry"],"c":2,"e":"Urea, CO(NH₂)₂, is a carbon-containing compound, so its synthesis is studied under organic chemistry, the branch dealing with carbon compounds."},
  {"i":"chem-b3-0030","g":9,"u":"Chemistry & Its Importance","d":"medium","t":"application","q":"In a traditional Ethiopian process, dried 'enset' is left to ferment for weeks before making kocho. The breaking down of starch into simpler substances by microbes is best described as which kind of change?","o":["A physical change only","A chemical change producing new substances","A change of state","A nuclear change"],"c":1,"e":"Fermentation converts starch into new substances (acids and gases) with new chemical compositions, so it is a chemical change."},
  {"i":"chem-b3-0031","g":9,"u":"Measurements & Scientific Methods","d":"medium","t":"calculation","q":"A student measures a copper wire's length as 0.04250 m. How many significant figures does this measurement contain?","o":["3","4","5","6"],"c":1,"e":"Leading zeros are not significant; the digits 4, 2, 5 and the trailing 0 after the decimal are significant, giving 4 significant figures."},
  {"i":"chem-b3-0032","g":9,"u":"Measurements & Scientific Methods","d":"medium","t":"calculation","q":"A sample of honey from Bonga has a mass of 360 g and occupies a volume of 250 cm³. What is its density in g/cm³?","o":["0.69 g/cm³","1.30 g/cm³","1.44 g/cm³","1.80 g/cm³"],"c":2,"e":"Density = mass ÷ volume = 360 g ÷ 250 cm³ = 1.44 g/cm³."},
  {"i":"chem-b3-0033","g":9,"u":"Measurements & Scientific Methods","d":"medium","t":"application","q":"A researcher proposes that adding wood ash raises the pH of soil. She treats several plots with ash and several without, then measures pH. In this experiment, the plots without ash serve as the:","o":["Dependent variable","Independent variable","Control group","Hypothesis"],"c":2,"e":"The untreated plots are the control group, used as a baseline for comparison against the treated plots."},
  {"i":"chem-b3-0034","g":9,"u":"Measurements & Scientific Methods","d":"medium","t":"calculation","q":"Convert a temperature of 27 °C, typical of an Addis Ababa afternoon, to the Kelvin scale.","o":["246 K","300 K","327 K","254 K"],"c":1,"e":"K = °C + 273; 27 + 273 = 300 K."},
  {"i":"chem-b3-0035","g":9,"u":"Structure of the Atom","d":"medium","t":"calculation","q":"An atom of an element has 17 protons, 18 neutrons and 17 electrons. What are its mass number and net charge?","o":["Mass number 35, charge 0","Mass number 34, charge 0","Mass number 35, charge +1","Mass number 18, charge −1"],"c":0,"e":"Mass number = protons + neutrons = 17 + 18 = 35; protons equal electrons, so the atom is neutral (charge 0)."},
  {"i":"chem-b3-0036","g":9,"u":"Structure of the Atom","d":"medium","t":"calculation","q":"Chlorine has two isotopes: ³⁵Cl (mass 35, abundance 75%) and ³⁷Cl (mass 37, abundance 25%). What is its relative atomic mass?","o":["35.5","36.0","35.0","37.0"],"c":0,"e":"Average = (35 × 0.75) + (37 × 0.25) = 26.25 + 9.25 = 35.5."},
  {"i":"chem-b3-0037","g":9,"u":"Structure of the Atom","d":"medium","t":"conceptual","q":"Using the n=2, 8, 8 filling rule, what is the electron configuration of a calcium atom (Z = 20)?","o":["2, 8, 10","2, 8, 8, 2","2, 18","2, 8, 9, 1"],"c":1,"e":"Filling shells in order 2, then 8, then 8, then 2 accounts for all 20 electrons: 2, 8, 8, 2."},
  {"i":"chem-b3-0038","g":9,"u":"Structure of the Atom","d":"medium","t":"definition","q":"Atoms of the same element that have the same number of protons but different numbers of neutrons are called:","o":["Isomers","Isotopes","Ions","Allotropes"],"c":1,"e":"Isotopes share proton number (same element) but differ in neutron number, giving different mass numbers."},
  {"i":"chem-b3-0039","g":9,"u":"Structure of the Atom","d":"medium","t":"conceptual","q":"An ion has 12 protons, 12 neutrons and 10 electrons. What is the symbol of this ion?","o":["Mg²⁺","Mg²⁻","Ne","Ca²⁺"],"c":0,"e":"12 protons identify magnesium (Mg); having 10 electrons means 2 more protons than electrons, giving a 2+ charge, so Mg²⁺."},
  {"i":"chem-b3-0040","g":9,"u":"Periodic Classification of Elements","d":"medium","t":"conceptual","q":"An element has the electron configuration 2, 8, 7. In which group and period of the periodic table is it found?","o":["Group VIIA, Period 3","Group VA, Period 3","Group VIIA, Period 2","Group IIIA, Period 7"],"c":0,"e":"Three occupied shells means Period 3; 7 outer-shell electrons means Group VIIA (the halogens)."},
  {"i":"chem-b3-0041","g":9,"u":"Periodic Classification of Elements","d":"medium","t":"conceptual","q":"Going across Period 3 from sodium (Na) to chlorine (Cl), how do atomic radius and the metallic character generally change?","o":["Both increase","Both decrease","Atomic radius increases, metallic character decreases","Atomic radius decreases, metallic character increases"],"c":1,"e":"Increasing nuclear charge pulls electrons closer, so atomic radius decreases and metallic character decreases across a period."},
  {"i":"chem-b3-0042","g":9,"u":"Periodic Classification of Elements","d":"medium","t":"application","q":"Element X is in Group IA and element Y is in Group VIIA. What is the most likely formula of the compound they form?","o":["XY","XY₂","X₂Y","X₇Y"],"c":0,"e":"Group IA loses 1 electron (X⁺) and Group VIIA gains 1 (Y⁻); a 1:1 ratio gives the neutral formula XY."},
  {"i":"chem-b3-0043","g":9,"u":"Periodic Classification of Elements","d":"medium","t":"conceptual","q":"Which property increases from top to bottom down Group IA (the alkali metals)?","o":["Ionization energy","Electronegativity","Atomic radius","Melting point"],"c":2,"e":"Down a group, additional electron shells are added, so atomic radius increases while ionization energy and electronegativity decrease."},
  {"i":"chem-b3-0044","g":9,"u":"Chemical Bonding","d":"medium","t":"conceptual","q":"When sodium (2, 8, 1) reacts with chlorine (2, 8, 7) to form table salt, the bond formed is best described as:","o":["A covalent bond by sharing electrons","An ionic bond by transfer of one electron from Na to Cl","A metallic bond","A coordinate covalent bond"],"c":1,"e":"Na transfers its single outer electron to Cl, forming Na⁺ and Cl⁻ ions held together by electrostatic attraction: an ionic bond."},
  {"i":"chem-b3-0045","g":9,"u":"Chemical Bonding","d":"medium","t":"application","q":"How many covalent bonds and lone pairs are on the nitrogen atom in an ammonia molecule, NH₃?","o":["3 bonds, 0 lone pairs","3 bonds, 1 lone pair","4 bonds, 0 lone pairs","2 bonds, 2 lone pairs"],"c":1,"e":"Nitrogen has 5 valence electrons; it shares 3 to bond with three H atoms, leaving one lone pair: 3 bonds and 1 lone pair."},
  {"i":"chem-b3-0046","g":9,"u":"Chemical Bonding","d":"medium","t":"conceptual","q":"Solid potassium chloride does not conduct electricity, but molten potassium chloride does. The best explanation is that conduction requires:","o":["Free-moving delocalized electrons that appear on melting","Free-moving ions, which exist only when the ionic lattice melts","Covalent bonds breaking into atoms","Hydrogen bonds forming between ions"],"c":1,"e":"In the solid, ions are fixed in a lattice; melting frees the K⁺ and Cl⁻ ions to move and carry charge, enabling conduction."},
  {"i":"chem-b3-0047","g":9,"u":"Chemical Bonding","d":"medium","t":"conceptual","q":"Which pair of atoms will form a polar covalent bond rather than a nonpolar covalent or ionic bond?","o":["Cl and Cl","H and Cl","Na and Cl","O and O"],"c":1,"e":"Identical atoms (Cl–Cl, O–O) share equally (nonpolar); Na–Cl transfers electrons (ionic); H–Cl shares unequally due to an electronegativity difference, giving a polar covalent bond."},
  {"i":"chem-b3-0048","g":9,"u":"Chemical Bonding","d":"medium","t":"application","q":"Magnesium (Group IIA) reacts with oxygen (Group VIA) to form an ionic oxide. What is the correct formula of the product?","o":["MgO","Mg₂O","MgO₂","Mg₂O₃"],"c":0,"e":"Mg loses 2 electrons (Mg²⁺) and O gains 2 (O²⁻); equal and opposite charges combine 1:1 to give MgO."},
  {"i":"chem-b3-0049","g":9,"u":"Chemical Bonding","d":"medium","t":"conceptual","q":"In a piece of pure iron used to make a traditional 'sefed' tool, the atoms are held together by:","o":["Ionic bonds between Fe²⁺ and Fe³⁻","Covalent bonds sharing pairs of electrons","Metallic bonding: cations in a sea of delocalized electrons","Hydrogen bonding"],"c":2,"e":"Metals consist of positive cations surrounded by a sea of delocalized (mobile) electrons, which explains their conductivity and malleability."},
  {"i":"chem-b3-0050","g":9,"u":"Chemical Bonding","d":"medium","t":"conceptual","q":"Why does carbon typically form four covalent bonds, as in methane (CH₄), rather than gaining or losing electrons to form ions?","o":["It has 4 valence electrons and gaining or losing 4 is energetically unfavourable, so it shares to reach 8","It has 8 valence electrons already","It is a metal that loses electrons easily","It has only 2 valence electrons"],"c":0,"e":"Carbon has 4 valence electrons; transferring four electrons would require too much energy, so it shares four pairs to complete an octet, forming four covalent bonds."},
  {"i":"chem-b3-0051","g":9,"u":"Chemistry & Its Importance","d":"medium","t":"conceptual","q":"A teacher in Bahir Dar classifies several school activities. Which one is an example of applying chemistry to solve a problem rather than a purely physical observation?","o":["Measuring the length of a desk with a ruler","Treating drinking water with chlorine to kill germs","Reading the temperature on a wall thermometer","Counting the number of students in a classroom"],"c":1,"e":"Adding chlorine causes a chemical reaction that destroys microorganisms (water purification), a direct application of chemistry; the others are physical measurements or counts."},
  {"i":"chem-b3-0052","g":9,"u":"Chemistry & Its Importance","d":"medium","t":"application","q":"In an Ethiopian tannery, raw hides are converted into leather using chemical agents. This best illustrates the role of chemistry in which sector?","o":["Pure mathematics","Industry and manufacturing","Astronomy","Literature"],"c":1,"e":"Leather tanning uses chemical processing to transform hides into durable products, an industrial/manufacturing application of chemistry."},
  {"i":"chem-b3-0053","g":9,"u":"Measurements & Scientific Methods","d":"medium","t":"calculation","q":"A student measures a copper block: mass = 89.6 g and volume = 10.0 cm³. What is its density in g/cm³?","o":["0.112 g/cm³","8.96 g/cm³","896 g/cm³","9.86 g/cm³"],"c":1,"e":"Density = mass ÷ volume = 89.6 g ÷ 10.0 cm³ = 8.96 g/cm³."},
  {"i":"chem-b3-0054","g":9,"u":"Measurements & Scientific Methods","d":"medium","t":"calculation","q":"A length is recorded as 0.00452 m. Expressed in standard scientific notation, this equals:","o":["4.52 × 10⁻³ m","45.2 × 10⁻⁴ m","4.52 × 10³ m","0.452 × 10⁻² m"],"c":0,"e":"Moving the decimal point 3 places right gives a coefficient 4.52 between 1 and 10, so 0.00452 = 4.52 × 10⁻³ m."},
  {"i":"chem-b3-0055","g":9,"u":"Measurements & Scientific Methods","d":"medium","t":"conceptual","q":"While testing a hypothesis on how temperature affects how fast sugar dissolves in water, a student keeps the amount of sugar, volume of water, and stirring the same, changing only temperature. The temperature is the:","o":["Controlled variable","Dependent variable","Independent variable","Constant"],"c":2,"e":"The factor the experimenter deliberately changes to observe its effect is the independent variable; the dissolving rate measured is the dependent variable."},
  {"i":"chem-b3-0056","g":9,"u":"Structure of the Atom","d":"medium","t":"calculation","q":"An atom of an element has 17 protons, 18 neutrons, and 17 electrons. What are its atomic number and mass number?","o":["Atomic number 17, mass number 35","Atomic number 18, mass number 35","Atomic number 17, mass number 34","Atomic number 35, mass number 17"],"c":0,"e":"Atomic number = number of protons = 17; mass number = protons + neutrons = 17 + 18 = 35."},
  {"i":"chem-b3-0057","g":9,"u":"Structure of the Atom","d":"medium","t":"conceptual","q":"Two atoms X and Y both have 6 protons, but X has 6 neutrons and Y has 8 neutrons. X and Y are best described as:","o":["Isotopes of the same element","Two different elements","Ions of carbon","Allotropes"],"c":0,"e":"Same number of protons (same element) but different numbers of neutrons (different mass numbers) makes X and Y isotopes."},
  {"i":"chem-b3-0058","g":9,"u":"Structure of the Atom","d":"medium","t":"calculation","q":"An atom has the electron configuration 2, 8, 7. Which statement is correct?","o":["It has 7 protons in its nucleus","It needs to gain 1 electron to become stable","It has a full outer shell","It will lose 7 electrons easily"],"c":1,"e":"Total electrons = 2+8+7 = 17, with 7 in the outer shell; gaining 1 electron completes the octet (8), giving a stable configuration like a noble gas."},
  {"i":"chem-b3-0059","g":9,"u":"Periodic Classification of Elements","d":"medium","t":"conceptual","q":"An element is found in Period 3, Group IA (the alkali metals) of the periodic table. Which property is expected?","o":["It is an unreactive gas","It readily loses one electron to form a 1+ ion","It gains two electrons to form a 2− ion","It is a non-metal that does not conduct electricity"],"c":1,"e":"Group IA elements have one valence electron, which they readily lose to form 1+ ions; this is sodium (Na), a reactive metal."},
  {"i":"chem-b3-0060","g":9,"u":"Periodic Classification of Elements","d":"medium","t":"conceptual","q":"Across Period 3 from sodium (Na) to chlorine (Cl), how does atomic radius generally change and why?","o":["Increases, because more shells are added","Decreases, because increasing nuclear charge pulls the same shell closer","Stays constant, because the period number is fixed","Decreases, because electrons are removed"],"c":1,"e":"Across a period the number of shells stays the same while nuclear charge rises, pulling the outer electrons in more tightly, so atomic radius decreases."},
  {"i":"chem-b3-0061","g":9,"u":"Chemical Bonding","d":"medium","t":"conceptual","q":"When magnesium (Group IIA) reacts with chlorine (Group VIIA) to form MgCl₂, the bonding involved is:","o":["Ionic, by transfer of 2 electrons from Mg to 2 Cl atoms","Covalent, by sharing 2 electrons between Mg and Cl","Metallic, by a sea of electrons","Hydrogen bonding"],"c":0,"e":"A metal (Mg loses 2 e⁻) and non-metals (each Cl gains 1 e⁻) form ions; the electrostatic attraction between Mg²⁺ and two Cl⁻ is ionic bonding, giving MgCl₂."},
  {"i":"chem-b3-0062","g":9,"u":"Chemical Bonding","d":"medium","t":"application","q":"In a water molecule (H₂O), how many shared (bonding) electron pairs link the oxygen atom to the two hydrogen atoms?","o":["1 shared pair","2 shared pairs","4 shared pairs","0 shared pairs"],"c":1,"e":"Oxygen forms a single covalent bond with each hydrogen, so there are 2 O–H bonds, meaning 2 shared electron pairs total."},
  {"i":"chem-b3-0063","g":9,"u":"Structure of the Atom","d":"hard","t":"calculation","q":"An element X has two isotopes: X-63 (abundance 69.2%) and X-65 (abundance 30.8%). Using these data, what is the approximate relative atomic mass of X, and what is the element?","o":["63.6, copper (Cu)","64.4, zinc (Zn)","64.0, zinc (Zn)","63.0, copper (Cu)"],"c":0,"e":"A.r = (63×0.692)+(65×0.308) = 43.596+20.02 = 63.62 ≈ 63.6, which identifies copper (Cu)."},
  {"i":"chem-b3-0064","g":9,"u":"Measurements & Scientific Methods","d":"hard","t":"calculation","q":"A sample of pure ethanol has a density of 0.789 g/cm³. A student in Bahir Dar measures out 25.0 cm³. To how many grams does this correspond, expressed to the correct number of significant figures?","o":["19.7 g","19.725 g","20.0 g","19.73 g"],"c":0,"e":"mass = density×volume = 0.789×25.0 = 19.725 g; the data have 3 significant figures, so the answer is 19.7 g."},
  {"i":"chem-b3-0065","g":9,"u":"Chemical Bonding","d":"hard","t":"calculation","q":"In the compound aluminium oxide formed when aluminium burns, what are the correct formula and the number of electrons transferred per formula unit?","o":["AlO, 2 electrons","Al₂O₃, 6 electrons","Al₃O₂, 6 electrons","Al₂O₃, 3 electrons"],"c":1,"e":"Al³⁺ and O²⁻ combine as Al₂O₃; 2 Al lose 3 each (6 e⁻) and 3 O gain 2 each (6 e⁻), so 6 electrons transfer per formula unit."},
  {"i":"chem-b3-0066","g":9,"u":"Periodic Classification of Elements","d":"hard","t":"conceptual","q":"Element Q has electron configuration 2,8,7. Considering its position, which statement about Q is correct?","o":["Q is in Period 2, Group VII, and is a metal","Q is in Period 3, Group VII, and forms a 1− ion","Q is in Period 3, Group V, and forms a 3− ion","Q is in Period 7, Group III, and forms a 1+ ion"],"c":1,"e":"Three occupied shells means Period 3; 7 valence electrons means Group VII; it gains 1 electron to form a 1− ion (a halogen, non-metal)."},
  {"i":"chem-b3-0067","g":9,"u":"Structure of the Atom","d":"hard","t":"calculation","q":"An ion has 18 electrons, 17 protons and 18 neutrons. What is its charge and mass number?","o":["1−, mass number 35","1+, mass number 35","1−, mass number 36","2−, mass number 35"],"c":0,"e":"Protons (17) < electrons (18) gives charge 1−; mass number = protons + neutrons = 17+18 = 35 (chloride, Cl⁻)."},
  {"i":"chem-b3-0068","g":9,"u":"Chemistry & Its Importance","d":"hard","t":"application","q":"A teacher classifies changes as physical or chemical. Which of the following sets contains ONLY chemical changes?","o":["Rusting of iron, burning of charcoal, souring of milk","Melting of butter, rusting of iron, boiling of water","Burning of charcoal, dissolving salt, melting wax","Souring of milk, evaporating water, crushing chalk"],"c":0,"e":"Rusting, burning and souring all form new substances (chemical), whereas melting, boiling, dissolving, evaporating and crushing are physical changes."},
  {"i":"chem-b3-0069","g":9,"u":"Periodic Classification of Elements","d":"hard","t":"conceptual","q":"Going across Period 3 from Na to Cl, which trend is correct for atomic radius and first ionization energy respectively?","o":["Radius increases; ionization energy decreases","Radius decreases; ionization energy increases","Both increase","Both decrease"],"c":1,"e":"Across a period nuclear charge rises while shielding stays roughly constant, so atomic radius decreases and first ionization energy generally increases."},
  {"i":"chem-b3-0070","g":9,"u":"Structure of the Atom","d":"hard","t":"calculation","q":"The chromium atom (Z=24) has an anomalous configuration. How many electrons occupy its 3d and 4s subshells respectively in the ground state?","o":["4 in 3d and 2 in 4s","5 in 3d and 1 in 4s","6 in 3d and 0 in 4s","3 in 3d and 3 in 4s"],"c":1,"e":"Chromium is an exception: a half-filled 3d⁵ with 4s¹ is more stable than 3d⁴4s², giving [Ar]3d⁵4s¹."},
  {"i":"chem-b3-0071","g":9,"u":"Chemical Bonding","d":"hard","t":"conceptual","q":"Considering electronegativity differences, which pair of compounds is correctly classified as (ionic, polar covalent) respectively?","o":["(KCl, HF)","(HF, KCl)","(CO₂, O₂)","(NaCl, MgO)"],"c":0,"e":"KCl has a large electronegativity difference (metal + non-metal) so it is ionic; HF is two non-metals with a difference of about 1.9, making it polar covalent."},
  {"i":"chem-b3-0072","g":9,"u":"Measurements & Scientific Methods","d":"hard","t":"calculation","q":"A rectangular metal block measures 2.0 cm × 3.0 cm × 4.0 cm and has a mass of 216 g. Its density (in g/cm³) is approximately which of these?","o":["9.0 g/cm³","8.0 g/cm³","6.0 g/cm³","7.2 g/cm³"],"c":0,"e":"Volume = 2.0×3.0×4.0 = 24 cm³; density = 216/24 = 9.0 g/cm³."},
  {"i":"chem-b3-0073","g":9,"u":"Structure of the Atom","d":"hard","t":"calculation","q":"How many moles of oxygen atoms are present in 4.4 g of carbon dioxide, CO₂ (molar mass 44 g/mol)?","o":["0.10 mol","0.20 mol","0.05 mol","0.40 mol"],"c":1,"e":"Moles CO₂ = 4.4/44 = 0.10 mol; each molecule has 2 O atoms, so moles of O atoms = 0.10×2 = 0.20 mol."},
  {"i":"chem-b3-0074","g":9,"u":"Chemical Bonding","d":"hard","t":"calculation","q":"In the polyatomic ion sulfate, SO₄²⁻, what is the oxidation number of sulfur (oxygen = −2)?","o":["+4","+6","+2","−2"],"c":1,"e":"Let S = x: x + 4(−2) = −2, so x − 8 = −2, giving x = +6."},
  {"i":"chem-b3-0075","g":9,"u":"Periodic Classification of Elements","d":"hard","t":"application","q":"Elements P (2,8,1), R (2,8,8,1) and T (2,8,2) are given. Which is the most reactive metal and why?","o":["T, because it has 2 valence electrons","P, because it has the fewest total electrons","R, because its single valence electron is farthest from the nucleus","T, because its valence electrons are closest to the nucleus"],"c":2,"e":"All are metals losing valence electrons; R's single valence electron is in the 4th shell, farthest from the nucleus with most shielding, so it is lost most easily, making R the most reactive."},
  {"i":"chem-b3-0076","g":9,"u":"Structure of the Atom","d":"hard","t":"calculation","q":"A neutral atom has total configuration 2,8,8,2. What is its atomic number, and to which group does it belong?","o":["Z=20, Group II","Z=18, Group VIII","Z=20, Group IV","Z=12, Group II"],"c":0,"e":"Total electrons = 2+8+8+2 = 20, so Z = 20 (calcium); 2 valence electrons place it in Group II."},
  {"i":"chem-b3-0077","g":9,"u":"Chemical Bonding","d":"hard","t":"conceptual","q":"Water (H₂O) is a bent molecule while carbon dioxide (CO₂) is linear, although both are triatomic. The key reason is that:","o":["Oxygen in water has no lone pairs","The two lone pairs on the oxygen of water force a bent shape","CO₂ contains ionic bonds","Water has double bonds and CO₂ has single bonds"],"c":1,"e":"The central O in water has two bonding pairs and two lone pairs; lone-pair repulsion bends the molecule, whereas CO₂'s central C has only two bonding regions, giving a linear shape."},
  {"i":"chem-b3-0078","g":9,"u":"Measurements & Scientific Methods","d":"hard","t":"application","q":"A student writes a hypothesis, then changes only the temperature while keeping concentration and volume fixed, measuring reaction time. In this experiment, the temperature is the:","o":["Dependent variable","Independent variable","Controlled variable","Constant of proportionality"],"c":1,"e":"The factor deliberately changed by the experimenter is the independent variable; reaction time (measured) is dependent, and concentration/volume are controlled."},
  {"i":"chem-b3-0079","g":9,"u":"Structure of the Atom","d":"hard","t":"calculation","q":"The mass number of an atom is 39 and it has 20 neutrons. If it loses one electron to form an ion, how many protons, neutrons and electrons does the ion have?","o":["19 protons, 20 neutrons, 18 electrons","20 protons, 19 neutrons, 19 electrons","19 protons, 20 neutrons, 19 electrons","18 protons, 21 neutrons, 18 electrons"],"c":0,"e":"Protons = mass number − neutrons = 39 − 20 = 19; the neutral atom has 19 electrons, and losing one gives 18 electrons (K⁺)."},
  {"i":"chem-b3-0080","g":9,"u":"Chemistry & Its Importance","d":"hard","t":"definition","q":"Which statement best distinguishes a compound from a mixture in chemistry?","o":["A compound can be separated by physical means; a mixture cannot","A compound has a fixed composition by mass; a mixture has variable composition","A mixture always forms through a chemical reaction","A compound is always a metal and a mixture a non-metal"],"c":1,"e":"A compound has elements chemically combined in a fixed ratio by mass, while a mixture has components physically combined in variable proportions and separable by physical means."},
  {"i":"chem-b3-0081","g":9,"u":"Chemical Bonding","d":"hard","t":"calculation","q":"Magnesium reacts with nitrogen to form magnesium nitride. What is the correct balanced equation?","o":["Mg + N₂ → MgN₂","3Mg + N₂ → Mg₃N₂","Mg₃ + 2N → Mg₃N₂","2Mg + 3N₂ → 2MgN₃"],"c":1,"e":"Mg²⁺ and N³⁻ give the formula Mg₃N₂; balancing: 3Mg + N₂ → Mg₃N₂ (3 Mg and 2 N on each side)."},
  {"i":"chem-b3-0082","g":9,"u":"Periodic Classification of Elements","d":"hard","t":"conceptual","q":"Noble gases (Group VIII/0) are generally unreactive. Considering electron configuration, helium is grouped with them even though it has only 2 electrons because:","o":["Helium has 8 valence electrons","Helium's outer shell (n=1) is completely full with 2 electrons","Helium is a metal with full d-orbitals","Helium readily forms He²⁺ ions"],"c":1,"e":"The first shell holds a maximum of 2 electrons; helium's outermost shell is therefore full and stable, giving it noble-gas inertness despite having only 2 electrons."},
  {"i":"chem-b3-0083","g":9,"u":"Structure of the Atom","d":"hard","t":"calculation","q":"How many atoms are present in 0.25 mol of aluminium (Avogadro's number = 6.0×10²³ /mol)?","o":["1.5×10²³ atoms","2.4×10²³ atoms","6.0×10²³ atoms","1.5×10²² atoms"],"c":0,"e":"Number of atoms = moles × Avogadro's number = 0.25 × 6.0×10²³ = 1.5×10²³ atoms."},
  {"i":"chem-b3-0084","g":9,"u":"Measurements & Scientific Methods","d":"hard","t":"calculation","q":"A measured length is recorded as 0.04060 km. How many significant figures does this value contain?","o":["3","4","5","6"],"c":1,"e":"Leading zeros are not significant; the digits 4, 0, 6 and the trailing 0 after the decimal are significant, giving 4 significant figures."},
  {"i":"chem-b3-0085","g":9,"u":"Structure of the Atom","d":"hard","t":"calculation","q":"A sample of a metal used in Ethiopian electrical wiring consists of two isotopes: one of mass 62.93 u at 69.2% abundance, and one of mass 64.93 u at 30.8% abundance. What is the relative atomic mass of the metal (to 1 decimal place)?","o":["63.5 u","63.9 u","64.0 u","62.9 u"],"c":0,"e":"Relative atomic mass = (0.692 × 62.93) + (0.308 × 64.93) = 43.55 + 20.00 = 63.5 u, the weighted mean of the two isotopic masses (this is copper, Z = 29)."},
  {"i":"chem-b3-0086","g":9,"u":"Chemical Bonding","d":"hard","t":"calculation","q":"Propane (C₃H₈), a fuel in Ethiopian gas cylinders, burns completely in oxygen. If 11 g of propane is burned, what mass of carbon dioxide is produced? (C = 12, H = 1, O = 16)","o":["33 g","11 g","44 g","22 g"],"c":0,"e":"Balanced: C₃H₈ + 5O₂ → 3CO₂ + 4H₂O. Moles propane = 11/44 = 0.25; moles CO₂ = 3 × 0.25 = 0.75; mass CO₂ = 0.75 × 44 = 33 g."},
  {"i":"chem-b3-0087","g":9,"u":"Periodic Classification of Elements","d":"hard","t":"conceptual","q":"A neutral atom has the electron arrangement 2, 8, 7. Which set correctly gives its period, group, and the ion it most likely forms?","o":["Period 3, Group VIIA, forms a 1⁻ ion","Period 7, Group IIIA, forms a 1⁺ ion","Period 3, Group VA, forms a 3⁻ ion","Period 2, Group VIIA, forms a 7⁺ ion"],"c":0,"e":"Three occupied shells means Period 3; 7 valence electrons means Group VIIA. To reach a stable octet it gains 1 electron, forming a 1⁻ ion (this is chlorine)."},
  {"i":"chem-b3-0088","g":9,"u":"Chemical Bonding","d":"impossible","t":"calculation","q":"An unknown alkene CₙH₂ₙ is fully hydrogenated (1 mol H₂ per mol alkene) to give a straight-chain alkane of molar mass 72 g/mol. How many sigma (σ) bonds were present in one molecule of the ORIGINAL alkene?","o":["14","15","13","16"],"c":0,"e":"Alkane CₙH₂ₙ₊₂ = 72 → 14n+2 = 72 → n = 5, so the alkene is C₅H₁₀. A 5-carbon chain has 4 C–C σ bonds (the C=C contributes one σ) plus 10 C–H σ bonds: total σ = 4 + 10 = 14."},
  {"i":"chem-b3-0089","g":9,"u":"Periodic Classification of Elements","d":"impossible","t":"conceptual","q":"Element X is in Period 3, forms an amphoteric oxide, and its highest fluoride is XF₃. Element Y is the Period 3 element whose highest oxide is the most acidic. Which statement about their first ionization energies is correct?","o":["IE₁(X) < IE₁(Y) because Y lies to the right of X with higher effective nuclear charge","IE₁(X) > IE₁(Y) because X has a half-filled p-subshell","IE₁(X) = IE₁(Y) since both are in Period 3","IE₁(Y) < IE₁(Mg) due to greater shielding in Y"],"c":0,"e":"Amphoteric oxide with fluoride XF₃ identifies X = Al; the most acidic Period-3 oxide is Cl₂O₇, so Y = Cl. Cl is right of Al with higher effective nuclear charge, so IE₁(Al) < IE₁(Cl)."},
  {"i":"chem-b3-0090","g":9,"u":"Structure of the Atom","d":"impossible","t":"calculation","q":"In the Bohr model an electron in hydrogen falls from n=4 to n=2, where Eₙ = −2.18×10⁻¹⁸/n² J. What is the wavelength of the emitted photon? (h=6.626×10⁻³⁴ J·s, c=3.00×10⁸ m/s)","o":["486 nm","434 nm","656 nm","410 nm"],"c":0,"e":"ΔE = 2.18×10⁻¹⁸(1/4 − 1/16) = 2.18×10⁻¹⁸×0.1875 = 4.0875×10⁻¹⁹ J. λ = hc/ΔE = (6.626×10⁻³⁴×3.00×10⁸)/4.0875×10⁻¹⁹ = 4.86×10⁻⁷ m = 486 nm."},
  {"i":"chem-b3-0091","g":9,"u":"Chemical Bonding","d":"impossible","t":"application","q":"Of CO₂, H₂O, NH₃, and BF₃, which single molecule is nonpolar overall, contains polar bonds, AND has its central atom obeying the octet rule (exactly 8 electrons around it)?","o":["CO₂","BF₃","H₂O","NH₃"],"c":0,"e":"CO₂ is linear, so its polar C=O dipoles cancel (net nonpolar) and carbon has 8 electrons via two double bonds. BF₃ is nonpolar but boron has only 6 electrons (electron-deficient), failing the octet condition."},
  {"i":"chem-b3-0092","g":9,"u":"Chemistry & Its Importance","d":"impossible","t":"calculation","q":"A water-treatment plant near Lake Hawassa softens water by adding lime, Ca(OH)₂, to precipitate magnesium as Mg(OH)₂ (Mg²⁺ + 2OH⁻ → Mg(OH)₂). For water containing 0.0120 mol Mg²⁺ per liter, what minimum mass of Ca(OH)₂ (M = 74.1 g/mol) is needed per liter for complete precipitation?","o":["0.889 g","0.444 g","1.78 g","0.296 g"],"c":0,"e":"Each Mg²⁺ requires 2 OH⁻ and each Ca(OH)₂ supplies 2 OH⁻, so mol Ca(OH)₂ = mol Mg²⁺ = 0.0120. Mass = 0.0120×74.1 = 0.889 g."},
  {"i":"chem-b3-0093","g":9,"u":"Periodic Classification of Elements","d":"impossible","t":"calculation","q":"Elements A and B have ground-state configurations [Ne]3s²3p⁴ and [Ar]4s² respectively. When they form their most stable ionic compound, what is the empirical formula and the total number of atoms in one formula unit?","o":["CaS, total = 2","Ca₂S, total = 3","CaS₂, total = 3","Ca₂S₃, total = 5"],"c":0,"e":"[Ne]3s²3p⁴ = S (gains 2e⁻ → S²⁻); [Ar]4s² = Ca (loses 2e⁻ → Ca²⁺). The 2+ and 2− charges balance 1:1 giving CaS, so the formula unit contains 1+1 = 2 atoms."},
  {"i":"chem-b3-0094","g":9,"u":"Structure of the Atom","d":"impossible","t":"calculation","q":"A monatomic ion has 18 electrons, 20 neutrons, and a charge of 2+. What is the mass number of the ion, and the period and group of the neutral atom?","o":["A=40, Period 4, Group 2","A=38, Period 3, Group 2","A=40, Period 3, Group 18","A=38, Period 4, Group 2"],"c":0,"e":"A 2+ charge with 18 electrons means 20 protons (Z=20, calcium). Mass number = 20 protons + 20 neutrons = 40; Z=20 places it in Period 4, Group 2."},
  {"i":"chem-b3-0095","g":9,"u":"Measurements & Scientific Methods","d":"impossible","t":"calculation","q":"A gas occupies 4.50 L at 27 °C and 101.3 kPa. Using the ideal gas law, how many moles are present, to the correct number of significant figures? (R = 8.314 J/(mol·K))","o":["0.183 mol","0.205 mol","0.166 mol","1.83 mol"],"c":0,"e":"n = PV/RT = (101300 Pa × 0.00450 m³)/(8.314 × 300.15 K) = 455.85/2495.4 = 0.1826 ≈ 0.183 mol (3 sig figs)."},
  {"i":"chem-b3-0096","g":10,"u":"Chemical Reactions & Stoichiometry","d":"easy","t":"definition","q":"What is the value of Avogadro's number, the number of particles in one mole of a substance?","o":["6.02 × 10²³","6.02 × 10²²","3.01 × 10²³","1.20 × 10²⁴"],"c":0,"e":"One mole contains 6.02 × 10²³ particles (Avogadro's number)."},
  {"i":"chem-b3-0097","g":10,"u":"Chemical Reactions & Stoichiometry","d":"easy","t":"calculation","q":"How many moles are present in 11 g of carbon dioxide, CO₂ (M = 44 g/mol)?","o":["0.50 mol","0.25 mol","1.0 mol","2.0 mol"],"c":1,"e":"n = m/M = 11/44 = 0.25 mol."},
  {"i":"chem-b3-0098","g":10,"u":"Chemical Reactions & Stoichiometry","d":"easy","t":"calculation","q":"What is the mass of 2 moles of sodium hydroxide, NaOH (M = 40 g/mol)?","o":["20 g","40 g","80 g","120 g"],"c":2,"e":"m = n × M = 2 × 40 = 80 g."},
  {"i":"chem-b3-0099","g":10,"u":"Chemical Reactions & Stoichiometry","d":"easy","t":"application","q":"When the equation N₂ + ___ H₂ → 2 NH₃ is balanced, the coefficient of H₂ is:","o":["1","2","3","4"],"c":2,"e":"N₂ + 3H₂ → 2NH₃ balances 2 N and 6 H on each side; coefficient of H₂ is 3."},
  {"i":"chem-b3-0100","g":10,"u":"Chemical Reactions & Stoichiometry","d":"easy","t":"conceptual","q":"In the reaction 2H₂ + O₂ → 2H₂O, how many moles of water form from 2 moles of hydrogen gas?","o":["1 mol","2 mol","3 mol","4 mol"],"c":1,"e":"The ratio H₂ : H₂O is 2 : 2, so 2 mol H₂ gives 2 mol H₂O."},
  {"i":"chem-b3-0101","g":10,"u":"Chemical Reactions & Stoichiometry","d":"easy","t":"definition","q":"The molar mass of an element expressed in grams is numerically equal to its:","o":["Atomic number","Relative atomic mass","Number of neutrons","Valency"],"c":1,"e":"Molar mass in g/mol equals the relative atomic mass; e.g. Na is 23, so 23 g/mol."},
  {"i":"chem-b3-0102","g":10,"u":"Solutions","d":"easy","t":"calculation","q":"What is the molarity of a solution containing 0.5 mol of solute dissolved in 2 L of solution?","o":["0.25 M","0.50 M","1.0 M","2.0 M"],"c":0,"e":"Molarity = moles/volume = 0.5/2 = 0.25 M."},
  {"i":"chem-b3-0103","g":10,"u":"Solutions","d":"easy","t":"definition","q":"In a solution of salt dissolved in water, the water is called the:","o":["Solute","Solvent","Precipitate","Suspension"],"c":1,"e":"The substance present in larger amount that dissolves the solute is the solvent; here, water."},
  {"i":"chem-b3-0104","g":10,"u":"Solutions","d":"easy","t":"calculation","q":"A solution contains 20 g of sugar in 100 g of solution. What is its mass percent of sugar?","o":["10%","20%","25%","50%"],"c":1,"e":"Mass % = (mass solute/mass solution) × 100 = (20/100) × 100 = 20%."},
  {"i":"chem-b3-0105","g":10,"u":"Solutions","d":"easy","t":"conceptual","q":"Which type of mixture has particles too small to settle or be filtered and appears completely uniform?","o":["Suspension","True solution","Colloid","Emulsion"],"c":1,"e":"A true solution is homogeneous; its particles do not settle and pass through filter paper."},
  {"i":"chem-b3-0106","g":10,"u":"Important Inorganic Compounds","d":"easy","t":"definition","q":"According to the Arrhenius theory, an acid is a substance that releases which ion in water?","o":["OH⁻","H⁺","Na⁺","Cl⁻"],"c":1,"e":"An Arrhenius acid produces hydrogen ions (H⁺) when dissolved in water."},
  {"i":"chem-b3-0107","g":10,"u":"Important Inorganic Compounds","d":"easy","t":"calculation","q":"What is the pH of a 0.001 M HCl solution (a strong acid)?","o":["1","2","3","4"],"c":2,"e":"[H⁺] = 10⁻³ M, so pH = −log(10⁻³) = 3."},
  {"i":"chem-b3-0108","g":10,"u":"Important Inorganic Compounds","d":"easy","t":"calculation","q":"If a solution has pH = 9, what is its pOH at 25 °C?","o":["3","5","7","9"],"c":1,"e":"pH + pOH = 14, so pOH = 14 − 9 = 5."},
  {"i":"chem-b3-0109","g":10,"u":"Important Inorganic Compounds","d":"easy","t":"conceptual","q":"Which colour does blue litmus paper turn when dipped in an acidic solution such as lemon juice?","o":["Blue","Red","Green","Yellow"],"c":1,"e":"Acids turn blue litmus red; bases turn red litmus blue."},
  {"i":"chem-b3-0110","g":10,"u":"Important Inorganic Compounds","d":"easy","t":"application","q":"The reaction HCl + NaOH → NaCl + H₂O is best classified as a:","o":["Combustion reaction","Neutralization reaction","Decomposition reaction","Displacement reaction"],"c":1,"e":"An acid reacting with a base to give salt and water is a neutralization reaction."},
  {"i":"chem-b3-0111","g":10,"u":"Energy Changes & Electrochemistry","d":"easy","t":"definition","q":"A chemical reaction that releases heat to the surroundings is described as:","o":["Endothermic","Exothermic","Catalytic","Reversible"],"c":1,"e":"Exothermic reactions release heat, so ΔH is negative."},
  {"i":"chem-b3-0112","g":10,"u":"Energy Changes & Electrochemistry","d":"easy","t":"conceptual","q":"In electrolysis, the electrode connected to the negative terminal of the battery is the:","o":["Anode","Cathode","Salt bridge","Electrolyte"],"c":1,"e":"In electrolysis the cathode is the negative electrode, where reduction (gain of electrons) occurs."},
  {"i":"chem-b3-0113","g":10,"u":"Energy Changes & Electrochemistry","d":"easy","t":"definition","q":"In an oxidation–reduction reaction, oxidation is defined as the:","o":["Gain of electrons","Loss of electrons","Gain of protons","Loss of neutrons"],"c":1,"e":"Oxidation is loss of electrons; reduction is gain of electrons (OIL RIG)."},
  {"i":"chem-b3-0114","g":10,"u":"Energy Changes & Electrochemistry","d":"easy","t":"calculation","q":"What is the oxidation number of sulfur in sulfuric acid, H₂SO₄?","o":["+2","+4","+6","−2"],"c":2,"e":"2(+1) + S + 4(−2) = 0, so S = +6."},
  {"i":"chem-b3-0115","g":10,"u":"Metals & Nonmetals","d":"easy","t":"conceptual","q":"Which of the following is a typical physical property of most metals?","o":["Poor conductor of electricity","Brittle when solid","Good conductor of heat","Dull and non-shiny"],"c":2,"e":"Metals are good conductors of heat and electricity, malleable, ductile and shiny."},
  {"i":"chem-b3-0116","g":10,"u":"Hydrocarbons","d":"easy","t":"calculation","q":"Using the general formula for alkanes, CₙH₂ₙ₊₂, what is the molecular formula of butane (n = 4)?","o":["C₄H₈","C₄H₁₀","C₄H₆","C₄H₄"],"c":1,"e":"For alkanes H = 2n+2 = 2(4)+2 = 10, giving C₄H₁₀."},
  {"i":"chem-b3-0117","g":10,"u":"Hydrocarbons","d":"easy","t":"definition","q":"Hydrocarbons that contain a carbon–carbon double bond (general formula CₙH₂ₙ) are called:","o":["Alkanes","Alkenes","Alkynes","Alcohols"],"c":1,"e":"Alkenes contain a C=C double bond and follow CₙH₂ₙ; alkynes (CₙH₂ₙ₋₂) have a triple bond."},
  {"i":"chem-b3-0118","g":10,"u":"Chemical Reactions & Stoichiometry","d":"easy","t":"definition","q":"How many particles are contained in exactly 1 mole of any substance (Avogadro's number)?","o":["6.02 × 10²³","3.01 × 10²³","6.02 × 10²²","1.20 × 10²⁴"],"c":0,"e":"One mole of any substance contains Avogadro's number of particles, 6.02 × 10²³."},
  {"i":"chem-b3-0119","g":10,"u":"Chemical Reactions & Stoichiometry","d":"easy","t":"calculation","q":"What is the mass of 2 moles of water (H₂O), given molar mass = 18 g/mol?","o":["18 g","36 g","9 g","54 g"],"c":1,"e":"Mass = moles × molar mass = 2 × 18 = 36 g."},
  {"i":"chem-b3-0120","g":10,"u":"Chemical Reactions & Stoichiometry","d":"easy","t":"calculation","q":"How many moles are present in 88 g of CO₂ (molar mass = 44 g/mol)?","o":["1 mol","4 mol","2 mol","0.5 mol"],"c":2,"e":"Moles = mass ÷ molar mass = 88 ÷ 44 = 2 mol."},
  {"i":"chem-b3-0121","g":10,"u":"Chemical Reactions & Stoichiometry","d":"easy","t":"calculation","q":"What coefficient balances the equation: N₂ + __ H₂ → 2 NH₃?","o":["2","3","1","4"],"c":1,"e":"N₂ + 3H₂ → 2NH₃ balances: 2 N and 6 H on each side, so the coefficient is 3."},
  {"i":"chem-b3-0122","g":10,"u":"Chemical Reactions & Stoichiometry","d":"easy","t":"conceptual","q":"In the reaction 2H₂ + O₂ → 2H₂O, how many moles of water form from 4 moles of H₂ (excess O₂)?","o":["2 mol","8 mol","4 mol","1 mol"],"c":2,"e":"The mole ratio of H₂ to H₂O is 2:2 (i.e. 1:1), so 4 mol H₂ gives 4 mol H₂O."},
  {"i":"chem-b3-0123","g":10,"u":"Solutions","d":"easy","t":"definition","q":"In a solution of salt dissolved in water, the substance present in the larger amount (water) is called the:","o":["Solute","Solvent","Suspension","Colloid"],"c":1,"e":"The solvent is the component present in greater quantity that dissolves the solute; here water is the solvent."},
  {"i":"chem-b3-0124","g":10,"u":"Solutions","d":"easy","t":"calculation","q":"What is the molarity of a solution containing 0.5 mol of NaCl in 2 L of solution?","o":["0.25 M","1 M","0.5 M","2 M"],"c":0,"e":"Molarity = moles ÷ volume (L) = 0.5 ÷ 2 = 0.25 M."},
  {"i":"chem-b3-0125","g":10,"u":"Solutions","d":"easy","t":"calculation","q":"How many moles of solute are in 500 mL of a 2 M glucose solution?","o":["2 mol","0.5 mol","1 mol","4 mol"],"c":2,"e":"Moles = molarity × volume (L) = 2 × 0.5 = 1 mol."},
  {"i":"chem-b3-0126","g":10,"u":"Solutions","d":"easy","t":"conceptual","q":"Which of the following will dissolve readily in water, a polar solvent?","o":["Cooking oil","Sodium chloride","Wax","Petrol"],"c":1,"e":"Like dissolves like: ionic/polar sodium chloride dissolves in polar water, while non-polar oil, wax and petrol do not."},
  {"i":"chem-b3-0127","g":10,"u":"Important Inorganic Compounds","d":"easy","t":"conceptual","q":"What gas is produced when calcium carbonate (limestone) is strongly heated?","o":["Oxygen","Hydrogen","Carbon dioxide","Nitrogen"],"c":2,"e":"CaCO₃ → CaO + CO₂ on heating; the gas released is carbon dioxide."},
  {"i":"chem-b3-0128","g":10,"u":"Important Inorganic Compounds","d":"easy","t":"definition","q":"What is the common name for sodium hydrogen carbonate (NaHCO₃), used in baking?","o":["Baking soda","Washing soda","Table salt","Lime"],"c":0,"e":"NaHCO₃ is commonly called baking soda (sodium bicarbonate)."},
  {"i":"chem-b3-0129","g":10,"u":"Important Inorganic Compounds","d":"easy","t":"conceptual","q":"Which oxide dissolves in water to form an acidic solution?","o":["Na₂O","CaO","SO₂","MgO"],"c":2,"e":"Non-metal oxide SO₂ forms sulfurous acid (H₂SO₃) in water; Na₂O, CaO and MgO form basic solutions."},
  {"i":"chem-b3-0130","g":10,"u":"Important Inorganic Compounds","d":"easy","t":"conceptual","q":"What is the pH range of an acidic solution at 25 °C?","o":["Exactly 7","Greater than 7","Less than 7","Exactly 14"],"c":2,"e":"At 25 °C, acidic solutions have pH less than 7, neutral = 7, and basic greater than 7."},
  {"i":"chem-b3-0131","g":10,"u":"Important Inorganic Compounds","d":"easy","t":"calculation","q":"A solution has [H⁺] = 1 × 10⁻³ mol/L. What is its pH?","o":["3","11","7","10⁻³"],"c":0,"e":"pH = −log[H⁺] = −log(10⁻³) = 3."},
  {"i":"chem-b3-0132","g":10,"u":"Important Inorganic Compounds","d":"easy","t":"calculation","q":"If a solution has pH = 9 at 25 °C, what is its pOH?","o":["9","5","14","23"],"c":1,"e":"pH + pOH = 14, so pOH = 14 − 9 = 5."},
  {"i":"chem-b3-0133","g":10,"u":"Energy Changes & Electrochemistry","d":"easy","t":"conceptual","q":"In electrolysis, the electrode connected to the positive terminal of the battery is the:","o":["Cathode","Anode","Cation","Salt bridge"],"c":1,"e":"The anode is the positive electrode where oxidation occurs during electrolysis."},
  {"i":"chem-b3-0134","g":10,"u":"Energy Changes & Electrochemistry","d":"easy","t":"definition","q":"The loss of electrons by a species during a redox reaction is called:","o":["Reduction","Oxidation","Neutralization","Condensation"],"c":1,"e":"Oxidation is loss of electrons (OIL: Oxidation Is Loss); reduction is gain of electrons."},
  {"i":"chem-b3-0135","g":10,"u":"Metals & Nonmetals","d":"easy","t":"conceptual","q":"Which element is a nonmetal that exists as a gas at room temperature?","o":["Iron","Oxygen","Copper","Aluminium"],"c":1,"e":"Oxygen is a gaseous nonmetal; iron, copper and aluminium are solid metals."},
  {"i":"chem-b3-0136","g":10,"u":"Hydrocarbons","d":"easy","t":"definition","q":"What is the general molecular formula of an alkane?","o":["CₙH₂ₙ","CₙH₂ₙ₊₂","CₙH₂ₙ₋₂","CₙHₙ"],"c":1,"e":"Saturated alkanes follow the general formula CₙH₂ₙ₊₂ (e.g. CH₄, C₂H₆)."},
  {"i":"chem-b3-0137","g":10,"u":"Hydrocarbons","d":"easy","t":"conceptual","q":"Which hydrocarbon contains a carbon–carbon double bond (an alkene)?","o":["C₂H₆ (ethane)","C₂H₄ (ethene)","C₂H₂ (ethyne)","CH₄ (methane)"],"c":1,"e":"Ethene (C₂H₄) fits the alkene formula CₙH₂ₙ and has a C=C double bond; ethyne has a triple bond and ethane/methane are saturated."},
  {"i":"chem-b3-0138","g":10,"u":"Chemical Reactions & Stoichiometry","d":"easy","t":"calculation","q":"How many moles are present in 11 g of carbon dioxide (CO₂)? (C = 12, O = 16 g/mol)","o":["0.25 mol","0.50 mol","1.00 mol","2.00 mol"],"c":0,"e":"Molar mass of CO₂ = 12 + 2(16) = 44 g/mol. Moles = mass ÷ molar mass = 11 ÷ 44 = 0.25 mol."},
  {"i":"chem-b3-0139","g":10,"u":"Chemical Reactions & Stoichiometry","d":"easy","t":"calculation","q":"For the reaction 2H₂ + O₂ → 2H₂O, how many moles of water form when 4 mol of H₂ react completely with excess O₂?","o":["2 mol","4 mol","6 mol","8 mol"],"c":1,"e":"The mole ratio of H₂ to H₂O is 2:2, i.e. 1:1. So 4 mol H₂ produces 4 mol H₂O."},
  {"i":"chem-b3-0140","g":10,"u":"Solutions","d":"easy","t":"calculation","q":"What is the molarity of a solution made by dissolving 0.5 mol of NaCl in enough water to make 2 L of solution?","o":["0.25 mol/L","0.50 mol/L","1.00 mol/L","2.00 mol/L"],"c":0,"e":"Molarity = moles of solute ÷ volume in litres = 0.5 mol ÷ 2 L = 0.25 mol/L."},
  {"i":"chem-b3-0141","g":10,"u":"Solutions","d":"easy","t":"definition","q":"In a cup of Ethiopian coffee with sugar dissolved in it, which component is the solute?","o":["The water","The sugar","The coffee cup","The dissolved air"],"c":1,"e":"The solute is the substance that is dissolved and is present in the smaller amount; here the sugar dissolves in the water (solvent)."},
  {"i":"chem-b3-0142","g":10,"u":"Important Inorganic Compounds","d":"easy","t":"calculation","q":"What is the molar mass of sodium hydroxide, NaOH? (Na = 23, O = 16, H = 1 g/mol)","o":["24 g/mol","39 g/mol","40 g/mol","58 g/mol"],"c":2,"e":"Molar mass of NaOH = 23 + 16 + 1 = 40 g/mol."},
  {"i":"chem-b3-0143","g":10,"u":"Important Inorganic Compounds","d":"easy","t":"calculation","q":"A dilute solution has a pH of 3. What is its pOH at 25 °C?","o":["3","7","11","14"],"c":2,"e":"At 25 °C, pH + pOH = 14, so pOH = 14 − 3 = 11."},
  {"i":"chem-b3-0144","g":10,"u":"Energy Changes & Electrochemistry","d":"easy","t":"conceptual","q":"In any electrochemical cell, the electrode at which oxidation takes place is called the","o":["cathode","anode","electrolyte","salt bridge"],"c":1,"e":"Oxidation (loss of electrons) always occurs at the anode, while reduction occurs at the cathode."},
  {"i":"chem-b3-0145","g":10,"u":"Hydrocarbons","d":"easy","t":"definition","q":"Which general molecular formula represents the alkene family of hydrocarbons?","o":["CₙH₂ₙ₊₂","CₙH₂ₙ","CₙH₂ₙ₋₂","CₙHₙ"],"c":1,"e":"Alkenes contain one carbon–carbon double bond and follow the general formula CₙH₂ₙ (e.g. ethene C₂H₄)."},
  {"i":"chem-b3-0146","g":10,"u":"Chemical Reactions & Stoichiometry","d":"medium","t":"calculation","q":"How many moles of CO₂ are produced when 0.50 mol of C₃H₈ burns completely? (C₃H₈ + 5O₂ → 3CO₂ + 4H₂O)","o":["0.50 mol","1.5 mol","3.0 mol","2.0 mol"],"c":1,"e":"From the balanced equation, 1 mol C₃H₈ gives 3 mol CO₂, so 0.50 mol gives 0.50 × 3 = 1.5 mol CO₂."},
  {"i":"chem-b3-0147","g":10,"u":"Chemical Reactions & Stoichiometry","d":"medium","t":"calculation","q":"What mass of CaO is obtained from the complete decomposition of 25 g of CaCO₃? (CaCO₃ → CaO + CO₂; molar masses: CaCO₃ = 100 g/mol, CaO = 56 g/mol)","o":["11 g","14 g","25 g","56 g"],"c":1,"e":"Moles CaCO₃ = 25/100 = 0.25 mol; this gives 0.25 mol CaO = 0.25 × 56 = 14 g."},
  {"i":"chem-b3-0148","g":10,"u":"Chemical Reactions & Stoichiometry","d":"medium","t":"calculation","q":"At STP, what volume is occupied by 8.0 g of O₂ gas? (O = 16; molar volume = 22.4 L/mol)","o":["2.8 L","5.6 L","11.2 L","22.4 L"],"c":1,"e":"Moles O₂ = 8.0/32 = 0.25 mol; volume = 0.25 × 22.4 = 5.6 L."},
  {"i":"chem-b3-0149","g":10,"u":"Chemical Reactions & Stoichiometry","d":"medium","t":"calculation","q":"How many grams of H₂ are needed to react completely with 56 g of N₂ to form ammonia? (N₂ + 3H₂ → 2NH₃; N = 14, H = 1)","o":["6 g","12 g","2 g","4 g"],"c":1,"e":"Moles N₂ = 56/28 = 2 mol; H₂ needed = 2 × 3 = 6 mol = 6 × 2 = 12 g."},
  {"i":"chem-b3-0150","g":10,"u":"Chemical Reactions & Stoichiometry","d":"medium","t":"calculation","q":"A compound contains 40% carbon, 6.7% hydrogen and 53.3% oxygen by mass. What is its empirical formula? (C = 12, H = 1, O = 16)","o":["CH₂O","C₂H₄O","CHO","C₂H₆O"],"c":0,"e":"Mole ratio C:H:O = 40/12 : 6.7/1 : 53.3/16 = 3.33 : 6.7 : 3.33 = 1:2:1, giving CH₂O."},
  {"i":"chem-b3-0151","g":10,"u":"Chemical Reactions & Stoichiometry","d":"medium","t":"calculation","q":"When 4.0 g of H₂ reacts with 16 g of O₂ (2H₂ + O₂ → 2H₂O), which is the limiting reactant? (H = 1, O = 16)","o":["H₂","O₂","Both used exactly","Neither reacts"],"c":1,"e":"Moles H₂ = 2, moles O₂ = 0.5; the reaction needs 2 mol H₂ per 1 mol O₂, so 0.5 mol O₂ consumes only 1 mol H₂. O₂ runs out first, so O₂ is limiting."},
  {"i":"chem-b3-0152","g":10,"u":"Solutions","d":"medium","t":"calculation","q":"What is the molarity of a solution made by dissolving 4.0 g of NaOH in enough water to make 500 mL of solution? (NaOH = 40 g/mol)","o":["0.10 M","0.20 M","0.40 M","2.0 M"],"c":1,"e":"Moles NaOH = 4.0/40 = 0.10 mol in 0.500 L; molarity = 0.10/0.500 = 0.20 M."},
  {"i":"chem-b3-0153","g":10,"u":"Solutions","d":"medium","t":"calculation","q":"How many grams of glucose (C₆H₁₂O₆, 180 g/mol) are needed to prepare 250 mL of a 0.20 M solution?","o":["4.5 g","9.0 g","18 g","36 g"],"c":1,"e":"Moles = 0.20 × 0.250 = 0.050 mol; mass = 0.050 × 180 = 9.0 g."},
  {"i":"chem-b3-0154","g":10,"u":"Solutions","d":"medium","t":"calculation","q":"If 100 mL of 2.0 M HCl is diluted with water to a final volume of 500 mL, what is the new concentration?","o":["0.20 M","0.40 M","1.0 M","4.0 M"],"c":1,"e":"Using C₁V₁ = C₂V₂: (2.0 × 100)/500 = 0.40 M."},
  {"i":"chem-b3-0155","g":10,"u":"Solutions","d":"medium","t":"conceptual","q":"A solution that holds the maximum amount of dissolved solute at a given temperature while in contact with undissolved solute is best described as:","o":["Dilute","Unsaturated","Saturated","Supersaturated"],"c":2,"e":"A saturated solution contains the maximum dissolvable solute at that temperature and is in equilibrium with undissolved solute."},
  {"i":"chem-b3-0156","g":10,"u":"Important Inorganic Compounds","d":"medium","t":"conceptual","q":"Which oxide, when dissolved in water, produces a solution that turns blue litmus red?","o":["Na₂O","CaO","SO₂","K₂O"],"c":2,"e":"SO₂ is a nonmetal (acidic) oxide; with water it forms H₂SO₃, an acid that turns blue litmus red. The others are basic oxides."},
  {"i":"chem-b3-0157","g":10,"u":"Important Inorganic Compounds","d":"medium","t":"definition","q":"The reaction 2HCl + Ca(OH)₂ → CaCl₂ + 2H₂O is best classified as:","o":["Combustion","Neutralization","Decomposition","Displacement"],"c":1,"e":"An acid (HCl) reacting with a base (Ca(OH)₂) to give a salt and water is a neutralization reaction."},
  {"i":"chem-b3-0158","g":10,"u":"Important Inorganic Compounds","d":"medium","t":"application","q":"Limestone (CaCO₃) is heated strongly in a kiln near Dire Dawa to make quicklime. Which gas is released during this process?","o":["O₂","CO₂","SO₂","H₂"],"c":1,"e":"Thermal decomposition: CaCO₃ → CaO + CO₂, releasing carbon dioxide gas."},
  {"i":"chem-b3-0159","g":10,"u":"Energy Changes & Electrochemistry","d":"medium","t":"calculation","q":"In the ion MnO₄⁻, what is the oxidation number of manganese? (O = −2)","o":["+5","+6","+7","+2"],"c":2,"e":"Let x be Mn: x + 4(−2) = −1, so x − 8 = −1, giving x = +7."},
  {"i":"chem-b3-0160","g":10,"u":"Energy Changes & Electrochemistry","d":"medium","t":"conceptual","q":"In a redox reaction a substance gains electrons. This substance is:","o":["Oxidized and acts as reducing agent","Reduced and acts as oxidizing agent","Oxidized and acts as oxidizing agent","Reduced and acts as reducing agent"],"c":1,"e":"Gaining electrons is reduction; the species that is reduced removes electrons from another, so it acts as the oxidizing agent."},
  {"i":"chem-b3-0161","g":10,"u":"Energy Changes & Electrochemistry","d":"medium","t":"conceptual","q":"For a reaction in which the products have lower energy than the reactants and heat is released, the reaction is:","o":["Endothermic with positive ΔH","Exothermic with negative ΔH","Endothermic with negative ΔH","Exothermic with positive ΔH"],"c":1,"e":"Releasing heat means energy leaves the system: the reaction is exothermic and ΔH is negative."},
  {"i":"chem-b3-0162","g":10,"u":"Energy Changes & Electrochemistry","d":"medium","t":"application","q":"During the electrolysis of molten NaCl, what occurs at the cathode (negative electrode)?","o":["Cl⁻ is oxidized to Cl₂","Na⁺ is reduced to Na","Na is oxidized to Na⁺","Cl₂ is reduced to Cl⁻"],"c":1,"e":"At the cathode, cations gain electrons (reduction): Na⁺ + e⁻ → Na."},
  {"i":"chem-b3-0163","g":10,"u":"Metals & Nonmetals","d":"medium","t":"application","q":"A strip of zinc is placed in copper(II) sulfate solution. Given that Zn is more reactive than Cu, what is observed?","o":["No reaction occurs","Zinc dissolves and reddish copper deposits","Copper dissolves and zinc deposits","A gas is released and the solution stays blue"],"c":1,"e":"More reactive Zn displaces Cu: Zn + CuSO₄ → ZnSO₄ + Cu, so zinc dissolves and reddish copper forms."},
  {"i":"chem-b3-0164","g":10,"u":"Metals & Nonmetals","d":"medium","t":"conceptual","q":"An element X has the electron configuration 2, 8, 7. To which group does it belong and what is its type?","o":["Group I, metal","Group VII, nonmetal","Group II, metal","Group VI, nonmetal"],"c":1,"e":"Seven valence electrons place X in Group VII (halogens), a nonmetal that gains 1 electron to form X⁻."},
  {"i":"chem-b3-0165","g":10,"u":"Hydrocarbons","d":"medium","t":"calculation","q":"An alkene contains 4 carbon atoms. Using the general formula CₙH₂ₙ, what is its molecular formula?","o":["C₄H₈","C₄H₁₀","C₄H₆","C₄H₄"],"c":0,"e":"For alkenes CₙH₂ₙ with n = 4: H = 2 × 4 = 8, giving C₄H₈."},
  {"i":"chem-b3-0166","g":10,"u":"Hydrocarbons","d":"medium","t":"conceptual","q":"Which test best distinguishes an alkene from an alkane?","o":["Both burn, so the combustion test works","Alkene decolorizes bromine water; alkane does not","Alkane decolorizes bromine water; alkene does not","Neither reacts with bromine water"],"c":1,"e":"The C=C double bond of an alkene adds bromine (addition reaction), decolorizing bromine water, while a saturated alkane does not under normal conditions."},
  {"i":"chem-b3-0167","g":10,"u":"Hydrocarbons","d":"medium","t":"calculation","q":"A hydrocarbon has the general formula CₙH₂ₙ₋₂ and contains 3 carbon atoms. How many hydrogen atoms does it have and to which family does it belong?","o":["8 H, alkane","6 H, alkene","4 H, alkyne","4 H, alkene"],"c":2,"e":"CₙH₂ₙ₋₂ is the alkyne family; with n = 3, H = 2(3) − 2 = 4, giving C₃H₄ (propyne)."},
  {"i":"chem-b3-0168","g":10,"u":"Chemical Reactions & Stoichiometry","d":"medium","t":"calculation","q":"How many moles of oxygen gas (O₂) are required to completely burn 0.50 mol of methane (CH₄)? (CH₄ + 2O₂ → CO₂ + 2H₂O)","o":["0.50 mol","1.0 mol","2.0 mol","0.25 mol"],"c":1,"e":"The balanced equation shows 1 mol CH₄ needs 2 mol O₂, so 0.50 mol × 2 = 1.0 mol O₂."},
  {"i":"chem-b3-0169","g":10,"u":"Chemical Reactions & Stoichiometry","d":"medium","t":"calculation","q":"What mass of CO₂ is produced when 5.0 g of CaCO₃ decomposes completely? (CaCO₃ → CaO + CO₂; Ca=40, C=12, O=16)","o":["2.2 g","4.4 g","5.0 g","1.1 g"],"c":0,"e":"Moles CaCO₃ = 5.0/100 = 0.05 mol; 1:1 ratio gives 0.05 mol CO₂; mass = 0.05 × 44 = 2.2 g."},
  {"i":"chem-b3-0170","g":10,"u":"Chemical Reactions & Stoichiometry","d":"medium","t":"calculation","q":"How many atoms are present in 8.0 g of helium gas? (He=4, Nᴀ=6.0×10²³)","o":["6.0×10²³","1.2×10²⁴","3.0×10²³","2.4×10²⁴"],"c":1,"e":"Moles He = 8.0/4 = 2.0 mol; atoms = 2.0 × 6.0×10²³ = 1.2×10²⁴ (helium is monatomic)."},
  {"i":"chem-b3-0171","g":10,"u":"Chemical Reactions & Stoichiometry","d":"medium","t":"calculation","q":"In the reaction N₂ + 3H₂ → 2NH₃, if 4.0 mol H₂ reacts with excess N₂, how many moles of NH₃ form?","o":["4.0 mol","2.7 mol","1.3 mol","6.0 mol"],"c":1,"e":"Ratio H₂:NH₃ = 3:2, so NH₃ = 4.0 × (2/3) = 2.7 mol."},
  {"i":"chem-b3-0172","g":10,"u":"Chemical Reactions & Stoichiometry","d":"medium","t":"calculation","q":"What volume does 0.25 mol of any ideal gas occupy at STP (molar volume 22.4 L/mol)?","o":["5.6 L","22.4 L","11.2 L","2.24 L"],"c":0,"e":"Volume = moles × molar volume = 0.25 × 22.4 = 5.6 L."},
  {"i":"chem-b3-0173","g":10,"u":"Solutions","d":"medium","t":"calculation","q":"What is the molarity of a solution made by dissolving 4.0 g of NaOH in water to make 500 mL of solution? (Na=23, O=16, H=1)","o":["0.10 M","0.20 M","0.40 M","2.0 M"],"c":1,"e":"Moles NaOH = 4.0/40 = 0.10 mol; molarity = 0.10/0.500 L = 0.20 M."},
  {"i":"chem-b3-0174","g":10,"u":"Solutions","d":"medium","t":"calculation","q":"How many grams of glucose (C₆H₁₂O₆, M=180 g/mol) are needed to prepare 250 mL of a 0.20 M solution?","o":["9.0 g","18 g","4.5 g","36 g"],"c":0,"e":"Moles = 0.20 × 0.250 = 0.050 mol; mass = 0.050 × 180 = 9.0 g."},
  {"i":"chem-b3-0175","g":10,"u":"Solutions","d":"medium","t":"calculation","q":"If 50 mL of 2.0 M HCl is diluted to 200 mL with water, what is the new concentration?","o":["0.50 M","1.0 M","8.0 M","0.25 M"],"c":0,"e":"Using M₁V₁ = M₂V₂: M₂ = (2.0 × 50)/200 = 0.50 M."},
  {"i":"chem-b3-0176","g":10,"u":"Solutions","d":"medium","t":"conceptual","q":"A solution that contains the maximum amount of dissolved solute at a given temperature, in contact with undissolved solute, is best described as:","o":["Unsaturated","Saturated","Dilute","Supersaturated"],"c":1,"e":"A saturated solution holds the maximum solute that can dissolve at that temperature and is in equilibrium with undissolved solute."},
  {"i":"chem-b3-0177","g":10,"u":"Important Inorganic Compounds","d":"medium","t":"calculation","q":"What is the pH of a 0.010 M HCl solution? (HCl is a strong acid)","o":["1","2","12","10"],"c":1,"e":"HCl fully ionizes, so [H⁺] = 0.010 = 10⁻² M; pH = -log(10⁻²) = 2."},
  {"i":"chem-b3-0178","g":10,"u":"Important Inorganic Compounds","d":"medium","t":"calculation","q":"A solution has [OH⁻] = 1.0×10⁻⁴ M at 25°C. What is its pH? (Kw = 1.0×10⁻¹⁴)","o":["4","10","7","11"],"c":1,"e":"pOH = -log(10⁻⁴) = 4; pH = 14 - 4 = 10."},
  {"i":"chem-b3-0179","g":10,"u":"Important Inorganic Compounds","d":"medium","t":"application","q":"Which salt is produced when sulphuric acid reacts with sodium hydroxide? (H₂SO₄ + 2NaOH → ? + 2H₂O)","o":["NaSO₄","Na₂SO₄","NaHSO₄","Na₂SO₃"],"c":1,"e":"Diprotic H₂SO₄ with two NaOH gives the normal salt sodium sulphate, Na₂SO₄, plus water."},
  {"i":"chem-b3-0180","g":10,"u":"Important Inorganic Compounds","d":"medium","t":"conceptual","q":"According to the Brønsted–Lowry definition, when ammonia reacts with water (NH₃ + H₂O ⇌ NH₄⁺ + OH⁻), water acts as a(n):","o":["Acid","Base","Salt","Spectator"],"c":0,"e":"Water donates a proton (H⁺) to NH₃, so by Brønsted–Lowry it acts as an acid."},
  {"i":"chem-b3-0181","g":10,"u":"Energy Changes & Electrochemistry","d":"medium","t":"conceptual","q":"For an exothermic reaction, which statement about the enthalpy change (ΔH) and the surroundings is correct?","o":["ΔH is positive; surroundings cool","ΔH is negative; surroundings warm","ΔH is positive; surroundings warm","ΔH is zero; no temperature change"],"c":1,"e":"Exothermic reactions release heat to the surroundings (which warm up), so ΔH is negative."},
  {"i":"chem-b3-0182","g":10,"u":"Energy Changes & Electrochemistry","d":"medium","t":"calculation","q":"What is the oxidation number of manganese in the permanganate ion, MnO₄⁻? (O = -2)","o":["+5","+6","+7","+4"],"c":2,"e":"Let Mn = x: x + 4(-2) = -1, so x - 8 = -1, giving x = +7."},
  {"i":"chem-b3-0183","g":10,"u":"Energy Changes & Electrochemistry","d":"medium","t":"conceptual","q":"In a galvanic (voltaic) cell, oxidation takes place at the ____ and electrons flow through the external wire ____.","o":["cathode; to the anode","anode; from anode to cathode","cathode; from cathode to anode","anode; from cathode to anode"],"c":1,"e":"Oxidation occurs at the anode; electrons travel through the external circuit from the anode to the cathode."},
  {"i":"chem-b3-0184","g":10,"u":"Metals & Nonmetals","d":"medium","t":"application","q":"A more reactive metal X displaces metal Y from solution: X + YSO₄ → XSO₄ + Y. Which pair correctly fits X and Y based on the reactivity series?","o":["X = Cu, Y = Zn","X = Zn, Y = Cu","X = Ag, Y = Fe","X = Cu, Y = Mg"],"c":1,"e":"A metal displaces a less reactive one; Zn is above Cu in the reactivity series, so Zn displaces Cu."},
  {"i":"chem-b3-0185","g":10,"u":"Metals & Nonmetals","d":"medium","t":"conceptual","q":"Which property is characteristic of nonmetals compared with metals?","o":["Good electrical conductivity","High malleability","Tendency to gain electrons forming anions","Metallic lustre"],"c":2,"e":"Nonmetals have high electronegativity and tend to gain electrons to form negative ions (anions)."},
  {"i":"chem-b3-0186","g":10,"u":"Hydrocarbons","d":"medium","t":"calculation","q":"An alkane has 5 carbon atoms. Using the general formula CₙH₂ₙ₊₂, how many hydrogen atoms does it contain?","o":["10","11","12","8"],"c":2,"e":"For n = 5: H = 2(5)+2 = 12, giving C₅H₁₂ (pentane)."},
  {"i":"chem-b3-0187","g":10,"u":"Hydrocarbons","d":"medium","t":"conceptual","q":"Which feature distinguishes an alkene (CₙH₂ₙ) from an alkane (CₙH₂ₙ₊₂) having the same number of carbons?","o":["The alkene has a carbon–carbon double bond and is unsaturated","The alkene has more hydrogen atoms","The alkene contains only single bonds","The alkene has a triple bond"],"c":0,"e":"Alkenes contain a C=C double bond, making them unsaturated, and they have two fewer H atoms than the corresponding alkane."},
  {"i":"chem-b3-0188","g":10,"u":"Chemical Reactions & Stoichiometry","d":"medium","t":"calculation","q":"How many moles of O₂ are required to completely burn 4.0 mol of CH₄ according to: CH₄ + 2O₂ → CO₂ + 2H₂O?","o":["4.0 mol","8.0 mol","2.0 mol","16 mol"],"c":1,"e":"The mole ratio CH₄:O₂ is 1:2, so 4.0 mol CH₄ needs 4.0 × 2 = 8.0 mol O₂."},
  {"i":"chem-b3-0189","g":10,"u":"Chemical Reactions & Stoichiometry","d":"medium","t":"calculation","q":"What mass of CO₂ (M = 44 g/mol) is produced when 24 g of carbon (M = 12 g/mol) burns completely: C + O₂ → CO₂?","o":["44 g","66 g","88 g","22 g"],"c":2,"e":"24 g C = 24/12 = 2.0 mol C; ratio C:CO₂ is 1:1, so 2.0 mol CO₂ × 44 g/mol = 88 g."},
  {"i":"chem-b3-0190","g":10,"u":"Chemical Reactions & Stoichiometry","d":"medium","t":"calculation","q":"A sample contains 1.204 × 10²⁴ molecules of water. How many moles is this? (Nᴀ = 6.02 × 10²³)","o":["2.0 mol","0.5 mol","1.0 mol","4.0 mol"],"c":0,"e":"moles = (1.204 × 10²⁴) / (6.02 × 10²³) = 2.0 mol."},
  {"i":"chem-b3-0191","g":10,"u":"Chemical Reactions & Stoichiometry","d":"medium","t":"calculation","q":"In 2Al + 3Cl₂ → 2AlCl₃, how many moles of AlCl₃ form from 0.30 mol Cl₂ (Cl₂ limiting)?","o":["0.30 mol","0.45 mol","0.20 mol","0.10 mol"],"c":2,"e":"Ratio Cl₂:AlCl₃ is 3:2, so 0.30 mol Cl₂ × (2/3) = 0.20 mol AlCl₃."},
  {"i":"chem-b3-0192","g":10,"u":"Solutions","d":"medium","t":"calculation","q":"What is the molarity of a solution made by dissolving 0.50 mol of NaCl in enough water to make 250 mL of solution?","o":["1.0 M","0.5 M","2.0 M","0.125 M"],"c":2,"e":"M = mol/L = 0.50 mol / 0.250 L = 2.0 M."},
  {"i":"chem-b3-0193","g":10,"u":"Solutions","d":"medium","t":"calculation","q":"How many grams of NaOH (M = 40 g/mol) are needed to prepare 500 mL of a 0.20 M solution?","o":["4.0 g","8.0 g","2.0 g","40 g"],"c":0,"e":"mol = 0.20 M × 0.500 L = 0.10 mol; mass = 0.10 × 40 = 4.0 g."},
  {"i":"chem-b3-0194","g":10,"u":"Solutions","d":"medium","t":"calculation","q":"If 100 mL of 2.0 M HCl is diluted to a final volume of 500 mL, what is the new concentration?","o":["0.40 M","1.0 M","0.20 M","4.0 M"],"c":0,"e":"M₁V₁ = M₂V₂: (2.0)(100) = M₂(500), so M₂ = 200/500 = 0.40 M."},
  {"i":"chem-b3-0195","g":10,"u":"Important Inorganic Compounds","d":"medium","t":"application","q":"Limestone (CaCO₃) decomposes on strong heating. Which gas is released: CaCO₃ → CaO + ?","o":["O₂","CO₂","CO","H₂O"],"c":1,"e":"Thermal decomposition of CaCO₃ gives CaO (quicklime) and carbon dioxide, CO₂."},
  {"i":"chem-b3-0196","g":10,"u":"Important Inorganic Compounds","d":"medium","t":"definition","q":"Which oxide, when dissolved in water, produces an acidic solution?","o":["CaO","Na₂O","SO₃","MgO"],"c":2,"e":"SO₃ is a nonmetal oxide that reacts with water to form H₂SO₄, an acid; the others are basic metal oxides."},
  {"i":"chem-b3-0197","g":10,"u":"Energy Changes & Electrochemistry","d":"medium","t":"calculation","q":"If a solution has pOH = 4, what is its pH at 25 °C?","o":["4","14","10","7"],"c":2,"e":"pH + pOH = 14, so pH = 14 − 4 = 10."},
  {"i":"chem-b3-0198","g":10,"u":"Energy Changes & Electrochemistry","d":"medium","t":"conceptual","q":"During the electrolysis of molten NaCl, what happens at the cathode?","o":["Cl⁻ loses electrons","Na⁺ gains electrons","Na⁺ loses electrons","Cl⁻ gains electrons"],"c":1,"e":"The cathode is negative; cations Na⁺ migrate there and gain electrons (reduction) to form Na metal."},
  {"i":"chem-b3-0199","g":10,"u":"Energy Changes & Electrochemistry","d":"medium","t":"conceptual","q":"In the reaction Zn + Cu²⁺ → Zn²⁺ + Cu, which species is oxidized?","o":["Cu²⁺","Cu","Zn","Zn²⁺"],"c":2,"e":"Zn goes from 0 to +2, losing electrons; loss of electrons is oxidation, so Zn is oxidized (the reducing agent)."},
  {"i":"chem-b3-0200","g":10,"u":"Metals & Nonmetals","d":"medium","t":"application","q":"A more reactive metal can displace a less reactive metal from its salt. Which reaction will occur?","o":["Cu + ZnSO₄ → CuSO₄ + Zn","Fe + CuSO₄ → FeSO₄ + Cu","Ag + FeSO₄ → Ag₂SO₄ + Fe","Cu + MgSO₄ → CuSO₄ + Mg"],"c":1,"e":"Fe is more reactive than Cu, so Fe displaces Cu from CuSO₄; the other pairs have the less reactive metal trying to displace a more reactive one."},
  {"i":"chem-b3-0201","g":10,"u":"Hydrocarbons","d":"medium","t":"calculation","q":"An alkane has 5 carbon atoms. Using the general formula CₙH₂ₙ₊₂, how many hydrogen atoms does it have?","o":["10","12","11","8"],"c":1,"e":"For n = 5: H = 2(5) + 2 = 12, so the molecular formula is C₅H₁₂ (pentane)."},
  {"i":"chem-b3-0202","g":10,"u":"Hydrocarbons","d":"medium","t":"conceptual","q":"Which general formula represents an alkene, and what bond characterizes it?","o":["CₙH₂ₙ₊₂, single bonds only","CₙH₂ₙ, one C=C double bond","CₙH₂ₙ₋₂, one C≡C triple bond","CₙHₙ, aromatic ring"],"c":1,"e":"Alkenes have the general formula CₙH₂ₙ and contain one carbon-carbon double bond (C=C)."},
  {"i":"chem-b3-0203","g":10,"u":"Chemical Reactions & Stoichiometry","d":"hard","t":"calculation","q":"When 25.0 g of CaCO₃ is heated, it decomposes: CaCO₃ → CaO + CO₂. If only 80% of the sample decomposes, what mass of CaO is produced? (Ca=40, C=12, O=16)","o":["11.2 g","14.0 g","8.96 g","20.0 g"],"c":0,"e":"Mass decomposed = 0.80×25.0 = 20.0 g CaCO₃ = 20.0/100 = 0.20 mol. This gives 0.20 mol CaO = 0.20×56 = 11.2 g."},
  {"i":"chem-b3-0204","g":10,"u":"Chemical Reactions & Stoichiometry","d":"hard","t":"calculation","q":"In the reaction N₂ + 3H₂ → 2NH₃, 14 g of N₂ is mixed with 6.0 g of H₂. Which is the limiting reactant and what mass of NH₃ forms? (N=14, H=1)","o":["N₂ limiting; 17 g NH₃","H₂ limiting; 17 g NH₃","N₂ limiting; 34 g NH₃","H₂ limiting; 51 g NH₃"],"c":0,"e":"N₂ = 14/28 = 0.50 mol needs 1.5 mol H₂; H₂ = 6.0/2 = 3.0 mol available, so N₂ limits. NH₃ = 2×0.50 = 1.0 mol = 17 g."},
  {"i":"chem-b3-0205","g":10,"u":"Chemical Reactions & Stoichiometry","d":"hard","t":"calculation","q":"A 6.0 g sample of carbon is burned in 8.0 g of O₂ to form CO₂ (C + O₂ → CO₂). What mass of CO₂ forms and which reactant is limiting? (C=12, O=16)","o":["11.0 g CO₂; O₂ limiting","22.0 g CO₂; C limiting","11.0 g CO₂; C limiting","8.0 g CO₂; O₂ limiting"],"c":0,"e":"C = 6.0/12 = 0.50 mol; O₂ = 8.0/32 = 0.25 mol. Reaction needs 1:1, so O₂ limits (0.25 mol). CO₂ = 0.25 mol = 0.25×44 = 11.0 g."},
  {"i":"chem-b3-0206","g":10,"u":"Chemical Reactions & Stoichiometry","d":"hard","t":"calculation","q":"What volume of CO₂ at STP is released when 50.0 g of NaHCO₃ decomposes: 2NaHCO₃ → Na₂CO₃ + H₂O + CO₂? (Na=23, H=1, C=12, O=16; molar volume=22.4 L/mol)","o":["6.67 L","13.3 L","26.6 L","3.33 L"],"c":0,"e":"NaHCO₃ molar mass = 84; moles = 50.0/84 = 0.595 mol. CO₂ = 0.595/2 = 0.298 mol → 0.298×22.4 = 6.67 L."},
  {"i":"chem-b3-0207","g":10,"u":"Chemical Reactions & Stoichiometry","d":"hard","t":"application","q":"A hydrocarbon contains 80.0% carbon and 20.0% hydrogen by mass and has a molar mass of 30 g/mol. What is its molecular formula? (C=12, H=1)","o":["CH₄","C₂H₆","C₂H₄","CH₃"],"c":1,"e":"C: 80/12 = 6.67; H: 20/1 = 20.0; ratio 1:3 → empirical CH₃ (mass 15). Molar 30/15 = 2 → C₂H₆."},
  {"i":"chem-b3-0208","g":10,"u":"Solutions","d":"hard","t":"calculation","q":"What mass of NaOH is needed to prepare 250 mL of a 0.40 mol/L solution? (Na=23, O=16, H=1)","o":["4.0 g","16 g","10 g","2.5 g"],"c":0,"e":"Moles = 0.40×0.250 = 0.10 mol; mass = 0.10×40 = 4.0 g."},
  {"i":"chem-b3-0209","g":10,"u":"Solutions","d":"hard","t":"calculation","q":"50.0 mL of 0.60 mol/L HCl is mixed with 100.0 mL of 0.20 mol/L HCl. What is the molarity of the resulting solution (assume volumes additive)?","o":["0.33 mol/L","0.40 mol/L","0.80 mol/L","0.27 mol/L"],"c":0,"e":"Moles = (0.050×0.60)+(0.100×0.20) = 0.030+0.020 = 0.050 mol; total V = 0.150 L; M = 0.050/0.150 = 0.33 mol/L."},
  {"i":"chem-b3-0210","g":10,"u":"Solutions","d":"hard","t":"calculation","q":"How many mL of concentrated 12 mol/L HCl are needed to prepare 500 mL of 0.30 mol/L HCl by dilution?","o":["12.5 mL","25 mL","6.25 mL","18 mL"],"c":0,"e":"M₁V₁=M₂V₂: V₁ = (0.30×500)/12 = 150/12 = 12.5 mL."},
  {"i":"chem-b3-0211","g":10,"u":"Solutions","d":"hard","t":"calculation","q":"A solution is made by dissolving 18 g of glucose (C₆H₁₂O₆, M=180) in water to a final volume of 400 mL. What is its molar concentration?","o":["0.25 mol/L","0.10 mol/L","0.40 mol/L","0.45 mol/L"],"c":0,"e":"Moles = 18/180 = 0.10 mol; M = 0.10/0.400 = 0.25 mol/L."},
  {"i":"chem-b3-0212","g":10,"u":"Energy Changes & Electrochemistry","d":"hard","t":"calculation","q":"In the titration 2NaOH + H₂SO₄ → Na₂SO₄ + 2H₂O, 20.0 mL of NaOH neutralizes 25.0 mL of 0.10 mol/L H₂SO₄. What is the molarity of the NaOH?","o":["0.25 mol/L","0.125 mol/L","0.50 mol/L","0.10 mol/L"],"c":0,"e":"Moles H₂SO₄ = 0.025×0.10 = 0.0025 mol; NaOH = 2×0.0025 = 0.0050 mol; M = 0.0050/0.020 = 0.25 mol/L."},
  {"i":"chem-b3-0213","g":10,"u":"Energy Changes & Electrochemistry","d":"hard","t":"calculation","q":"What is the pH of a 0.0050 mol/L HCl solution? (log 5 = 0.70)","o":["2.30","2.70","2.00","3.30"],"c":0,"e":"HCl fully dissociates: [H⁺] = 5.0×10⁻³. pH = −log(5.0×10⁻³) = 3 − 0.70 = 2.30."},
  {"i":"chem-b3-0214","g":10,"u":"Energy Changes & Electrochemistry","d":"hard","t":"calculation","q":"A 0.10 mol/L solution of a weak acid HA has Ka = 1.0×10⁻⁵. What is its approximate pH?","o":["3.00","5.00","2.00","4.00"],"c":0,"e":"[H⁺] = √(Ka·C) = √(1.0×10⁻⁵×0.10) = √(1.0×10⁻⁶) = 1.0×10⁻³. pH = 3.00."},
  {"i":"chem-b3-0215","g":10,"u":"Energy Changes & Electrochemistry","d":"hard","t":"conceptual","q":"In the electrolysis of molten NaCl, what occurs at the cathode and how does the oxidation number of sodium change?","o":["Na⁺ + e⁻ → Na; oxidation number +1 → 0 (reduction)","2Cl⁻ → Cl₂ + 2e⁻; +1 → 0 (oxidation)","Na → Na⁺ + e⁻; 0 → +1 (oxidation)","Cl⁻ → Cl; −1 → 0 (reduction)"],"c":0,"e":"The cathode is the site of reduction: Na⁺ gains an electron, Na⁺ + e⁻ → Na, so sodium's oxidation number falls from +1 to 0."},
  {"i":"chem-b3-0216","g":10,"u":"Energy Changes & Electrochemistry","d":"hard","t":"application","q":"Given standard reduction potentials Zn²⁺/Zn = −0.76 V and Cu²⁺/Cu = +0.34 V, what is the EMF of the Zn–Cu galvanic cell and which metal is the anode?","o":["1.10 V; Zn anode","0.42 V; Cu anode","1.10 V; Cu anode","0.42 V; Zn anode"],"c":0,"e":"E°cell = E°cathode − E°anode = 0.34 − (−0.76) = 1.10 V. Zn has the more negative potential so it is oxidized — the anode."},
  {"i":"chem-b3-0217","g":10,"u":"Energy Changes & Electrochemistry","d":"hard","t":"calculation","q":"For the equilibrium N₂O₄ ⇌ 2NO₂, at equilibrium [N₂O₄] = 0.40 mol/L and [NO₂] = 0.20 mol/L. What is Kc?","o":["0.10","0.50","0.025","0.20"],"c":0,"e":"Kc = [NO₂]²/[N₂O₄] = (0.20)²/0.40 = 0.040/0.40 = 0.10."},
  {"i":"chem-b3-0218","g":10,"u":"Important Inorganic Compounds","d":"hard","t":"conceptual","q":"In sulfuric acid production, SO₂ is converted to SO₃ (2SO₂ + O₂ → 2SO₃). What is the oxidation number of sulfur in SO₂ and SO₃ respectively?","o":["+4 and +6","+2 and +3","+4 and +4","+6 and +4"],"c":0,"e":"In SO₂: S + 2(−2) = 0 → S = +4. In SO₃: S + 3(−2) = 0 → S = +6. Sulfur is oxidized from +4 to +6."},
  {"i":"chem-b3-0219","g":10,"u":"Important Inorganic Compounds","d":"hard","t":"application","q":"Limewater absorbs CO₂: Ca(OH)₂ + CO₂ → CaCO₃ + H₂O. If 0.74 g of Ca(OH)₂ reacts completely, what mass of CaCO₃ precipitates? (Ca=40, O=16, H=1, C=12)","o":["1.0 g","0.74 g","2.0 g","0.50 g"],"c":0,"e":"M(Ca(OH)₂) = 74; moles = 0.74/74 = 0.010 mol. CaCO₃ = 0.010 mol × 100 = 1.0 g."},
  {"i":"chem-b3-0220","g":10,"u":"Metals & Nonmetals","d":"hard","t":"application","q":"Iron is extracted in a blast furnace by Fe₂O₃ + 3CO → 2Fe + 3CO₂. What maximum mass of iron is obtained from 320 g of pure Fe₂O₃? (Fe=56, O=16)","o":["224 g","112 g","160 g","320 g"],"c":0,"e":"M(Fe₂O₃) = 160; moles = 320/160 = 2.0 mol. Fe = 2×2.0 = 4.0 mol = 4.0×56 = 224 g."},
  {"i":"chem-b3-0221","g":10,"u":"Metals & Nonmetals","d":"hard","t":"conceptual","q":"Given the activity order K > Ca > Mg > Zn > Fe > Cu, which combination will produce a displacement reaction?","o":["Zn added to FeSO₄ solution","Cu added to ZnSO₄ solution","Fe added to MgSO₄ solution","Cu added to FeSO₄ solution"],"c":0,"e":"A metal displaces another only if it is higher in the activity series. Zn is above Fe, so Zn displaces Fe from FeSO₄; the other three pairs have the added metal below the salt's metal."},
  {"i":"chem-b3-0222","g":10,"u":"Hydrocarbons","d":"hard","t":"application","q":"Complete combustion of an alkane gives CO₂ and H₂O. If 0.10 mol of an alkane CₙH₂ₙ₊₂ produces 0.30 mol CO₂, identify the alkane and the moles of O₂ consumed.","o":["Propane C₃H₈; 0.50 mol O₂","Ethane C₂H₆; 0.35 mol O₂","Propane C₃H₈; 0.40 mol O₂","Butane C₄H₁₀; 0.65 mol O₂"],"c":0,"e":"CO₂/alkane = 0.30/0.10 = 3, so n=3 → C₃H₈. Combustion: C₃H₈ + 5O₂ → 3CO₂ + 4H₂O, so O₂ = 5×0.10 = 0.50 mol."},
  {"i":"chem-b3-0223","g":10,"u":"Hydrocarbons","d":"hard","t":"conceptual","q":"An unknown hydrocarbon with molecular formula C₄H₆ decolorizes bromine water. To which homologous series does it belong, and what is the general formula?","o":["Alkyne; CₙH₂ₙ₋₂","Alkane; CₙH₂ₙ₊₂","Alkene; CₙH₂ₙ","Cycloalkane; CₙH₂ₙ"],"c":0,"e":"For n=4, CₙH₂ₙ₋₂ = C₄H₆, matching the alkyne general formula; the triple bond decolorizes bromine water by addition."},
  {"i":"chem-b3-0224","g":10,"u":"Chemical Reactions & Stoichiometry","d":"hard","t":"calculation","q":"When 13.4 g of impure CaCO₃ is heated completely, 4.4 g of CO₂ is released (CaCO₃ → CaO + CO₂). What is the percentage purity of the limestone sample? (Ca=40, C=12, O=16)","o":["56.7%","65.3%","74.6%","100%"],"c":2,"e":"Moles CO₂ = 4.4/44 = 0.1 mol = moles CaCO₃; mass pure CaCO₃ = 0.1×100 = 10 g; purity = 10/13.4 ×100 = 74.6%."},
  {"i":"chem-b3-0225","g":10,"u":"Chemical Reactions & Stoichiometry","d":"hard","t":"calculation","q":"In the reaction N₂ + 3H₂ → 2NH₃, 14 g of N₂ is mixed with 4 g of H₂. Which is the limiting reactant and what mass of NH₃ forms? (N=14, H=1)","o":["H₂ limiting; 11.3 g NH₃","N₂ limiting; 17 g NH₃","N₂ limiting; 8.5 g NH₃","H₂ limiting; 34 g NH₃"],"c":1,"e":"N₂ = 14/28 = 0.5 mol needs 1.5 mol H₂; H₂ = 4/2 = 2 mol available, so N₂ limits; NH₃ = 2×0.5 = 1.0 mol = 17 g."},
  {"i":"chem-b3-0226","g":10,"u":"Chemical Reactions & Stoichiometry","d":"hard","t":"calculation","q":"A 0.250 mol sample of a hydrate MgSO₄·xH₂O has a mass of 61.5 g. What is the value of x? (Mg=24, S=32, O=16, H=1)","o":["5","6","7","8"],"c":2,"e":"Molar mass = 61.5/0.250 = 246 g/mol; anhydrous MgSO₄ = 120; water mass = 246−120 = 126 = x×18, so x = 7."},
  {"i":"chem-b3-0227","g":10,"u":"Chemical Reactions & Stoichiometry","d":"hard","t":"calculation","q":"At STP, what volume of O₂ is needed to completely combust 5.6 L of C₃H₈ (propane)? C₃H₈ + 5O₂ → 3CO₂ + 4H₂O","o":["11.2 L","22.4 L","28.0 L","56.0 L"],"c":2,"e":"At STP volume ratio = mole ratio; O₂ = 5×5.6 = 28.0 L."},
  {"i":"chem-b3-0228","g":10,"u":"Chemical Reactions & Stoichiometry","d":"hard","t":"calculation","q":"How many oxygen atoms are present in 8.8 g of CO₂? (C=12, O=16, Nₐ=6.02×10²³)","o":["1.20×10²³","2.41×10²³","6.02×10²³","1.20×10²⁴"],"c":1,"e":"Moles CO₂ = 8.8/44 = 0.2 mol; O atoms = 0.2×2×6.02×10²³ = 2.41×10²³."},
  {"i":"chem-b3-0229","g":10,"u":"Solutions","d":"hard","t":"calculation","q":"What mass of NaOH is needed to prepare 500 mL of 0.20 M solution? (Na=23, O=16, H=1)","o":["2.0 g","4.0 g","8.0 g","40 g"],"c":1,"e":"Moles = 0.20×0.500 = 0.10 mol; mass = 0.10×40 = 4.0 g."},
  {"i":"chem-b3-0230","g":10,"u":"Solutions","d":"hard","t":"calculation","q":"36 mL of 0.50 M H₂SO₄ is diluted to 250 mL. A 25 mL portion of this diluted acid is then titrated with 0.10 M NaOH. What volume of NaOH is required? H₂SO₄ + 2NaOH → Na₂SO₄ + 2H₂O","o":["14.4 mL","18.0 mL","36.0 mL","72.0 mL"],"c":2,"e":"Diluted conc = (0.50×36)/250 = 0.072 M; moles H₂SO₄ in 25 mL = 0.072×0.025 = 0.0018; NaOH = 2×0.0018 = 0.0036 mol; V = 0.0036/0.10 = 0.036 L = 36.0 mL."},
  {"i":"chem-b3-0231","g":10,"u":"Solutions","d":"hard","t":"calculation","q":"A solution is made by dissolving 18 g of glucose (C₆H₁₂O₆, M=180) in water to make 200 mL. What is its molarity?","o":["0.10 M","0.50 M","0.90 M","1.0 M"],"c":1,"e":"Moles = 18/180 = 0.10 mol; molarity = 0.10/0.200 = 0.50 M."},
  {"i":"chem-b3-0232","g":10,"u":"Solutions","d":"hard","t":"conceptual","q":"Lake Abijata water is saturated with dissolved Na₂CO₃ (solubility increases with temperature). As the dry-season temperature rises and water evaporates, which statement is correct?","o":["The solution becomes unsaturated","Solubility decreases, so salt always precipitates","Evaporation can force precipitation even though higher temperature raises solubility","Molarity stays constant during evaporation"],"c":2,"e":"Evaporation removes solvent; even though higher temperature raises solubility per litre, the shrinking water volume can push the solution past saturation and precipitate salt."},
  {"i":"chem-b3-0233","g":10,"u":"Important Inorganic Compounds","d":"hard","t":"calculation","q":"What are the oxidation numbers of sulfur in the sulfate ion SO₄²⁻ and of chromium in the dichromate ion Cr₂O₇²⁻ respectively?","o":["+6 and +6","+4 and +7","+6 and +7","+2 and +6"],"c":0,"e":"In SO₄²⁻: x+4(−2)=−2 → x=+6; in Cr₂O₇²⁻: 2x+7(−2)=−2 → 2x=12 → x=+6."},
  {"i":"chem-b3-0234","g":10,"u":"Important Inorganic Compounds","d":"hard","t":"application","q":"Concentrated H₂SO₄ is added to solid NaCl and the gas evolved is led to the mouth of a tube where NH₃ gas escapes. What is observed and what white solid forms?","o":["Brown gas; NaNO₃","Dense white fumes; NH₄Cl","No reaction; NaOH","Green gas; NH₄NO₃"],"c":1,"e":"H₂SO₄ + NaCl → NaHSO₄ + HCl gas; HCl meets NH₃ to give dense white fumes of NH₄Cl (HCl + NH₃ → NH₄Cl)."},
  {"i":"chem-b3-0235","g":10,"u":"Important Inorganic Compounds","d":"hard","t":"calculation","q":"Ammonium sulfate fertilizer (NH₄)₂SO₄ is used on Ethiopian teff farms. What is its nitrogen percentage by mass? (N=14, H=1, S=32, O=16)","o":["10.6%","21.2%","28.0%","35.0%"],"c":1,"e":"M = 2(18)+32+64 = 132; N mass = 2×14 = 28; %N = 28/132 ×100 = 21.2%."},
  {"i":"chem-b3-0236","g":10,"u":"Important Inorganic Compounds","d":"hard","t":"conceptual","q":"Which statement correctly explains why rainwater containing dissolved CO₂ is weakly acidic and is classed as a weak acid system?","o":["CO₂ + H₂O ⇌ H₂CO₃, which only partially ionises to H⁺ + HCO₃⁻","CO₂ reacts with water to give the strong acid HNO₃","CO₂ is basic and neutralises the rain","CO₂ does not react with water at all"],"c":0,"e":"CO₂ + H₂O ⇌ H₂CO₃, and carbonic acid ionises only partially (H₂CO₃ ⇌ H⁺ + HCO₃⁻), giving a weak acid and slightly acidic rain."},
  {"i":"chem-b3-0237","g":10,"u":"Energy Changes & Electrochemistry","d":"hard","t":"calculation","q":"Given ΔH for C(s)+O₂→CO₂ is −394 kJ/mol and for CO+½O₂→CO₂ is −283 kJ/mol, what is ΔH for C(s)+½O₂→CO using Hess's law?","o":["−677 kJ/mol","−111 kJ/mol","+111 kJ/mol","−394 kJ/mol"],"c":1,"e":"Target = reaction1 − reaction2 = (−394) − (−283) = −111 kJ/mol."},
  {"i":"chem-b3-0238","g":10,"u":"Energy Changes & Electrochemistry","d":"hard","t":"calculation","q":"In the electrolysis of molten NaCl, a current of 5.0 A flows for 1930 s. What mass of sodium is deposited at the cathode? (Na=23, F=96500 C/mol)","o":["1.15 g","2.30 g","0.23 g","4.60 g"],"c":1,"e":"Q = 5.0×1930 = 9650 C; moles e⁻ = 9650/96500 = 0.10; Na⁺ + e⁻ → Na so moles Na = 0.10; mass = 0.10×23 = 2.30 g."},
  {"i":"chem-b3-0239","g":10,"u":"Energy Changes & Electrochemistry","d":"hard","t":"conceptual","q":"For the cell Zn|Zn²⁺ || Cu²⁺|Cu with E°(Zn²⁺/Zn)=−0.76 V and E°(Cu²⁺/Cu)=+0.34 V, what is the cell EMF and which electrode is the anode?","o":["1.10 V; Zn is anode","0.42 V; Cu is anode","1.10 V; Cu is anode","−1.10 V; Zn is anode"],"c":0,"e":"E°cell = E°cathode − E°anode = 0.34 − (−0.76) = 1.10 V; Zn is oxidised, so it is the anode."},
  {"i":"chem-b3-0240","g":10,"u":"Energy Changes & Electrochemistry","d":"hard","t":"application","q":"During the electrolysis of dilute aqueous Na₂SO₄, which products form at the cathode and anode respectively?","o":["Na and SO₃","H₂ and O₂","O₂ and H₂","Na and O₂"],"c":1,"e":"Water is preferentially discharged: cathode 2H₂O+2e⁻→H₂+2OH⁻ (H₂); anode 2H₂O→O₂+4H⁺+4e⁻ (O₂); Na⁺ and SO₄²⁻ remain in solution."},
  {"i":"chem-b3-0241","g":10,"u":"Metals & Nonmetals","d":"hard","t":"conceptual","q":"An element X has electron configuration 2,8,7. Which set correctly describes X's group, typical ion, and bonding with metallic sodium?","o":["Group VIIA; X⁻; ionic NaX","Group VIIA; X⁺; covalent","Group IIA; X²⁻; ionic","Group VA; X³⁻; metallic"],"c":0,"e":"7 valence electrons → Group VIIA (halogen); it gains 1 e⁻ to form X⁻; with Na (Group IA) it forms ionic NaX."},
  {"i":"chem-b3-0242","g":10,"u":"Metals & Nonmetals","d":"hard","t":"application","q":"Why is aluminium obtained by electrolysis of molten Al₂O₃ rather than reduction with carbon, whereas iron is reduced by carbon in a blast furnace?","o":["Al is below carbon in reactivity","Al is too reactive for carbon to displace it economically, so electrolysis is used","Iron is more reactive than aluminium","Al₂O₃ does not conduct when molten"],"c":1,"e":"Aluminium is more reactive than carbon, so carbon cannot reduce Al₂O₃ practically and electrolysis is required; iron, being less reactive than carbon, is reduced in the blast furnace."},
  {"i":"chem-b3-0243","g":10,"u":"Hydrocarbons","d":"hard","t":"calculation","q":"A hydrocarbon contains 82.76% carbon and 17.24% hydrogen by mass and has a molar mass of 58 g/mol. What is its molecular formula? (C=12, H=1)","o":["C₃H₈","C₄H₁₀","C₄H₈","C₅H₁₀"],"c":1,"e":"C: 82.76/12 = 6.90; H: 17.24/1 = 17.24; ratio ≈ 1:2.5 → empirical C₂H₅ (M=29); 58/29 = 2 → molecular C₄H₁₀."},
  {"i":"chem-b3-0244","g":10,"u":"Hydrocarbons","d":"hard","t":"conceptual","q":"A hydrocarbon rapidly decolourises bromine water without UV light and has the general formula CₙH₂ₙ. To which homologous series does it belong and what is the formula of its C₄ member?","o":["Alkane; C₄H₁₀","Alkene; C₄H₈","Alkyne; C₄H₆","Alkene; C₄H₁₀"],"c":1,"e":"CₙH₂ₙ with rapid (addition) decolourisation of bromine water indicates an alkene; the C₄ member is C₄H₈ (2×4=8)."},
  {"i":"chem-b3-0245","g":10,"u":"Hydrocarbons","d":"hard","t":"calculation","q":"Complete combustion of 0.05 mol of an alkyne (CₙH₂ₙ₋₂) produces 4.4 g of CO₂. Identify the alkyne. (C=12, O=16)","o":["Ethyne C₂H₂","Propyne C₃H₄","Butyne C₄H₆","Pentyne C₅H₈"],"c":0,"e":"Moles CO₂ = 4.4/44 = 0.1; carbons per molecule = 0.1/0.05 = 2, so the alkyne is C₂H₂ (ethyne)."},
  {"i":"chem-b3-0246","g":10,"u":"Chemical Reactions & Stoichiometry","d":"impossible","t":"calculation","q":"A 5.00 g sample of impure CaCO₃ (limestone from Mugher) is fully decomposed by heating; the CO₂ liberated is passed into excess Ca(OH)₂, precipitating 4.00 g of CaCO₃. What is the percent purity of the original limestone? (Molar masses g/mol: CaCO₃=100, CO₂=44)","o":["64.0%","80.0%","88.0%","100%"],"c":1,"e":"Precipitate 4.00 g CaCO₃ = 0.0400 mol → 0.0400 mol CO₂ → 0.0400 mol CaCO₃ in sample = 4.00 g pure. Purity = 4.00/5.00 = 80.0%."},
  {"i":"chem-b3-0247","g":10,"u":"Chemical Reactions & Stoichiometry","d":"impossible","t":"calculation","q":"When 0.50 mol C₃H₈ is burned in 2.00 mol O₂, which reactant limits the reaction and how many moles of CO₂ form? Balanced: C₃H₈ + 5O₂ → 3CO₂ + 4H₂O.","o":["C₃H₈ limits; 1.50 mol CO₂","O₂ limits; 1.20 mol CO₂","O₂ limits; 1.50 mol CO₂","C₃H₈ limits; 2.00 mol CO₂"],"c":1,"e":"0.50 mol C₃H₈ needs 2.50 mol O₂ but only 2.00 mol is available, so O₂ limits. 2.00 mol O₂ × (3 CO₂ / 5 O₂) = 1.20 mol CO₂."},
  {"i":"chem-b3-0248","g":10,"u":"Chemical Reactions & Stoichiometry","d":"impossible","t":"calculation","q":"Complete combustion of a sample of hydrocarbon CₓHᵧ gives 0.150 mol CO₂ and 0.300 mol H₂O. What is the empirical formula of the hydrocarbon?","o":["CH₄","CH₂","CH₃","C₂H₃"],"c":0,"e":"Mol C = 0.150; mol H = 2 × 0.300 = 0.600. Ratio C:H = 0.150:0.600 = 1:4, giving empirical formula CH₄."},
  {"i":"chem-b3-0249","g":10,"u":"Chemical Reactions & Stoichiometry","d":"impossible","t":"calculation","q":"What volume of CO₂ gas (at STP, 22.4 L/mol) is produced when 8.4 g of NaHCO₃ (baking soda) decomposes? 2NaHCO₃ → Na₂CO₃ + H₂O + CO₂. (NaHCO₃ = 84 g/mol)","o":["1.12 L","2.24 L","1.00 L","3.36 L"],"c":0,"e":"8.4/84 = 0.100 mol NaHCO₃ → CO₂ = 0.100 × (1/2) = 0.0500 mol → 0.0500 × 22.4 = 1.12 L."},
  {"i":"chem-b3-0250","g":10,"u":"Solutions","d":"impossible","t":"calculation","q":"How many mL of 0.250 M H₂SO₄ are needed to exactly neutralize 40.0 mL of 0.150 M NaOH? H₂SO₄ + 2NaOH → Na₂SO₄ + 2H₂O.","o":["12.0 mL","24.0 mL","6.00 mL","48.0 mL"],"c":0,"e":"mol NaOH = 0.0400 × 0.150 = 0.00600. mol H₂SO₄ = 0.00600/2 = 0.00300. V = 0.00300/0.250 = 0.0120 L = 12.0 mL."},
  {"i":"chem-b3-0251","g":10,"u":"Solutions","d":"impossible","t":"calculation","q":"50.0 mL of 0.200 M HCl is mixed with 50.0 mL of 0.120 M NaOH. What is the pH of the resulting solution? (log 4 = 0.60)","o":["1.40","1.30","2.00","1.70"],"c":0,"e":"mol HCl = 0.0100, mol NaOH = 0.00600; excess H⁺ = 0.00400 mol in 0.100 L → 0.0400 M. pH = −log(0.0400) = 2 − log4 = 2 − 0.60 = 1.40."},
  {"i":"chem-b3-0252","g":10,"u":"Solutions","d":"impossible","t":"calculation","q":"A solution is made by dissolving 0.0100 mol of the weak acid HA (Ka = 1.0×10⁻⁵) in water to 1.00 L. Assuming x ≪ 0.0100, what is the pH?","o":["3.50","5.00","2.50","4.00"],"c":0,"e":"[H⁺] = √(Ka·C) = √(1.0×10⁻⁵ × 0.0100) = √(1.0×10⁻⁷) = 3.16×10⁻⁴. pH = −log(3.16×10⁻⁴) ≈ 3.50."},
  {"i":"chem-b3-0253","g":10,"u":"Solutions","d":"impossible","t":"calculation","q":"11.7 g of NaCl is dissolved in water and made up to 500 mL of solution. What is the molarity of the solution? (NaCl = 58.5 g/mol)","o":["0.400 M","0.200 M","0.800 M","0.100 M"],"c":0,"e":"mol NaCl = 11.7/58.5 = 0.200 mol in 0.500 L → 0.200/0.500 = 0.400 M."},
  {"i":"chem-b3-0254","g":10,"u":"Important Inorganic Compounds","d":"impossible","t":"calculation","q":"In the compound (NH₄)₂Cr₂O₇ (ammonium dichromate), what is the oxidation number of chromium?","o":["+6","+3","+7","+12"],"c":0,"e":"Each NH₄⁺ is +1 (×2 = +2), so Cr₂O₇ carries −2. With 7 O at −2: 2Cr + 7(−2) = −2 → 2Cr = +12 → Cr = +6."},
  {"i":"chem-b3-0255","g":10,"u":"Important Inorganic Compounds","d":"impossible","t":"conceptual","q":"Which statement correctly explains why concentrated H₂SO₄ chars sucrose (C₁₂H₂₂O₁₁) while dilute H₂SO₄ does not?","o":["Concentrated H₂SO₄ removes H and O as water from the sugar, leaving carbon; dilute is mostly water already","Dilute H₂SO₄ is a stronger acid than concentrated","Concentrated H₂SO₄ oxidizes the carbon to CO₂ while dilute reduces it","Only dilute H₂SO₄ can break C–C bonds in sucrose"],"c":0,"e":"Concentrated H₂SO₄ has a strong affinity for water and abstracts H and O in a 2:1 ratio from sucrose, leaving a black carbon residue. Dilute acid is already largely water and cannot dehydrate it."},
  {"i":"chem-b3-0256","g":10,"u":"Important Inorganic Compounds","d":"impossible","t":"calculation","q":"Ammonia is produced via N₂ + 3H₂ → 2NH₃. If 28.0 g of N₂ reacts completely with sufficient H₂, what mass of NH₃ forms? (N=14, H=1)","o":["34.0 g","17.0 g","28.0 g","68.0 g"],"c":0,"e":"28.0 g N₂ = 1.00 mol → 2.00 mol NH₃ → 2.00 × 17.0 = 34.0 g."},
  {"i":"chem-b3-0257","g":10,"u":"Energy Changes & Electrochemistry","d":"impossible","t":"calculation","q":"In the electrolysis of molten NaCl, a current of 5.00 A flows for 1930 s. What mass of sodium metal is deposited at the cathode? (Na = 23 g/mol, F = 96500 C/mol)","o":["2.30 g","1.15 g","4.60 g","0.230 g"],"c":0,"e":"Q = 5.00 × 1930 = 9650 C → mol e⁻ = 9650/96500 = 0.100. Na⁺ + e⁻ → Na, so 0.100 mol Na = 0.100 × 23 = 2.30 g."},
  {"i":"chem-b3-0258","g":10,"u":"Energy Changes & Electrochemistry","d":"impossible","t":"calculation","q":"Given E°(Cu²⁺/Cu) = +0.34 V and E°(Zn²⁺/Zn) = −0.76 V, what is the standard cell potential of the Daniell cell and which electrode is the anode?","o":["+1.10 V; Zn anode","−1.10 V; Cu anode","+0.42 V; Zn anode","+1.10 V; Cu anode"],"c":0,"e":"E°cell = E°cathode − E°anode = 0.34 − (−0.76) = +1.10 V. Zn has the lower E° and is oxidized, so Zn is the anode."},
  {"i":"chem-b3-0259","g":10,"u":"Energy Changes & Electrochemistry","d":"impossible","t":"calculation","q":"For 2H₂(g) + O₂(g) → 2H₂O(l), ΔH = −572 kJ. How much heat is released when 4.00 g of H₂ reacts completely? (H₂ = 2.00 g/mol)","o":["572 kJ","286 kJ","1144 kJ","143 kJ"],"c":0,"e":"4.00 g H₂ = 2.00 mol. The equation releases 572 kJ per 2 mol H₂, so 2.00 mol releases 572 kJ."},
  {"i":"chem-b3-0260","g":10,"u":"Metals & Nonmetals","d":"impossible","t":"calculation","q":"Aluminium is extracted by electrolysis: Al³⁺ + 3e⁻ → Al. How many moles of electrons are required to produce 54.0 g of aluminium? (Al = 27 g/mol)","o":["6.00 mol","2.00 mol","3.00 mol","18.0 mol"],"c":0,"e":"54.0/27 = 2.00 mol Al. Each Al³⁺ needs 3 e⁻ → 2.00 × 3 = 6.00 mol electrons."},
  {"i":"chem-b3-0261","g":10,"u":"Metals & Nonmetals","d":"impossible","t":"conceptual","q":"A strip of metal X displaces copper from CuSO₄ solution but cannot displace zinc from ZnSO₄. Where does X lie in the reactivity (activity) series relative to Cu and Zn?","o":["Below Zn but above Cu","Above Zn","Below Cu","Between Cu and silver"],"c":0,"e":"X reduces Cu²⁺, so X is more reactive than Cu. X cannot reduce Zn²⁺, so X is less reactive than Zn. Thus Zn > X > Cu."},
  {"i":"chem-b3-0262","g":10,"u":"Hydrocarbons","d":"impossible","t":"calculation","q":"A gaseous alkyne has a molar mass of 40.0 g/mol. Using the alkyne general formula CₙH₂ₙ₋₂, identify the compound. (C=12, H=1)","o":["Propyne (C₃H₄)","Ethyne (C₂H₂)","Butyne (C₄H₆)","Propene (C₃H₆)"],"c":0,"e":"For CₙH₂ₙ₋₂: molar mass = 12n + (2n−2) = 14n − 2 = 40 → 14n = 42 → n = 3. C₃H₄ is propyne."},
  {"i":"chem-b3-0263","g":11,"u":"Atomic Structure & Periodic Properties","d":"easy","t":"calculation","q":"An atom of an element has 17 protons and 18 neutrons. What is its mass number?","o":["17","18","35","1"],"c":2,"e":"Mass number = number of protons + number of neutrons = 17 + 18 = 35."},
  {"i":"chem-b3-0264","g":11,"u":"Atomic Structure & Periodic Properties","d":"easy","t":"conceptual","q":"Which element has the ground-state electron configuration 1s² 2s² 2p⁶ 3s¹?","o":["Neon (Ne)","Sodium (Na)","Magnesium (Mg)","Lithium (Li)"],"c":1,"e":"The configuration totals 11 electrons, so the neutral atom is sodium (Z = 11)."},
  {"i":"chem-b3-0265","g":11,"u":"Atomic Structure & Periodic Properties","d":"easy","t":"conceptual","q":"Across Period 3 from Na to Cl, how does atomic radius generally change?","o":["Increases","Decreases","Stays constant","First increases then decreases"],"c":1,"e":"Across a period nuclear charge increases while electrons fill the same shell, pulling electrons closer, so atomic radius decreases."},
  {"i":"chem-b3-0266","g":11,"u":"Atomic Structure & Periodic Properties","d":"easy","t":"definition","q":"The energy required to remove the most loosely bound electron from a gaseous atom is called the:","o":["Electron affinity","Electronegativity","Ionisation energy","Lattice energy"],"c":2,"e":"Ionisation energy is the minimum energy needed to remove an electron from a gaseous atom in its ground state."},
  {"i":"chem-b3-0267","g":11,"u":"Chemical Bonding","d":"easy","t":"conceptual","q":"What type of bond is formed between the atoms in sodium chloride (NaCl)?","o":["Covalent bond","Ionic bond","Metallic bond","Hydrogen bond"],"c":1,"e":"Sodium (a metal) transfers an electron to chlorine (a non-metal), forming Na⁺ and Cl⁻ ions held by ionic bonding."},
  {"i":"chem-b3-0268","g":11,"u":"Chemical Bonding","d":"easy","t":"calculation","q":"How many shared (bonding) electron pairs are present in a nitrogen molecule, N₂?","o":["1","2","3","4"],"c":2,"e":"N₂ has a triple bond between the two nitrogen atoms, which consists of 3 shared electron pairs."},
  {"i":"chem-b3-0269","g":11,"u":"Chemical Bonding","d":"easy","t":"conceptual","q":"Which molecule is non-polar overall despite having polar bonds?","o":["H₂O","NH₃","CO₂","HCl"],"c":2,"e":"CO₂ is linear, so the two equal C=O bond dipoles point in opposite directions and cancel, giving a non-polar molecule."},
  {"i":"chem-b3-0270","g":11,"u":"Chemical Bonding","d":"easy","t":"definition","q":"A chemical bond formed by the electrostatic attraction between metal cations and a 'sea' of delocalised electrons is called:","o":["Ionic bonding","Covalent bonding","Metallic bonding","Dative bonding"],"c":2,"e":"Metallic bonding arises from positive metal ions surrounded by mobile delocalised electrons, explaining conductivity and malleability."},
  {"i":"chem-b3-0271","g":11,"u":"Chemical Bonding","d":"easy","t":"conceptual","q":"How many lone pairs are on the central oxygen atom in a water (H₂O) molecule?","o":["0","1","2","3"],"c":2,"e":"Oxygen has 6 valence electrons; 2 are used in the two O–H bonds, leaving 4 electrons as 2 lone pairs."},
  {"i":"chem-b3-0272","g":11,"u":"Physical States of Matter","d":"easy","t":"conceptual","q":"According to the kinetic theory, what happens to the average kinetic energy of gas particles when temperature increases?","o":["It decreases","It increases","It stays the same","It becomes zero"],"c":1,"e":"Average kinetic energy of gas particles is directly proportional to absolute temperature, so it increases as temperature rises."},
  {"i":"chem-b3-0273","g":11,"u":"Physical States of Matter","d":"easy","t":"calculation","q":"A gas occupies 2.0 L at 1.0 atm. At constant temperature, what volume does it occupy at 2.0 atm (Boyle's law)?","o":["0.5 L","1.0 L","2.0 L","4.0 L"],"c":1,"e":"Boyle's law: P₁V₁ = P₂V₂, so V₂ = (1.0 × 2.0)/2.0 = 1.0 L."},
  {"i":"chem-b3-0274","g":11,"u":"Physical States of Matter","d":"easy","t":"definition","q":"The direct change of a substance from the solid state to the gaseous state is called:","o":["Condensation","Sublimation","Evaporation","Deposition"],"c":1,"e":"Sublimation is the phase transition in which a solid converts directly to vapour without passing through the liquid state."},
  {"i":"chem-b3-0275","g":11,"u":"Physical States of Matter","d":"easy","t":"calculation","q":"A gas occupies 300 mL at 200 K. At constant pressure, what is its volume at 400 K (Charles's law)?","o":["150 mL","300 mL","600 mL","900 mL"],"c":2,"e":"Charles's law: V₁/T₁ = V₂/T₂, so V₂ = 300 × (400/200) = 600 mL."},
  {"i":"chem-b3-0276","g":11,"u":"Chemical Kinetics","d":"easy","t":"definition","q":"In chemical kinetics, the minimum energy that colliding particles must possess to react is called the:","o":["Bond energy","Activation energy","Kinetic energy","Lattice energy"],"c":1,"e":"Activation energy (Eₐ) is the minimum energy barrier that reacting particles must overcome for a successful reaction."},
  {"i":"chem-b3-0277","g":11,"u":"Chemical Kinetics","d":"easy","t":"conceptual","q":"How does a catalyst increase the rate of a reaction?","o":["By raising the activation energy","By lowering the activation energy","By increasing the temperature","By being consumed in the reaction"],"c":1,"e":"A catalyst provides an alternative pathway with a lower activation energy, so more collisions are successful and the rate increases."},
  {"i":"chem-b3-0278","g":11,"u":"Chemical Kinetics","d":"easy","t":"conceptual","q":"Increasing the concentration of a reactant generally increases reaction rate because it:","o":["Lowers activation energy","Increases collision frequency","Raises the temperature","Changes the products"],"c":1,"e":"More reactant particles per unit volume means more frequent collisions per second, increasing the rate of reaction."},
  {"i":"chem-b3-0279","g":11,"u":"Chemical Equilibrium","d":"easy","t":"definition","q":"At chemical equilibrium, the rate of the forward reaction compared with the rate of the reverse reaction is:","o":["Greater","Equal","Smaller","Zero"],"c":1,"e":"Dynamic equilibrium is reached when the forward and reverse reaction rates become equal, so concentrations stay constant."},
  {"i":"chem-b3-0280","g":11,"u":"Chemical Equilibrium","d":"easy","t":"application","q":"For N₂(g) + 3H₂(g) ⇌ 2NH₃(g), according to Le Chatelier's principle, increasing the pressure shifts the equilibrium:","o":["To the left","To the right","No shift","Stops the reaction"],"c":1,"e":"There are 4 gas moles on the left and 2 on the right; higher pressure favours the side with fewer gas moles, shifting right."},
  {"i":"chem-b3-0281","g":11,"u":"Chemical Equilibrium","d":"easy","t":"calculation","q":"An aqueous solution has [H⁺] = 1 × 10⁻³ mol/L. What is its pH?","o":["1","3","7","11"],"c":1,"e":"pH = −log[H⁺] = −log(1 × 10⁻³) = 3."},
  {"i":"chem-b3-0282","g":11,"u":"Chemical Equilibrium","d":"easy","t":"conceptual","q":"At 25 °C, a solution with pH = 9 is best described as:","o":["Acidic","Neutral","Basic","Saturated"],"c":2,"e":"At 25 °C, pH > 7 indicates a basic (alkaline) solution; pH = 9 is greater than 7, so it is basic."},
  {"i":"chem-b3-0283","g":11,"u":"Oxygen-Containing Organic Compounds","d":"easy","t":"definition","q":"Which functional group characterises an alcohol such as ethanol (C₂H₅OH)?","o":["Carboxyl (–COOH)","Hydroxyl (–OH)","Carbonyl (C=O)","Amino (–NH₂)"],"c":1,"e":"Alcohols contain the hydroxyl functional group (–OH) bonded to a carbon atom, as in ethanol, C₂H₅OH."},
  {"i":"chem-b3-0284","g":11,"u":"Atomic Structure & Periodic Properties","d":"easy","t":"definition","q":"Which subatomic particle determines the atomic number of an element?","o":["Proton","Neutron","Electron","Positron"],"c":0,"e":"The atomic number equals the number of protons in the nucleus, which defines the element's identity."},
  {"i":"chem-b3-0285","g":11,"u":"Atomic Structure & Periodic Properties","d":"easy","t":"calculation","q":"An atom has a mass number of 39 and 19 protons. How many neutrons does it contain?","o":["20","19","39","58"],"c":0,"e":"Neutrons = mass number − protons = 39 − 19 = 20."},
  {"i":"chem-b3-0286","g":11,"u":"Atomic Structure & Periodic Properties","d":"easy","t":"conceptual","q":"What is the maximum number of electrons that can occupy the third principal energy level (n = 3)?","o":["18","8","9","32"],"c":0,"e":"Maximum electrons in a shell = 2n² = 2(3)² = 18."},
  {"i":"chem-b3-0287","g":11,"u":"Atomic Structure & Periodic Properties","d":"easy","t":"conceptual","q":"Across a period from left to right in the periodic table, atomic radius generally:","o":["Decreases","Increases","Stays constant","Doubles"],"c":0,"e":"Increasing nuclear charge pulls electrons in the same shell closer, so atomic radius decreases across a period."},
  {"i":"chem-b3-0288","g":11,"u":"Atomic Structure & Periodic Properties","d":"easy","t":"definition","q":"The energy required to remove the most loosely bound electron from a gaseous atom is called:","o":["Ionization energy","Electron affinity","Electronegativity","Lattice energy"],"c":0,"e":"Ionization energy is the energy needed to remove an electron from a gaseous atom."},
  {"i":"chem-b3-0289","g":11,"u":"Chemical Bonding","d":"easy","t":"conceptual","q":"What type of bond forms when electrons are transferred from a metal to a non-metal?","o":["Ionic bond","Covalent bond","Metallic bond","Hydrogen bond"],"c":0,"e":"Electron transfer from metal to non-metal produces oppositely charged ions held by an ionic bond."},
  {"i":"chem-b3-0290","g":11,"u":"Chemical Bonding","d":"easy","t":"calculation","q":"How many shared electron pairs are present in a nitrogen molecule, N₂?","o":["3","1","2","4"],"c":0,"e":"N₂ has a triple bond, which consists of three shared electron pairs."},
  {"i":"chem-b3-0291","g":11,"u":"Chemical Bonding","d":"easy","t":"definition","q":"A covalent bond in which the shared electron pair comes entirely from one atom is called:","o":["Coordinate (dative) bond","Polar bond","Ionic bond","Metallic bond"],"c":0,"e":"In a coordinate (dative) covalent bond, both shared electrons are donated by a single atom."},
  {"i":"chem-b3-0292","g":11,"u":"Chemical Bonding","d":"easy","t":"conceptual","q":"Which molecule has a non-polar covalent bond?","o":["Cl₂","HCl","H₂O","NH₃"],"c":0,"e":"Cl₂ has two identical atoms with equal electronegativity, so the bond is non-polar covalent."},
  {"i":"chem-b3-0293","g":11,"u":"Chemical Bonding","d":"easy","t":"application","q":"Which property is characteristic of most ionic compounds?","o":["High melting point","Low boiling point","Conduct electricity as solids","Soft and waxy"],"c":0,"e":"Strong electrostatic forces in ionic lattices give ionic compounds high melting points."},
  {"i":"chem-b3-0294","g":11,"u":"Physical States of Matter","d":"easy","t":"definition","q":"The change of a substance directly from solid to gas without passing through the liquid state is called:","o":["Sublimation","Condensation","Vaporization","Freezing"],"c":0,"e":"Sublimation is the direct solid-to-gas phase transition, e.g. solid CO₂."},
  {"i":"chem-b3-0295","g":11,"u":"Physical States of Matter","d":"easy","t":"calculation","q":"A fixed amount of gas at constant temperature has a volume of 4 L at 2 atm. What is its volume at 1 atm?","o":["8 L","2 L","4 L","1 L"],"c":0,"e":"By Boyle's law P₁V₁ = P₂V₂: (2)(4) = (1)(V₂), so V₂ = 8 L."},
  {"i":"chem-b3-0296","g":11,"u":"Physical States of Matter","d":"easy","t":"conceptual","q":"According to the kinetic theory, increasing the temperature of a gas increases the:","o":["Average kinetic energy of its particles","Mass of its particles","Number of its particles","Size of its particles"],"c":0,"e":"Temperature is a measure of the average kinetic energy of gas particles, which rises with heating."},
  {"i":"chem-b3-0297","g":11,"u":"Physical States of Matter","d":"easy","t":"calculation","q":"At constant pressure, a gas occupies 300 mL at 200 K. What volume will it occupy at 400 K?","o":["600 mL","150 mL","300 mL","450 mL"],"c":0,"e":"By Charles's law V₁/T₁ = V₂/T₂: 300/200 = V₂/400, so V₂ = 600 mL."},
  {"i":"chem-b3-0298","g":11,"u":"Chemical Kinetics","d":"easy","t":"definition","q":"A substance that increases the rate of a reaction without being consumed is called a:","o":["Catalyst","Reactant","Product","Inhibitor"],"c":0,"e":"A catalyst speeds up a reaction by lowering activation energy and is not used up overall."},
  {"i":"chem-b3-0299","g":11,"u":"Chemical Kinetics","d":"easy","t":"conceptual","q":"How does a catalyst speed up a chemical reaction?","o":["By lowering the activation energy","By increasing the activation energy","By increasing the enthalpy of products","By raising the temperature"],"c":0,"e":"A catalyst provides an alternative pathway with lower activation energy, so more collisions are effective."},
  {"i":"chem-b3-0300","g":11,"u":"Chemical Equilibrium","d":"easy","t":"calculation","q":"What is the pH of a solution with a hydrogen ion concentration [H⁺] = 1 × 10⁻³ mol/L?","o":["3","11","2","10⁻³"],"c":0,"e":"pH = −log[H⁺] = −log(10⁻³) = 3."},
  {"i":"chem-b3-0301","g":11,"u":"Chemical Equilibrium","d":"easy","t":"calculation","q":"At 25 °C a solution has pOH = 4. What is its pH?","o":["10","4","14","7"],"c":0,"e":"At 25 °C, pH + pOH = 14, so pH = 14 − 4 = 10."},
  {"i":"chem-b3-0302","g":11,"u":"Chemical Equilibrium","d":"easy","t":"conceptual","q":"For an exothermic equilibrium, increasing the temperature shifts the equilibrium position toward the:","o":["Reactants","Products","No shift occurs","Catalyst"],"c":0,"e":"By Le Chatelier's principle, added heat favors the endothermic (reverse) direction, shifting toward reactants."},
  {"i":"chem-b3-0303","g":11,"u":"Chemical Equilibrium","d":"easy","t":"definition","q":"According to the Arrhenius definition, a base is a substance that produces which ion in water?","o":["Hydroxide ion, OH⁻","Hydrogen ion, H⁺","Oxide ion, O²⁻","Chloride ion, Cl⁻"],"c":0,"e":"An Arrhenius base dissociates in water to release hydroxide (OH⁻) ions."},
  {"i":"chem-b3-0304","g":11,"u":"Oxygen-Containing Organic Compounds","d":"easy","t":"definition","q":"Which functional group characterizes a carboxylic acid such as the acetic acid in Ethiopian vinegar?","o":["−COOH","−OH","−CHO","−CO−"],"c":0,"e":"Carboxylic acids contain the carboxyl group −COOH; acetic acid is CH₃COOH."},
  {"i":"chem-b3-0305","g":11,"u":"Atomic Structure & Periodic Properties","d":"easy","t":"definition","q":"The full electron configuration of a neutral sodium atom (Z = 11) is:","o":["1s² 2s² 2p⁶ 3s¹","1s² 2s² 2p⁶","1s² 2s² 2p⁶ 3s²","1s² 2s² 2p⁵ 3s²"],"c":0,"e":"Eleven electrons fill as 1s² 2s² 2p⁶ 3s¹, giving one valence electron."},
  {"i":"chem-b3-0306","g":11,"u":"Atomic Structure & Periodic Properties","d":"easy","t":"conceptual","q":"Which element has the highest first ionization energy?","o":["Na","Mg","Cl","Ar"],"c":3,"e":"Ionization energy increases across a period; Ar (a noble gas with a full shell) has the highest among these."},
  {"i":"chem-b3-0307","g":11,"u":"Chemical Bonding","d":"easy","t":"definition","q":"The bond formed by the complete transfer of electrons from a metal to a non-metal is called:","o":["Covalent bond","Ionic bond","Metallic bond","Hydrogen bond"],"c":1,"e":"Electron transfer from metal to non-metal produces oppositely charged ions held by ionic bonding."},
  {"i":"chem-b3-0308","g":11,"u":"Chemical Bonding","d":"easy","t":"conceptual","q":"How many shared pairs of electrons are in a nitrogen molecule, N₂?","o":["1","2","3","4"],"c":2,"e":"N₂ has a triple bond, which consists of three shared electron pairs."},
  {"i":"chem-b3-0309","g":11,"u":"Chemical Bonding","d":"easy","t":"application","q":"What is the molecular geometry of methane, CH₄?","o":["Linear","Trigonal planar","Tetrahedral","Bent"],"c":2,"e":"Four bonding pairs around carbon with no lone pairs give a tetrahedral shape (≈109.5°)."},
  {"i":"chem-b3-0310","g":11,"u":"Chemical Bonding","d":"easy","t":"conceptual","q":"Which type of bonding accounts for the high electrical conductivity of metals?","o":["Ionic bonding","Covalent bonding","Metallic bonding","Van der Waals forces"],"c":2,"e":"Metallic bonding has a sea of delocalized electrons free to move, conducting electricity."},
  {"i":"chem-b3-0311","g":11,"u":"Chemical Bonding","d":"easy","t":"calculation","q":"The molar mass of calcium carbonate, CaCO₃, is (Ca = 40, C = 12, O = 16 g/mol):","o":["84 g/mol","100 g/mol","116 g/mol","60 g/mol"],"c":1,"e":"40 + 12 + (3 × 16) = 40 + 12 + 48 = 100 g/mol."},
  {"i":"chem-b3-0312","g":11,"u":"Physical States of Matter","d":"easy","t":"definition","q":"The direct change of a solid into a gas without passing through the liquid state is called:","o":["Condensation","Sublimation","Vaporization","Deposition"],"c":1,"e":"Sublimation is the solid-to-gas transition (e.g. solid iodine forming vapour)."},
  {"i":"chem-b3-0313","g":11,"u":"Physical States of Matter","d":"easy","t":"calculation","q":"A gas occupies 2.0 L at 1.0 atm. At constant temperature, what volume does it occupy at 4.0 atm (Boyle's law)?","o":["8.0 L","0.50 L","2.0 L","4.0 L"],"c":1,"e":"P₁V₁ = P₂V₂ → V₂ = (1.0 × 2.0)/4.0 = 0.50 L."},
  {"i":"chem-b3-0314","g":11,"u":"Physical States of Matter","d":"easy","t":"conceptual","q":"According to the kinetic molecular theory, the average kinetic energy of gas particles is directly proportional to:","o":["Pressure","Volume","Absolute temperature","Density"],"c":2,"e":"Average kinetic energy of gas particles is directly proportional to absolute (Kelvin) temperature."},
  {"i":"chem-b3-0315","g":11,"u":"Physical States of Matter","d":"easy","t":"calculation","q":"How many moles are in 8.0 g of methane gas, CH₄ (molar mass = 16 g/mol)?","o":["0.25 mol","0.50 mol","1.0 mol","2.0 mol"],"c":1,"e":"n = mass/molar mass = 8.0/16 = 0.50 mol."},
  {"i":"chem-b3-0316","g":11,"u":"Chemical Kinetics","d":"easy","t":"definition","q":"The minimum energy that colliding particles must possess for a reaction to occur is called:","o":["Bond energy","Activation energy","Kinetic energy","Lattice energy"],"c":1,"e":"Activation energy is the minimum energy needed for an effective, reactive collision."},
  {"i":"chem-b3-0317","g":11,"u":"Chemical Kinetics","d":"easy","t":"conceptual","q":"Which of the following will generally increase the rate of a chemical reaction?","o":["Lowering the temperature","Decreasing surface area","Adding a catalyst","Diluting the reactants"],"c":2,"e":"A catalyst lowers the activation energy, increasing the reaction rate."},
  {"i":"chem-b3-0318","g":11,"u":"Chemical Equilibrium","d":"easy","t":"conceptual","q":"For the equilibrium N₂(g) + 3H₂(g) ⇌ 2NH₃(g), increasing the pressure will shift the equilibrium toward:","o":["The reactants","The products","No change","Both sides equally"],"c":1,"e":"Higher pressure favours the side with fewer gas moles; products (2 mol) versus reactants (4 mol), so it shifts toward products."},
  {"i":"chem-b3-0319","g":11,"u":"Chemical Equilibrium","d":"easy","t":"calculation","q":"A solution has pH = 9 at 25 °C. What is its pOH?","o":["5","9","14","23"],"c":0,"e":"pH + pOH = 14, so pOH = 14 - 9 = 5."},
  {"i":"chem-b3-0320","g":11,"u":"Oxygen-Containing Organic Compounds","d":"easy","t":"definition","q":"Which functional group characterizes alcohols?","o":["-COOH","-CHO","-OH","-CO-"],"c":2,"e":"Alcohols contain the hydroxyl (-OH) functional group, as in ethanol CH₃CH₂OH."},
  {"i":"chem-b3-0321","g":11,"u":"Oxygen-Containing Organic Compounds","d":"easy","t":"application","q":"What is the name of the organic acid found in vinegar, with formula CH₃COOH?","o":["Methanoic acid","Ethanoic acid","Propanoic acid","Ethanol"],"c":1,"e":"CH₃COOH is ethanoic (acetic) acid, the carboxylic acid that gives vinegar its sour taste."},
  {"i":"chem-b3-0322","g":11,"u":"Atomic Structure & Periodic Properties","d":"easy","t":"application","q":"The electron configuration of a neutral magnesium atom (Z = 12) is:","o":["1s² 2s² 2p⁶ 3s²","1s² 2s² 2p⁶","1s² 2s² 2p⁶ 3s¹","1s² 2s² 2p⁴ 3s⁴"],"c":0,"e":"With 12 electrons, filling order gives 1s² 2s² 2p⁶ 3s², which sums to 12 electrons."},
  {"i":"chem-b3-0323","g":11,"u":"Chemical Bonding","d":"easy","t":"definition","q":"A chemical bond formed by the complete transfer of electrons from a metal to a non-metal is called:","o":["Covalent bond","Ionic bond","Metallic bond","Hydrogen bond"],"c":1,"e":"Ionic bonding involves electron transfer from a metal (forming a cation) to a non-metal (forming an anion)."},
  {"i":"chem-b3-0324","g":11,"u":"Chemical Bonding","d":"easy","t":"conceptual","q":"Which type of bonding explains why metals conduct electricity?","o":["Ionic bonding","Covalent bonding","Metallic bonding","Hydrogen bonding"],"c":2,"e":"In metallic bonding, delocalized 'sea' electrons move freely and carry electric current."},
  {"i":"chem-b3-0325","g":11,"u":"Chemical Bonding","d":"easy","t":"conceptual","q":"Which molecule is non-polar despite containing polar bonds?","o":["H₂O","NH₃","CO₂","HCl"],"c":2,"e":"CO₂ is linear and symmetric, so the two bond dipoles cancel, giving a non-polar molecule."},
  {"i":"chem-b3-0326","g":11,"u":"Physical States of Matter","d":"easy","t":"calculation","q":"A gas occupies 4 L at 2 atm. At constant temperature, what volume will it occupy at 1 atm (Boyle's law)?","o":["2 L","4 L","8 L","1 L"],"c":2,"e":"By Boyle's law P₁V₁ = P₂V₂: (2)(4) = (1)V₂, so V₂ = 8 L."},
  {"i":"chem-b3-0327","g":11,"u":"Physical States of Matter","d":"easy","t":"conceptual","q":"Which state of matter has a definite volume but no definite shape?","o":["Solid","Liquid","Gas","Plasma"],"c":1,"e":"A liquid keeps a fixed volume but takes the shape of its container, unlike a solid (fixed shape) or gas (neither)."},
  {"i":"chem-b3-0328","g":11,"u":"Chemical Kinetics","d":"easy","t":"conceptual","q":"Increasing the temperature of a reaction generally increases its rate mainly because:","o":["Molecules collide more frequently and with more energy","Activation energy increases","The number of molecules decreases","Bonds become stronger"],"c":0,"e":"Higher temperature raises molecular kinetic energy, increasing both collision frequency and the fraction of collisions exceeding the activation energy."},
  {"i":"chem-b3-0329","g":11,"u":"Chemical Kinetics","d":"easy","t":"conceptual","q":"For a solid reactant, which change increases the reaction rate?","o":["Using larger lumps","Grinding it into a fine powder","Cooling the mixture","Reducing reactant concentration"],"c":1,"e":"Powdering increases surface area, exposing more particles to collisions and raising the rate."},
  {"i":"chem-b3-0330","g":11,"u":"Chemical Equilibrium","d":"easy","t":"definition","q":"At chemical equilibrium, the rates of the forward and reverse reactions are:","o":["Equal","Zero","Forward is greater","Reverse is greater"],"c":0,"e":"Dynamic equilibrium occurs when forward and reverse reaction rates are equal, so concentrations stay constant."},
  {"i":"chem-b3-0331","g":11,"u":"Chemical Equilibrium","d":"easy","t":"application","q":"For the reaction N₂(g) + 3H₂(g) ⇌ 2NH₃(g), the equilibrium constant expression Kc is:","o":["[NH₃]² / ([N₂][H₂]³)","[N₂][H₂]³ / [NH₃]²","[NH₃] / ([N₂][H₂])","[N₂][H₂] / [NH₃]"],"c":0,"e":"Kc = products over reactants, each raised to its coefficient: [NH₃]² / ([N₂][H₂]³)."},
  {"i":"chem-b3-0332","g":11,"u":"Chemical Equilibrium","d":"easy","t":"conceptual","q":"For an exothermic reaction at equilibrium, increasing the temperature shifts the equilibrium:","o":["Toward the products","Toward the reactants","No shift occurs","Toward both sides equally"],"c":1,"e":"By Le Chatelier's principle, adding heat to an exothermic reaction shifts equilibrium toward the reactants (the heat-absorbing direction)."},
  {"i":"chem-b3-0333","g":11,"u":"Oxygen-Containing Organic Compounds","d":"easy","t":"application","q":"Which functional group characterizes alcohols such as the ethanol used in Ethiopian distilled drinks?","o":["-COOH","-OH","-CHO","-O-"],"c":1,"e":"Alcohols contain the hydroxyl group (-OH); ethanol is CH₃CH₂OH."},
  {"i":"chem-b3-0334","g":11,"u":"Atomic Structure & Periodic Properties","d":"easy","t":"calculation","q":"A neutral atom has 17 protons and 18 neutrons. How many electrons does it contain?","o":["17","18","35","1"],"c":0,"e":"A neutral atom has equal protons and electrons, so the number of electrons equals the proton number, 17. The mass number (35) is protons plus neutrons."},
  {"i":"chem-b3-0335","g":11,"u":"Atomic Structure & Periodic Properties","d":"easy","t":"conceptual","q":"Across a period from left to right in the periodic table, the atomic radius generally:","o":["Increases","Decreases","Stays constant","First increases then doubles"],"c":1,"e":"Across a period the nuclear charge increases while electrons enter the same shell, so the stronger pull shrinks the atom and the atomic radius decreases."},
  {"i":"chem-b3-0336","g":11,"u":"Chemical Bonding","d":"easy","t":"definition","q":"An ionic bond is best described as the force that results from:","o":["Sharing of electron pairs between two atoms","Transfer of electrons forming oppositely charged ions","Overlap of half-filled p orbitals only","A sea of delocalized electrons among metal cations"],"c":1,"e":"An ionic bond forms when electrons transfer from a metal to a non-metal, producing oppositely charged ions held together by electrostatic attraction. Sharing describes covalent bonding."},
  {"i":"chem-b3-0337","g":11,"u":"Physical States of Matter","d":"easy","t":"conceptual","q":"At constant temperature, increasing the pressure on a fixed amount of an ideal gas causes its volume to:","o":["Increase proportionally","Decrease","Remain unchanged","Become zero"],"c":1,"e":"By Boyle's law, at constant temperature pressure and volume are inversely proportional (PV = constant), so raising the pressure decreases the volume."},
  {"i":"chem-b3-0338","g":11,"u":"Chemical Kinetics","d":"easy","t":"conceptual","q":"Which change will generally increase the rate of a chemical reaction?","o":["Lowering the temperature","Decreasing the surface area of a solid reactant","Adding a suitable catalyst","Diluting the reactant solution"],"c":2,"e":"A catalyst provides an alternative pathway with lower activation energy, increasing reaction rate. Lowering temperature, reducing surface area, and dilution all slow the rate."},
  {"i":"chem-b3-0339","g":11,"u":"Chemical Equilibrium","d":"easy","t":"calculation","q":"An aqueous solution at 25 °C has [H⁺] = 1 × 10⁻³ mol/L. What is its pH?","o":["3","11","7","10⁻³"],"c":0,"e":"pH = −log[H⁺] = −log(1 × 10⁻³) = 3. Since pH < 7 the solution is acidic, consistent with the relatively high hydrogen-ion concentration."},
  {"i":"chem-b3-0340","g":11,"u":"Atomic Structure & Periodic Properties","d":"medium","t":"calculation","q":"An element has two isotopes: 69% with mass 63 and 31% with mass 65 (atomic mass units). What is its relative atomic mass?","o":["63.31","63.62","64.00","64.38"],"c":1,"e":"Ar = (0.69 × 63) + (0.31 × 65) = 43.47 + 20.15 = 63.62. This matches copper."},
  {"i":"chem-b3-0341","g":11,"u":"Atomic Structure & Periodic Properties","d":"medium","t":"conceptual","q":"Which electron configuration represents the element with the largest first ionization energy among these neutral atoms?","o":["1s² 2s² 2p⁶ 3s¹","1s² 2s² 2p⁶","1s² 2s² 2p⁴","1s² 2s² 2p⁶ 3s² 3p¹"],"c":1,"e":"1s² 2s² 2p⁶ is neon, a noble gas with a stable full shell, giving the highest ionization energy of the set."},
  {"i":"chem-b3-0342","g":11,"u":"Atomic Structure & Periodic Properties","d":"medium","t":"calculation","q":"How many neutrons are present in one atom of ⁵⁶Fe (atomic number 26)?","o":["26","30","56","82"],"c":1,"e":"Neutrons = mass number − atomic number = 56 − 26 = 30."},
  {"i":"chem-b3-0343","g":11,"u":"Atomic Structure & Periodic Properties","d":"medium","t":"conceptual","q":"Moving left to right across Period 3 (Na to Ar), atomic radius generally:","o":["increases due to added shells","decreases due to greater nuclear charge","stays constant","increases then decreases"],"c":1,"e":"Across a period electrons enter the same shell while nuclear charge rises, pulling electrons inward, so radius decreases."},
  {"i":"chem-b3-0344","g":11,"u":"Chemical Bonding","d":"medium","t":"calculation","q":"In the compound formed between magnesium and nitrogen, what is the correct formula based on their common ionic charges?","o":["MgN","Mg₂N₃","Mg₃N₂","MgN₂"],"c":2,"e":"Mg²⁺ and N³⁻ balance as Mg₃N₂: three (+2) = +6 and two (−3) = −6."},
  {"i":"chem-b3-0345","g":11,"u":"Chemical Bonding","d":"medium","t":"conceptual","q":"Which molecule contains a triple covalent bond?","o":["O₂","N₂","H₂O","CO₂"],"c":1,"e":"N₂ shares three electron pairs (N≡N) to satisfy the octet for each nitrogen."},
  {"i":"chem-b3-0346","g":11,"u":"Chemical Bonding","d":"medium","t":"application","q":"Which of these substances is expected to have the highest boiling point due to hydrogen bonding?","o":["CH₄","H₂S","H₂O","HCl"],"c":2,"e":"H₂O forms strong O–H···O hydrogen bonds, giving it an anomalously high boiling point versus the others."},
  {"i":"chem-b3-0347","g":11,"u":"Chemical Bonding","d":"medium","t":"conceptual","q":"The shape of a molecule with a central atom bonded to 4 atoms and no lone pairs (e.g. CH₄) is:","o":["trigonal planar","tetrahedral","bent","linear"],"c":1,"e":"Four bonding pairs repel to maximum separation giving a tetrahedral shape with 109.5° angles."},
  {"i":"chem-b3-0348","g":11,"u":"Physical States of Matter","d":"medium","t":"calculation","q":"A fixed mass of gas occupies 4.0 L at 300 K. At constant pressure, what volume does it occupy at 450 K?","o":["2.7 L","6.0 L","5.0 L","9.0 L"],"c":1,"e":"Charles's law: V₂ = V₁ × T₂/T₁ = 4.0 × 450/300 = 6.0 L."},
  {"i":"chem-b3-0349","g":11,"u":"Physical States of Matter","d":"medium","t":"calculation","q":"What volume does 0.50 mol of an ideal gas occupy at standard temperature and pressure (molar volume 22.4 L/mol)?","o":["11.2 L","22.4 L","44.8 L","5.6 L"],"c":0,"e":"V = n × 22.4 = 0.50 × 22.4 = 11.2 L at STP."},
  {"i":"chem-b3-0350","g":11,"u":"Physical States of Matter","d":"medium","t":"calculation","q":"A gas at 2.0 atm and 5.0 L is compressed at constant temperature to 2.0 L. What is the new pressure?","o":["0.8 atm","5.0 atm","4.0 atm","10 atm"],"c":1,"e":"Boyle's law: P₂ = P₁V₁/V₂ = (2.0 × 5.0)/2.0 = 5.0 atm."},
  {"i":"chem-b3-0351","g":11,"u":"Chemical Kinetics","d":"medium","t":"conceptual","q":"Increasing the temperature of a reaction speeds it up mainly because:","o":["activation energy is lowered","more molecules have energy ≥ the activation energy","the bonds become weaker permanently","concentration automatically rises"],"c":1,"e":"Higher temperature widens the Maxwell distribution so a larger fraction of collisions exceed the activation energy."},
  {"i":"chem-b3-0352","g":11,"u":"Chemical Kinetics","d":"medium","t":"application","q":"A catalyst increases reaction rate by:","o":["raising the activation energy","providing an alternative path with lower activation energy","shifting the equilibrium toward products","increasing the temperature of the system"],"c":1,"e":"A catalyst offers a lower-activation-energy pathway, speeding both directions without changing equilibrium position."},
  {"i":"chem-b3-0353","g":11,"u":"Chemical Kinetics","d":"medium","t":"conceptual","q":"For the reaction of solid CaCO₃ with acid, which change increases the rate by increasing surface area?","o":["using larger lumps","using powdered CaCO₃","cooling the acid","diluting the acid"],"c":1,"e":"Powdering exposes more solid surface for collisions with acid, increasing the reaction rate."},
  {"i":"chem-b3-0354","g":11,"u":"Chemical Equilibrium","d":"medium","t":"calculation","q":"For N₂ + 3H₂ ⇌ 2NH₃, equilibrium concentrations are [N₂]=1.0, [H₂]=2.0 and [NH₃]=4.0 mol/L. What is Kc?","o":["2.0","8.0","16","0.5"],"c":0,"e":"Kc = [NH₃]²/([N₂][H₂]³) = 16/(1.0 × 8.0) = 2.0."},
  {"i":"chem-b3-0355","g":11,"u":"Chemical Equilibrium","d":"medium","t":"application","q":"For the exothermic reaction 2SO₂ + O₂ ⇌ 2SO₃, increasing temperature will:","o":["shift equilibrium toward SO₃","shift equilibrium toward SO₂ and O₂","not affect the position","increase Kc"],"c":1,"e":"By Le Chatelier's principle, raising temperature favors the endothermic (reverse) direction, shifting toward reactants."},
  {"i":"chem-b3-0356","g":11,"u":"Chemical Equilibrium","d":"medium","t":"calculation","q":"A 0.010 mol/L solution of a strong monoprotic acid (fully ionized) has what pH?","o":["1.0","2.0","3.0","10.0"],"c":1,"e":"[H⁺] = 0.010 = 1×10⁻² mol/L, so pH = −log(10⁻²) = 2.0."},
  {"i":"chem-b3-0357","g":11,"u":"Chemical Equilibrium","d":"medium","t":"calculation","q":"A solution has [OH⁻] = 1×10⁻⁴ mol/L at 25°C. What is its pH?","o":["4.0","7.0","10.0","14.0"],"c":2,"e":"pOH = −log(10⁻⁴) = 4, so pH = 14 − 4 = 10."},
  {"i":"chem-b3-0358","g":11,"u":"Chemical Equilibrium","d":"medium","t":"application","q":"Adding a catalyst to a system at equilibrium will:","o":["shift it toward products","shift it toward reactants","increase the value of Kc","leave the equilibrium position unchanged"],"c":3,"e":"A catalyst speeds forward and reverse rates equally, so it does not shift the position or change Kc."},
  {"i":"chem-b3-0359","g":11,"u":"Oxygen-Containing Organic Compounds","d":"medium","t":"conceptual","q":"Which functional group characterizes a carboxylic acid?","o":["−OH only","−CHO","−COOH","−CO−"],"c":2,"e":"Carboxylic acids contain the carboxyl group −COOH (a carbonyl bonded to a hydroxyl)."},
  {"i":"chem-b3-0360","g":11,"u":"Oxygen-Containing Organic Compounds","d":"medium","t":"application","q":"Mild oxidation of ethanol (a primary alcohol) first produces:","o":["ethane","ethanoic acid directly","ethanal (an aldehyde)","ethene"],"c":2,"e":"Primary alcohols oxidize first to an aldehyde (ethanal), which can further oxidize to ethanoic acid."},
  {"i":"chem-b3-0361","g":11,"u":"Oxygen-Containing Organic Compounds","d":"medium","t":"calculation","q":"What is the molar mass of ethanol, C₂H₅OH (H=1, C=12, O=16)?","o":["44 g/mol","46 g/mol","48 g/mol","60 g/mol"],"c":1,"e":"C₂H₅OH = 2(12) + 6(1) + 16 = 24 + 6 + 16 = 46 g/mol."},
  {"i":"chem-b3-0362","g":11,"u":"Atomic Structure & Periodic Properties","d":"medium","t":"calculation","q":"Chlorine has two isotopes, ³⁵Cl (mass 35, abundance 75%) and ³⁷Cl (mass 37, abundance 25%). What is the relative atomic mass of chlorine?","o":["35.5","36.0","35.0","36.5"],"c":0,"e":"Average mass = (35×0.75) + (37×0.25) = 26.25 + 9.25 = 35.5."},
  {"i":"chem-b3-0363","g":11,"u":"Atomic Structure & Periodic Properties","d":"medium","t":"conceptual","q":"An element has the ground-state electron configuration 1s² 2s² 2p⁶ 3s² 3p³. In which group and period of the periodic table is it located?","o":["Group VA (15), Period 3","Group IIIA (13), Period 3","Group VA (15), Period 2","Group VIIA (17), Period 3"],"c":0,"e":"The highest principal quantum number is 3 (Period 3); the outer shell has 5 electrons (3s²3p³), placing it in Group VA (15). This is phosphorus."},
  {"i":"chem-b3-0364","g":11,"u":"Atomic Structure & Periodic Properties","d":"medium","t":"conceptual","q":"Which of the following correctly lists Na, Mg, Al and Si in order of increasing atomic radius?","o":["Si < Al < Mg < Na","Na < Mg < Al < Si","Si < Mg < Al < Na","Al < Si < Mg < Na"],"c":0,"e":"Across a period, atomic radius decreases as nuclear charge rises. From left to right Na > Mg > Al > Si, so increasing order is Si < Al < Mg < Na."},
  {"i":"chem-b3-0365","g":11,"u":"Atomic Structure & Periodic Properties","d":"medium","t":"calculation","q":"How many neutrons are present in one ion of ⁵⁶Fe³⁺ (atomic number 26)?","o":["30","26","23","56"],"c":0,"e":"Neutrons = mass number − atomic number = 56 − 26 = 30. Forming the 3+ ion removes electrons, not neutrons."},
  {"i":"chem-b3-0366","g":11,"u":"Chemical Bonding","d":"medium","t":"conceptual","q":"Which molecule has a trigonal pyramidal shape according to VSEPR theory?","o":["NH₃","BF₃","CH₄","CO₂"],"c":0,"e":"NH₃ has 3 bonding pairs and 1 lone pair on nitrogen, giving a trigonal pyramidal shape. BF₃ is trigonal planar, CH₄ tetrahedral, CO₂ linear."},
  {"i":"chem-b3-0367","g":11,"u":"Chemical Bonding","d":"medium","t":"calculation","q":"Using electronegativities (Na 0.9, Cl 3.0, H 2.1, O 3.5), which bond is the most polar?","o":["Na–Cl","H–O","H–Cl","O–Cl"],"c":0,"e":"Polarity rises with electronegativity difference: Na–Cl = 2.1, H–O = 1.4, H–Cl = 0.9, O–Cl = 0.5. Na–Cl is most polar (in fact largely ionic)."},
  {"i":"chem-b3-0368","g":11,"u":"Chemical Bonding","d":"medium","t":"conceptual","q":"Why does water (H₂O, molar mass 18) have a much higher boiling point than hydrogen sulfide (H₂S, molar mass 34)?","o":["Water forms hydrogen bonds while H₂S does not","H₂S has a lower molar mass","Water is a nonpolar molecule","H₂S has stronger London forces"],"c":0,"e":"Oxygen is small and highly electronegative, so water forms strong hydrogen bonds; sulfur is too large and not electronegative enough, so H₂S has only weak dipole/London forces and boils lower despite greater mass."},
  {"i":"chem-b3-0369","g":11,"u":"Chemical Bonding","d":"medium","t":"conceptual","q":"How many sigma (σ) and pi (π) bonds are present in a molecule of ethyne (C₂H₂, H–C≡C–H)?","o":["3 σ and 2 π","2 σ and 3 π","5 σ and 0 π","4 σ and 1 π"],"c":0,"e":"Two C–H single bonds (2 σ) plus the triple bond between carbons (1 σ + 2 π) gives 3 σ and 2 π bonds total."},
  {"i":"chem-b3-0370","g":11,"u":"Physical States of Matter","d":"medium","t":"calculation","q":"A fixed mass of gas occupies 250 mL at 27 °C. At what temperature (constant pressure) will it occupy 500 mL?","o":["327 °C","54 °C","600 °C","150 °C"],"c":0,"e":"Charles's law: V₁/T₁ = V₂/T₂. T₁ = 300 K, so T₂ = 300 × (500/250) = 600 K = 327 °C."},
  {"i":"chem-b3-0371","g":11,"u":"Physical States of Matter","d":"medium","t":"calculation","q":"What is the volume occupied by 0.50 mol of an ideal gas at STP (0 °C, 1 atm)?","o":["11.2 L","22.4 L","5.6 L","44.8 L"],"c":0,"e":"At STP one mole occupies 22.4 L, so 0.50 mol occupies 0.50 × 22.4 = 11.2 L."},
  {"i":"chem-b3-0372","g":11,"u":"Physical States of Matter","d":"medium","t":"calculation","q":"A gas exerts a pressure of 760 mmHg in a 2.0 L container. If the volume is reduced to 0.50 L at constant temperature, what is the new pressure?","o":["3040 mmHg","190 mmHg","1520 mmHg","380 mmHg"],"c":0,"e":"Boyle's law: P₁V₁ = P₂V₂. P₂ = (760 × 2.0)/0.50 = 3040 mmHg."},
  {"i":"chem-b3-0373","g":11,"u":"Physical States of Matter","d":"medium","t":"conceptual","q":"According to the kinetic molecular theory, what happens to the average kinetic energy of gas molecules when the absolute temperature of the gas is doubled?","o":["It doubles","It is halved","It quadruples","It stays the same"],"c":0,"e":"Average kinetic energy is directly proportional to absolute (Kelvin) temperature, so doubling T doubles the average kinetic energy."},
  {"i":"chem-b3-0374","g":11,"u":"Chemical Kinetics","d":"medium","t":"conceptual","q":"Which of the following will NOT increase the rate of a reaction between solid CaCO₃ and dilute HCl?","o":["Decreasing the temperature","Increasing the acid concentration","Powdering the CaCO₃","Adding a suitable catalyst"],"c":0,"e":"Lowering temperature slows molecular motion and reduces collision frequency and energy, decreasing the rate. The other three increase rate."},
  {"i":"chem-b3-0375","g":11,"u":"Chemical Kinetics","d":"medium","t":"calculation","q":"The rate of a reaction doubles for every 10 °C rise in temperature. By what factor does the rate increase when the temperature rises from 20 °C to 50 °C?","o":["8","6","3","16"],"c":0,"e":"A 30 °C rise is three 10 °C steps, so the rate increases by 2³ = 8 times."},
  {"i":"chem-b3-0376","g":11,"u":"Chemical Kinetics","d":"medium","t":"conceptual","q":"How does a catalyst increase the rate of a chemical reaction?","o":["It lowers the activation energy by providing an alternative pathway","It increases the activation energy of the reaction","It shifts the position of equilibrium toward products","It raises the temperature of the reaction mixture"],"c":0,"e":"A catalyst provides an alternative reaction pathway with lower activation energy, so a larger fraction of collisions are effective, speeding both forward and reverse rates equally."},
  {"i":"chem-b3-0377","g":11,"u":"Chemical Equilibrium","d":"medium","t":"application","q":"For the equilibrium N₂(g) + 3H₂(g) ⇌ 2NH₃(g), ΔH = −92 kJ/mol. Which change increases the yield of ammonia?","o":["Increasing pressure and decreasing temperature","Decreasing pressure and increasing temperature","Increasing temperature only","Removing N₂ from the system"],"c":0,"e":"The forward reaction is exothermic and reduces moles of gas (4 → 2). By Le Chatelier, high pressure and low temperature both shift the equilibrium toward NH₃."},
  {"i":"chem-b3-0378","g":11,"u":"Chemical Equilibrium","d":"medium","t":"calculation","q":"At equilibrium, [H₂] = 0.20 M, [I₂] = 0.20 M and [HI] = 1.6 M for H₂(g) + I₂(g) ⇌ 2HI(g). What is Kc?","o":["64","6.4","16","0.016"],"c":0,"e":"Kc = [HI]² / ([H₂][I₂]) = (1.6)² / (0.20 × 0.20) = 2.56 / 0.04 = 64."},
  {"i":"chem-b3-0379","g":11,"u":"Chemical Equilibrium","d":"medium","t":"calculation","q":"A 0.0010 M solution of a strong monoprotic acid is prepared. What is the pH of the solution?","o":["3","4","2","11"],"c":0,"e":"A strong acid fully dissociates, so [H⁺] = 1.0 × 10⁻³ M and pH = −log(10⁻³) = 3."},
  {"i":"chem-b3-0380","g":11,"u":"Chemical Equilibrium","d":"medium","t":"calculation","q":"A weak acid HA has Ka = 1.0 × 10⁻⁵ and an initial concentration of 0.10 M. Using the approximation, what is the pH of the solution?","o":["3","5","1","2"],"c":0,"e":"[H⁺] ≈ √(Ka × C) = √(1.0×10⁻⁵ × 0.10) = √(1.0×10⁻⁶) = 1.0×10⁻³ M, so pH = 3."},
  {"i":"chem-b3-0381","g":11,"u":"Chemical Equilibrium","d":"medium","t":"calculation","q":"What is the pOH of a solution whose hydroxide ion concentration is 1.0 × 10⁻⁴ M at 25 °C?","o":["4","10","6","8"],"c":0,"e":"pOH = −log[OH⁻] = −log(1.0×10⁻⁴) = 4."},
  {"i":"chem-b3-0382","g":11,"u":"Oxygen-Containing Organic Compounds","d":"medium","t":"calculation","q":"A saturated alcohol contains one –OH group and has the molecular formula CₙH₂ₙ₊₂O. If its molar mass is 46 g/mol, what is its molecular formula? (C=12, H=1, O=16)","o":["C₂H₆O","CH₄O","C₃H₈O","C₂H₄O"],"c":0,"e":"For C₂H₆O: (2×12) + (6×1) + 16 = 24 + 6 + 16 = 46 g/mol. This is ethanol."},
  {"i":"chem-b3-0383","g":11,"u":"Oxygen-Containing Organic Compounds","d":"medium","t":"conceptual","q":"What is the organic product formed when ethanol is mildly oxidized (e.g. with acidified K₂Cr₂O₇) under controlled conditions?","o":["Ethanal (acetaldehyde)","Ethane","Ethene","Ethyl ethanoate"],"c":0,"e":"Mild, controlled oxidation of a primary alcohol gives an aldehyde; ethanol → ethanal (CH₃CHO). Further oxidation would give ethanoic acid."},
  {"i":"chem-b3-0384","g":11,"u":"Oxygen-Containing Organic Compounds","d":"medium","t":"application","q":"Ethanoic acid reacts with ethanol in the presence of concentrated H₂SO₄. What type of reaction occurs and what class of product forms?","o":["Esterification, forming an ester","Saponification, forming a soap","Neutralization, forming a salt","Hydrogenation, forming an alkane"],"c":0,"e":"A carboxylic acid plus an alcohol with an acid catalyst undergoes esterification (a condensation), producing an ester (ethyl ethanoate) and water."},
  {"i":"chem-b3-0385","g":11,"u":"Atomic Structure & Periodic Properties","d":"medium","t":"calculation","q":"An element has two isotopes: ⁶³Cu (mass 62.93 u, 69.2%) and ⁶⁵Cu (mass 64.93 u, 30.8%). What is the relative atomic mass of copper?","o":["63.55 u","63.93 u","64.31 u","62.93 u"],"c":0,"e":"Ar = (62.93×0.692) + (64.93×0.308) = 43.55 + 20.00 = 63.55 u."},
  {"i":"chem-b3-0386","g":11,"u":"Atomic Structure & Periodic Properties","d":"medium","t":"conceptual","q":"The ground-state electron configuration of an element ends in 3d⁵4s¹. To which group and period of the periodic table does this element (chromium) belong?","o":["Group 6, Period 4","Group 1, Period 4","Group 5, Period 3","Group 6, Period 3"],"c":0,"e":"Total d plus s electrons = 5+1 = 6, placing it in Group 6; the highest principal quantum number is n=4, so Period 4."},
  {"i":"chem-b3-0387","g":11,"u":"Atomic Structure & Periodic Properties","d":"medium","t":"conceptual","q":"Across Period 3 from Na to Cl, atomic radius decreases. The main reason is that:","o":["nuclear charge increases while electrons add to the same shell","the number of occupied shells decreases","electron shielding increases sharply","electrons are removed from the atom"],"c":0,"e":"Moving left to right, protons are added and electrons fill the same outer shell; the rising effective nuclear charge pulls electrons inward, shrinking the radius."},
  {"i":"chem-b3-0388","g":11,"u":"Atomic Structure & Periodic Properties","d":"medium","t":"calculation","q":"How many moles of atoms are present in 5.85 g of pure sodium chloride? (Na = 23, Cl = 35.5 g/mol)","o":["0.20 mol","0.10 mol","0.05 mol","0.40 mol"],"c":0,"e":"Molar mass NaCl = 58.5 g/mol; moles of NaCl = 5.85/58.5 = 0.10 mol; each formula unit has 2 atoms, so 0.20 mol of atoms."},
  {"i":"chem-b3-0389","g":11,"u":"Chemical Bonding","d":"medium","t":"conceptual","q":"In the ammonium ion NH₄⁺, all four N–H bonds are identical even though one forms differently. The bond formed by nitrogen donating both shared electrons is called a:","o":["coordinate (dative) covalent bond","nonpolar covalent bond","ionic bond","metallic bond"],"c":0,"e":"Nitrogen's lone pair is donated to H⁺, forming a coordinate (dative) covalent bond; once formed it is indistinguishable from the other N–H bonds."},
  {"i":"chem-b3-0390","g":11,"u":"Chemical Bonding","d":"medium","t":"application","q":"Using VSEPR theory, what is the molecular geometry of a water molecule, which has two bonding pairs and two lone pairs on the central oxygen?","o":["Bent (angular)","Linear","Trigonal planar","Tetrahedral"],"c":0,"e":"Four electron domains give a tetrahedral arrangement, but with two lone pairs the shape of the atoms is bent, with an angle near 104.5°."},
  {"i":"chem-b3-0391","g":11,"u":"Chemical Bonding","d":"medium","t":"conceptual","q":"Which of the following molecules is nonpolar despite containing polar bonds?","o":["CO₂","H₂O","NH₃","HCl"],"c":0,"e":"In CO₂ the two C=O bond dipoles point in opposite directions along a linear molecule and cancel, giving zero net dipole, unlike the bent or asymmetric others."},
  {"i":"chem-b3-0392","g":11,"u":"Chemical Bonding","d":"medium","t":"conceptual","q":"Solid potassium iodide does not conduct electricity, but molten potassium iodide does. This is best explained because in the molten state:","o":["ions become mobile and free to carry charge","covalent bonds break into atoms","delocalised electrons are released","the compound decomposes into K and I₂"],"c":0,"e":"Ionic conduction requires mobile charge carriers; in the solid the ions are locked in the lattice, but melting frees the K⁺ and I⁻ ions to move."},
  {"i":"chem-b3-0393","g":11,"u":"Physical States of Matter","d":"medium","t":"calculation","q":"A fixed mass of gas occupies 250 mL at 27 °C. At constant pressure, what volume will it occupy at 127 °C?","o":["333 mL","187 mL","1176 mL","275 mL"],"c":0,"e":"By Charles's law, V₂ = V₁×T₂/T₁ = 250×(400/300) = 333 mL (temperatures in kelvin: 300 K and 400 K)."},
  {"i":"chem-b3-0394","g":11,"u":"Physical States of Matter","d":"medium","t":"conceptual","q":"According to the kinetic molecular theory, when the temperature of a gas is raised at constant volume, the pressure increases mainly because:","o":["molecules move faster and collide with the walls more frequently and forcefully","the molecules expand in size","the number of gas molecules increases","intermolecular forces become stronger"],"c":0,"e":"Higher temperature raises the average kinetic energy, so molecules strike the container walls more often and harder, increasing pressure at fixed volume."},
  {"i":"chem-b3-0395","g":11,"u":"Chemical Kinetics","d":"medium","t":"conceptual","q":"Adding a catalyst speeds up a reaction primarily because it:","o":["provides an alternative pathway with lower activation energy","increases the enthalpy change of the reaction","raises the temperature of the reactants","increases the concentration of reactants"],"c":0,"e":"A catalyst lowers the activation energy by offering a different mechanism, so a larger fraction of collisions are effective; it does not change ΔH."},
  {"i":"chem-b3-0396","g":11,"u":"Chemical Kinetics","d":"medium","t":"calculation","q":"For a reaction the rate law is rate = k[A][B]². If the concentration of B is tripled while [A] is held constant, by what factor does the rate change?","o":["9","3","6","27"],"c":0,"e":"Rate depends on [B]², so tripling B multiplies the rate by 3² = 9."},
  {"i":"chem-b3-0397","g":11,"u":"Chemical Kinetics","d":"medium","t":"conceptual","q":"Which change would NOT increase the rate of reaction between solid calcium carbonate and dilute hydrochloric acid?","o":["Adding more acid of the same concentration","Grinding the calcium carbonate into a powder","Increasing the concentration of the acid","Warming the reaction mixture"],"c":0,"e":"Rate depends on concentration, surface area and temperature; adding more acid of the same concentration does not change the collision frequency per unit volume, so the rate is unchanged."},
  {"i":"chem-b3-0398","g":11,"u":"Chemical Equilibrium","d":"medium","t":"calculation","q":"For the equilibrium N₂(g) + 3H₂(g) ⇌ 2NH₃(g), equilibrium concentrations are [N₂] = 0.20 M, [H₂] = 0.20 M, [NH₃] = 0.40 M. What is Kc?","o":["100","20","0.40","50"],"c":0,"e":"Kc = [NH₃]²/([N₂][H₂]³) = (0.40)²/(0.20×0.20³) = 0.16/(0.20×0.008) = 0.16/0.0016 = 100."},
  {"i":"chem-b3-0399","g":11,"u":"Chemical Equilibrium","d":"medium","t":"application","q":"For the exothermic reaction 2SO₂(g) + O₂(g) ⇌ 2SO₃(g), which change shifts the equilibrium toward more SO₃?","o":["Increasing the pressure on the system","Increasing the temperature","Adding a catalyst","Removing some O₂"],"c":0,"e":"The forward side has fewer gas moles (3 → 2), so higher pressure shifts equilibrium right toward SO₃; raising T favours the endothermic reverse, and a catalyst only changes rate."},
  {"i":"chem-b3-0400","g":11,"u":"Chemical Equilibrium","d":"medium","t":"calculation","q":"A 0.0010 M solution of a strong monoprotic acid is fully ionized. What is the pH of the solution?","o":["3","4","2","11"],"c":0,"e":"A strong acid gives [H⁺] = 0.0010 = 1×10⁻³ M, so pH = −log(10⁻³) = 3."},
  {"i":"chem-b3-0401","g":11,"u":"Chemical Equilibrium","d":"medium","t":"calculation","q":"A weak acid HA has Ka = 1.0×10⁻⁵ and an initial concentration of 0.10 M. Using the approximation [H⁺] = √(Ka·C), what is the pH?","o":["3","5","4","2"],"c":0,"e":"[H⁺] = √(1.0×10⁻⁵ × 0.10) = √(1.0×10⁻⁶) = 1.0×10⁻³ M, so pH = 3."},
  {"i":"chem-b3-0402","g":11,"u":"Chemical Equilibrium","d":"medium","t":"calculation","q":"At 25 °C a solution has pOH = 9. What is its hydrogen-ion concentration [H⁺]?","o":["1×10⁻⁵ M","1×10⁻⁹ M","1×10⁻¹⁴ M","1×10⁻⁷ M"],"c":0,"e":"pH = 14 − pOH = 14 − 9 = 5, so [H⁺] = 1×10⁻⁵ M."},
  {"i":"chem-b3-0403","g":11,"u":"Oxygen-Containing Organic Compounds","d":"medium","t":"conceptual","q":"Which functional group is characteristic of a carboxylic acid such as ethanoic acid (the acid in Ethiopian vinegar)?","o":["–COOH","–OH only","–CHO","–CO– between two carbons"],"c":0,"e":"Carboxylic acids contain the carboxyl group –COOH, a hydroxyl bonded to a carbonyl carbon; ethanoic acid is CH₃COOH."},
  {"i":"chem-b3-0404","g":11,"u":"Oxygen-Containing Organic Compounds","d":"medium","t":"application","q":"Controlled oxidation of ethanol first gives which class of compound, linked to the sharp odour when 'tella' spoils toward vinegar?","o":["An aldehyde (ethanal), later a carboxylic acid","An ester directly","A ketone","An ether"],"c":0,"e":"A primary alcohol like ethanol oxidizes first to the aldehyde ethanal (CH₃CHO) and on further oxidation to ethanoic acid; ketones come only from secondary alcohols."},
  {"i":"chem-b3-0405","g":11,"u":"Oxygen-Containing Organic Compounds","d":"medium","t":"application","q":"Ethanoic acid reacts with ethanol in the presence of concentrated H₂SO₄ to form a sweet-smelling product. This reaction and product are:","o":["esterification forming ethyl ethanoate","neutralization forming a salt","oxidation forming an aldehyde","addition forming an alkene"],"c":0,"e":"A carboxylic acid plus an alcohol with an acid catalyst undergoes esterification, producing an ester (ethyl ethanoate) and water."},
  {"i":"chem-b3-0406","g":11,"u":"Atomic Structure & Periodic Properties","d":"medium","t":"calculation","q":"An element has two isotopes: one of mass 63 (69.0%) and one of mass 65 (31.0%). What is its relative atomic mass?","o":["63.31","63.62","64.00","64.38"],"c":1,"e":"Ar = (63×0.690)+(65×0.310) = 43.47+20.15 = 63.62. This identifies the element as copper."},
  {"i":"chem-b3-0407","g":11,"u":"Atomic Structure & Periodic Properties","d":"medium","t":"conceptual","q":"The electron configuration of a neutral atom is 1s² 2s² 2p⁶ 3s² 3p⁶ 4s² 3d⁵. To which period and group does it belong?","o":["Period 4, Group VB","Period 4, Group VIIB","Period 3, Group VB","Period 4, Group IIA"],"c":1,"e":"With 4s²3d⁵ the highest n is 4 (Period 4) and the d-block count places it in Group VIIB. This is manganese, Z=25."},
  {"i":"chem-b3-0408","g":11,"u":"Atomic Structure & Periodic Properties","d":"medium","t":"conceptual","q":"Across Period 3 from Na to Cl, which trend is correct as atomic number increases?","o":["Atomic radius increases, electronegativity decreases","Atomic radius decreases, electronegativity increases","Both atomic radius and ionization energy decrease","First ionization energy decreases steadily"],"c":1,"e":"Across a period nuclear charge rises while shielding is nearly constant, so atomic radius decreases and electronegativity (and ionization energy) generally increases."},
  {"i":"chem-b3-0409","g":11,"u":"Atomic Structure & Periodic Properties","d":"medium","t":"calculation","q":"How many protons, electrons and neutrons are present in the ion ⁵⁶Fe²⁺ (Z = 26)?","o":["26 p, 24 e, 30 n","26 p, 28 e, 30 n","24 p, 24 e, 32 n","26 p, 24 e, 26 n"],"c":0,"e":"Protons = Z = 26; neutrons = 56−26 = 30; the 2+ charge means 2 electrons lost, so electrons = 26−2 = 24."},
  {"i":"chem-b3-0410","g":11,"u":"Chemical Bonding","d":"medium","t":"conceptual","q":"Which molecule is non-polar overall even though it contains polar bonds?","o":["H₂O","NH₃","CO₂","HCl"],"c":2,"e":"CO₂ is linear (O=C=O); the two equal bond dipoles point in opposite directions and cancel to a net dipole of zero, unlike bent H₂O or pyramidal NH₃."},
  {"i":"chem-b3-0411","g":11,"u":"Chemical Bonding","d":"medium","t":"application","q":"Using VSEPR, what is the molecular shape of NH₃, which has three bonding pairs and one lone pair on nitrogen?","o":["Trigonal planar","Tetrahedral","Trigonal pyramidal","Bent"],"c":2,"e":"Four electron domains give a tetrahedral arrangement, but one is a lone pair, so the shape of the atoms is trigonal pyramidal with bond angles near 107°."},
  {"i":"chem-b3-0412","g":11,"u":"Chemical Bonding","d":"medium","t":"conceptual","q":"Which substance is expected to have the highest boiling point because of hydrogen bonding?","o":["CH₄","H₂S","HF","Cl₂"],"c":2,"e":"HF has H bonded directly to highly electronegative F, allowing strong hydrogen bonding; CH₄, H₂S and Cl₂ rely only on weaker dispersion (and dipole) forces."},
  {"i":"chem-b3-0413","g":11,"u":"Chemical Bonding","d":"medium","t":"calculation","q":"In which species does sulfur exhibit an oxidation number of +6?","o":["H₂S","SO₂","SO₄²⁻","S₈"],"c":2,"e":"In SO₄²⁻: 4(−2)+S = −2, so S = +6. H₂S gives −2, SO₂ gives +4, and elemental S₈ is 0."},
  {"i":"chem-b3-0414","g":11,"u":"Physical States of Matter","d":"medium","t":"calculation","q":"A gas occupies 4.0 L at 27 °C and 1.0 atm. What volume does it occupy at 127 °C and the same pressure?","o":["2.7 L","4.0 L","5.3 L","18.8 L"],"c":2,"e":"By Charles's law V₂ = V₁(T₂/T₁) = 4.0×(400/300) = 5.33 L, using absolute temperatures 300 K and 400 K."},
  {"i":"chem-b3-0415","g":11,"u":"Physical States of Matter","d":"medium","t":"calculation","q":"What is the volume of 8.8 g of CO₂ gas at STP (molar volume 22.4 L/mol, M = 44 g/mol)?","o":["2.24 L","4.48 L","8.96 L","22.4 L"],"c":1,"e":"Moles = 8.8/44 = 0.20 mol; volume = 0.20×22.4 = 4.48 L."},
  {"i":"chem-b3-0416","g":11,"u":"Physical States of Matter","d":"medium","t":"calculation","q":"Using PV = nRT, what pressure (atm) is exerted by 0.50 mol of an ideal gas in a 2.0 L vessel at 273 K? (R = 0.0821 L·atm/mol·K)","o":["2.8 atm","5.6 atm","11.2 atm","0.56 atm"],"c":1,"e":"P = nRT/V = (0.50×0.0821×273)/2.0 = 11.21/2.0 = 5.6 atm."},
  {"i":"chem-b3-0417","g":11,"u":"Chemical Kinetics","d":"medium","t":"conceptual","q":"Which change will NOT increase the rate of reaction between solid CaCO₃ and dilute HCl?","o":["Grinding the CaCO₃ into a powder","Increasing the HCl concentration","Raising the temperature","Adding water to dilute the acid"],"c":3,"e":"Diluting the acid lowers reactant concentration and collision frequency, decreasing the rate; the other three each increase effective collisions."},
  {"i":"chem-b3-0418","g":11,"u":"Chemical Kinetics","d":"medium","t":"calculation","q":"For a reaction rate = k[A][B]², if [A] is doubled and [B] is tripled, by what factor does the rate change?","o":["×6","×12","×18","×9"],"c":2,"e":"Rate ∝ [A]¹[B]²; doubling A gives ×2 and tripling B gives ×3² = 9, so total = 2×9 = 18."},
  {"i":"chem-b3-0419","g":11,"u":"Chemical Equilibrium","d":"medium","t":"calculation","q":"For N₂O₄(g) ⇌ 2NO₂(g), equilibrium concentrations are [N₂O₄] = 0.40 M and [NO₂] = 0.20 M. What is Kc?","o":["0.050","0.10","0.80","0.20"],"c":1,"e":"Kc = [NO₂]²/[N₂O₄] = (0.20)²/0.40 = 0.040/0.40 = 0.10."},
  {"i":"chem-b3-0420","g":11,"u":"Chemical Equilibrium","d":"medium","t":"calculation","q":"A 0.0100 M solution of a weak acid HA has [H⁺] = 1.0×10⁻⁴ M. What is its Ka?","o":["1.0×10⁻⁴","1.0×10⁻⁶","1.0×10⁻⁸","1.0×10⁻²"],"c":1,"e":"Ka = [H⁺][A⁻]/[HA] ≈ (1.0×10⁻⁴)²/0.0100 = 1.0×10⁻⁸/1.0×10⁻² = 1.0×10⁻⁶."},
  {"i":"chem-b3-0421","g":11,"u":"Chemical Equilibrium","d":"medium","t":"calculation","q":"What is the pH of a 0.0010 M solution of the strong base NaOH at 25 °C?","o":["3.0","11.0","10.0","12.0"],"c":1,"e":"[OH⁻] = 1.0×10⁻³, so pOH = 3.0; pH = 14.0 − 3.0 = 11.0."},
  {"i":"chem-b3-0422","g":11,"u":"Chemical Equilibrium","d":"medium","t":"calculation","q":"In a galvanic cell, given E°(Cu²⁺/Cu) = +0.34 V and E°(Zn²⁺/Zn) = −0.76 V, what is the standard cell potential?","o":["+0.42 V","−0.42 V","+1.10 V","−1.10 V"],"c":2,"e":"E°cell = E°cathode − E°anode = (+0.34) − (−0.76) = +1.10 V; Cu²⁺ is reduced at the cathode and Zn oxidized at the anode."},
  {"i":"chem-b3-0423","g":11,"u":"Oxygen-Containing Organic Compounds","d":"medium","t":"conceptual","q":"What is the product when a primary alcohol such as ethanol is mildly oxidized with acidified K₂Cr₂O₇ under controlled conditions?","o":["A ketone","An aldehyde","An ester","An alkane"],"c":1,"e":"Mild controlled oxidation of a primary alcohol gives an aldehyde (ethanol → ethanal); further oxidation gives a carboxylic acid, while secondary alcohols give ketones."},
  {"i":"chem-b3-0424","g":11,"u":"Oxygen-Containing Organic Compounds","d":"medium","t":"application","q":"Which reaction produces an ester with a characteristic fruity smell?","o":["Alcohol + carboxylic acid with an acid catalyst","Alkene + hydrogen","Alcohol + sodium metal","Aldehyde + an oxidizing agent"],"c":0,"e":"Esterification combines a carboxylic acid and an alcohol with an acid catalyst, releasing water, e.g., ethanoic acid + ethanol → ethyl ethanoate, which smells fruity."},
  {"i":"chem-b3-0425","g":11,"u":"Oxygen-Containing Organic Compounds","d":"medium","t":"calculation","q":"Complete combustion of ethanol follows C₂H₅OH + 3O₂ → 2CO₂ + 3H₂O. How many moles of O₂ are needed to burn 0.50 mol of ethanol?","o":["1.0 mol","1.5 mol","3.0 mol","2.0 mol"],"c":1,"e":"The balanced equation needs 3 mol O₂ per 1 mol ethanol, so 0.50 mol ethanol requires 0.50×3 = 1.5 mol O₂."},
  {"i":"chem-b3-0426","g":11,"u":"Atomic Structure & Periodic Properties","d":"medium","t":"calculation","q":"An element has two isotopes: ⁶³Cu (mass 62.93 u, abundance 69.2%) and ⁶⁵Cu (mass 64.93 u, abundance 30.8%). What is its relative atomic mass?","o":["63.55 u","63.93 u","64.55 u","62.93 u"],"c":0,"e":"Ar = (62.93 × 0.692) + (64.93 × 0.308) = 43.55 + 20.00 = 63.55 u. The weighted mean lies closer to the more abundant lighter isotope."},
  {"i":"chem-b3-0427","g":11,"u":"Atomic Structure & Periodic Properties","d":"medium","t":"conceptual","q":"For the ion S²⁻ (Z = 16), how many electrons, protons and neutrons (mass number 32) are present respectively?","o":["18, 16, 16","16, 16, 16","18, 18, 16","16, 18, 16"],"c":0,"e":"Protons = Z = 16; neutrons = 32 − 16 = 16; a 2− charge means 2 extra electrons, so 16 + 2 = 18 electrons."},
  {"i":"chem-b3-0428","g":11,"u":"Atomic Structure & Periodic Properties","d":"medium","t":"application","q":"Write the ground-state electron configuration of a chromium atom (Z = 24), accounting for the stable half-filled exception.","o":["[Ar]3d⁵4s¹","[Ar]3d⁴4s²","[Ar]3d⁶","[Ar]3d⁵4s²"],"c":0,"e":"Chromium promotes one 4s electron to 3d to gain the stability of a half-filled 3d⁵ and half-filled 4s¹, giving [Ar]3d⁵4s¹."},
  {"i":"chem-b3-0429","g":11,"u":"Atomic Structure & Periodic Properties","d":"medium","t":"conceptual","q":"Across Period 3 from Na to Cl, which trend correctly describes atomic radius and first ionization energy?","o":["Radius decreases, ionization energy increases","Radius increases, ionization energy decreases","Both increase","Both decrease"],"c":0,"e":"Increasing nuclear charge with electrons added to the same shell pulls electrons inward (radius decreases) and binds them more tightly (ionization energy increases)."},
  {"i":"chem-b3-0430","g":11,"u":"Chemical Bonding","d":"medium","t":"conceptual","q":"Which molecule has a bent (angular) shape with a bond angle of about 104.5° due to two lone pairs on the central atom?","o":["H₂O","CO₂","BF₃","CH₄"],"c":0,"e":"Water's oxygen has 2 bonding pairs and 2 lone pairs; the lone-pair repulsion compresses the angle to ~104.5°, giving a bent shape."},
  {"i":"chem-b3-0431","g":11,"u":"Chemical Bonding","d":"medium","t":"application","q":"What is the formal name and bond type predicted for the compound formed between magnesium (Z = 12) and nitrogen (Z = 7)?","o":["Magnesium nitride, Mg₃N₂, ionic","Magnesium nitride, MgN, ionic","Magnesium nitrate, Mg(NO₃)₂, ionic","Magnesium nitride, Mg₂N₃, covalent"],"c":0,"e":"Mg²⁺ and N³⁻ combine in a 3:2 ratio to balance charge, giving Mg₃N₂; the large electronegativity gap makes it ionic."},
  {"i":"chem-b3-0432","g":11,"u":"Chemical Bonding","d":"medium","t":"conceptual","q":"Which sequence correctly ranks these substances by increasing boiling point, based on intermolecular forces: CH₄, HCl, H₂O?","o":["CH₄ < HCl < H₂O","H₂O < HCl < CH₄","HCl < CH₄ < H₂O","CH₄ < H₂O < HCl"],"c":0,"e":"CH₄ has only weak London forces, HCl adds dipole–dipole, and H₂O has strong hydrogen bonding, so boiling point rises CH₄ < HCl < H₂O."},
  {"i":"chem-b3-0433","g":11,"u":"Physical States of Matter","d":"medium","t":"calculation","q":"How many moles of an ideal gas are present in 4.48 L measured at STP (molar volume 22.4 L/mol)?","o":["0.200 mol","0.100 mol","2.00 mol","0.448 mol"],"c":0,"e":"n = V/Vm = 4.48 / 22.4 = 0.200 mol at standard temperature and pressure."},
  {"i":"chem-b3-0434","g":11,"u":"Physical States of Matter","d":"medium","t":"calculation","q":"A gas exerts 100 kPa in a 2.0 L container. If compressed to 0.50 L at constant temperature, what is the new pressure?","o":["400 kPa","25 kPa","200 kPa","50 kPa"],"c":0,"e":"Boyle's law P₁V₁ = P₂V₂: P₂ = (100 × 2.0)/0.50 = 400 kPa."},
  {"i":"chem-b3-0435","g":11,"u":"Chemical Kinetics","d":"medium","t":"calculation","q":"For a reaction, rate = k[A][B]². If [B] is tripled while [A] is unchanged, by what factor does the rate change?","o":["9","3","6","27"],"c":0,"e":"Rate depends on [B]²; tripling B multiplies the rate by 3² = 9."},
  {"i":"chem-b3-0436","g":11,"u":"Chemical Kinetics","d":"medium","t":"conceptual","q":"Which statement best explains how a catalyst increases reaction rate?","o":["It lowers the activation energy by providing an alternative pathway","It increases the enthalpy change of the reaction","It raises the temperature of the system","It shifts the equilibrium toward products"],"c":0,"e":"A catalyst offers a route with lower activation energy, so more collisions succeed per second; it does not change ΔH or the equilibrium position."},
  {"i":"chem-b3-0437","g":11,"u":"Chemical Kinetics","d":"medium","t":"application","q":"Powdered limestone reacts faster with dilute HCl than a single lump of the same mass. The best explanation is that powdering:","o":["increases the surface area available for collisions","increases the activation energy","raises the concentration of HCl","increases the temperature of the acid"],"c":0,"e":"More finely divided solid exposes a larger surface area, so more acid particles collide with solid per unit time, increasing the rate."},
  {"i":"chem-b3-0438","g":11,"u":"Chemical Equilibrium","d":"medium","t":"calculation","q":"For N₂(g) + 3H₂(g) ⇌ 2NH₃(g), equilibrium concentrations are [N₂] = 0.20 M, [H₂] = 0.20 M, [NH₃] = 0.40 M. What is Kc?","o":["100","50","2.0","8.0"],"c":0,"e":"Kc = [NH₃]²/([N₂][H₂]³) = (0.40²)/(0.20 × 0.20³) = 0.16/(0.20 × 0.008) = 0.16/0.0016 = 100."},
  {"i":"chem-b3-0439","g":11,"u":"Chemical Equilibrium","d":"medium","t":"calculation","q":"A 0.10 M solution of a weak acid HA has Ka = 1.0 × 10⁻⁵. What is its approximate pH?","o":["3.0","5.0","2.0","4.0"],"c":0,"e":"[H⁺] ≈ √(Ka·C) = √(1.0×10⁻⁵ × 0.10) = √(1.0×10⁻⁶) = 1.0×10⁻³ M, so pH = 3.0."},
  {"i":"chem-b3-0440","g":11,"u":"Chemical Equilibrium","d":"medium","t":"calculation","q":"What is the pH of a solution with hydroxide concentration [OH⁻] = 1.0 × 10⁻⁴ M at 25 °C?","o":["10.0","4.0","7.0","11.0"],"c":0,"e":"pOH = −log(1.0×10⁻⁴) = 4.0; pH = 14 − pOH = 14 − 4 = 10.0."},
  {"i":"chem-b3-0441","g":11,"u":"Chemical Equilibrium","d":"medium","t":"calculation","q":"How many moles of NaOH are needed to neutralize 25.0 mL of 0.20 M H₂SO₄ completely?","o":["0.010 mol","0.0050 mol","0.020 mol","0.0025 mol"],"c":0,"e":"Moles H₂SO₄ = 0.025 × 0.20 = 0.0050 mol; the diprotic acid needs 2 mol NaOH each, so 2 × 0.0050 = 0.010 mol NaOH."},
  {"i":"chem-b3-0442","g":11,"u":"Oxygen-Containing Organic Compounds","d":"medium","t":"definition","q":"Which functional group characterizes a carboxylic acid such as the acetic acid in Ethiopian table vinegar?","o":["−COOH","−OH","−CHO","−CO−"],"c":0,"e":"Carboxylic acids contain the carboxyl group −COOH (a carbonyl bonded to a hydroxyl); −OH alone is alcohol, −CHO is aldehyde, −CO− is ketone."},
  {"i":"chem-b3-0443","g":11,"u":"Oxygen-Containing Organic Compounds","d":"medium","t":"application","q":"Controlled oxidation of ethanol (CH₃CH₂OH) first gives which product?","o":["Ethanal (acetaldehyde), CH₃CHO","Ethane, C₂H₆","Ethanoic acid directly, with no aldehyde","Ethene, C₂H₄"],"c":0,"e":"A primary alcohol is oxidized first to an aldehyde; ethanol gives ethanal (CH₃CHO), which on further oxidation becomes ethanoic acid."},
  {"i":"chem-b3-0444","g":11,"u":"Oxygen-Containing Organic Compounds","d":"medium","t":"calculation","q":"What is the molar mass of ethanol, C₂H₅OH (C=12, H=1, O=16 g/mol)?","o":["46 g/mol","44 g/mol","48 g/mol","32 g/mol"],"c":0,"e":"C₂H₆O: (2×12) + (6×1) + 16 = 24 + 6 + 16 = 46 g/mol."},
  {"i":"chem-b3-0445","g":11,"u":"Oxygen-Containing Organic Compounds","d":"medium","t":"conceptual","q":"An organic compound has molecular formula C₃H₆O and reacts to give a ketone test result (no reaction with Tollens' reagent). Its structure is most likely:","o":["Propanone, CH₃COCH₃","Propanal, CH₃CH₂CHO","Propan-1-ol, CH₃CH₂CH₂OH","Propene oxide"],"c":0,"e":"C₃H₆O as a ketone with no silver-mirror (Tollens) reaction must be propanone (CH₃COCH₃); propanal is an aldehyde and would react with Tollens' reagent."},
  {"i":"chem-b3-0446","g":11,"u":"Atomic Structure & Periodic Properties","d":"hard","t":"calculation","q":"A sample of chlorine has two isotopes: ³⁵Cl (mass 34.97 u) and ³⁷Cl (mass 36.97 u). If the relative atomic mass of chlorine is 35.45 u, what percentage of the sample is ³⁷Cl?","o":["24%","76%","35%","18%"],"c":0,"e":"Let x = fraction of ³⁷Cl: 34.97(1−x) + 36.97x = 35.45, so 2.00x = 0.48, x = 0.24 = 24%."},
  {"i":"chem-b3-0447","g":11,"u":"Atomic Structure & Periodic Properties","d":"hard","t":"conceptual","q":"An element X has the ground-state configuration 1s²2s²2p⁶3s²3p⁶3d¹⁰4s²4p³. To which group and period does X belong, and how many unpaired electrons does it have?","o":["Group VA, Period 4, 3 unpaired","Group IIIA, Period 4, 1 unpaired","Group VA, Period 3, 3 unpaired","Group VIIA, Period 4, 5 unpaired"],"c":0,"e":"Highest principal level is 4 (Period 4); valence electrons 4s²4p³ = 5 give Group VA; the three 4p electrons are each in separate orbitals giving 3 unpaired electrons (Hund's rule)."},
  {"i":"chem-b3-0448","g":11,"u":"Atomic Structure & Periodic Properties","d":"hard","t":"calculation","q":"The successive ionization energies (kJ/mol) of an element are 738, 1451, 7733, 10540. Based on the large jump, to which group does this element most likely belong?","o":["Group IIA","Group IA","Group IIIA","Group IVA"],"c":0,"e":"The big jump occurs after the 2nd ionization (1451 → 7733), showing 2 easily-removed valence electrons before reaching a stable core, characteristic of Group IIA."},
  {"i":"chem-b3-0449","g":11,"u":"Chemical Bonding","d":"hard","t":"conceptual","q":"Using VSEPR theory, what is the molecular geometry and approximate bond angle of the sulfur tetrafluoride molecule, SF₄?","o":["See-saw, ~120° and ~90°","Tetrahedral, 109.5°","Square planar, 90°","Trigonal pyramidal, 107°"],"c":0,"e":"SF₄ has 5 electron domains (4 bonding + 1 lone pair) giving trigonal bipyramidal arrangement; the lone pair occupies an equatorial position, producing a see-saw shape with ~120° and ~90° angles."},
  {"i":"chem-b3-0450","g":11,"u":"Chemical Bonding","d":"hard","t":"calculation","q":"Using bond enthalpies (H–H = 436, Cl–Cl = 242, H–Cl = 431 kJ/mol), calculate ΔH for the reaction H₂(g) + Cl₂(g) → 2HCl(g).","o":["−184 kJ","−253 kJ","+184 kJ","−92 kJ"],"c":0,"e":"ΔH = bonds broken − bonds formed = (436 + 242) − (2 × 431) = 678 − 862 = −184 kJ."},
  {"i":"chem-b3-0451","g":11,"u":"Chemical Bonding","d":"hard","t":"conceptual","q":"Which of the following correctly explains why the boiling point of HF (19.5 °C) is much higher than that of HCl (−85 °C), despite HCl having a larger molar mass?","o":["HF forms strong hydrogen bonds; HCl has only dipole-dipole and dispersion forces","HF has stronger London dispersion forces than HCl","HCl is ionic whereas HF is covalent","HF has a larger dipole moment caused by its larger size"],"c":0,"e":"Fluorine's high electronegativity and small size let HF molecules hydrogen-bond strongly (F–H···F), which requires much more energy to overcome than the dipole-dipole/dispersion forces in HCl."},
  {"i":"chem-b3-0452","g":11,"u":"Chemical Bonding","d":"hard","t":"calculation","q":"A diatomic molecule has bond order calculated from molecular orbital theory. For the O₂ molecule (12 valence electrons in MOs), what is the bond order and is it paramagnetic?","o":["Bond order 2, paramagnetic","Bond order 2, diamagnetic","Bond order 3, paramagnetic","Bond order 1, paramagnetic"],"c":0,"e":"O₂ has 8 bonding and 4 antibonding valence electrons: bond order = (8−4)/2 = 2; the two electrons in degenerate π* orbitals are unpaired, making O₂ paramagnetic."},
  {"i":"chem-b3-0453","g":11,"u":"Physical States of Matter","d":"hard","t":"calculation","q":"A 0.50 g sample of an unknown gas occupies 280 cm³ at 27 °C and 100 kPa. What is its molar mass? (R = 8.314 J·mol⁻¹·K⁻¹)","o":["44.5 g/mol","32.0 g/mol","28.0 g/mol","16.0 g/mol"],"c":0,"e":"n = PV/RT = (100000 × 280×10⁻⁶)/(8.314 × 300) = 28/2494.2 = 0.01123 mol; M = 0.50/0.01123 ≈ 44.5 g/mol."},
  {"i":"chem-b3-0454","g":11,"u":"Physical States of Matter","d":"hard","t":"calculation","q":"At the same temperature, gas A effuses 1.5 times faster than gas B. If the molar mass of gas A is 16 g/mol, what is the molar mass of gas B (Graham's law)?","o":["36 g/mol","24 g/mol","10.7 g/mol","32 g/mol"],"c":0,"e":"rate_A/rate_B = √(M_B/M_A), so 1.5 = √(M_B/16); M_B = 1.5² × 16 = 2.25 × 16 = 36 g/mol."},
  {"i":"chem-b3-0455","g":11,"u":"Physical States of Matter","d":"hard","t":"calculation","q":"A fixed mass of gas at 2.0 atm and 300 K occupies 4.0 L. It is compressed to 2.0 L while heated to 450 K. What is the new pressure?","o":["6.0 atm","3.0 atm","4.5 atm","8.0 atm"],"c":0,"e":"Combined gas law: P₂ = P₁V₁T₂/(T₁V₂) = (2.0 × 4.0 × 450)/(300 × 2.0) = 3600/600 = 6.0 atm."},
  {"i":"chem-b3-0456","g":11,"u":"Chemical Kinetics","d":"hard","t":"calculation","q":"For a reaction, doubling [A] quadruples the rate, and doubling [B] doubles the rate. If [A] is tripled and [B] is halved simultaneously, by what factor does the rate change?","o":["×4.5","×1.5","×6","×3"],"c":0,"e":"Rate = k[A]²[B] (order 2 in A, 1 in B); tripling A gives 3² = 9, halving B gives ×0.5, so overall 9 × 0.5 = 4.5."},
  {"i":"chem-b3-0457","g":11,"u":"Chemical Kinetics","d":"hard","t":"calculation","q":"A first-order reaction has a rate constant k = 0.0231 s⁻¹. What is the half-life of the reaction?","o":["30 s","15 s","23 s","69 s"],"c":0,"e":"For first order, t½ = 0.693/k = 0.693/0.0231 = 30 s."},
  {"i":"chem-b3-0458","g":11,"u":"Chemical Kinetics","d":"hard","t":"calculation","q":"The rate constant of a reaction doubles when temperature rises from 300 K to 310 K. Using the Arrhenius equation (R = 8.314 J·mol⁻¹·K⁻¹), the activation energy is closest to:","o":["53 kJ/mol","27 kJ/mol","107 kJ/mol","11 kJ/mol"],"c":0,"e":"ln(k₂/k₁) = (Ea/R)(1/T₁ − 1/T₂); ln2 = (Ea/8.314)(1/300 − 1/310) = (Ea/8.314)(1.075×10⁻⁴); Ea = 0.693 × 8.314 / 1.075×10⁻⁴ ≈ 53600 J ≈ 53 kJ/mol."},
  {"i":"chem-b3-0459","g":11,"u":"Chemical Equilibrium","d":"hard","t":"calculation","q":"A 0.10 M solution of a weak acid HA has a pH of 2.87. What is the Ka of the acid?","o":["1.8 × 10⁻⁵","1.3 × 10⁻³","1.4 × 10⁻⁴","2.9 × 10⁻²"],"c":0,"e":"[H⁺] = 10⁻²·⁸⁷ = 1.35×10⁻³ M; Ka = [H⁺]²/([HA]−[H⁺]) ≈ (1.35×10⁻³)²/0.10 = 1.82×10⁻⁶/0.10 = 1.8×10⁻⁵."},
  {"i":"chem-b3-0460","g":11,"u":"Chemical Equilibrium","d":"hard","t":"calculation","q":"What is the pH of a buffer made by mixing 0.20 mol CH₃COOH and 0.30 mol CH₃COONa in 1.0 L? (Ka = 1.8 × 10⁻⁵)","o":["4.92","4.74","4.57","5.05"],"c":0,"e":"pKa = −log(1.8×10⁻⁵) = 4.74; pH = pKa + log([A⁻]/[HA]) = 4.74 + log(0.30/0.20) = 4.74 + log1.5 = 4.74 + 0.176 = 4.92."},
  {"i":"chem-b3-0461","g":11,"u":"Chemical Equilibrium","d":"hard","t":"conceptual","q":"For the exothermic equilibrium 2SO₂(g) + O₂(g) ⇌ 2SO₃(g), which change increases the equilibrium yield of SO₃?","o":["Decreasing the temperature","Adding a catalyst","Increasing the temperature","Increasing the container volume"],"c":0,"e":"The forward reaction is exothermic, so lowering temperature shifts equilibrium right (Le Chatelier). A catalyst only speeds attainment, and increasing volume favors the side with more moles of gas (reactants)."},
  {"i":"chem-b3-0462","g":11,"u":"Oxygen-Containing Organic Compounds","d":"hard","t":"calculation","q":"Complete combustion of 0.10 mol of an alcohol CₙH₂ₙ₊₁OH produces 8.8 g of CO₂. What is the molecular formula of the alcohol?","o":["C₂H₅OH","CH₃OH","C₃H₇OH","C₄H₉OH"],"c":0,"e":"Moles CO₂ = 8.8/44 = 0.20 mol; carbon atoms per molecule = 0.20/0.10 = 2, so n = 2 giving C₂H₅OH (ethanol)."},
  {"i":"chem-b3-0463","g":11,"u":"Oxygen-Containing Organic Compounds","d":"hard","t":"conceptual","q":"When ethanol is heated with acidified potassium dichromate under reflux (excess oxidant), the final organic product is:","o":["Ethanoic acid","Ethanal","Ethene","Ethyl ethanoate"],"c":0,"e":"A primary alcohol is first oxidized to an aldehyde (ethanal), then under reflux with excess oxidant it is further oxidized to the carboxylic acid, ethanoic acid."},
  {"i":"chem-b3-0464","g":11,"u":"Oxygen-Containing Organic Compounds","d":"hard","t":"application","q":"A carboxylic acid reacts with an alcohol in the presence of concentrated H₂SO₄. Ethanoic acid + propan-1-ol gives which ester (and the by-product)?","o":["Propyl ethanoate + water","Ethyl propanoate + water","Propyl ethanoate + hydrogen","Ethyl propanoate + carbon dioxide"],"c":0,"e":"In esterification the acyl group comes from the acid (ethanoate) and the alkyl group from the alcohol (propyl): CH₃COOH + C₃H₇OH → CH₃COOC₃H₇ (propyl ethanoate) + H₂O."},
  {"i":"chem-b3-0465","g":11,"u":"Oxygen-Containing Organic Compounds","d":"hard","t":"conceptual","q":"Three isomers share the formula C₃H₆O. Which pair of functional groups can this formula represent?","o":["Aldehyde (propanal) and ketone (propanone)","Carboxylic acid and ester","Alcohol and ether","Aldehyde and carboxylic acid"],"c":0,"e":"C₃H₆O has one degree of unsaturation (a C=O); with three carbons it can be the aldehyde propanal (CH₃CH₂CHO) or the ketone propanone (CH₃COCH₃). Acids/esters require an extra oxygen (C₃H₆O₂)."},
  {"i":"chem-b3-0466","g":11,"u":"Atomic Structure & Periodic Properties","d":"hard","t":"calculation","q":"A sample of natural boron contains only the isotopes ¹⁰B and ¹¹B. If the relative atomic mass of boron is 10.81 u, what is the percentage abundance of the ¹¹B isotope?","o":["19%","42%","58%","81%"],"c":3,"e":"Let x = fraction of ¹¹B; 10(1−x) + 11x = 10.81, so x = 0.81 = 81%."},
  {"i":"chem-b3-0467","g":11,"u":"Atomic Structure & Periodic Properties","d":"hard","t":"conceptual","q":"An element X has the ground-state electron configuration 1s²2s²2p⁶3s²3p⁶3d¹⁰4s²4p³. To which group and period does X belong, and what is its most common oxidation state in oxides?","o":["Group VA, Period 4, +5","Group IIIA, Period 4, +3","Group VA, Period 3, +5","Group VIIA, Period 4, +5"],"c":0,"e":"Highest n = 4 (Period 4); valence 4s²4p³ gives 5 valence electrons (Group VA, like As), with a common +5 oxidation state in oxides."},
  {"i":"chem-b3-0468","g":11,"u":"Atomic Structure & Periodic Properties","d":"hard","t":"calculation","q":"The first four successive ionization energies (kJ/mol) of an element are 738, 1451, 7733, 10540. Based on the large jump between IE₂ and IE₃, to which group does the element most likely belong?","o":["Group IA","Group IIA","Group IIIA","Group IVA"],"c":1,"e":"The big jump after removing 2 electrons shows only 2 valence electrons before reaching a noble-gas core, so the element is in Group IIA (e.g., Mg)."},
  {"i":"chem-b3-0469","g":11,"u":"Atomic Structure & Periodic Properties","d":"hard","t":"calculation","q":"A line in the hydrogen spectrum arises from an electron transition from n = 4 to n = 2. Using the Rydberg constant R = 1.097 × 10⁷ m⁻¹, what is the wavelength of the emitted light?","o":["486 nm","656 nm","410 nm","434 nm"],"c":0,"e":"1/λ = R(1/2² − 1/4²) = 1.097×10⁷(0.25 − 0.0625) = 2.057×10⁶ m⁻¹, so λ ≈ 4.86×10⁻⁷ m = 486 nm."},
  {"i":"chem-b3-0470","g":11,"u":"Chemical Bonding","d":"hard","t":"conceptual","q":"In the molecule XeF₄, the central xenon atom is surrounded by 4 bonding pairs and 2 lone pairs. What are the electron-domain geometry and the molecular shape, respectively?","o":["Octahedral; square planar","Tetrahedral; square planar","Octahedral; see-saw","Trigonal bipyramidal; square planar"],"c":0,"e":"6 electron domains give octahedral electron geometry; with 2 lone pairs placed axially (trans), the 4 F atoms form a square planar shape."},
  {"i":"chem-b3-0471","g":11,"u":"Chemical Bonding","d":"hard","t":"calculation","q":"Using bond enthalpies (H–H = 436, Cl–Cl = 242, H–Cl = 431 kJ/mol), estimate the enthalpy change for H₂(g) + Cl₂(g) → 2HCl(g).","o":["−184 kJ","−247 kJ","+184 kJ","−93 kJ"],"c":0,"e":"ΔH = bonds broken − bonds formed = (436 + 242) − 2(431) = 678 − 862 = −184 kJ."},
  {"i":"chem-b3-0472","g":11,"u":"Chemical Bonding","d":"hard","t":"conceptual","q":"Which of the following statements correctly explains why the boiling point of HF (19.5 °C) is much higher than that of HCl (−85 °C)?","o":["HF forms intermolecular hydrogen bonds while HCl relies mainly on weaker dipole–dipole forces","HCl has a larger molar mass and so weaker London forces","HF is ionic whereas HCl is covalent","HF molecules are nonpolar so they pack more tightly"],"c":0,"e":"F is highly electronegative and small, so HF forms strong N/O/F hydrogen bonds; HCl has only dipole–dipole and London forces, giving a far lower boiling point."},
  {"i":"chem-b3-0473","g":11,"u":"Chemical Bonding","d":"hard","t":"conceptual","q":"Arrange the carbon–carbon bonds in ethane, ethene, and ethyne in order of increasing bond length.","o":["ethyne < ethene < ethane","ethane < ethene < ethyne","ethene < ethane < ethyne","ethyne < ethane < ethene"],"c":0,"e":"More bonds between the carbons mean a shorter, stronger bond: triple (ethyne) < double (ethene) < single (ethane)."},
  {"i":"chem-b3-0474","g":11,"u":"Physical States of Matter","d":"hard","t":"calculation","q":"A 4.0 g sample of helium gas occupies 5.0 L at 27 °C. What is the pressure of the gas? (R = 0.0821 L·atm·mol⁻¹·K⁻¹, molar mass He = 4 g/mol)","o":["4.93 atm","2.46 atm","9.86 atm","1.64 atm"],"c":0,"e":"n = 4.0/4 = 1.0 mol; T = 300 K; P = nRT/V = (1.0)(0.0821)(300)/5.0 = 4.93 atm."},
  {"i":"chem-b3-0475","g":11,"u":"Physical States of Matter","d":"hard","t":"calculation","q":"At the same temperature and pressure, gas X effuses 1.5 times faster than oxygen (O₂, M = 32 g/mol). What is the approximate molar mass of gas X?","o":["14 g/mol","21 g/mol","48 g/mol","72 g/mol"],"c":0,"e":"By Graham's law, rate ∝ 1/√M: (rₓ/r₀₂)² = M₀₂/Mₓ, so Mₓ = 32/1.5² = 32/2.25 ≈ 14 g/mol."},
  {"i":"chem-b3-0476","g":11,"u":"Physical States of Matter","d":"hard","t":"calculation","q":"A fixed mass of gas at 2.0 atm and 300 K occupies 6.0 L. If it is compressed to 4.0 L and heated to 400 K, what is the new pressure?","o":["4.0 atm","2.25 atm","3.0 atm","6.0 atm"],"c":0,"e":"Combined gas law: P₂ = P₁V₁T₂/(T₁V₂) = (2.0)(6.0)(400)/(300×4.0) = 4800/1200 = 4.0 atm."},
  {"i":"chem-b3-0477","g":11,"u":"Chemical Kinetics","d":"hard","t":"calculation","q":"For a reaction A + B → products, the rate law is rate = k[A][B]². If the concentration of A is doubled and that of B is tripled, by what factor does the reaction rate increase?","o":["18","6","9","12"],"c":0,"e":"Rate factor = (2)¹ × (3)² = 2 × 9 = 18."},
  {"i":"chem-b3-0478","g":11,"u":"Chemical Kinetics","d":"hard","t":"calculation","q":"A reaction has rate constant k₁ at 300 K and its rate doubles when temperature rises to 310 K. Using the approximation that the rate roughly doubles per 10 K rise, what is the approximate rate ratio between 330 K and 300 K?","o":["8","4","6","16"],"c":0,"e":"A rise of 30 K = three 10-K steps; rate multiplies by 2³ = 8."},
  {"i":"chem-b3-0479","g":11,"u":"Chemical Kinetics","d":"hard","t":"conceptual","q":"Which statement best describes the effect of a catalyst on a reversible reaction at equilibrium?","o":["It lowers the activation energy of both forward and reverse reactions equally, speeding both without shifting the equilibrium position","It increases the yield of products by shifting equilibrium to the right","It only speeds the forward reaction, increasing Kc","It raises the activation energy of the reverse reaction"],"c":0,"e":"A catalyst provides an alternative lower-Eₐ path for both directions equally, so it reaches equilibrium faster but does not change Kc or the equilibrium position."},
  {"i":"chem-b3-0480","g":11,"u":"Chemical Equilibrium","d":"hard","t":"calculation","q":"For N₂(g) + 3H₂(g) ⇌ 2NH₃(g), an equilibrium mixture in a 1.0 L vessel contains 0.20 mol N₂, 0.40 mol H₂, and 0.60 mol NH₃. What is Kc?","o":["28.1","5.6","11.3","1.88"],"c":0,"e":"Kc = [NH₃]²/([N₂][H₂]³) = (0.60)²/((0.20)(0.40)³) = 0.36/(0.20×0.064) = 0.36/0.0128 = 28.1."},
  {"i":"chem-b3-0481","g":11,"u":"Chemical Equilibrium","d":"hard","t":"conceptual","q":"For the exothermic equilibrium 2SO₂(g) + O₂(g) ⇌ 2SO₃(g), which change shifts the equilibrium toward more SO₃?","o":["Increasing the pressure by decreasing the volume","Raising the temperature","Adding a catalyst","Removing some O₂"],"c":0,"e":"Increasing pressure favors the side with fewer gas moles (3 mol → 2 mol), shifting toward SO₃; heating shifts an exothermic reaction backward, a catalyst doesn't shift, and removing O₂ shifts left."},
  {"i":"chem-b3-0482","g":11,"u":"Chemical Equilibrium","d":"hard","t":"calculation","q":"A weak acid HA has Ka = 1.0 × 10⁻⁵. What is the pH of a 0.10 M solution of HA? (assume x ≪ 0.10)","o":["3.0","5.0","2.0","4.0"],"c":0,"e":"[H⁺] = √(Ka·C) = √(1.0×10⁻⁵ × 0.10) = √(1.0×10⁻⁶) = 1.0×10⁻³ M, so pH = 3.0."},
  {"i":"chem-b3-0483","g":11,"u":"Chemical Equilibrium","d":"hard","t":"calculation","q":"What volume of 0.10 M NaOH is required to neutralize 25.0 mL of 0.20 M H₂SO₄ completely?","o":["100 mL","50 mL","25 mL","200 mL"],"c":0,"e":"Moles H₂SO₄ = 0.025×0.20 = 0.005 mol; it needs 2× moles OH⁻ = 0.010 mol; V = 0.010/0.10 = 0.10 L = 100 mL."},
  {"i":"chem-b3-0484","g":11,"u":"Chemical Equilibrium","d":"hard","t":"calculation","q":"A buffer is made by mixing 0.20 mol of acetic acid (Ka = 1.8 × 10⁻⁵) and 0.20 mol of sodium acetate in 1.0 L. What is the pH? (log 1.8 ≈ 0.26)","o":["4.74","5.26","4.00","3.74"],"c":0,"e":"By Henderson–Hasselbalch, pH = pKa + log([A⁻]/[HA]); with equal moles the log term is 0, so pH = pKa = −log(1.8×10⁻⁵) = 4.74."},
  {"i":"chem-b3-0485","g":11,"u":"Oxygen-Containing Organic Compounds","d":"hard","t":"conceptual","q":"When ethanol is heated with acidified potassium dichromate(VI) under reflux, the organic product is which compound, and what colour change is observed?","o":["Ethanoic acid; orange to green","Ethanal; green to orange","Ethene; orange to colourless","Ethyl ethanoate; orange to green"],"c":0,"e":"Under reflux the primary alcohol is fully oxidised to the carboxylic acid (ethanoic acid); Cr₂O₇²⁻ (orange) is reduced to Cr³⁺ (green)."},
  {"i":"chem-b3-0486","g":11,"u":"Oxygen-Containing Organic Compounds","d":"hard","t":"calculation","q":"Complete combustion of 0.10 mol of an alcohol CₙH₂ₙ₊₁OH produces 0.30 mol of CO₂. What is the molecular formula of the alcohol?","o":["C₃H₇OH","C₂H₅OH","C₄H₉OH","CH₃OH"],"c":0,"e":"Moles CO₂ per mole alcohol = n = 0.30/0.10 = 3, so the alcohol is C₃H₇OH (propanol)."},
  {"i":"chem-b3-0487","g":11,"u":"Oxygen-Containing Organic Compounds","d":"hard","t":"application","q":"A carboxylic acid reacts with an alcohol in the presence of concentrated H₂SO₄. Ethanoic acid (CH₃COOH) and propan-1-ol (CH₃CH₂CH₂OH) give which ester and by-product?","o":["Propyl ethanoate and water","Ethyl propanoate and water","Propyl ethanoate and hydrogen","Ethyl ethanoate and water"],"c":0,"e":"Esterification combines the acid's acyl group (ethanoate) with the alcohol's alkyl group (propyl) to give propyl ethanoate (CH₃COOCH₂CH₂CH₃), releasing water."},
  {"i":"chem-b3-0488","g":11,"u":"Atomic Structure & Periodic Properties","d":"hard","t":"calculation","q":"Chlorine in a sample of Afar lake salt consists of ³⁵Cl (mass 34.97 u) and ³⁷Cl (mass 36.97 u) giving an average atomic mass of 35.45 u. What is the percentage abundance of the ³⁷Cl isotope?","o":["24.0%","25.5%","75.8%","18.5%"],"c":0,"e":"Let x = fraction of ³⁷Cl: 36.97x + 34.97(1−x) = 35.45 → 2.00x = 0.48 → x = 0.24, so 24.0%."},
  {"i":"chem-b3-0489","g":11,"u":"Atomic Structure & Periodic Properties","d":"hard","t":"calculation","q":"An electron drops from n=4 to n=2 in a hydrogen atom (R_H = 2.18×10⁻¹⁸ J). What is the energy released?","o":["4.09×10⁻¹⁹ J","2.18×10⁻¹⁸ J","5.45×10⁻¹⁹ J","1.64×10⁻¹⁸ J"],"c":0,"e":"ΔE = R_H(1/n₁²−1/n₂²) = 2.18×10⁻¹⁸(1/4−1/16) = 2.18×10⁻¹⁸(0.1875) = 4.09×10⁻¹⁹ J released."},
  {"i":"chem-b3-0490","g":11,"u":"Atomic Structure & Periodic Properties","d":"hard","t":"conceptual","q":"Which ground-state configuration correctly represents a chromium atom (Z=24), reflecting the stability of a half-filled d-subshell?","o":["[Ar]3d⁵4s¹","[Ar]3d⁴4s²","[Ar]3d⁶","[Ar]3d⁵3d¹"],"c":0,"e":"Cr promotes one 4s electron to 3d, giving [Ar]3d⁵4s¹ — a stable half-filled 3d and half-filled 4s."},
  {"i":"chem-b3-0491","g":11,"u":"Atomic Structure & Periodic Properties","d":"hard","t":"conceptual","q":"The successive ionization energies of element X (kJ/mol) are 738, 1451, 7733, 10543. The large jump after the 2nd ionization indicates X belongs to which group?","o":["Group 2 (IIA)","Group 1 (IA)","Group 13 (IIIA)","Group 14 (IVA)"],"c":0,"e":"The big jump between IE₂ and IE₃ means only 2 valence electrons are easily removed; X is a Group 2 metal like Mg."},
  {"i":"chem-b3-0492","g":11,"u":"Chemical Bonding","d":"hard","t":"calculation","q":"Using bond energies (H–H = 436, Cl–Cl = 242, H–Cl = 431 kJ/mol), calculate ΔH for H₂(g) + Cl₂(g) → 2HCl(g).","o":["−184 kJ","−862 kJ","+184 kJ","−247 kJ"],"c":0,"e":"ΔH = bonds broken − bonds formed = (436+242) − 2(431) = 678 − 862 = −184 kJ."},
  {"i":"chem-b3-0493","g":11,"u":"Chemical Bonding","d":"hard","t":"conceptual","q":"According to VSEPR, what is the molecular geometry of the SF₄ molecule (S has one lone pair)?","o":["See-saw","Tetrahedral","Trigonal pyramidal","Square planar"],"c":0,"e":"SF₄ has 5 electron domains (4 bonding + 1 lone pair), trigonal bipyramidal arrangement; the lone pair gives a see-saw shape."},
  {"i":"chem-b3-0494","g":11,"u":"Chemical Bonding","d":"hard","t":"conceptual","q":"Which species has a bond order of 2.5 according to molecular orbital theory?","o":["O₂⁺","O₂","N₂","O₂²⁻"],"c":0,"e":"O₂ has bond order 2 (16 e⁻). Removing one electron from a π* orbital gives O₂⁺ (15 e⁻), bond order = (10−5)/2 = 2.5."},
  {"i":"chem-b3-0495","g":11,"u":"Chemical Bonding","d":"hard","t":"conceptual","q":"Why does HF have a markedly higher boiling point than HCl despite HCl having a larger molar mass?","o":["HF forms intermolecular hydrogen bonds","HCl is nonpolar","HF has stronger London forces","HCl has hydrogen bonding, HF does not"],"c":0,"e":"F is highly electronegative and small, so HF forms strong N/O/F hydrogen bonds, raising its boiling point above HCl."},
  {"i":"chem-b3-0496","g":11,"u":"Physical States of Matter","d":"hard","t":"calculation","q":"A 4.0 L sample of nitrogen at 27 °C and 1.0 atm is compressed to 2.0 L and heated to 127 °C. What is the new pressure?","o":["2.67 atm","1.50 atm","3.00 atm","2.00 atm"],"c":0,"e":"P₂ = P₁V₁T₂/(T₁V₂) = (1.0)(4.0)(400)/((300)(2.0)) = 1600/600 = 2.67 atm (T in K)."},
  {"i":"chem-b3-0497","g":11,"u":"Physical States of Matter","d":"hard","t":"calculation","q":"What is the density of CO₂ gas (M = 44 g/mol) at 2.0 atm and 300 K? (R = 0.0821 L·atm·mol⁻¹·K⁻¹)","o":["3.57 g/L","1.79 g/L","7.14 g/L","2.44 g/L"],"c":0,"e":"d = PM/RT = (2.0×44)/(0.0821×300) = 88/24.63 = 3.57 g/L."},
  {"i":"chem-b3-0498","g":11,"u":"Physical States of Matter","d":"hard","t":"calculation","q":"At a given temperature, gas X effuses 1.5 times faster than an unknown gas Y. If M(X) = 32 g/mol, what is the molar mass of Y?","o":["72 g/mol","48 g/mol","21.3 g/mol","64 g/mol"],"c":0,"e":"By Graham's law, rate_X/rate_Y = √(M_Y/M_X) → 1.5 = √(M_Y/32) → M_Y = 2.25×32 = 72 g/mol."},
  {"i":"chem-b3-0499","g":11,"u":"Chemical Kinetics","d":"hard","t":"calculation","q":"A reaction is second order in A with rate constant k = 0.025 L·mol⁻¹·s⁻¹. Starting from [A]₀ = 0.50 M, what is [A] after 40 s?","o":["0.33 M","0.25 M","0.40 M","0.50 M"],"c":0,"e":"Second order: 1/[A] = 1/[A]₀ + kt = 1/0.50 + 0.025×40 = 2.0 + 1.0 = 3.0 → [A] = 0.333 ≈ 0.33 M."},
  {"i":"chem-b3-0500","g":11,"u":"Chemical Kinetics","d":"hard","t":"conceptual","q":"For the rate law rate = k[A][B]², what happens to the rate if [A] is halved and [B] is tripled?","o":["Increases by a factor of 4.5","Increases by a factor of 9","Increases by a factor of 6","Decreases by a factor of 2"],"c":0,"e":"Rate factor = (1/2)(3)² = (0.5)(9) = 4.5, so the rate increases 4.5 times."},
  {"i":"chem-b3-0501","g":11,"u":"Chemical Equilibrium","d":"hard","t":"calculation","q":"For N₂O₄(g) ⇌ 2NO₂(g), 0.20 mol N₂O₄ is placed in a 1.0 L vessel and 25% dissociates at equilibrium. What is Kc?","o":["0.067","0.033","0.013","0.10"],"c":0,"e":"Dissociated = 0.05 mol: [N₂O₄]=0.15, [NO₂]=0.10. Kc = (0.10)²/0.15 = 0.010/0.15 = 0.067."},
  {"i":"chem-b3-0502","g":11,"u":"Chemical Equilibrium","d":"hard","t":"calculation","q":"What is the pH of a 0.10 M acetic acid solution? (Ka = 1.8×10⁻⁵)","o":["2.87","3.74","4.74","1.00"],"c":0,"e":"[H⁺] = √(Ka·C) = √(1.8×10⁻⁵×0.10) = √(1.8×10⁻⁶) = 1.34×10⁻³; pH = −log(1.34×10⁻³) = 2.87."},
  {"i":"chem-b3-0503","g":11,"u":"Chemical Equilibrium","d":"hard","t":"calculation","q":"A buffer is made from 0.20 M NH₃ and 0.30 M NH₄Cl. What is the pH? (Kb of NH₃ = 1.8×10⁻⁵)","o":["9.08","9.43","4.92","8.78"],"c":0,"e":"pOH = pKb + log([salt]/[base]) = 4.74 + log(0.30/0.20) = 4.74 + 0.176 = 4.92; pH = 14 − 4.92 = 9.08."},
  {"i":"chem-b3-0504","g":11,"u":"Chemical Equilibrium","d":"hard","t":"calculation","q":"What is the pH of a solution prepared by mixing 50 mL of 0.10 M HCl with 50 mL of 0.10 M NaOH?","o":["7.00","1.00","13.00","3.00"],"c":0,"e":"Moles HCl = moles NaOH = 0.005 mol, exact neutralization gives only NaCl and water, so pH = 7.00."},
  {"i":"chem-b3-0505","g":11,"u":"Oxygen-Containing Organic Compounds","d":"hard","t":"calculation","q":"Complete combustion of 0.10 mol of an alcohol CₙH₂ₙ₊₁OH produces 0.30 mol CO₂. What is the alcohol?","o":["Propan-1-ol","Ethanol","Methanol","Butan-1-ol"],"c":0,"e":"Moles CO₂/moles alcohol = n = 0.30/0.10 = 3, so the alcohol has 3 carbons: C₃H₇OH (propan-1-ol)."},
  {"i":"chem-b3-0506","g":11,"u":"Oxygen-Containing Organic Compounds","d":"hard","t":"conceptual","q":"Oxidation of a secondary alcohol such as propan-2-ol with acidified K₂Cr₂O₇ produces which product?","o":["Propanone (a ketone)","Propanoic acid","Propanal","Propane"],"c":0,"e":"Secondary alcohols oxidize to ketones; propan-2-ol gives propanone (acetone). Carboxylic acids form only from primary alcohols."},
  {"i":"chem-b3-0507","g":11,"u":"Oxygen-Containing Organic Compounds","d":"hard","t":"application","q":"Ethanol from Ethiopian sugar-cane molasses reacts with ethanoic acid in the presence of concentrated H₂SO₄. What type of product forms, and what is its name?","o":["An ester, ethyl ethanoate","An ether, diethyl ether","A carboxylic acid, butanoic acid","An aldehyde, ethanal"],"c":0,"e":"Acid-catalyzed esterification of an alcohol with a carboxylic acid gives an ester plus water: CH₃COOH + C₂H₅OH → CH₃COOC₂H₅ (ethyl ethanoate)."},
  {"i":"chem-b3-0508","g":11,"u":"Oxygen-Containing Organic Compounds","d":"hard","t":"conceptual","q":"Which pair of compounds are functional-group isomers having the molecular formula C₃H₆O?","o":["Propanal and propanone","Propanal and propan-1-ol","Propanone and propanoic acid","Propan-1-ol and propan-2-ol"],"c":0,"e":"Propanal (aldehyde) and propanone (ketone) both have formula C₃H₆O but different functional groups, making them functional isomers."},
  {"i":"chem-b3-0509","g":11,"u":"Atomic Structure & Periodic Properties","d":"hard","t":"calculation","q":"Chlorine has two stable isotopes, ³⁵Cl and ³⁷Cl. If the relative atomic mass on the periodic table is 35.5, what is the percentage abundance of the heavier isotope ³⁷Cl?","o":["25%","50%","75%","37%"],"c":0,"e":"Let x = fraction of ³⁷Cl: 35(1−x) + 37x = 35.5, so 2x = 0.5, x = 0.25 = 25%."},
  {"i":"chem-b3-0510","g":11,"u":"Atomic Structure & Periodic Properties","d":"hard","t":"conceptual","q":"An element X has the ground-state electron configuration 1s² 2s² 2p⁶ 3s² 3p⁶ 4s² 3d¹⁰ 4p³. To which group and period of the periodic table does X belong?","o":["Group VA (15), Period 4","Group IIIA (13), Period 4","Group VA (15), Period 3","Group VIIA (17), Period 4"],"c":0,"e":"The highest principal quantum number is n = 4 (Period 4); the valence electrons 4s² 4p³ total 5, placing X in Group VA (15). This is arsenic."},
  {"i":"chem-b3-0511","g":11,"u":"Chemical Bonding","d":"hard","t":"conceptual","q":"Among CO₂, H₂O, NH₃ and BF₃, which molecule is non-polar despite containing polar covalent bonds, owing to its symmetric geometry?","o":["H₂O only","NH₃ only","CO₂ and BF₃","NH₃ and H₂O"],"c":2,"e":"CO₂ is linear and BF₃ is trigonal planar, so their bond dipoles cancel giving zero net dipole; H₂O (bent) and NH₃ (pyramidal) are asymmetric and remain polar."},
  {"i":"chem-b3-0512","g":11,"u":"Chemical Bonding","d":"hard","t":"calculation","q":"In which species does sulfur have the same oxidation number as the chromium atoms in the dichromate ion, Cr₂O₇²⁻?","o":["SO₃","H₂S","SO₃²⁻","S₂O₃²⁻"],"c":0,"e":"In Cr₂O₇²⁻: 2(Cr) + 7(−2) = −2 gives Cr = +6. In SO₃: S + 3(−2) = 0 gives S = +6, matching; H₂S is −2, SO₃²⁻ is +4, S₂O₃²⁻ averages +2."},
  {"i":"chem-b3-0513","g":11,"u":"Physical States of Matter","d":"hard","t":"calculation","q":"A 5.6 L sample of an ideal gas at STP is heated so that its absolute temperature doubles and its pressure is halved. What is the new volume of the gas?","o":["11.2 L","5.6 L","22.4 L","2.8 L"],"c":2,"e":"Combined gas law: V₂ = V₁(P₁/P₂)(T₂/T₁) = 5.6 × 2 × 2 = 22.4 L."},
  {"i":"chem-b3-0514","g":11,"u":"Physical States of Matter","d":"hard","t":"calculation","q":"What mass of glucose, C₆H₁₂O₆ (M = 180 g/mol), must be dissolved to prepare 250 mL of a 2.0 mol/L solution for a laboratory exercise in Addis Ababa?","o":["45 g","90 g","180 g","22.5 g"],"c":1,"e":"n = C × V = 2.0 mol/L × 0.250 L = 0.50 mol; mass = 0.50 × 180 = 90 g."},
  {"i":"chem-b3-0515","g":11,"u":"Chemical Kinetics","d":"hard","t":"application","q":"For the reaction 2A + B → products, doubling [A] doubles the rate, while doubling [B] increases the rate fourfold. What is the overall order of the reaction?","o":["2","3","4","1"],"c":1,"e":"Rate doubling with [A] means first order in A; a fourfold increase with [B] means second order in B; overall order = 1 + 2 = 3."},
  {"i":"chem-b3-0516","g":11,"u":"Chemical Kinetics","d":"hard","t":"conceptual","q":"Increasing the temperature of a reaction speeds it up mainly because it increases the:","o":["activation energy of the reaction","fraction of molecules with energy ≥ Eₐ","enthalpy change of the reaction","equilibrium constant only"],"c":1,"e":"Higher temperature widens the Maxwell–Boltzmann distribution so a larger fraction of collisions exceeds the activation energy Eₐ; Eₐ itself and ΔH are not changed by temperature."},
  {"i":"chem-b3-0517","g":11,"u":"Chemical Equilibrium","d":"hard","t":"calculation","q":"For N₂(g) + 3H₂(g) ⇌ 2NH₃(g) at equilibrium, [N₂] = 0.50 M, [H₂] = 0.50 M and [NH₃] = 0.50 M. What is the value of Kc?","o":["1.0","2.0","4.0","0.25"],"c":2,"e":"Kc = [NH₃]²/([N₂][H₂]³) = (0.50)²/((0.50)(0.50)³) = 0.25/(0.50 × 0.125) = 4.0."},
  {"i":"chem-b3-0518","g":11,"u":"Chemical Equilibrium","d":"hard","t":"calculation","q":"A 0.10 mol/L solution of ethanoic acid (CH₃COOH) has Ka = 1.8 × 10⁻⁵. Assuming x is small, what is the approximate pH of the solution?","o":["2.87","4.74","3.74","1.00"],"c":0,"e":"[H⁺] = √(Ka × C) = √(1.8×10⁻⁵ × 0.10) = √(1.8×10⁻⁶) = 1.34×10⁻³; pH = −log(1.34×10⁻³) ≈ 2.87."},
  {"i":"chem-b3-0519","g":11,"u":"Chemical Equilibrium","d":"hard","t":"calculation","q":"A buffer is made by mixing equal volumes of 0.40 mol/L ammonia (Kb = 1.8 × 10⁻⁵) with 0.40 mol/L ammonium chloride. What is the pH of this buffer at 25 °C?","o":["9.26","4.74","11.13","8.74"],"c":0,"e":"Equal concentrations of base and conjugate acid give pOH = pKb = −log(1.8×10⁻⁵) = 4.74; pH = 14 − 4.74 = 9.26."},
  {"i":"chem-b3-0520","g":11,"u":"Oxygen-Containing Organic Compounds","d":"hard","t":"application","q":"When ethanol is heated with acidified potassium dichromate under reflux (excess oxidant), what is the final organic product?","o":["Ethanal (CH₃CHO)","Ethanoic acid (CH₃COOH)","Ethene (C₂H₄)","Ethoxyethane"],"c":1,"e":"A primary alcohol is first oxidized to the aldehyde (ethanal); under reflux with excess oxidant it is further oxidized to the carboxylic acid, ethanoic acid."},
  {"i":"chem-b3-0521","g":11,"u":"Oxygen-Containing Organic Compounds","d":"hard","t":"calculation","q":"Complete combustion of a sample of propane (C₃H₈) yields 8.8 g of CO₂. What mass of propane was burned? (M: C₃H₈ = 44, CO₂ = 44 g/mol)","o":["2.93 g","8.80 g","0.98 g","4.40 g"],"c":0,"e":"C₃H₈ + 5O₂ → 3CO₂ + 4H₂O. n(CO₂) = 8.8/44 = 0.20 mol; n(C₃H₈) = 0.20/3 = 0.0667 mol; mass = 0.0667 × 44 = 2.93 g."},
  {"i":"chem-b3-0522","g":11,"u":"Atomic Structure & Periodic Properties","d":"impossible","t":"calculation","q":"A sample of gallium contains only ⁶⁹Ga (68.926 u) and ⁷¹Ga (70.925 u) and has an average atomic mass of 69.723 u. What percent of the atoms are ⁷¹Ga?","o":["39.9%","60.1%","30.1%","69.7%"],"c":0,"e":"Let x = fraction of ⁷¹Ga: 70.925x + 68.926(1−x) = 69.723, so 1.999x = 0.797, x = 0.399 = 39.9%."},
  {"i":"chem-b3-0523","g":11,"u":"Atomic Structure & Periodic Properties","d":"impossible","t":"calculation","q":"The first four successive ionization energies (MJ/mol) of an element are 0.738, 1.451, 7.733, 10.54. To which group does it most likely belong?","o":["Group 1 (IA)","Group 2 (IIA)","Group 13 (IIIA)","Group 14 (IVA)"],"c":1,"e":"A large jump occurs after the 2nd ionization (1.451 → 7.733), showing two easily removed valence electrons and a stable noble-gas core, so it is Group 2 (Mg)."},
  {"i":"chem-b3-0524","g":11,"u":"Atomic Structure & Periodic Properties","d":"impossible","t":"calculation","q":"An electron in a hydrogen atom falls from n=4 to n=2. Using the Rydberg constant 1.097×10⁷ m⁻¹, the wavelength of emitted light is closest to:","o":["486 nm","656 nm","434 nm","410 nm"],"c":0,"e":"1/λ = R(1/4 − 1/16) = 1.097×10⁷ × (3/16) = 2.057×10⁶ m⁻¹, so λ = 4.86×10⁻⁷ m = 486 nm (Balmer Hβ line)."},
  {"i":"chem-b3-0525","g":11,"u":"Atomic Structure & Periodic Properties","d":"impossible","t":"conceptual","q":"Which ground-state species has exactly 3 unpaired electrons and is paramagnetic?","o":["Cr³⁺ (Z=24)","Fe²⁺ (Z=26)","Ni²⁺ (Z=28)","Zn²⁺ (Z=30)"],"c":0,"e":"Cr³⁺ is [Ar]3d³, giving three unpaired d electrons; Fe²⁺ has 4, Ni²⁺ has 2, and Zn²⁺ (d¹⁰) has none."},
  {"i":"chem-b3-0526","g":11,"u":"Chemical Bonding","d":"impossible","t":"calculation","q":"Using bond enthalpies (kJ/mol): H–H 436, Cl–Cl 242, H–Cl 431, estimate ΔH for H₂(g) + Cl₂(g) → 2HCl(g).","o":["−184 kJ","−247 kJ","+184 kJ","−93 kJ"],"c":0,"e":"ΔH = (436 + 242) − 2(431) = 678 − 862 = −184 kJ, exothermic as bonds formed release more than bonds broken absorb."},
  {"i":"chem-b3-0527","g":11,"u":"Chemical Bonding","d":"impossible","t":"conceptual","q":"According to MO theory, which diatomic species has a bond order of 2.5 and is paramagnetic?","o":["O₂⁺","N₂","O₂","F₂"],"c":0,"e":"O₂⁺ has 15 electrons: bond order = (10−5)/2 = 2.5 with one unpaired electron, so it is paramagnetic; N₂ is 3, O₂ is 2, F₂ is 1."},
  {"i":"chem-b3-0528","g":11,"u":"Chemical Bonding","d":"impossible","t":"conceptual","q":"Which molecule has a nonzero dipole moment despite all bonds being to identical atoms?","o":["SF₄","XeF₄","BF₃","CF₄"],"c":0,"e":"SF₄ has a see-saw geometry (one lone pair on S) that does not cancel bond dipoles; XeF₄ (square planar), BF₃ (trigonal planar), and CF₄ (tetrahedral) are all symmetric and nonpolar."},
  {"i":"chem-b3-0529","g":11,"u":"Chemical Bonding","d":"impossible","t":"application","q":"A central atom uses sp³d² hybridization with two lone pairs. What is the molecular geometry?","o":["Square planar","Octahedral","See-saw","Trigonal bipyramidal"],"c":0,"e":"sp³d² gives six electron domains (octahedral); with two lone pairs occupying axial positions, the four bonding pairs form a square planar shape (e.g., XeF₄)."},
  {"i":"chem-b3-0530","g":11,"u":"Physical States of Matter","d":"impossible","t":"calculation","q":"A real gas obeys van der Waals. For 2.0 mol in a 5.0 L vessel at 300 K with a = 3.6 L²·atm·mol⁻² and b = 0.043 L·mol⁻¹, the pressure correction term n²a/V² subtracted from ideal pressure is:","o":["0.576 atm","1.44 atm","0.288 atm","2.88 atm"],"c":0,"e":"n²a/V² = (2.0)²(3.6)/(5.0)² = 14.4/25 = 0.576 atm, the attraction term lowering observed pressure below ideal."},
  {"i":"chem-b3-0531","g":11,"u":"Physical States of Matter","d":"impossible","t":"calculation","q":"Two gases effuse through the same orifice. Gas X effuses 1.5 times faster than gas Y. If Y is O₂ (32 g/mol), the molar mass of X is closest to:","o":["14.2 g/mol","48 g/mol","21.3 g/mol","72 g/mol"],"c":0,"e":"By Graham's law rₓ/r_Y = √(M_Y/Mₓ): 1.5 = √(32/Mₓ), so Mₓ = 32/2.25 = 14.2 g/mol."},
  {"i":"chem-b3-0532","g":11,"u":"Physical States of Matter","d":"impossible","t":"calculation","q":"A 0.250 L flask holds an unknown gas at 27 °C and 1.20 atm with mass 0.366 g. Its molar mass (R=0.0821) is closest to:","o":["30.0 g/mol","44.0 g/mol","36.6 g/mol","24.0 g/mol"],"c":0,"e":"n = PV/RT = (1.20×0.250)/(0.0821×300) = 0.01218 mol; M = 0.366/0.01218 = 30.0 g/mol."},
  {"i":"chem-b3-0533","g":11,"u":"Chemical Kinetics","d":"impossible","t":"calculation","q":"A reaction is first order with a rate constant of 0.0231 min⁻¹. What fraction of reactant remains after 100 minutes?","o":["0.099","0.231","0.901","0.050"],"c":0,"e":"[A]/[A]₀ = e^(−kt) = e^(−0.0231×100) = e^(−2.31) = 0.099, so about 9.9% remains (t½ ≈ 30 min, ~3.3 half-lives)."},
  {"i":"chem-b3-0534","g":11,"u":"Chemical Kinetics","d":"impossible","t":"calculation","q":"A rate doubles when [A] doubles, and quadruples when [B] doubles (with [A] fixed). If both [A] and [B] are tripled, the rate increases by a factor of:","o":["27","9","6","81"],"c":0,"e":"Order is 1 in A and 2 in B, so factor = 3¹ × 3² = 3 × 9 = 27."},
  {"i":"chem-b3-0535","g":11,"u":"Chemical Kinetics","d":"impossible","t":"calculation","q":"A reaction rate constant doubles when temperature rises from 300 K to 310 K. Using the Arrhenius equation (R=8.314 J·mol⁻¹·K⁻¹), the activation energy is closest to:","o":["53.6 kJ/mol","26.8 kJ/mol","107 kJ/mol","5.36 kJ/mol"],"c":0,"e":"ln2 = (Eₐ/R)(1/300 − 1/310) = (Eₐ/8.314)(1.075×10⁻⁴); Eₐ = 0.693×8.314/1.075×10⁻⁴ = 53,600 J ≈ 53.6 kJ/mol."},
  {"i":"chem-b3-0536","g":11,"u":"Chemical Equilibrium","d":"impossible","t":"calculation","q":"For N₂O₄(g) ⇌ 2NO₂(g), 1.00 mol N₂O₄ in a 1.00 L vessel is 20% dissociated at equilibrium. The value of Kc is:","o":["0.20","0.10","0.40","0.050"],"c":0,"e":"At equilibrium [N₂O₄]=0.80, [NO₂]=0.40; Kc = (0.40)²/0.80 = 0.16/0.80 = 0.20."},
  {"i":"chem-b3-0537","g":11,"u":"Chemical Equilibrium","d":"impossible","t":"calculation","q":"Acetic acid (Ka = 1.8×10⁻⁵) is prepared at 0.10 M. The pH of the solution is closest to:","o":["2.87","2.37","4.74","3.37"],"c":0,"e":"[H⁺] = √(Ka·C) = √(1.8×10⁻⁵×0.10) = √(1.8×10⁻⁶) = 1.34×10⁻³; pH = −log(1.34×10⁻³) = 2.87."},
  {"i":"chem-b3-0538","g":11,"u":"Chemical Equilibrium","d":"impossible","t":"calculation","q":"A buffer is made from 0.20 M NH₃ and 0.30 M NH₄Cl. Given Kb(NH₃) = 1.8×10⁻⁵, the pH is closest to:","o":["9.08","9.43","4.92","8.74"],"c":0,"e":"pKa(NH₄⁺) = 14 − pKb = 14 − 4.74 = 9.26; pH = pKa + log([NH₃]/[NH₄⁺]) = 9.26 + log(0.20/0.30) = 9.26 − 0.18 = 9.08."},
  {"i":"chem-b3-0539","g":11,"u":"Chemical Equilibrium","d":"impossible","t":"calculation","q":"The solubility product of Mg(OH)₂ is 5.6×10⁻¹². Its molar solubility in pure water is closest to:","o":["1.1×10⁻⁴ M","2.4×10⁻⁶ M","5.6×10⁻⁴ M","1.7×10⁻⁶ M"],"c":0,"e":"Ksp = (s)(2s)² = 4s³ = 5.6×10⁻¹², so s³ = 1.4×10⁻¹², s = 1.12×10⁻⁴ M."},
  {"i":"chem-b3-0540","g":11,"u":"Chemical Equilibrium","d":"impossible","t":"calculation","q":"In the cell Zn|Zn²⁺(1M)||Cu²⁺(1M)|Cu with E°(Zn²⁺/Zn)=−0.76 V and E°(Cu²⁺/Cu)=+0.34 V, the standard ΔG° (F=96485 C/mol) is closest to:","o":["−212 kJ","−106 kJ","+212 kJ","−1.10 kJ"],"c":0,"e":"E°cell = 0.34 − (−0.76) = 1.10 V; ΔG° = −nFE° = −(2)(96485)(1.10) = −212,000 J ≈ −212 kJ."},
  {"i":"chem-b3-0541","g":11,"u":"Oxygen-Containing Organic Compounds","d":"impossible","t":"calculation","q":"Complete combustion of 0.10 mol of a saturated monohydric alcohol CₙH₂ₙ₊₁OH yields 13.2 g CO₂. What is the alcohol?","o":["Propan-1-ol","Ethanol","Methanol","Butan-1-ol"],"c":0,"e":"Moles CO₂ = 13.2/44 = 0.30; carbons per molecule = 0.30/0.10 = 3, so n=3: C₃H₇OH, propan-1-ol."},
  {"i":"chem-b3-0542","g":11,"u":"Oxygen-Containing Organic Compounds","d":"impossible","t":"conceptual","q":"Which sequence correctly orders the compounds by increasing boiling point: propane, propan-1-ol, propanal, ethanoic acid?","o":["propane < propanal < propan-1-ol < ethanoic acid","propanal < propane < propan-1-ol < ethanoic acid","propane < propan-1-ol < propanal < ethanoic acid","ethanoic acid < propan-1-ol < propanal < propane"],"c":0,"e":"Propane has only dispersion forces; propanal adds dipole-dipole; propan-1-ol has H-bonding; ethanoic acid forms strong dimers, giving the highest boiling point."},
  {"i":"chem-b3-0543","g":11,"u":"Oxygen-Containing Organic Compounds","d":"impossible","t":"application","q":"Oxidation of a secondary alcohol with acidified K₂Cr₂O₇ gives propanone (acetone). The starting alcohol is:","o":["Propan-2-ol","Propan-1-ol","Ethanol","2-methylpropan-2-ol"],"c":0,"e":"Secondary alcohols oxidize to ketones; propan-2-ol (CH₃CHOHCH₃) oxidizes to propanone. Propan-1-ol (primary) gives an aldehyde/acid and the tertiary alcohol resists oxidation."},
  {"i":"chem-b3-0544","g":11,"u":"Atomic Structure & Periodic Properties","d":"impossible","t":"calculation","q":"A sample of naturally occurring boron has an average atomic mass of 10.81 u and consists only of ¹⁰B (10.013 u) and ¹¹B (11.009 u). In a pure compound containing exactly 4.00 mol of boron atoms, how many moles of the ¹¹B isotope are present?","o":["3.20 mol","3.18 mol","0.800 mol","2.40 mol"],"c":0,"e":"Let x = fraction of ¹¹B: 11.009x + 10.013(1−x) = 10.81 → 0.996x = 0.797 → x = 0.800. Moles of ¹¹B = 0.800 × 4.00 = 3.20 mol."},
  {"i":"chem-b3-0545","g":11,"u":"Chemical Bonding","d":"impossible","t":"conceptual","q":"For the species XeF₄, predict the electron-domain geometry around Xe and the resulting molecular shape, given that Xe contributes 8 valence electrons and forms 4 Xe–F bonds.","o":["Octahedral domains; square planar molecule","Tetrahedral domains; tetrahedral molecule","Trigonal bipyramidal domains; seesaw molecule","Octahedral domains; square pyramidal molecule"],"c":0,"e":"Xe has 4 bonding pairs and 2 lone pairs (6 domains → octahedral). The two lone pairs occupy opposite axial positions to minimise repulsion, leaving the four F atoms in a square planar arrangement."},
  {"i":"chem-b3-0546","g":11,"u":"Oxygen-Containing Organic Compounds","d":"impossible","t":"calculation","q":"Complete combustion of 0.100 mol of a saturated monohydric alcohol CₙH₂ₙ₊₁OH produces 13.2 g of CO₂. What is the alcohol?","o":["Propan-1-ol (C₃H₇OH)","Ethanol (C₂H₅OH)","Methanol (CH₃OH)","Butan-1-ol (C₄H₉OH)"],"c":0,"e":"Moles CO₂ = 13.2/44 = 0.300 mol; carbons per molecule = 0.300/0.100 = 3, so n = 3, giving propan-1-ol C₃H₇OH."},
  {"i":"chem-b3-0547","g":11,"u":"Chemical Equilibrium","d":"impossible","t":"calculation","q":"Ethanoic acid has Ka = 1.8×10⁻⁵. A buffer is made by dissolving 0.20 mol CH₃COOH and 0.10 mol CH₃COONa in 1.0 L of water. What is the pH (log 1.8 = 0.26)?","o":["4.44","4.74","5.04","3.74"],"c":0,"e":"pH = pKa + log([salt]/[acid]) = 4.74 + log(0.10/0.20) = 4.74 + log(0.5) = 4.74 − 0.30 = 4.44."},
  {"i":"chem-b3-0548","g":11,"u":"Chemical Kinetics","d":"impossible","t":"calculation","q":"A reaction is first order in A and first order in B. When [A] is tripled and [B] is halved simultaneously, by what factor does the initial rate change?","o":["× 1.5","× 3.0","× 6.0","× 0.5"],"c":0,"e":"Rate = k[A][B]. New rate factor = 3 × (1/2) = 1.5, so the rate increases by a factor of 1.5."},
  {"i":"chem-b3-0549","g":11,"u":"Physical States of Matter","d":"impossible","t":"calculation","q":"A fixed mass of ideal gas occupies 2.00 L at 27 °C and 1.00 atm. It is heated to 127 °C while the pressure is raised to 2.00 atm. What is the new volume?","o":["1.33 L","1.50 L","3.00 L","2.67 L"],"c":0,"e":"Combined gas law: V₂ = V₁(P₁/P₂)(T₂/T₁) = 2.00 × (1.00/2.00) × (400/300) = 2.00 × 0.5 × 1.333 = 1.33 L."},
  {"i":"chem-b3-0550","g":11,"u":"Atomic Structure & Periodic Properties","d":"impossible","t":"application","q":"An element X (Z = 33) is found in trace amounts in some Rift Valley groundwater. Using its ground-state electron configuration, identify its period, group, and expected most common oxidation states.","o":["Period 4, Group VA, oxidation states +3 and +5","Period 4, Group IIIA, oxidation states +1 and +3","Period 3, Group VA, oxidation states −3 and +5","Period 4, Group VIA, oxidation states +4 and +6"],"c":0,"e":"Z = 33 gives [Ar]3d¹⁰4s²4p³: the 4p³ valence places it in Period 4, Group VA (arsenic), which characteristically shows +3 and +5 oxidation states."},
  {"i":"chem-b3-0551","g":11,"u":"Chemical Equilibrium","d":"impossible","t":"calculation","q":"For N₂(g) + 3H₂(g) ⇌ 2NH₃(g), 1.00 mol N₂ and 3.00 mol H₂ are placed in a 1.00 L vessel. At equilibrium 1.00 mol NH₃ has formed. What is Kc?","o":["0.593","0.119","1.00","0.296"],"c":0,"e":"Forming 1.00 mol NH₃ consumes 0.50 mol N₂ and 1.50 mol H₂, giving [N₂]=0.50, [H₂]=1.50, [NH₃]=1.00. Kc = (1.00)²/((0.50)(1.50)³) = 1.00/1.6875 = 0.593."},
  {"i":"chem-b3-0552","g":11,"u":"Chemical Bonding","d":"impossible","t":"calculation","q":"Using bond enthalpies (H–H 436, Cl–Cl 242, H–Cl 431 kJ/mol), calculate the standard enthalpy change for H₂(g) + Cl₂(g) → 2HCl(g).","o":["−184 kJ","−431 kJ","+184 kJ","−92 kJ"],"c":0,"e":"ΔH = Σ(bonds broken) − Σ(bonds formed) = (436 + 242) − (2 × 431) = 678 − 862 = −184 kJ."},
  {"i":"chem-b3-0553","g":11,"u":"Oxygen-Containing Organic Compounds","d":"impossible","t":"conceptual","q":"A compound with molecular formula C₃H₆O gives a positive Tollens' (silver mirror) test and a positive 2,4-DNPH test but a negative iodoform test. What is its identity?","o":["Propanal (CH₃CH₂CHO)","Propanone (CH₃COCH₃)","Prop-2-en-1-ol (CH₂=CHCH₂OH)","Methoxyethene (CH₃OCH=CH₂)"],"c":0,"e":"Positive 2,4-DNPH indicates a carbonyl; positive Tollens' means an aldehyde; negative iodoform rules out CH₃CO– groups. Propanal is the aldehyde without a CH₃CO– group, whereas propanone (a methyl ketone) would give iodoform but no silver mirror."},
  {"i":"chem-b3-0554","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"definition","q":"According to the Arrhenius theory, an acid is a substance that, when dissolved in water, increases the concentration of which ion?","o":["OH⁻","H⁺ (H₃O⁺)","Na⁺","Cl⁻"],"c":1,"e":"An Arrhenius acid ionizes in water to release H⁺ (hydronium, H₃O⁺) ions; a base releases OH⁻."},
  {"i":"chem-b3-0555","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"calculation","q":"What is the pH of a solution whose hydrogen-ion concentration [H⁺] is 1×10⁻³ mol/L at 25 °C?","o":["3","11","7","4"],"c":0,"e":"pH = −log[H⁺] = −log(1×10⁻³) = 3."},
  {"i":"chem-b3-0556","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"calculation","q":"If a solution has pOH = 9 at 25 °C, what is its pH?","o":["9","5","7","14"],"c":1,"e":"At 25 °C, pH + pOH = 14, so pH = 14 − 9 = 5."},
  {"i":"chem-b3-0557","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"conceptual","q":"In the Brønsted–Lowry theory, what is the conjugate base of the ammonium ion (NH₄⁺)?","o":["NH₃","NH₂⁻","N₂","OH⁻"],"c":0,"e":"A Brønsted–Lowry acid loses a proton to form its conjugate base; NH₄⁺ loses H⁺ to give NH₃."},
  {"i":"chem-b3-0558","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"calculation","q":"A weak acid HA has [H⁺] = 1×10⁻⁴ mol/L at equilibrium. What is the pH of this solution at 25 °C?","o":["10","4","8","3"],"c":1,"e":"pH = −log(1×10⁻⁴) = 4."},
  {"i":"chem-b3-0559","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"conceptual","q":"Which of the following is classified as a strong acid in aqueous solution?","o":["CH₃COOH","H₂CO₃","HCl","H₃PO₄"],"c":2,"e":"HCl ionizes essentially completely in water, making it a strong acid; the others are weak acids."},
  {"i":"chem-b3-0560","g":12,"u":"Electrochemistry","d":"easy","t":"definition","q":"In any electrochemical cell, oxidation always takes place at which electrode?","o":["Cathode","Anode","Salt bridge","Electrolyte"],"c":1,"e":"By definition, oxidation (loss of electrons) occurs at the anode and reduction at the cathode."},
  {"i":"chem-b3-0561","g":12,"u":"Electrochemistry","d":"easy","t":"conceptual","q":"What is the oxidation number of manganese (Mn) in the permanganate ion, MnO₄⁻?","o":["+2","+4","+7","+6"],"c":2,"e":"With each O at −2 (4×−2 = −8) and overall charge −1: Mn + (−8) = −1, so Mn = +7."},
  {"i":"chem-b3-0562","g":12,"u":"Electrochemistry","d":"easy","t":"conceptual","q":"In a galvanic (voltaic) cell, the spontaneous reaction produces a cell potential E°cell that is:","o":["Negative","Zero","Positive","Always 1.23 V"],"c":2,"e":"A spontaneous galvanic cell reaction has a positive E°cell, corresponding to negative ΔG."},
  {"i":"chem-b3-0563","g":12,"u":"Electrochemistry","d":"easy","t":"conceptual","q":"During the electrolysis of molten sodium chloride, which species is reduced at the cathode?","o":["Cl⁻","Na⁺","O₂","H₂O"],"c":1,"e":"At the cathode Na⁺ gains an electron (Na⁺ + e⁻ → Na), so sodium ions are reduced."},
  {"i":"chem-b3-0564","g":12,"u":"Electrochemistry","d":"easy","t":"calculation","q":"What is the oxidation number of chromium (Cr) in the dichromate ion, Cr₂O₇²⁻?","o":["+3","+6","+7","+2"],"c":1,"e":"7 O at −2 = −14; for charge −2: 2Cr − 14 = −2, so 2Cr = +12, Cr = +6."},
  {"i":"chem-b3-0565","g":12,"u":"Electrochemistry","d":"easy","t":"definition","q":"In electrochemistry, the part that allows ions to flow between the two half-cells and keeps them electrically neutral is the:","o":["Salt bridge","Voltmeter","Anode","External wire"],"c":0,"e":"The salt bridge permits ion migration that maintains charge balance and completes the circuit."},
  {"i":"chem-b3-0566","g":12,"u":"Electrochemistry","d":"easy","t":"conceptual","q":"What is the oxidation number of sulfur (S) in sulfuric acid, H₂SO₄?","o":["+4","+2","+6","−2"],"c":2,"e":"H is +1 (2×+1 = +2), O is −2 (4×−2 = −8); for neutral molecule: 2 + S − 8 = 0, so S = +6."},
  {"i":"chem-b3-0567","g":12,"u":"Industrial Chemistry","d":"easy","t":"definition","q":"The Haber process is the industrial method used to synthesize which compound?","o":["Sulfuric acid","Ammonia (NH₃)","Nitric acid","Sodium carbonate"],"c":1,"e":"The Haber process combines N₂ and H₂ over an iron catalyst to produce ammonia: N₂ + 3H₂ ⇌ 2NH₃."},
  {"i":"chem-b3-0568","g":12,"u":"Industrial Chemistry","d":"easy","t":"definition","q":"In the Contact process for manufacturing sulfuric acid, sulfur dioxide is converted to sulfur trioxide. The balanced equation is 2SO₂ + O₂ → 2SO₃. Which catalyst is used?","o":["Iron (Fe)","Nickel (Ni)","Vanadium(V) oxide (V₂O₅)","Platinum sponge only"],"c":2,"e":"The Contact process uses V₂O₅ as catalyst for the oxidation of SO₂ to SO₃."},
  {"i":"chem-b3-0569","g":12,"u":"Industrial Chemistry","d":"easy","t":"application","q":"Many Ethiopian farms use a nitrogen fertilizer made from ammonia. Which fertilizer below supplies nitrogen and is produced from NH₃?","o":["Urea, CO(NH₂)₂","Calcium carbonate, CaCO₃","Sodium chloride, NaCl","Gypsum, CaSO₄"],"c":0,"e":"Urea, CO(NH₂)₂, is a nitrogen fertilizer manufactured from ammonia and carbon dioxide."},
  {"i":"chem-b3-0570","g":12,"u":"Polymers","d":"easy","t":"definition","q":"A polymer is a very large molecule built from many repeating small units called:","o":["Isotopes","Monomers","Isomers","Catalysts"],"c":1,"e":"Polymers are macromolecules formed by joining many small repeating units called monomers."},
  {"i":"chem-b3-0571","g":12,"u":"Polymers","d":"easy","t":"conceptual","q":"Polyethene (polythene) is made from ethene molecules joining together without losing any atoms. This type of polymerization is called:","o":["Condensation polymerization","Addition polymerization","Hydrolysis","Saponification"],"c":1,"e":"Ethene monomers (C=C) add together with no small molecule eliminated, so it is addition polymerization."},
  {"i":"chem-b3-0572","g":12,"u":"Polymers","d":"easy","t":"conceptual","q":"Which of the following is a natural polymer?","o":["Polythene","Nylon","Starch (cellulose)","PVC"],"c":2,"e":"Starch and cellulose are natural polymers of glucose; the others are synthetic polymers."},
  {"i":"chem-b3-0573","g":12,"u":"Introduction to Environmental Chemistry","d":"easy","t":"conceptual","q":"Which gas is the main contributor to the greenhouse effect from the burning of fossil fuels?","o":["Carbon dioxide (CO₂)","Nitrogen (N₂)","Oxygen (O₂)","Argon (Ar)"],"c":0,"e":"CO₂ released by combustion of fossil fuels is the principal greenhouse gas driving warming."},
  {"i":"chem-b3-0574","g":12,"u":"Introduction to Environmental Chemistry","d":"easy","t":"application","q":"Acid rain commonly forms when which oxide dissolves in atmospheric water to give an acidic solution?","o":["Sodium oxide (Na₂O)","Calcium oxide (CaO)","Sulfur dioxide (SO₂)","Magnesium oxide (MgO)"],"c":2,"e":"SO₂ (a non-metal oxide) dissolves in rainwater forming acids (H₂SO₃/H₂SO₄), causing acid rain."},
  {"i":"chem-b3-0575","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"definition","q":"In the Brønsted–Lowry theory, a base is best defined as a species that is a","o":["proton donor","proton acceptor","electron-pair donor","electron-pair acceptor"],"c":1,"e":"A Brønsted–Lowry base accepts a proton (H⁺); the acid is the proton donor."},
  {"i":"chem-b3-0576","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"calculation","q":"A solution has [H⁺] = 1 × 10⁻³ mol/L at 25 °C. What is its pH?","o":["3","11","7","−3"],"c":0,"e":"pH = −log[H⁺] = −log(1×10⁻³) = 3."},
  {"i":"chem-b3-0577","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"calculation","q":"At 25 °C a solution has pOH = 4. What is its pH? (Kw gives pH + pOH = 14)","o":["4","10","14","18"],"c":1,"e":"pH = 14 − pOH = 14 − 4 = 10."},
  {"i":"chem-b3-0578","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"calculation","q":"What is the pH of a 0.01 mol/L solution of the strong acid HCl at 25 °C?","o":["1","2","12","0.01"],"c":1,"e":"HCl fully dissociates, so [H⁺] = 0.01 = 1×10⁻²; pH = −log(10⁻²) = 2."},
  {"i":"chem-b3-0579","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"conceptual","q":"In the equilibrium NH₃ + H₂O ⇌ NH₄⁺ + OH⁻, which species is the conjugate acid of NH₃?","o":["OH⁻","H₂O","NH₄⁺","NH₃"],"c":2,"e":"NH₃ gains a proton to become NH₄⁺, so NH₄⁺ is its conjugate acid."},
  {"i":"chem-b3-0580","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"calculation","q":"A weak acid HA has [H⁺] = 1 × 10⁻⁴ mol/L. Its pH is","o":["4","10","14","−4"],"c":0,"e":"pH = −log(1×10⁻⁴) = 4."},
  {"i":"chem-b3-0581","g":12,"u":"Electrochemistry","d":"easy","t":"definition","q":"In any electrochemical cell, oxidation always takes place at the","o":["cathode","anode","salt bridge","electrolyte"],"c":1,"e":"Oxidation (loss of electrons) occurs at the anode; reduction occurs at the cathode."},
  {"i":"chem-b3-0582","g":12,"u":"Electrochemistry","d":"easy","t":"conceptual","q":"In a galvanic (voltaic) cell, chemical energy is converted directly into","o":["heat energy","electrical energy","light energy","nuclear energy"],"c":1,"e":"A galvanic cell uses a spontaneous redox reaction to convert chemical energy into electrical energy."},
  {"i":"chem-b3-0583","g":12,"u":"Electrochemistry","d":"easy","t":"definition","q":"A substance that conducts electricity when molten or dissolved in water because it forms free-moving ions is called","o":["an insulator","an electrolyte","a catalyst","a semiconductor"],"c":1,"e":"Electrolytes conduct electricity through mobile ions when molten or in solution."},
  {"i":"chem-b3-0584","g":12,"u":"Electrochemistry","d":"easy","t":"conceptual","q":"During the electrolysis of molten sodium chloride, sodium metal is produced at the cathode because Na⁺ ions are","o":["oxidized","reduced","neutralized","evaporated"],"c":1,"e":"Na⁺ + e⁻ → Na is a gain of electrons (reduction), which occurs at the cathode."},
  {"i":"chem-b3-0585","g":12,"u":"Electrochemistry","d":"easy","t":"application","q":"In the redox reaction Zn + Cu²⁺ → Zn²⁺ + Cu, which species is the reducing agent?","o":["Zn","Cu²⁺","Zn²⁺","Cu"],"c":0,"e":"Zn loses electrons (is oxidized), so it reduces Cu²⁺; the species oxidized is the reducing agent."},
  {"i":"chem-b3-0586","g":12,"u":"Industrial Chemistry","d":"easy","t":"definition","q":"In the Haber process used to manufacture ammonia, nitrogen gas reacts with","o":["oxygen","hydrogen","chlorine","carbon dioxide"],"c":1,"e":"The Haber process combines N₂ and H₂: N₂ + 3H₂ ⇌ 2NH₃."},
  {"i":"chem-b3-0587","g":12,"u":"Industrial Chemistry","d":"easy","t":"definition","q":"The Contact process is the industrial method used to manufacture","o":["nitric acid","ammonia","sulfuric acid","sodium hydroxide"],"c":2,"e":"The Contact process produces sulfuric acid (H₂SO₄) via SO₂ → SO₃ → H₂SO₄."},
  {"i":"chem-b3-0588","g":12,"u":"Industrial Chemistry","d":"easy","t":"conceptual","q":"In the Haber process, which catalyst is commonly used to speed up the formation of ammonia?","o":["platinum","iron","nickel","vanadium(V) oxide"],"c":1,"e":"Finely divided iron is the catalyst in the Haber process; V₂O₅ is used in the Contact process."},
  {"i":"chem-b3-0589","g":12,"u":"Polymers","d":"easy","t":"definition","q":"The small repeating unit from which a polymer is built is called a","o":["monomer","isomer","catalyst","copolymer"],"c":0,"e":"Polymers are large molecules made of many repeating monomer units joined together."},
  {"i":"chem-b3-0590","g":12,"u":"Polymers","d":"easy","t":"conceptual","q":"Polyethene (polythene) is formed from ethene by which type of polymerization?","o":["condensation","addition","hydrolysis","substitution"],"c":1,"e":"Ethene molecules (C₂H₄) add together across their double bonds with no by-product, an addition polymerization."},
  {"i":"chem-b3-0591","g":12,"u":"Polymers","d":"easy","t":"definition","q":"Which of the following is a naturally occurring polymer?","o":["polyvinyl chloride (PVC)","nylon","starch","polystyrene"],"c":2,"e":"Starch is a natural polymer of glucose; PVC, nylon and polystyrene are synthetic polymers."},
  {"i":"chem-b3-0592","g":12,"u":"Introduction to Environmental Chemistry","d":"easy","t":"definition","q":"Which gas is the main contributor to the enhanced greenhouse effect from burning fossil fuels?","o":["nitrogen, N₂","carbon dioxide, CO₂","oxygen, O₂","argon, Ar"],"c":1,"e":"CO₂ released from burning fossil fuels is the principal greenhouse gas driving global warming."},
  {"i":"chem-b3-0593","g":12,"u":"Introduction to Environmental Chemistry","d":"easy","t":"conceptual","q":"Acid rain is most directly caused by oxides of sulfur and nitrogen because they react with rainwater to form","o":["acids","bases","salts only","pure oxygen"],"c":0,"e":"SO₂ and NOₓ dissolve in rainwater to form sulfuric and nitric acids, lowering the pH of rain."},
  {"i":"chem-b3-0594","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"calculation","q":"At 25 °C a solution has pOH = 9. What is its pH?","o":["3","5","9","14"],"c":1,"e":"pH + pOH = 14, so pH = 14 − 9 = 5."},
  {"i":"chem-b3-0595","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"conceptual","q":"In the Brønsted–Lowry sense, what is the conjugate base of HCO₃⁻?","o":["H₂CO₃","CO₃²⁻","CO₂","OH⁻"],"c":1,"e":"A conjugate base is formed by removing one H⁺; HCO₃⁻ loses H⁺ to give CO₃²⁻."},
  {"i":"chem-b3-0596","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"calculation","q":"What is the pH of a 0.01 mol/L solution of the strong acid HNO₃ at 25 °C?","o":["1","2","12","13"],"c":1,"e":"HNO₃ fully ionizes, so [H⁺] = 0.01 = 10⁻²; pH = −log(10⁻²) = 2."},
  {"i":"chem-b3-0597","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"definition","q":"A buffer solution resists large changes in pH when small amounts of acid or base are added. It typically consists of:","o":["A strong acid and a strong base","A weak acid and its conjugate base","Two strong acids","Pure water only"],"c":1,"e":"A buffer is made of a weak acid and its conjugate base (or a weak base and its conjugate acid)."},
  {"i":"chem-b3-0598","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"calculation","q":"For a solution, [H⁺] = 1 × 10⁻⁴ mol/L. What is [OH⁻] at 25 °C (Kw = 1 × 10⁻¹⁴)?","o":["1 × 10⁻⁴","1 × 10⁻¹⁰","1 × 10⁻⁷","1 × 10⁻¹⁴"],"c":1,"e":"[OH⁻] = Kw / [H⁺] = 10⁻¹⁴ / 10⁻⁴ = 10⁻¹⁰ mol/L."},
  {"i":"chem-b3-0599","g":12,"u":"Electrochemistry","d":"easy","t":"conceptual","q":"In a galvanic (voltaic) cell, electrons flow through the external wire from the:","o":["Cathode to the anode","Anode to the cathode","Salt bridge to the anode","Solution to the cathode"],"c":1,"e":"Electrons are released at the anode (oxidation) and travel through the wire to the cathode."},
  {"i":"chem-b3-0600","g":12,"u":"Electrochemistry","d":"easy","t":"definition","q":"Electrolysis is best defined as a process in which:","o":["A spontaneous reaction produces electrical energy","Electrical energy drives a non-spontaneous reaction","Heat decomposes a compound","Light causes a chemical change"],"c":1,"e":"In electrolysis an external electric current forces a non-spontaneous redox reaction to occur."},
  {"i":"chem-b3-0601","g":12,"u":"Electrochemistry","d":"easy","t":"conceptual","q":"During the electrolysis of molten sodium chloride (NaCl), which product is formed at the cathode?","o":["Chlorine gas","Sodium metal","Oxygen gas","Hydrogen gas"],"c":1,"e":"Na⁺ ions are reduced (gain electrons) at the cathode to form sodium metal; Cl₂ forms at the anode."},
  {"i":"chem-b3-0602","g":12,"u":"Industrial Chemistry","d":"easy","t":"definition","q":"In the Haber process used to manufacture ammonia, nitrogen reacts with which other gas?","o":["Oxygen","Hydrogen","Chlorine","Carbon dioxide"],"c":1,"e":"The Haber process combines N₂ and H₂: N₂ + 3H₂ ⇌ 2NH₃."},
  {"i":"chem-b3-0603","g":12,"u":"Industrial Chemistry","d":"easy","t":"conceptual","q":"The Contact process is used industrially to manufacture which of the following acids?","o":["Nitric acid (HNO₃)","Hydrochloric acid (HCl)","Sulfuric acid (H₂SO₄)","Phosphoric acid (H₃PO₄)"],"c":2,"e":"The Contact process produces sulfuric acid via SO₂ → SO₃ → H₂SO₄."},
  {"i":"chem-b3-0604","g":12,"u":"Industrial Chemistry","d":"easy","t":"application","q":"A key raw material for the Ethiopian cement industry, used in large amounts at plants such as Derba, is:","o":["Limestone (CaCO₃)","Common salt (NaCl)","Bauxite (Al₂O₃)","Sulfur (S)"],"c":0,"e":"Cement manufacture relies on limestone (calcium carbonate) as its principal raw material."},
  {"i":"chem-b3-0605","g":12,"u":"Industrial Chemistry","d":"easy","t":"conceptual","q":"In the Haber process, which is the correctly balanced equation for the formation of ammonia?","o":["N₂ + H₂ → NH₃","N₂ + 2H₂ → 2NH₃","N₂ + 3H₂ → 2NH₃","2N₂ + 3H₂ → 2NH₃"],"c":2,"e":"Balancing N and H gives N₂ + 3H₂ → 2NH₃ (2 N and 6 H on each side)."},
  {"i":"chem-b3-0606","g":12,"u":"Polymers","d":"easy","t":"definition","q":"A polymer is best defined as a very large molecule made by joining many small repeating units called:","o":["Isotopes","Monomers","Isomers","Catalysts"],"c":1,"e":"Polymers are built from many repeating small molecules called monomers."},
  {"i":"chem-b3-0607","g":12,"u":"Polymers","d":"easy","t":"conceptual","q":"Which type of polymerization occurs when ethene (CH₂=CH₂) molecules join to form polyethene without losing any atoms?","o":["Condensation polymerization","Addition polymerization","Hydrolysis","Saponification"],"c":1,"e":"Monomers with C=C double bonds add together with no small molecule lost — addition polymerization."},
  {"i":"chem-b3-0608","g":12,"u":"Introduction to Environmental Chemistry","d":"easy","t":"conceptual","q":"Acid rain is mainly caused by oxides of sulfur and nitrogen dissolving in rainwater. Which pair of gases is chiefly responsible?","o":["SO₂ and NO₂","CO₂ and CH₄","O₂ and N₂","H₂ and He"],"c":0,"e":"Sulfur dioxide (SO₂) and nitrogen dioxide (NO₂) form sulfuric and nitric acids in rain."},
  {"i":"chem-b3-0609","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"definition","q":"According to the Brønsted–Lowry theory, an acid is a substance that:","o":["Donates a proton (H⁺)","Accepts a proton (H⁺)","Donates an electron pair","Accepts an electron pair"],"c":0,"e":"A Brønsted–Lowry acid is a proton (H⁺) donor; a base is a proton acceptor."},
  {"i":"chem-b3-0610","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"calculation","q":"At 25 °C a solution has pH = 9. What is its pOH?","o":["5","9","14","23"],"c":0,"e":"At 25 °C, pH + pOH = 14, so pOH = 14 − 9 = 5."},
  {"i":"chem-b3-0611","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"conceptual","q":"In the equilibrium NH₃ + H₂O ⇌ NH₄⁺ + OH⁻, what is the conjugate acid of NH₃?","o":["NH₄⁺","OH⁻","H₂O","NH₂⁻"],"c":0,"e":"NH₃ accepts a proton to become NH₄⁺, so NH₄⁺ is its conjugate acid."},
  {"i":"chem-b3-0612","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"calculation","q":"What is the pH of a 0.01 mol/L HCl solution (assume complete dissociation)?","o":["2","12","1","0.01"],"c":0,"e":"HCl fully dissociates: [H⁺] = 0.01 = 1×10⁻², so pH = −log(10⁻²) = 2."},
  {"i":"chem-b3-0613","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"definition","q":"The value of the ion-product constant of water, Kw, at 25 °C is:","o":["1×10⁻¹⁴","1×10⁻⁷","1×10⁷","1×10¹⁴"],"c":0,"e":"At 25 °C, Kw = [H⁺][OH⁻] = 1×10⁻¹⁴."},
  {"i":"chem-b3-0614","g":12,"u":"Electrochemistry","d":"easy","t":"conceptual","q":"In a galvanic (voltaic) cell, the cathode is the electrode where:","o":["Reduction occurs","Oxidation occurs","Electrons are produced","Anions are oxidised"],"c":0,"e":"In a galvanic cell, reduction (gain of electrons) occurs at the cathode, which is the positive electrode."},
  {"i":"chem-b3-0615","g":12,"u":"Electrochemistry","d":"easy","t":"definition","q":"During the electrolysis of molten sodium chloride, sodium metal is formed at the cathode because Na⁺ ions are:","o":["Reduced","Oxidised","Neutralised","Hydrolysed"],"c":0,"e":"Na⁺ + e⁻ → Na: the ion gains an electron, which is reduction, occurring at the cathode."},
  {"i":"chem-b3-0616","g":12,"u":"Electrochemistry","d":"easy","t":"application","q":"The standard reference electrode against which all standard electrode potentials are measured is the:","o":["Standard hydrogen electrode","Calomel electrode","Silver/silver-chloride electrode","Copper electrode"],"c":0,"e":"The standard hydrogen electrode (SHE) is assigned E° = 0.00 V and is the universal reference."},
  {"i":"chem-b3-0617","g":12,"u":"Industrial Chemistry","d":"easy","t":"definition","q":"In the Haber process, ammonia is synthesised industrially from nitrogen and:","o":["Hydrogen","Oxygen","Carbon dioxide","Water vapour"],"c":0,"e":"The Haber process combines N₂ + 3H₂ ⇌ 2NH₃ over an iron catalyst."},
  {"i":"chem-b3-0618","g":12,"u":"Industrial Chemistry","d":"easy","t":"conceptual","q":"In the Contact process for manufacturing sulfuric acid, sulfur dioxide is oxidised to sulfur trioxide using a catalyst of:","o":["Vanadium(V) oxide","Iron","Platinum","Nickel"],"c":0,"e":"The Contact process uses V₂O₅ (vanadium(V) oxide) to catalyse 2SO₂ + O₂ ⇌ 2SO₃."},
  {"i":"chem-b3-0619","g":12,"u":"Industrial Chemistry","d":"easy","t":"application","q":"A balanced equation for ammonia synthesis in the Haber process is:","o":["N₂ + 3H₂ → 2NH₃","N₂ + H₂ → NH₃","N₂ + 2H₂ → 2NH₃","2N₂ + 3H₂ → 2NH₃"],"c":0,"e":"Balancing N and H: N₂ + 3H₂ → 2NH₃ gives 2 N and 6 H on each side."},
  {"i":"chem-b3-0620","g":12,"u":"Polymers","d":"easy","t":"definition","q":"Polyethene is formed from many ethene (C₂H₄) molecules by a reaction known as:","o":["Addition polymerisation","Condensation polymerisation","Neutralisation","Saponification"],"c":0,"e":"Ethene monomers join without losing any atoms, which is addition polymerisation."},
  {"i":"chem-b3-0621","g":12,"u":"Polymers","d":"easy","t":"definition","q":"The small repeating molecular unit from which a polymer is built is called a:","o":["Monomer","Polymer","Isotope","Isomer"],"c":0,"e":"A monomer is the small repeating unit that links to form a polymer (poly = many, mer = unit)."},
  {"i":"chem-b3-0622","g":12,"u":"Polymers","d":"easy","t":"application","q":"Nylon is produced by condensation polymerisation, in which the small molecule eliminated during bond formation is usually:","o":["Water","Carbon dioxide","Hydrogen","Methane"],"c":0,"e":"In condensation polymerisation forming nylon (amide links), water is eliminated as the monomers join."},
  {"i":"chem-b3-0623","g":12,"u":"Introduction to Environmental Chemistry","d":"easy","t":"definition","q":"Which gas is the principal contributor to the enhanced greenhouse effect from fossil-fuel combustion?","o":["Carbon dioxide","Nitrogen","Oxygen","Argon"],"c":0,"e":"CO₂ released by burning fossil fuels traps infrared radiation and is the main greenhouse gas contributor."},
  {"i":"chem-b3-0624","g":12,"u":"Introduction to Environmental Chemistry","d":"easy","t":"conceptual","q":"Acid rain is caused mainly by the release into the atmosphere of oxides of sulfur and:","o":["Nitrogen","Carbon (as CO)","Hydrogen","Helium"],"c":0,"e":"SO₂ and NOₓ dissolve in rainwater forming sulfuric and nitric acids, producing acid rain."},
  {"i":"chem-b3-0625","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"definition","q":"According to the Brønsted–Lowry theory, an acid is best defined as a species that:","o":["Donates a proton (H⁺)","Accepts a proton (H⁺)","Donates a pair of electrons","Accepts a hydroxide ion"],"c":0,"e":"In the Brønsted–Lowry model an acid is a proton (H⁺) donor, while a base is a proton acceptor."},
  {"i":"chem-b3-0626","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"calculation","q":"A strong acid solution has [H⁺] = 1×10⁻³ mol/L at 25 °C. What is its pH?","o":["2","3","11","1×10⁻³"],"c":1,"e":"pH = −log[H⁺] = −log(1×10⁻³) = 3."},
  {"i":"chem-b3-0627","g":12,"u":"Acid–Base Equilibria","d":"easy","t":"calculation","q":"At 25 °C a solution has pOH = 4. What is its pH (given pH + pOH = 14)?","o":["4","7","10","14"],"c":2,"e":"pH = 14 − pOH = 14 − 4 = 10."},
  {"i":"chem-b3-0628","g":12,"u":"Electrochemistry","d":"easy","t":"conceptual","q":"Which device converts chemical energy directly into electrical energy through a spontaneous redox reaction?","o":["Electrolytic cell","Galvanic (voltaic) cell","Step-up transformer","Photovoltaic cell"],"c":1,"e":"A galvanic (voltaic) cell uses a spontaneous redox reaction to produce electrical energy; an electrolytic cell does the reverse using electricity."},
  {"i":"chem-b3-0629","g":12,"u":"Industrial Chemistry","d":"easy","t":"conceptual","q":"In the Haber process used to manufacture ammonia, nitrogen and hydrogen combine according to which balanced equation?","o":["N₂ + H₂ → NH₃","N₂ + 3H₂ → 2NH₃","2N₂ + 3H₂ → 2NH₃","N₂ + 2H₂ → 2NH₂"],"c":1,"e":"Balanced: N₂ + 3H₂ → 2NH₃ gives 2 N and 6 H on each side."},
  {"i":"chem-b3-0630","g":12,"u":"Polymers","d":"easy","t":"definition","q":"Polyethene is formed from many ethene (C₂H₄) molecules joining without losing any atoms. This type of polymerization is called:","o":["Condensation polymerization","Addition polymerization","Hydrolysis","Saponification"],"c":1,"e":"Ethene monomers add across the C=C double bond with no small molecule eliminated, so it is addition polymerization."},
  {"i":"chem-b3-0631","g":12,"u":"Introduction to Environmental Chemistry","d":"easy","t":"conceptual","q":"Which gas, produced by incomplete combustion of fuels such as charcoal in poorly ventilated rooms, binds strongly to haemoglobin and reduces oxygen transport?","o":["Carbon dioxide (CO₂)","Carbon monoxide (CO)","Nitrogen (N₂)","Oxygen (O₂)"],"c":1,"e":"Carbon monoxide (CO) from incomplete combustion binds haemoglobin far more strongly than oxygen, reducing the blood's oxygen-carrying capacity."},
  {"i":"chem-b3-0632","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"A 0.020 mol/L solution of hydrochloric acid (HCl) is prepared at 25 °C. Assuming complete ionization, what is the pH of the solution?","o":["1.40","1.70","2.00","2.70"],"c":1,"e":"HCl is a strong acid, so [H⁺] = 0.020 mol/L. pH = −log(0.020) = 1.70."},
  {"i":"chem-b3-0633","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"Ethanoic acid (CH₃COOH) has Ka = 1.8 × 10⁻⁵. For a 0.10 mol/L solution at 25 °C, what is the approximate [H⁺]?","o":["1.3 × 10⁻³ mol/L","1.8 × 10⁻⁶ mol/L","4.2 × 10⁻³ mol/L","1.8 × 10⁻⁴ mol/L"],"c":0,"e":"[H⁺] ≈ √(Ka·C) = √(1.8 × 10⁻⁵ × 0.10) = √(1.8 × 10⁻⁶) = 1.34 × 10⁻³ mol/L."},
  {"i":"chem-b3-0634","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"At 25 °C a solution has pOH = 4.5. What is its hydrogen-ion concentration [H⁺]?","o":["3.2 × 10⁻⁵ mol/L","3.2 × 10⁻¹⁰ mol/L","3.2 × 10⁻⁹ mol/L","3.2 × 10⁻⁴ mol/L"],"c":1,"e":"pH = 14 − pOH = 14 − 4.5 = 9.5; [H⁺] = 10⁻⁹·⁵ = 3.2 × 10⁻¹⁰ mol/L."},
  {"i":"chem-b3-0635","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"What volume of 0.50 mol/L NaOH is required to exactly neutralize 25.0 mL of 0.20 mol/L H₂SO₄?","o":["10.0 mL","20.0 mL","12.5 mL","5.0 mL"],"c":1,"e":"mol H₂SO₄ = 0.025 × 0.20 = 0.0050; it needs 2 mol NaOH each, so 0.010 mol NaOH; V = 0.010 / 0.50 = 0.020 L = 20.0 mL."},
  {"i":"chem-b3-0636","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"conceptual","q":"According to the Brønsted–Lowry theory, what is the conjugate base of the hydrogen carbonate ion (HCO₃⁻) when it acts as an acid?","o":["H₂CO₃","CO₃²⁻","CO₂","OH⁻"],"c":1,"e":"As an acid HCO₃⁻ donates a proton: HCO₃⁻ → H⁺ + CO₃²⁻, so the conjugate base is the carbonate ion CO₃²⁻."},
  {"i":"chem-b3-0637","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"For the equilibrium N₂(g) + 3H₂(g) ⇌ 2NH₃(g), equilibrium concentrations are [N₂] = 0.20, [H₂] = 0.20 and [NH₃] = 0.40 mol/L. What is Kc?","o":["100","2.0","50","200"],"c":0,"e":"Kc = [NH₃]² / ([N₂][H₂]³) = (0.40)² / (0.20 × (0.20)³) = 0.16 / (0.20 × 0.008) = 0.16 / 0.0016 = 100."},
  {"i":"chem-b3-0638","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"application","q":"A buffer is made from ethanoic acid and sodium ethanoate. If pKa of the acid is 4.74 and [salt] = [acid], what is the pH of the buffer?","o":["4.74","7.00","9.26","2.37"],"c":0,"e":"Henderson–Hasselbalch: pH = pKa + log([salt]/[acid]) = 4.74 + log(1) = 4.74."},
  {"i":"chem-b3-0639","g":12,"u":"Electrochemistry","d":"medium","t":"calculation","q":"In the electrolysis of molten NaCl, a current of 5.0 A flows for 1930 s. How many moles of sodium metal are deposited? (F = 96500 C/mol)","o":["0.050 mol","0.10 mol","0.20 mol","0.025 mol"],"c":1,"e":"Q = It = 5.0 × 1930 = 9650 C; mol e⁻ = 9650/96500 = 0.10. Na⁺ + e⁻ → Na requires 1 e⁻ per Na, so 0.10 mol Na is deposited."},
  {"i":"chem-b3-0640","g":12,"u":"Electrochemistry","d":"medium","t":"calculation","q":"Using standard reduction potentials E°(Zn²⁺/Zn) = −0.76 V and E°(Cu²⁺/Cu) = +0.34 V, what is the standard cell potential of the Zn–Cu galvanic cell?","o":["+0.42 V","+1.10 V","−1.10 V","−0.42 V"],"c":1,"e":"E°cell = E°cathode − E°anode = (+0.34) − (−0.76) = +1.10 V; Zn is oxidized, Cu²⁺ reduced."},
  {"i":"chem-b3-0641","g":12,"u":"Electrochemistry","d":"medium","t":"calculation","q":"How many grams of copper are deposited when 0.30 mol of electrons pass through a CuSO₄ solution? (Ar Cu = 64)","o":["9.6 g","19.2 g","6.4 g","12.8 g"],"c":0,"e":"Cu²⁺ + 2e⁻ → Cu, so mol Cu = 0.30/2 = 0.15; mass = 0.15 × 64 = 9.6 g."},
  {"i":"chem-b3-0642","g":12,"u":"Electrochemistry","d":"medium","t":"conceptual","q":"In a galvanic (voltaic) cell, oxidation always occurs at which electrode, and what is its sign?","o":["Cathode, positive","Anode, negative","Cathode, negative","Anode, positive"],"c":1,"e":"In a galvanic cell oxidation occurs at the anode, which is the negative electrode (it releases electrons to the external circuit)."},
  {"i":"chem-b3-0643","g":12,"u":"Electrochemistry","d":"medium","t":"application","q":"Determine the oxidation number of manganese in the permanganate ion, MnO₄⁻.","o":["+5","+6","+7","+4"],"c":2,"e":"Oxygen is −2 (×4 = −8); overall charge −1, so Mn + (−8) = −1, giving Mn = +7."},
  {"i":"chem-b3-0644","g":12,"u":"Electrochemistry","d":"medium","t":"calculation","q":"A current is passed for 16 min 5 s (965 s) at 2.0 A through water. How many moles of electrons are transferred? (F = 96500 C/mol)","o":["0.010 mol","0.020 mol","0.040 mol","0.0020 mol"],"c":1,"e":"Q = It = 2.0 × 965 = 1930 C; mol e⁻ = 1930/96500 = 0.020 mol."},
  {"i":"chem-b3-0645","g":12,"u":"Industrial Chemistry","d":"medium","t":"calculation","q":"In the Haber process N₂ + 3H₂ → 2NH₃, what mass of ammonia can theoretically form from 28 g of nitrogen gas with excess hydrogen? (Ar N = 14, H = 1)","o":["17 g","34 g","28 g","51 g"],"c":1,"e":"mol N₂ = 28/28 = 1.0; ratio gives 2 mol NH₃ = 2.0 mol; mass = 2.0 × 17 = 34 g."},
  {"i":"chem-b3-0646","g":12,"u":"Industrial Chemistry","d":"medium","t":"conceptual","q":"In the Contact process for manufacturing sulfuric acid, the key catalyzed step 2SO₂ + O₂ ⇌ 2SO₃ uses which catalyst?","o":["Iron","Vanadium(V) oxide","Platinum only","Nickel"],"c":1,"e":"The Contact process oxidizes SO₂ to SO₃ over vanadium(V) oxide, V₂O₅, the standard industrial catalyst for this step."},
  {"i":"chem-b3-0647","g":12,"u":"Industrial Chemistry","d":"medium","t":"calculation","q":"A sample of limestone is 80% CaCO₃ by mass. On full decomposition, what mass of CaO is obtained from 250 g of this limestone? (Ar Ca = 40, C = 12, O = 16)","o":["112 g","140 g","100 g","56 g"],"c":0,"e":"CaCO₃ mass = 0.80 × 250 = 200 g; mol = 200/100 = 2.0; CaCO₃ → CaO + CO₂ gives 2.0 mol CaO; mass = 2.0 × 56 = 112 g."},
  {"i":"chem-b3-0648","g":12,"u":"Industrial Chemistry","d":"medium","t":"application","q":"Le Chatelier's principle predicts that ammonia yield in the Haber process is favoured by which set of conditions?","o":["High temperature, low pressure","Low temperature, high pressure","High temperature, high pressure","Low temperature, low pressure"],"c":1,"e":"The forward reaction is exothermic and reduces gas moles (4 → 2), so low temperature and high pressure shift equilibrium toward NH₃."},
  {"i":"chem-b3-0649","g":12,"u":"Polymers","d":"medium","t":"conceptual","q":"Which of the following polymers is formed by an addition (chain-growth) polymerization mechanism?","o":["Nylon-6,6","Polyethene","Terylene (PET)","Bakelite"],"c":1,"e":"Polyethene forms by addition polymerization of ethene monomers; nylon, PET and Bakelite are condensation polymers."},
  {"i":"chem-b3-0650","g":12,"u":"Polymers","d":"medium","t":"calculation","q":"Polyethene is made from ethene, C₂H₄. How many ethene monomer units are present in one polymer chain of relative molar mass 14 000? (Ar C = 12, H = 1)","o":["250","500","1000","700"],"c":1,"e":"Molar mass of ethene unit = 28; number of units = 14000/28 = 500."},
  {"i":"chem-b3-0651","g":12,"u":"Polymers","d":"medium","t":"definition","q":"Which statement correctly distinguishes condensation polymerization from addition polymerization?","o":["It releases a small molecule such as water","It requires only one type of monomer always","It occurs only with alkenes","It produces no by-product at all"],"c":0,"e":"Condensation polymerization joins monomers with loss of a small molecule (e.g. water or HCl), unlike addition polymerization which loses none."},
  {"i":"chem-b3-0652","g":12,"u":"Introduction to Environmental Chemistry","d":"medium","t":"conceptual","q":"Acid rain is mainly caused by atmospheric oxides that dissolve to form acids. Which pair of gases is chiefly responsible?","o":["CO₂ and CH₄","SO₂ and NO₂","O₃ and CO","N₂ and O₂"],"c":1,"e":"Sulfur dioxide (SO₂) and nitrogen dioxide (NO₂) dissolve and oxidize in rain to form sulfuric and nitric acids, the main cause of acid rain."},
  {"i":"chem-b3-0653","g":12,"u":"Introduction to Environmental Chemistry","d":"medium","t":"application","q":"A water sample has a dissolved-oxygen concentration of 2.0 mg/L. Compared with clean water (about 8 mg/L), this low value most directly indicates which condition?","o":["High dissolved oxygen and low pollution","High biochemical oxygen demand from organic pollution","Complete absence of microorganisms","Very low water temperature only"],"c":1,"e":"Low dissolved oxygen reflects high BOD: microorganisms decomposing organic pollutants consume oxygen, signalling organic water pollution."},
  {"i":"chem-b3-0654","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"A 0.020 mol/L solution of the strong acid HNO₃ is fully dissociated at 25 °C. What is the pH of the solution?","o":["1.40","1.70","2.00","2.70"],"c":1,"e":"[H⁺] = 0.020 mol/L, so pH = −log(0.020) = 1.70."},
  {"i":"chem-b3-0655","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"Acetic acid (CH₃COOH) has Ka = 1.8×10⁻⁵. For a 0.10 mol/L solution, what is the approximate [H⁺]?","o":["1.3×10⁻³ mol/L","1.8×10⁻⁶ mol/L","4.2×10⁻⁴ mol/L","1.0×10⁻⁷ mol/L"],"c":0,"e":"[H⁺] ≈ √(Ka·C) = √(1.8×10⁻⁵ × 0.10) = √(1.8×10⁻⁶) ≈ 1.3×10⁻³ mol/L."},
  {"i":"chem-b3-0656","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"A solution has pOH = 4.5 at 25 °C. What is its hydrogen-ion concentration [H⁺]?","o":["3.2×10⁻⁵ mol/L","3.2×10⁻¹⁰ mol/L","9.5 mol/L","1.0×10⁻⁴·⁵ mol/L"],"c":1,"e":"pH = 14 − 4.5 = 9.5, so [H⁺] = 10⁻⁹·⁵ ≈ 3.2×10⁻¹⁰ mol/L."},
  {"i":"chem-b3-0657","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"What volume of 0.10 mol/L NaOH is needed to neutralize 25.0 mL of 0.20 mol/L HCl?","o":["12.5 mL","25.0 mL","50.0 mL","100 mL"],"c":2,"e":"Moles HCl = 0.025 L × 0.20 = 5.0×10⁻³ mol; for 1:1 reaction V = 5.0×10⁻³ / 0.10 = 0.050 L = 50.0 mL."},
  {"i":"chem-b3-0658","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"For the equilibrium N₂(g) + 3H₂(g) ⇌ 2NH₃(g), if Kc favours products, increasing pressure shifts the equilibrium in which direction?","o":["Toward reactants (left)","Toward products (right)","No change","Toward forming H₂ only"],"c":1,"e":"Higher pressure shifts equilibrium toward the side with fewer gas moles; 2 mol NH₃ < 4 mol reactants, so it shifts right."},
  {"i":"chem-b3-0659","g":12,"u":"Electrochemistry","d":"medium","t":"calculation","q":"In the electrolysis of molten NaCl, a current of 5.0 A flows for 1930 s. How many moles of Na are deposited at the cathode? (F = 96500 C/mol)","o":["0.050 mol","0.10 mol","0.20 mol","0.025 mol"],"c":1,"e":"Q = It = 5.0×1930 = 9650 C; moles e⁻ = 9650/96500 = 0.10; Na⁺ + e⁻ → Na needs 1 e⁻, so 0.10 mol Na."},
  {"i":"chem-b3-0660","g":12,"u":"Electrochemistry","d":"medium","t":"calculation","q":"Given E°(Zn²⁺/Zn) = −0.76 V and E°(Cu²⁺/Cu) = +0.34 V, what is the standard cell potential of the Zn–Cu galvanic cell?","o":["+0.42 V","+1.10 V","−1.10 V","−0.42 V"],"c":1,"e":"E°cell = E°cathode − E°anode = (+0.34) − (−0.76) = +1.10 V."},
  {"i":"chem-b3-0661","g":12,"u":"Electrochemistry","d":"medium","t":"conceptual","q":"In a galvanic (voltaic) cell, oxidation occurs at which electrode, and what is its sign?","o":["Cathode, positive","Anode, negative","Cathode, negative","Anode, positive"],"c":1,"e":"Oxidation always occurs at the anode; in a galvanic cell the anode is the negative electrode."},
  {"i":"chem-b3-0662","g":12,"u":"Electrochemistry","d":"medium","t":"calculation","q":"How many coulombs of charge are required to deposit 0.50 mol of copper from Cu²⁺ ions during electrolysis? (F = 96500 C/mol)","o":["48250 C","96500 C","193000 C","24125 C"],"c":1,"e":"Cu²⁺ + 2e⁻ → Cu needs 2 mol e⁻ per mol Cu; Q = 0.50 × 2 × 96500 = 96500 C."},
  {"i":"chem-b3-0663","g":12,"u":"Electrochemistry","d":"medium","t":"application","q":"During the electrolysis of dilute aqueous Na₂SO₄, which gas is produced at the anode?","o":["Hydrogen","Oxygen","Sodium vapour","Sulfur dioxide"],"c":1,"e":"At the anode water is oxidized: 2H₂O → O₂ + 4H⁺ + 4e⁻; SO₄²⁻ is not discharged, so O₂ forms."},
  {"i":"chem-b3-0664","g":12,"u":"Industrial Chemistry","d":"medium","t":"conceptual","q":"In the Contact process for producing sulfuric acid, which catalyst is used to convert SO₂ to SO₃?","o":["Iron (Fe)","Vanadium(V) oxide (V₂O₅)","Platinum (Pt)","Nickel (Ni)"],"c":1,"e":"The Contact process uses V₂O₅ as the catalyst for 2SO₂ + O₂ ⇌ 2SO₃."},
  {"i":"chem-b3-0665","g":12,"u":"Industrial Chemistry","d":"medium","t":"calculation","q":"In the Haber process N₂ + 3H₂ → 2NH₃, what mass of NH₃ can be produced from 28 g of N₂ with excess H₂? (N = 14, H = 1)","o":["17 g","28 g","34 g","8.5 g"],"c":2,"e":"28 g N₂ = 1 mol; it yields 2 mol NH₃ = 2 × 17 = 34 g."},
  {"i":"chem-b3-0666","g":12,"u":"Industrial Chemistry","d":"medium","t":"conceptual","q":"In the Haber process, which set of conditions is industrially used to maximize the rate and yield of ammonia?","o":["Low pressure, high temperature","High pressure, moderate temperature with Fe catalyst","High temperature, no catalyst","Low pressure, low temperature"],"c":1,"e":"High pressure favours the lower-mole product side, while a moderate temperature with an iron catalyst balances acceptable yield with a practical rate."},
  {"i":"chem-b3-0667","g":12,"u":"Industrial Chemistry","d":"medium","t":"application","q":"The reaction 2SO₂ + O₂ ⇌ 2SO₃ is exothermic. To increase the equilibrium yield of SO₃, what temperature change helps?","o":["Increase temperature","Decrease temperature","Temperature has no effect","Remove the catalyst"],"c":1,"e":"For an exothermic reaction, lowering temperature shifts equilibrium toward products, increasing SO₃ yield."},
  {"i":"chem-b3-0668","g":12,"u":"Polymers","d":"medium","t":"conceptual","q":"The formation of polyethene from ethene monomers (n CH₂=CH₂ → −(CH₂−CH₂)ₙ−) is an example of which type of polymerization?","o":["Condensation polymerization","Addition polymerization","Hydrolysis","Cross-linking only"],"c":1,"e":"Ethene molecules add across their C=C double bonds with no small molecule released, which is addition polymerization."},
  {"i":"chem-b3-0669","g":12,"u":"Polymers","d":"medium","t":"definition","q":"Which of the following is a natural condensation polymer in which monomers join with the loss of water?","o":["Polyethene","Protein (from amino acids)","PVC","Polystyrene"],"c":1,"e":"Proteins form by condensation of amino acids, releasing water at each peptide bond; the others are synthetic addition polymers."},
  {"i":"chem-b3-0670","g":12,"u":"Polymers","d":"medium","t":"application","q":"Nylon-6,6 is produced from a diamine and a diacid. What small molecule is eliminated during its formation?","o":["Hydrogen gas","Water","Carbon dioxide","Ammonia"],"c":1,"e":"Nylon-6,6 forms by condensation polymerization, eliminating water as amide (peptide) bonds form."},
  {"i":"chem-b3-0671","g":12,"u":"Introduction to Environmental Chemistry","d":"medium","t":"conceptual","q":"Which gas is the principal cause of acid rain when it dissolves and is oxidized in the atmosphere to form sulfuric acid?","o":["Carbon dioxide (CO₂)","Sulfur dioxide (SO₂)","Methane (CH₄)","Oxygen (O₂)"],"c":1,"e":"SO₂ from burning sulfur-containing fuels is oxidized and reacts with water to form H₂SO₄, the main acid-rain contributor."},
  {"i":"chem-b3-0672","g":12,"u":"Introduction to Environmental Chemistry","d":"medium","t":"definition","q":"Biochemical Oxygen Demand (BOD) of a water sample is a measure of what?","o":["The amount of dissolved salts","The oxygen needed by microbes to decompose organic matter","The acidity of the water","The total chlorine content"],"c":1,"e":"BOD measures the dissolved oxygen consumed by microorganisms while breaking down organic matter; high BOD indicates heavy organic pollution."},
  {"i":"chem-b3-0673","g":12,"u":"Introduction to Environmental Chemistry","d":"medium","t":"application","q":"Chlorofluorocarbons (CFCs) damage the ozone layer because, under UV light, they release which reactive species that destroys O₃?","o":["Chlorine atoms (Cl·)","Fluorine gas (F₂)","Carbon atoms","Water vapour"],"c":0,"e":"UV light breaks C–Cl bonds in CFCs, releasing Cl· radicals that catalytically convert O₃ to O₂."},
  {"i":"chem-b3-0674","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"A 0.0010 mol/L solution of HCl (a strong acid) is prepared in a lab in Addis Ababa. What is the pH of the solution at 25 °C?","o":["2.0","3.0","4.0","11.0"],"c":1,"e":"HCl fully ionizes, so [H⁺] = 1.0×10⁻³ mol/L; pH = −log(1.0×10⁻³) = 3.0."},
  {"i":"chem-b3-0675","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"A solution has pOH = 4.2 at 25 °C. What is its pH?","o":["4.2","9.8","7.0","11.8"],"c":1,"e":"At 25 °C, pH + pOH = 14, so pH = 14 − 4.2 = 9.8."},
  {"i":"chem-b3-0676","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"Ethanoic acid (CH₃COOH) has Ka = 1.8×10⁻⁵. For a 0.10 mol/L solution, what is the approximate [H⁺]?","o":["1.8×10⁻⁶ mol/L","1.3×10⁻³ mol/L","4.2×10⁻³ mol/L","1.8×10⁻⁵ mol/L"],"c":1,"e":"[H⁺] ≈ √(Ka·C) = √(1.8×10⁻⁵ × 0.10) = √(1.8×10⁻⁶) ≈ 1.3×10⁻³ mol/L."},
  {"i":"chem-b3-0677","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"What volume of 0.20 mol/L NaOH is needed to exactly neutralize 25.0 mL of 0.10 mol/L HCl?","o":["12.5 mL","25.0 mL","50.0 mL","6.25 mL"],"c":0,"e":"Moles HCl = 0.025 L × 0.10 = 2.5×10⁻³ mol; NaOH:HCl is 1:1, so V = 2.5×10⁻³ / 0.20 = 0.0125 L = 12.5 mL."},
  {"i":"chem-b3-0678","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"A weak base has Kb = 2.5×10⁻⁵. What is the pKb of this base?","o":["3.6","4.6","5.4","9.4"],"c":1,"e":"pKb = −log(2.5×10⁻⁵) = 5 − log2.5 = 5 − 0.40 = 4.6."},
  {"i":"chem-b3-0679","g":12,"u":"Electrochemistry","d":"medium","t":"calculation","q":"In the electrolysis of molten NaCl, a current of 2.0 A passes for 32 min 10 s. How many moles of electrons are transferred? (F = 96500 C/mol)","o":["0.020 mol","0.040 mol","0.080 mol","0.10 mol"],"c":1,"e":"Q = I·t = 2.0 × 1930 s = 3860 C; moles e⁻ = 3860/96500 = 0.040 mol."},
  {"i":"chem-b3-0680","g":12,"u":"Electrochemistry","d":"medium","t":"calculation","q":"During electrolysis of aqueous CuSO₄, how many moles of Cu are deposited when 0.50 mol of electrons pass? (Cu²⁺ + 2e⁻ → Cu)","o":["0.25 mol","0.50 mol","1.0 mol","0.125 mol"],"c":0,"e":"Each Cu requires 2 electrons, so moles Cu = 0.50 / 2 = 0.25 mol."},
  {"i":"chem-b3-0681","g":12,"u":"Electrochemistry","d":"medium","t":"calculation","q":"A mass of 1.08 g of silver is deposited from AgNO₃ solution. How many moles of electrons were required? (Ag = 108, Ag⁺ + e⁻ → Ag)","o":["0.010 mol","0.020 mol","0.108 mol","0.001 mol"],"c":0,"e":"Moles Ag = 1.08/108 = 0.010 mol; since Ag⁺ + e⁻ → Ag is 1:1, moles e⁻ = 0.010 mol."},
  {"i":"chem-b3-0682","g":12,"u":"Industrial Chemistry","d":"medium","t":"conceptual","q":"In the Haber process for ammonia synthesis (N₂ + 3H₂ ⇌ 2NH₃, ΔH < 0), increasing pressure shifts the equilibrium in which direction and why?","o":["Toward reactants, fewer moles of gas there","Toward products, fewer moles of gas there","No shift, moles are equal","Toward products, more moles of gas there"],"c":1,"e":"Higher pressure favors the side with fewer gas moles; 4 mol reactant gas → 2 mol product, so equilibrium shifts toward NH₃."},
  {"i":"chem-b3-0683","g":12,"u":"Industrial Chemistry","d":"medium","t":"calculation","q":"In the Haber process, what mass of NH₃ can be made from 28 g of N₂ with excess H₂? (N = 14, H = 1)","o":["17 g","34 g","28 g","8.5 g"],"c":1,"e":"Moles N₂ = 28/28 = 1.0 mol; N₂ → 2NH₃ gives 2.0 mol NH₃; mass = 2.0 × 17 = 34 g."},
  {"i":"chem-b3-0684","g":12,"u":"Industrial Chemistry","d":"medium","t":"conceptual","q":"In the Contact process for sulfuric acid, which catalyst is used for the conversion 2SO₂ + O₂ ⇌ 2SO₃?","o":["Iron (Fe)","Vanadium(V) oxide (V₂O₅)","Platinum (Pt)","Nickel (Ni)"],"c":1,"e":"The Contact process uses vanadium(V) oxide, V₂O₅, to catalyze the oxidation of SO₂ to SO₃."},
  {"i":"chem-b3-0685","g":12,"u":"Industrial Chemistry","d":"medium","t":"application","q":"A common industrial use of limestone (CaCO₃) in Ethiopian cement production involves heating it. What is the main gas released during calcination?","o":["O₂","CO","CO₂","SO₂"],"c":2,"e":"On heating, CaCO₃ → CaO + CO₂; the gas released during calcination is carbon dioxide."},
  {"i":"chem-b3-0686","g":12,"u":"Polymers","d":"medium","t":"definition","q":"Which of the following is formed by an addition polymerization reaction?","o":["Nylon-6,6","Polyethene","Polyester (PET)","A polypeptide"],"c":1,"e":"Polyethene forms by addition polymerization of ethene monomers with no small molecule eliminated; the others are condensation polymers."},
  {"i":"chem-b3-0687","g":12,"u":"Polymers","d":"medium","t":"conceptual","q":"Condensation polymerization differs from addition polymerization mainly because condensation reactions also:","o":["Require a C=C double bond","Release a small molecule such as water","Produce only one product","Cannot form long chains"],"c":1,"e":"Condensation polymerization links monomers while eliminating a small molecule (often H₂O), unlike addition which adds across double bonds with no byproduct."},
  {"i":"chem-b3-0688","g":12,"u":"Polymers","d":"medium","t":"application","q":"The monomer of natural rubber and many synthetic addition polymers contains a C=C bond. Which monomer gives polyvinyl chloride (PVC)?","o":["Ethene (CH₂=CH₂)","Chloroethene (CH₂=CHCl)","Propene (CH₂=CHCH₃)","Tetrafluoroethene"],"c":1,"e":"PVC is the addition polymer of chloroethene (vinyl chloride), CH₂=CHCl."},
  {"i":"chem-b3-0689","g":12,"u":"Introduction to Environmental Chemistry","d":"medium","t":"calculation","q":"A water sample contains dissolved O₂ at 8.0 mg/L. Expressed in parts per million (assume water density 1.0 g/mL), this concentration is:","o":["0.80 ppm","8.0 ppm","80 ppm","800 ppm"],"c":1,"e":"For dilute aqueous solutions, 1 mg/L equals 1 ppm, so 8.0 mg/L = 8.0 ppm."},
  {"i":"chem-b3-0690","g":12,"u":"Introduction to Environmental Chemistry","d":"medium","t":"conceptual","q":"Which gas is the primary cause of acid rain when it dissolves in atmospheric moisture to form an acidic solution?","o":["CO₂ alone","SO₂ (and NOₓ)","CH₄","O₃"],"c":1,"e":"Sulfur dioxide (with nitrogen oxides) reacts with atmospheric water to form sulfuric and nitric acids, the main contributors to acid rain."},
  {"i":"chem-b3-0691","g":12,"u":"Introduction to Environmental Chemistry","d":"medium","t":"application","q":"A high BOD (biochemical oxygen demand) value in a river near a town indicates:","o":["Very clean, oxygen-rich water","Heavy organic pollution depleting dissolved oxygen","High dissolved mineral content only","Low microbial activity"],"c":1,"e":"High BOD means microbes consume large amounts of dissolved oxygen to break down organic waste, signaling heavy organic pollution."},
  {"i":"chem-b3-0692","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"A 0.0050 mol/L solution of HCl (strong acid) is prepared. What is the pH of the solution at 25 °C? (log 5 = 0.70)","o":["1.70","2.30","2.70","3.30"],"c":1,"e":"[H⁺] = 0.0050 mol/L, so pH = −log(5.0×10⁻³) = 3 − 0.70 = 2.30."},
  {"i":"chem-b3-0693","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"A weak acid HA has Ka = 1.0×10⁻⁵. For a 0.10 mol/L solution, what is the approximate [H⁺]? ","o":["1.0×10⁻³ mol/L","1.0×10⁻⁵ mol/L","1.0×10⁻⁶ mol/L","3.2×10⁻⁴ mol/L"],"c":0,"e":"[H⁺] ≈ √(Ka·C) = √(1.0×10⁻⁵ × 0.10) = √(1.0×10⁻⁶) = 1.0×10⁻³ mol/L."},
  {"i":"chem-b3-0694","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"At 25 °C a solution has pOH = 4.0. What is its hydrogen-ion concentration [H⁺]?","o":["1.0×10⁻⁴ mol/L","1.0×10⁻⁶ mol/L","1.0×10⁻¹⁰ mol/L","1.0×10⁻⁸ mol/L"],"c":2,"e":"pH = 14 − pOH = 14 − 4 = 10, so [H⁺] = 10⁻¹⁰ mol/L."},
  {"i":"chem-b3-0695","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"25.0 mL of 0.100 mol/L NaOH exactly neutralises 50.0 mL of HCl. What is the concentration of the HCl?","o":["0.0500 mol/L","0.100 mol/L","0.200 mol/L","0.0250 mol/L"],"c":0,"e":"Moles NaOH = 0.0250 L × 0.100 = 2.5×10⁻³ mol; HCl reacts 1:1, so c = 2.5×10⁻³ / 0.0500 L = 0.0500 mol/L."},
  {"i":"chem-b3-0696","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"conceptual","q":"In the equilibrium NH₃ + H₂O ⇌ NH₄⁺ + OH⁻, which species is the conjugate acid of the Brønsted–Lowry base NH₃?","o":["H₂O","NH₄⁺","OH⁻","NH₃"],"c":1,"e":"NH₃ accepts a proton to become NH₄⁺, so NH₄⁺ is the conjugate acid of NH₃."},
  {"i":"chem-b3-0697","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"A weak base has Kb = 4.0×10⁻⁴ at 25 °C. What is the Ka of its conjugate acid? (Kw = 1.0×10⁻¹⁴)","o":["2.5×10⁻¹¹","4.0×10⁻¹⁰","2.5×10⁻¹⁰","4.0×10⁻¹⁸"],"c":0,"e":"Ka = Kw / Kb = 1.0×10⁻¹⁴ / 4.0×10⁻⁴ = 2.5×10⁻¹¹."},
  {"i":"chem-b3-0698","g":12,"u":"Electrochemistry","d":"medium","t":"calculation","q":"A current of 2.0 A is passed through molten NaCl for 1930 s. How many moles of Na metal are deposited at the cathode? (F = 96500 C/mol)","o":["0.020 mol","0.040 mol","0.080 mol","0.010 mol"],"c":1,"e":"Q = 2.0 A × 1930 s = 3860 C. The cathode reaction Na⁺ + e⁻ → Na needs 1 mol e⁻ per mol Na, so n(Na) = 3860/96500 = 0.040 mol."},
  {"i":"chem-b3-0699","g":12,"u":"Electrochemistry","d":"medium","t":"conceptual","q":"In the electrolysis of aqueous copper(II) sulfate using inert platinum electrodes, what is the product formed at the anode?","o":["Copper metal","Hydrogen gas","Oxygen gas","Sulfur dioxide"],"c":2,"e":"At the inert anode, water is oxidised in preference to SO₄²⁻: 2H₂O → O₂ + 4H⁺ + 4e⁻, releasing oxygen gas."},
  {"i":"chem-b3-0700","g":12,"u":"Electrochemistry","d":"medium","t":"application","q":"During the iron rusting process, iron acts as the anode. What is the oxidation half-reaction occurring on the iron surface?","o":["Fe²⁺ + 2e⁻ → Fe","Fe → Fe²⁺ + 2e⁻","O₂ + 2H₂O + 4e⁻ → 4OH⁻","2H⁺ + 2e⁻ → H₂"],"c":1,"e":"At the anode, iron is oxidised: Fe → Fe²⁺ + 2e⁻; oxygen reduction occurs at the cathode."},
  {"i":"chem-b3-0701","g":12,"u":"Electrochemistry","d":"medium","t":"calculation","q":"How many coulombs of charge are required to deposit 0.50 mol of aluminium from molten Al₂O₃? (F = 96500 C/mol)","o":["48250 C","96500 C","144750 C","193000 C"],"c":2,"e":"Al³⁺ + 3e⁻ → Al needs 3 mol e⁻ per mol Al; for 0.50 mol Al, e⁻ = 1.5 mol, Q = 1.5 × 96500 = 144750 C."},
  {"i":"chem-b3-0702","g":12,"u":"Electrochemistry","d":"medium","t":"conceptual","q":"What is the role of the salt bridge in a galvanic cell?","o":["It supplies electrons to the external circuit","It maintains electrical neutrality by allowing ion migration","It oxidises the anode metal","It increases the cell voltage directly"],"c":1,"e":"The salt bridge completes the circuit internally and keeps each half-cell electrically neutral by allowing ions to migrate, preventing charge build-up."},
  {"i":"chem-b3-0703","g":12,"u":"Industrial Chemistry","d":"medium","t":"conceptual","q":"In the Haber process for ammonia synthesis (N₂ + 3H₂ ⇌ 2NH₃, ΔH < 0), which set of conditions favours a high equilibrium yield of ammonia?","o":["High temperature and low pressure","Low temperature and high pressure","High temperature and high pressure","Low temperature and low pressure"],"c":1,"e":"The forward reaction is exothermic and decreases moles of gas, so low temperature and high pressure shift equilibrium toward NH₃ (a catalyst is used to keep the rate practical)."},
  {"i":"chem-b3-0704","g":12,"u":"Industrial Chemistry","d":"medium","t":"calculation","q":"In the Contact process, sulfur is burned: S + O₂ → SO₂. What mass of SO₂ is produced from 16 g of sulfur burned completely? (S = 32, O = 16)","o":["16 g","32 g","48 g","64 g"],"c":1,"e":"Moles S = 16/32 = 0.50 mol; 1:1 ratio gives 0.50 mol SO₂; mass = 0.50 × 64 = 32 g."},
  {"i":"chem-b3-0705","g":12,"u":"Industrial Chemistry","d":"medium","t":"application","q":"A key step in the Contact process is 2SO₂ + O₂ ⇌ 2SO₃. Which catalyst is used industrially for this conversion?","o":["Iron","Vanadium(V) oxide","Platinum gauze","Nickel"],"c":1,"e":"Vanadium(V) oxide (V₂O₅) is the catalyst used in the Contact process to convert SO₂ to SO₃."},
  {"i":"chem-b3-0706","g":12,"u":"Industrial Chemistry","d":"medium","t":"conceptual","q":"Ethiopia's sugar factories produce ethanol by fermentation of molasses. Which products are formed when glucose is fermented by yeast?","o":["Ethanol and oxygen","Ethanol and carbon dioxide","Ethanoic acid and water","Methanol and carbon dioxide"],"c":1,"e":"Fermentation: C₆H₁₂O₆ → 2C₂H₅OH + 2CO₂, producing ethanol and carbon dioxide under anaerobic yeast action."},
  {"i":"chem-b3-0707","g":12,"u":"Polymers","d":"medium","t":"definition","q":"Polythene (polyethene) is made from ethene monomers joining without losing any atoms. This type of polymerisation is best described as:","o":["Condensation polymerisation","Addition polymerisation","Hydrolysis","Cross-linking by elimination"],"c":1,"e":"Ethene molecules add across their C=C double bonds with no small molecule eliminated, which is addition polymerisation."},
  {"i":"chem-b3-0708","g":12,"u":"Polymers","d":"medium","t":"conceptual","q":"Which of the following is a natural condensation polymer in which monomers are joined by peptide (amide) linkages?","o":["Starch","Protein","Poly(vinyl chloride)","Natural rubber"],"c":1,"e":"Proteins are condensation polymers of amino acids linked by peptide (amide) bonds; the others are not amide-linked."},
  {"i":"chem-b3-0709","g":12,"u":"Polymers","d":"medium","t":"application","q":"Nylon-6,6 is formed from a diamine and a dicarboxylic acid with elimination of water. What small molecule is released at each linkage formed?","o":["Carbon dioxide","Water","Hydrogen chloride","Ammonia"],"c":1,"e":"The –COOH of the acid reacts with the –NH₂ of the amine to form an amide bond, releasing a molecule of water (condensation)."},
  {"i":"chem-b3-0710","g":12,"u":"Introduction to Environmental Chemistry","d":"medium","t":"conceptual","q":"Which atmospheric gas is primarily responsible for acid rain when its oxides dissolve in rainwater to form sulfuric acid?","o":["Carbon dioxide","Sulfur dioxide","Methane","Nitrogen gas"],"c":1,"e":"Sulfur dioxide (SO₂) from burning sulfur-containing fuels is oxidised and dissolves to form H₂SO₄, a major cause of acid rain."},
  {"i":"chem-b3-0711","g":12,"u":"Introduction to Environmental Chemistry","d":"medium","t":"application","q":"Dissolved oxygen in a polluted stretch of the Akaki River is measured as a water-quality indicator. A very high biochemical oxygen demand (BOD) value most directly indicates:","o":["Low organic pollution and clean water","High organic pollution consuming dissolved oxygen","High dissolved oxygen content","High concentration of dissolved minerals"],"c":1,"e":"A high BOD means microbes need much oxygen to decompose organic matter, signalling heavy organic pollution and depleted dissolved oxygen."},
  {"i":"chem-b3-0712","g":12,"u":"Introduction to Environmental Chemistry","d":"medium","t":"calculation","q":"Rainwater in equilibrium with atmospheric CO₂ has [H⁺] = 2.0×10⁻⁶ mol/L. What is its pH? (log 2 = 0.30)","o":["5.7","6.3","6.7","5.3"],"c":0,"e":"pH = −log(2.0×10⁻⁶) = 6 − 0.30 = 5.70, the slightly acidic value of natural rainwater."},
  {"i":"chem-b3-0713","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"What is the pH of a 2.5 × 10⁻³ mol/L solution of the strong base Ca(OH)₂ at 25 °C? (log 5 = 0.70)","o":["2.30","11.70","11.30","2.70"],"c":1,"e":"Ca(OH)₂ gives 2 OH⁻, so [OH⁻] = 2 × 2.5×10⁻³ = 5.0×10⁻³ mol/L. pOH = −log(5.0×10⁻³) = 2.30, so pH = 14 − 2.30 = 11.70."},
  {"i":"chem-b3-0714","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"25.0 mL of 0.100 mol/L HCl is titrated with 0.100 mol/L NaOH. What volume of NaOH is needed to reach the equivalence point?","o":["12.5 mL","50.0 mL","25.0 mL","2.50 mL"],"c":2,"e":"At equivalence moles NaOH = moles HCl = 0.100 × 0.0250 = 2.50×10⁻³ mol. Volume = 2.50×10⁻³ / 0.100 = 0.0250 L = 25.0 mL."},
  {"i":"chem-b3-0715","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"conceptual","q":"In the equilibrium NH₃ + H₂O ⇌ NH₄⁺ + OH⁻, which species is the conjugate acid of the base NH₃ according to Brønsted–Lowry theory?","o":["H₂O","OH⁻","NH₄⁺","NH₃"],"c":2,"e":"A base accepts a proton to form its conjugate acid. NH₃ gains H⁺ to become NH₄⁺, so NH₄⁺ is the conjugate acid of NH₃."},
  {"i":"chem-b3-0716","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"A buffer contains 0.20 mol/L CH₃COOH and 0.20 mol/L CH₃COONa. If Ka of acetic acid is 1.8 × 10⁻⁵, what is the pH? (log 1.8 = 0.26)","o":["4.74","5.26","4.26","9.26"],"c":0,"e":"By Henderson–Hasselbalch, pH = pKa + log([salt]/[acid]). With equal concentrations the log term is 0, so pH = pKa = −log(1.8×10⁻⁵) = 4.74."},
  {"i":"chem-b3-0717","g":12,"u":"Acid–Base Equilibria","d":"medium","t":"calculation","q":"What is the pH of a 0.0010 mol/L HNO₃ solution at 25 °C?","o":["1.0","11.0","3.0","2.0"],"c":2,"e":"HNO₃ is a strong monoprotic acid, so [H⁺] = 1.0×10⁻³ mol/L. pH = −log(1.0×10⁻³) = 3.0."},
  {"i":"chem-b3-0718","g":12,"u":"Electrochemistry","d":"medium","t":"calculation","q":"During electrolysis of molten NaCl, a current of 5.0 A flows for 1930 s. How many moles of sodium metal are deposited at the cathode? (F = 96500 C/mol)","o":["0.20 mol","0.050 mol","0.10 mol","0.025 mol"],"c":2,"e":"Charge Q = 5.0 × 1930 = 9650 C; moles e⁻ = 9650/96500 = 0.10. Na⁺ + e⁻ → Na needs 1 e⁻ per Na, so 0.10 mol Na is deposited."},
  {"i":"chem-b3-0719","g":12,"u":"Electrochemistry","d":"medium","t":"calculation","q":"For the cell Zn|Zn²⁺||Cu²⁺|Cu, E°(Zn²⁺/Zn) = −0.76 V and E°(Cu²⁺/Cu) = +0.34 V. What is the standard cell potential, E°cell?","o":["+1.10 V","−0.42 V","+0.42 V","−1.10 V"],"c":0,"e":"E°cell = E°cathode − E°anode = E°(Cu²⁺/Cu) − E°(Zn²⁺/Zn) = 0.34 − (−0.76) = +1.10 V."},
  {"i":"chem-b3-0720","g":12,"u":"Electrochemistry","d":"medium","t":"conceptual","q":"In a galvanic cell, oxidation occurs at the anode. What is the correct sign of the anode in a galvanic (voltaic) cell and the direction of electron flow in the external wire?","o":["Negative; electrons flow from anode to cathode","Positive; electrons flow from anode to cathode","Negative; electrons flow from cathode to anode","Positive; electrons flow from cathode to anode"],"c":0,"e":"In a galvanic cell the anode is negative (it releases electrons by oxidation), and electrons travel through the external wire from anode to cathode."},
  {"i":"chem-b3-0721","g":12,"u":"Electrochemistry","d":"medium","t":"calculation","q":"What mass of copper is deposited when 0.40 mol of electrons passes through a CuSO₄ solution? (Cu = 64 g/mol)","o":["25.6 g","6.4 g","51.2 g","12.8 g"],"c":3,"e":"Cu²⁺ + 2e⁻ → Cu, so moles Cu = 0.40/2 = 0.20 mol. Mass = 0.20 × 64 = 12.8 g."},
  {"i":"chem-b3-0722","g":12,"u":"Electrochemistry","d":"medium","t":"application","q":"To protect an underground steel pipeline, a more reactive metal is connected to it so the metal corrodes instead of the iron. Which metal is most suitable for this sacrificial (cathodic) protection?","o":["Copper","Magnesium","Silver","Tin"],"c":1,"e":"Sacrificial protection needs a metal more easily oxidized than iron. Magnesium is above iron in the reactivity series, so it corrodes preferentially and protects the steel."},
  {"i":"chem-b3-0723","g":12,"u":"Electrochemistry","d":"medium","t":"calculation","q":"In the redox reaction Cr₂O₇²⁻ → Cr³⁺ in acidic solution, what is the change in oxidation number of chromium per Cr atom?","o":["Decreases from +6 to +3","Increases from +3 to +6","Decreases from +7 to +3","Decreases from +6 to +2"],"c":0,"e":"In Cr₂O₇²⁻, 2Cr + 7(−2) = −2, so each Cr is +6. In Cr³⁺ it is +3, a decrease (reduction) from +6 to +3."},
  {"i":"chem-b3-0724","g":12,"u":"Industrial Chemistry","d":"medium","t":"calculation","q":"In the Haber process N₂ + 3H₂ ⇌ 2NH₃, what mass of ammonia can be produced from 28 g of N₂ reacting completely? (N = 14, H = 1)","o":["17 g","34 g","68 g","51 g"],"c":1,"e":"Moles N₂ = 28/28 = 1.0 mol. Ratio N₂:NH₃ = 1:2, so 2.0 mol NH₃ forms. Mass = 2.0 × 17 = 34 g."},
  {"i":"chem-b3-0725","g":12,"u":"Industrial Chemistry","d":"medium","t":"conceptual","q":"The Haber process is run at high pressure (≈200 atm) and a moderate temperature (≈450 °C) with an iron catalyst. Why is a moderate temperature chosen rather than a very low one, despite the forward reaction being exothermic?","o":["Low temperature increases yield but makes the rate too slow","High temperature shifts equilibrium toward more ammonia","Low temperature destroys the iron catalyst","High temperature is needed to keep nitrogen gaseous"],"c":0,"e":"The exothermic forward reaction is favored by low temperature for yield, but the rate becomes impractically slow; a moderate temperature is a compromise between acceptable yield and reasonable rate."},
  {"i":"chem-b3-0726","g":12,"u":"Industrial Chemistry","d":"medium","t":"application","q":"In the Contact process for sulfuric acid, SO₃ is not absorbed directly in water but first dissolved in concentrated H₂SO₄ to form oleum. Why is direct absorption of SO₃ in water avoided?","o":["SO₃ does not react with water","It forms a dense corrosive mist of sulfuric acid that is hard to condense","Water decomposes SO₃ back to SO₂","The reaction with water is endothermic and stops"],"c":1,"e":"SO₃ reacting directly with water releases so much heat that it forms a fine sulfuric-acid mist (fog) that is difficult to collect; dissolving in concentrated H₂SO₄ to make oleum avoids this loss."},
  {"i":"chem-b3-0727","g":12,"u":"Industrial Chemistry","d":"medium","t":"calculation","q":"Limestone decomposes as CaCO₃ → CaO + CO₂. What mass of quicklime (CaO) is obtained from 250 g of pure CaCO₃? (Ca = 40, C = 12, O = 16)","o":["140 g","250 g","112 g","56 g"],"c":0,"e":"M(CaCO₃) = 100 g/mol, so moles = 250/100 = 2.5 mol. 1:1 gives 2.5 mol CaO; M(CaO) = 56, mass = 2.5 × 56 = 140 g."},
  {"i":"chem-b3-0728","g":12,"u":"Polymers","d":"medium","t":"definition","q":"Polyethene is made by joining many ethene (C₂H₄) molecules with no loss of any small molecule. What type of polymerization is this?","o":["Condensation polymerization","Addition polymerization","Hydrolysis","Cross-linking by vulcanization"],"c":1,"e":"When monomers with C=C double bonds add together to form a polymer without eliminating any small molecule, it is addition polymerization, as in ethene → polyethene."},
  {"i":"chem-b3-0729","g":12,"u":"Polymers","d":"medium","t":"conceptual","q":"Nylon-6,6 and proteins are both made by condensation polymerization. What small molecule is eliminated and what linkage forms between the monomers?","o":["CO₂ is lost, forming an ester linkage","H₂O is lost, forming an amide (peptide) linkage","H₂ is lost, forming a C=C linkage","HCl is lost, forming an ether linkage"],"c":1,"e":"A carboxylic acid group reacts with an amine group, eliminating water and forming an amide (–CONH–) linkage; in proteins this same linkage is called a peptide bond."},
  {"i":"chem-b3-0730","g":12,"u":"Polymers","d":"medium","t":"application","q":"A monomer must be able to form long polymer chains. Which of the following molecules can undergo addition polymerization?","o":["CH₃CH₃ (ethane)","CH₂=CHCl (chloroethene)","CH₃CH₂OH (ethanol)","CH₄ (methane)"],"c":1,"e":"Addition polymerization requires a C=C double bond. Chloroethene (vinyl chloride), CH₂=CHCl, has one and polymerizes to PVC; the saturated molecules cannot add together."},
  {"i":"chem-b3-0731","g":12,"u":"Introduction to Environmental Chemistry","d":"medium","t":"conceptual","q":"Rain becomes 'acid rain' mainly when certain gases from burning fossil fuels dissolve in atmospheric water. Which pair of gases is chiefly responsible?","o":["CO₂ and CH₄","SO₂ and NOₓ","O₂ and N₂","CO and O₃"],"c":1,"e":"Sulfur dioxide (SO₂) and nitrogen oxides (NOₓ) from fuel combustion react with water and oxygen to form sulfuric and nitric acids, lowering rain pH below normal."},
  {"i":"chem-b3-0732","g":12,"u":"Introduction to Environmental Chemistry","d":"medium","t":"definition","q":"Water from a river near Addis Ababa is tested and found to have a high BOD value. What does a high BOD (Biochemical Oxygen Demand) indicate about the water?","o":["The water is rich in dissolved oxygen","The water contains a high level of biodegradable organic pollution","The water has a high pH","The water contains heavy metals only"],"c":1,"e":"BOD measures the oxygen microorganisms need to decompose organic matter; a high BOD means much biodegradable organic pollution, which depletes dissolved oxygen and harms aquatic life."},
  {"i":"chem-b3-0733","g":12,"u":"Introduction to Environmental Chemistry","d":"medium","t":"application","q":"The depletion of stratospheric ozone is linked to chlorofluorocarbons (CFCs). What is the role of chlorine atoms released from CFCs in ozone destruction?","o":["They are consumed permanently after destroying one O₃ molecule","They act as catalysts, each destroying many O₃ molecules","They combine with O₃ to form harmless O₂ only once","They increase ozone by adding oxygen atoms"],"c":1,"e":"UV light frees Cl atoms from CFCs; a Cl atom converts O₃ to O₂ and is regenerated, so it acts catalytically and can destroy thousands of ozone molecules."},
  {"i":"chem-b3-0734","g":12,"u":"Electrochemistry","d":"medium","t":"calculation","q":"During the electrolytic refining of copper, a constant current of 5.0 A is passed for 1 hour through a CuSO₄ solution. Using F = 96500 C/mol and molar mass of Cu = 63.5 g/mol, what mass of copper is deposited at the cathode (Cu²⁺ + 2e⁻ → Cu)?","o":["5.92 g","11.84 g","2.96 g","7.10 g"],"c":0,"e":"Q = I·t = 5.0 × 3600 = 18000 C; moles e⁻ = 18000/96500 = 0.1865; moles Cu = 0.1865/2 = 0.0933; mass = 0.0933 × 63.5 = 5.92 g."},
  {"i":"chem-b3-0735","g":12,"u":"Industrial Chemistry","d":"medium","t":"application","q":"In the Haber process for synthesizing ammonia (N₂ + 3H₂ ⇌ 2NH₃, ΔH < 0), which set of conditions favours a higher equilibrium yield of NH₃?","o":["High pressure and low temperature","Low pressure and high temperature","High pressure and high temperature","Low pressure and low temperature"],"c":0,"e":"The forward reaction is exothermic and decreases moles of gas (4 → 2), so by Le Chatelier's principle high pressure and low temperature shift equilibrium toward NH₃ (a moderate temperature is used industrially only for adequate rate)."},
  {"i":"chem-b3-0736","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"A 0.20 mol/L solution of a weak monoprotic acid HA is 1.5% ionized at 25 °C. What is its Ka?","o":["4.5 × 10⁻⁵","6.8 × 10⁻⁵","3.0 × 10⁻³","2.3 × 10⁻⁴"],"c":0,"e":"[H⁺] = 0.015 × 0.20 = 3.0 × 10⁻³. Ka = (3.0 × 10⁻³)²/0.20 = 9.0 × 10⁻⁶/0.20 = 4.5 × 10⁻⁵."},
  {"i":"chem-b3-0737","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"25.0 mL of 0.100 mol/L CH₃COOH (Ka = 1.8 × 10⁻⁵) is titrated with 0.100 mol/L NaOH. What is the pH after adding 12.5 mL of NaOH?","o":["4.74","2.87","8.72","5.26"],"c":0,"e":"At half-equivalence [acid] = [conjugate base], so pH = pKa = −log(1.8 × 10⁻⁵) = 4.74."},
  {"i":"chem-b3-0738","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"A buffer contains 0.30 mol CH₃COOH and 0.50 mol CH₃COONa in 1.0 L (Ka = 1.8 × 10⁻⁵). What is the pH after adding 0.10 mol HCl, assuming no volume change?","o":["4.74","4.52","5.16","4.96"],"c":0,"e":"HCl converts acetate to acid: acid = 0.30 + 0.10 = 0.40 mol, base = 0.50 − 0.10 = 0.40 mol. pH = 4.74 + log(0.40/0.40) = 4.74 + 0 = 4.74."},
  {"i":"chem-b3-0739","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"What is the pH of a 0.050 mol/L Na₂CO₃ solution if Kb for CO₃²⁻ = 2.1 × 10⁻⁴?","o":["11.51","2.49","10.32","12.00"],"c":0,"e":"[OH⁻] = √(Kb·C) = √(2.1 × 10⁻⁴ × 0.050) = √(1.05 × 10⁻⁵) = 3.24 × 10⁻³. pOH = 2.49, pH = 14 − 2.49 = 11.51."},
  {"i":"chem-b3-0740","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"conceptual","q":"Equal volumes of 0.10 mol/L NH₃ (Kb = 1.8 × 10⁻⁵) and 0.10 mol/L NH₄Cl are mixed, then a tiny amount of strong base is added. Which best explains the small pH change?","o":["The buffer's NH₄⁺ neutralizes added OH⁻, keeping [NH₃]/[NH₄⁺] nearly constant","Water autoionization buffers the added base","NH₄Cl is a strong electrolyte so it cannot react","Added OH⁻ precipitates as solid NH₄OH"],"c":0,"e":"In an NH₃/NH₄⁺ buffer, added OH⁻ reacts with NH₄⁺ to form NH₃ and water; the ratio [NH₃]/[NH₄⁺] shifts only slightly, so pH barely moves."},
  {"i":"chem-b3-0741","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"The pH of a 0.10 mol/L solution of a weak base B is 11.13 at 25 °C. What is Kb of B?","o":["1.8 × 10⁻⁵","1.3 × 10⁻³","7.4 × 10⁻⁴","1.8 × 10⁻³"],"c":0,"e":"pOH = 14 − 11.13 = 2.87, [OH⁻] = 10⁻²·⁸⁷ = 1.35 × 10⁻³. Kb = (1.35 × 10⁻³)²/0.10 = 1.8 × 10⁻⁵."},
  {"i":"chem-b3-0742","g":12,"u":"Electrochemistry","d":"hard","t":"calculation","q":"A current of 2.50 A is passed through molten AlCl₃ for 1.00 hour. What mass of aluminium is deposited? (Al = 27 g/mol, F = 96 500 C/mol)","o":["0.839 g","2.52 g","0.280 g","1.68 g"],"c":0,"e":"Q = 2.50 × 3600 = 9000 C; mol e⁻ = 9000/96 500 = 0.0933; Al³⁺ + 3e⁻ → Al, mol Al = 0.0311; mass = 0.0311 × 27 = 0.839 g."},
  {"i":"chem-b3-0743","g":12,"u":"Electrochemistry","d":"hard","t":"calculation","q":"For Zn|Zn²⁺(1 M)||Cu²⁺(1 M)|Cu, E°(Zn²⁺/Zn) = −0.76 V and E°(Cu²⁺/Cu) = +0.34 V. What is ΔG° for the reaction? (F = 96 500 C/mol)","o":["−212 kJ/mol","−106 kJ/mol","+212 kJ/mol","−1.10 kJ/mol"],"c":0,"e":"E°cell = 0.34 − (−0.76) = 1.10 V; n = 2. ΔG° = −nFE° = −2 × 96 500 × 1.10 = −212 300 J ≈ −212 kJ/mol."},
  {"i":"chem-b3-0744","g":12,"u":"Electrochemistry","d":"hard","t":"calculation","q":"Using the Nernst equation at 25 °C, what is the cell potential for Zn|Zn²⁺(0.010 M)||Cu²⁺(1.0 M)|Cu? (E°cell = 1.10 V)","o":["1.16 V","1.04 V","1.10 V","1.22 V"],"c":0,"e":"Q = [Zn²⁺]/[Cu²⁺] = 0.010. E = 1.10 − (0.0592/2)log(0.010) = 1.10 − 0.0296 × (−2) = 1.10 + 0.0592 = 1.16 V."},
  {"i":"chem-b3-0745","g":12,"u":"Electrochemistry","d":"hard","t":"calculation","q":"In the electrolysis of aqueous CuSO₄ with inert electrodes, 0.635 g of copper is deposited at the cathode. What volume of O₂ at STP (22.4 L/mol) is released at the anode? (Cu = 63.5 g/mol)","o":["0.112 L","0.224 L","0.448 L","0.056 L"],"c":0,"e":"mol Cu = 0.635/63.5 = 0.0100 needs 0.0200 mol e⁻. Anode: 2H₂O → O₂ + 4H⁺ + 4e⁻, mol O₂ = 0.0200/4 = 0.00500; V = 0.00500 × 22.4 = 0.112 L."},
  {"i":"chem-b3-0746","g":12,"u":"Electrochemistry","d":"hard","t":"conceptual","q":"During electrolysis of concentrated aqueous NaCl (brine), Cl₂ forms at the anode rather than O₂ despite O₂ having a more favourable standard potential. The best explanation is:","o":["The overpotential for O₂ evolution raises its effective discharge potential above that of Cl₂","Cl⁻ is a stronger reducing agent than water under all conditions","Na⁺ catalyses chlorine formation at the anode","Water cannot be oxidized in any electrolytic cell"],"c":0,"e":"The high overpotential for O₂ evolution makes Cl₂ discharge kinetically favoured in concentrated brine, so chlorine is produced preferentially."},
  {"i":"chem-b3-0747","g":12,"u":"Electrochemistry","d":"hard","t":"calculation","q":"Two electrolytic cells with AgNO₃ and CuSO₄ are connected in series. If 1.08 g of silver deposits in the first, what mass of copper deposits in the second? (Ag = 108, Cu = 63.5 g/mol)","o":["0.318 g","0.635 g","1.08 g","0.159 g"],"c":0,"e":"mol Ag = 1.08/108 = 0.0100 → 0.0100 mol e⁻. Cu²⁺ + 2e⁻ → Cu, mol Cu = 0.00500; mass = 0.00500 × 63.5 = 0.318 g."},
  {"i":"chem-b3-0748","g":12,"u":"Industrial Chemistry","d":"hard","t":"calculation","q":"In the Haber process N₂ + 3H₂ ⇌ 2NH₃, if 28 kg of N₂ reacts completely with stoichiometric H₂, what maximum mass of NH₃ can form? (N = 14, H = 1 g/mol)","o":["34 kg","17 kg","28 kg","48 kg"],"c":0,"e":"mol N₂ = 28 000/28 = 1000 mol; each gives 2 NH₃ = 2000 mol; mass = 2000 × 17 = 34 000 g = 34 kg."},
  {"i":"chem-b3-0749","g":12,"u":"Industrial Chemistry","d":"hard","t":"conceptual","q":"In the Contact process step 2SO₂ + O₂ ⇌ 2SO₃ (ΔH < 0), the industrial choice of about 450 °C rather than a much lower temperature is best justified because:","o":["It is a compromise giving an acceptable rate while keeping equilibrium yield reasonably high","Lower temperatures would shift equilibrium toward SO₂","The reaction is endothermic so heat increases yield","V₂O₅ catalyst only forms above 450 °C"],"c":0,"e":"The reaction is exothermic, so low temperature favours yield but is too slow; ~450 °C is a kinetic/equilibrium compromise giving a fast enough rate while keeping yield high."},
  {"i":"chem-b3-0750","g":12,"u":"Industrial Chemistry","d":"hard","t":"calculation","q":"A limestone sample is 80.0% CaCO₃ by mass. What mass of CaO is produced by full calcination of 250 g of this limestone? (CaCO₃ = 100, CaO = 56 g/mol)","o":["112 g","140 g","200 g","56 g"],"c":0,"e":"Pure CaCO₃ = 0.800 × 250 = 200 g = 2.00 mol. CaCO₃ → CaO + CO₂, so 2.00 mol CaO × 56 = 112 g."},
  {"i":"chem-b3-0751","g":12,"u":"Industrial Chemistry","d":"hard","t":"calculation","q":"In the Ostwald process, 4NH₃ + 5O₂ → 4NO + 6H₂O. What volume of O₂ at STP is needed to oxidize 44.8 L of NH₃ measured at the same conditions?","o":["56.0 L","44.8 L","35.8 L","112 L"],"c":0,"e":"By volume ratios O₂:NH₃ = 5:4, so V(O₂) = 44.8 × 5/4 = 56.0 L."},
  {"i":"chem-b3-0752","g":12,"u":"Polymers","d":"hard","t":"conceptual","q":"Which pairing correctly classifies the polymer and its mechanism of formation?","o":["Nylon 6,6 — condensation polymer that releases water","Polyethene — condensation polymer that releases HCl","PVC — addition polymer that releases water","Polyester — addition polymer with no by-product"],"c":0,"e":"Nylon 6,6 forms by condensation between a diamine and a dicarboxylic acid, eliminating water at each amide linkage; the other three pairings are incorrect."},
  {"i":"chem-b3-0753","g":12,"u":"Polymers","d":"hard","t":"calculation","q":"A polyethene sample, −(CH₂CH₂)ₙ−, has an average molar mass of 70 000 g/mol. What is the average degree of polymerization n? (C₂H₄ = 28 g/mol)","o":["2500","1250","5000","700"],"c":0,"e":"Each repeat unit is C₂H₄ = 28 g/mol. n = 70 000/28 = 2500."},
  {"i":"chem-b3-0754","g":12,"u":"Polymers","d":"hard","t":"conceptual","q":"Natural rubber is hardened by vulcanization. At the molecular level, this increases strength mainly because:","o":["Sulfur forms cross-links between polyisoprene chains, restricting chain slippage","Sulfur breaks all C=C double bonds into single bonds","It increases average chain length by addition polymerization","It removes plasticizer molecules from between chains"],"c":0,"e":"Vulcanization introduces sulfur cross-links bridging adjacent polyisoprene chains; these covalent bridges prevent chains from sliding past one another, raising strength and elasticity."},
  {"i":"chem-b3-0755","g":12,"u":"Introduction to Environmental Chemistry","d":"hard","t":"calculation","q":"Factory wastewater contains 0.0200 mol/L dissolved CO₂ behaving as a weak acid (Ka = 4.5 × 10⁻⁷). What is the approximate pH of this water?","o":["4.02","3.70","2.70","5.35"],"c":0,"e":"[H⁺] = √(Ka·C) = √(4.5 × 10⁻⁷ × 0.0200) = √(9.0 × 10⁻⁹) = 9.49 × 10⁻⁵. pH = −log(9.49 × 10⁻⁵) = 4.02."},
  {"i":"chem-b3-0756","g":12,"u":"Introduction to Environmental Chemistry","d":"hard","t":"application","q":"Rain is classified as acid rain below about pH 5.6. A rain sample over an industrial area has [H⁺] = 4.0 × 10⁻⁵ mol/L. Is it acid rain, and what is its pH?","o":["Yes; pH = 4.40","No; pH = 5.60","Yes; pH = 4.00","No; pH = 6.40"],"c":0,"e":"pH = −log(4.0 × 10⁻⁵) = 5 − log4 = 5 − 0.60 = 4.40, which is below 5.6, so it is acid rain."},
  {"i":"chem-b3-0757","g":12,"u":"Introduction to Environmental Chemistry","d":"hard","t":"calculation","q":"The maximum recommended level of CO in air is near 9.0 ppm by volume. In 1.0 L of air at STP (22.4 L/mol), how many moles of CO does 9.0 ppm represent?","o":["4.0 × 10⁻⁷ mol","9.0 × 10⁻⁶ mol","2.0 × 10⁻⁷ mol","4.0 × 10⁻⁹ mol"],"c":0,"e":"9.0 ppm by volume = 9.0 × 10⁻⁶ × 1.0 L = 9.0 × 10⁻⁶ L of CO; mol = 9.0 × 10⁻⁶/22.4 = 4.0 × 10⁻⁷ mol."},
  {"i":"chem-b3-0758","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"At 25 °C a 0.20 mol/L solution of ethanoic (acetic) acid has Ka = 1.8×10⁻⁵. Assuming x ≪ 0.20, what is the pH of the solution?","o":["2.72","3.44","4.74","1.40"],"c":0,"e":"[H⁺] = √(Ka·C) = √(1.8×10⁻⁵ × 0.20) = 1.9×10⁻³ mol/L, so pH = −log(1.9×10⁻³) ≈ 2.72."},
  {"i":"chem-b3-0759","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"A buffer is made by mixing 0.30 mol/L ethanoic acid (Ka = 1.8×10⁻⁵) with 0.20 mol/L sodium ethanoate. Using the Henderson–Hasselbalch relation, the pH is closest to:","o":["4.57","4.92","5.05","4.74"],"c":0,"e":"pKa = −log(1.8×10⁻⁵) = 4.74; pH = pKa + log([salt]/[acid]) = 4.74 + log(0.20/0.30) = 4.74 − 0.18 = 4.57."},
  {"i":"chem-b3-0760","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"Ammonia has Kb = 1.8×10⁻⁵. For a 0.10 mol/L NH₃ solution at 25 °C, the pH (assuming x ≪ 0.10) is closest to:","o":["11.13","2.87","9.26","8.87"],"c":0,"e":"[OH⁻] = √(Kb·C) = √(1.8×10⁻⁶) = 1.34×10⁻³, pOH = 2.87, so pH = 14 − 2.87 = 11.13."},
  {"i":"chem-b3-0761","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"NH₄Cl is the salt of a weak base (Kb of NH₃ = 1.8×10⁻⁵). For a 0.10 mol/L NH₄Cl solution at 25 °C, the pH is closest to:","o":["5.13","8.87","7.00","6.13"],"c":0,"e":"Ka(NH₄⁺) = Kw/Kb = 1×10⁻¹⁴/1.8×10⁻⁵ = 5.6×10⁻¹⁰; [H⁺] = √(5.6×10⁻¹⁰ × 0.10) = 7.5×10⁻⁶, pH ≈ 5.13."},
  {"i":"chem-b3-0762","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"25.0 mL of 0.10 mol/L HCl is mixed with 15.0 mL of 0.10 mol/L NaOH. The pH of the resulting mixture is closest to:","o":["1.60","2.40","7.00","12.40"],"c":0,"e":"Excess H⁺ = (0.0025 − 0.0015) = 1.0×10⁻³ mol in 0.040 L = 0.025 mol/L; pH = −log(0.025) = 1.60."},
  {"i":"chem-b3-0763","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"For AgCl, Ksp = 1.8×10⁻¹⁰ at 25 °C. The molar solubility of AgCl in 0.10 mol/L NaCl (common-ion effect) is:","o":["1.8×10⁻⁹ mol/L","1.3×10⁻⁵ mol/L","1.8×10⁻¹⁰ mol/L","1.8×10⁻¹¹ mol/L"],"c":0,"e":"s = Ksp/[Cl⁻] = 1.8×10⁻¹⁰/0.10 = 1.8×10⁻⁹ mol/L, far below the 1.3×10⁻⁵ mol/L solubility in pure water."},
  {"i":"chem-b3-0764","g":12,"u":"Electrochemistry","d":"hard","t":"calculation","q":"A current of 2.0 A is passed for 30 minutes through CuSO₄ solution (Cu²⁺ + 2e⁻ → Cu). Using F = 96500 C/mol and Ar(Cu) = 63.5, the mass of copper deposited is:","o":["1.18 g","2.37 g","0.59 g","3.95 g"],"c":0,"e":"Q = 2.0 × 1800 = 3600 C; mol e⁻ = 3600/96500 = 0.0373; mol Cu = 0.0373/2 = 0.0187; mass = 0.0187 × 63.5 ≈ 1.18 g."},
  {"i":"chem-b3-0765","g":12,"u":"Electrochemistry","d":"hard","t":"calculation","q":"For the cell Zn|Zn²⁺(0.010 M)||Cu²⁺(0.10 M)|Cu with E°cell = 1.10 V at 25 °C, the Nernst equation (n = 2) gives Ecell closest to:","o":["1.13 V","1.07 V","1.10 V","1.16 V"],"c":0,"e":"E = 1.10 − (0.0592/2)·log([Zn²⁺]/[Cu²⁺]) = 1.10 − 0.0296·log(0.010/0.10) = 1.10 − 0.0296·log(0.1) = 1.10 + 0.030 = 1.13 V."},
  {"i":"chem-b3-0766","g":12,"u":"Electrochemistry","d":"hard","t":"calculation","q":"To deposit 1.08 g of silver (Ar = 108; Ag⁺ + e⁻ → Ag) from AgNO₃ using a current of 2.0 A, the time required is closest to (F = 96500 C/mol):","o":["483 s","241 s","965 s","120 s"],"c":0,"e":"mol Ag = 1.08/108 = 0.0100; Q = 0.0100 × 96500 = 965 C; t = Q/I = 965/2.0 = 482.5 ≈ 483 s."},
  {"i":"chem-b3-0767","g":12,"u":"Electrochemistry","d":"hard","t":"calculation","q":"For the Daniell cell (E°cell = 1.10 V, n = 2), the standard Gibbs free energy change ΔG° (F = 96500 C/mol) is:","o":["−212 kJ/mol","−106 kJ/mol","+212 kJ/mol","−1.10 kJ/mol"],"c":0,"e":"ΔG° = −nFE° = −(2)(96500)(1.10) = −2.123×10⁵ J ≈ −212 kJ/mol; the negative sign confirms a spontaneous cell."},
  {"i":"chem-b3-0768","g":12,"u":"Electrochemistry","d":"hard","t":"calculation","q":"In the industrial extraction of aluminium (Al³⁺ + 3e⁻ → Al), the charge needed to produce 1.0 kg of aluminium (Ar = 27, F = 96500 C/mol) is closest to:","o":["1.07×10⁷ C","3.57×10⁶ C","2.61×10⁵ C","9.65×10⁴ C"],"c":0,"e":"mol Al = 1000/27 = 37.0; mol e⁻ = 3 × 37.0 = 111.1; Q = 111.1 × 96500 ≈ 1.07×10⁷ C."},
  {"i":"chem-b3-0769","g":12,"u":"Electrochemistry","d":"hard","t":"conceptual","q":"During the electrolysis of dilute aqueous Na₂SO₄ with inert electrodes, the products at the cathode and anode respectively are:","o":["H₂ and O₂","Na and O₂","H₂ and S","Na and SO₂"],"c":0,"e":"Water is preferentially reduced (2H₂O + 2e⁻ → H₂ + 2OH⁻) over Na⁺, and oxidised (2H₂O → O₂ + 4H⁺ + 4e⁻) over sulfate, giving H₂ at the cathode and O₂ at the anode."},
  {"i":"chem-b3-0770","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"A 0.50 mol/L solution of a weak monoprotic acid HA is 2.0% ionised at 25 °C. Its acid-dissociation constant Ka is closest to:","o":["2.0×10⁻⁴","4.0×10⁻⁴","1.0×10⁻²","2.0×10⁻²"],"c":0,"e":"[H⁺] = 0.020 × 0.50 = 0.010 mol/L; Ka ≈ [H⁺]²/C = (0.010)²/0.50 = 1.0×10⁻⁴/0.50 = 2.0×10⁻⁴."},
  {"i":"chem-b3-0771","g":12,"u":"Industrial Chemistry","d":"hard","t":"calculation","q":"In the Haber process N₂ + 3H₂ ⇌ 2NH₃, equilibrium concentrations are [N₂] = 0.20, [H₂] = 0.40 and [NH₃] = 0.30 mol/L. The equilibrium constant Kc is closest to:","o":["7.0","1.1","0.14","28"],"c":0,"e":"Kc = [NH₃]²/([N₂][H₂]³) = (0.30)²/(0.20 × 0.40³) = 0.09/(0.20 × 0.064) = 0.09/0.0128 ≈ 7.0."},
  {"i":"chem-b3-0772","g":12,"u":"Industrial Chemistry","d":"hard","t":"conceptual","q":"In the Contact process step 2SO₂(g) + O₂(g) ⇌ 2SO₃(g) (ΔH < 0), which change increases the equilibrium yield of SO₃?","o":["Increasing pressure and lowering temperature","Increasing temperature and lowering pressure","Removing the V₂O₅ catalyst","Adding an inert gas at constant volume"],"c":0,"e":"The forward reaction reduces moles of gas (3 → 2) and is exothermic, so by Le Chatelier high pressure and low temperature both shift equilibrium toward SO₃; the catalyst only speeds attainment of equilibrium."},
  {"i":"chem-b3-0773","g":12,"u":"Industrial Chemistry","d":"hard","t":"calculation","q":"A factory near Addis Ababa produces NH₃ by the Haber process. If 28 g of N₂ reacts completely (N₂ + 3H₂ → 2NH₃; Mr N₂ = 28, NH₃ = 17), the maximum mass of ammonia formed is:","o":["34 g","17 g","28 g","51 g"],"c":0,"e":"28 g N₂ = 1.0 mol → 2.0 mol NH₃; mass = 2.0 × 17 = 34 g."},
  {"i":"chem-b3-0774","g":12,"u":"Introduction to Environmental Chemistry","d":"hard","t":"calculation","q":"A sample of rain collected on the outskirts of an industrial town has [H⁺] = 2.5×10⁻⁵ mol/L. Its pH, and whether it counts as acid rain (pH < 5.6), are:","o":["pH = 4.60; yes, acid rain","pH = 5.60; not acid rain","pH = 9.40; not acid rain","pH = 2.50; yes, acid rain"],"c":0,"e":"pH = −log(2.5×10⁻⁵) = 5 − log2.5 = 5 − 0.40 = 4.60, which is below 5.6, so it qualifies as acid rain."},
  {"i":"chem-b3-0775","g":12,"u":"Introduction to Environmental Chemistry","d":"hard","t":"conceptual","q":"Untreated sewage discharged into the Akaki River raises its biochemical oxygen demand (BOD). The most direct consequence for aquatic life is:","o":["A fall in dissolved oxygen, harming fish","A rise in dissolved oxygen, helping fish","An increase in water pH to strongly basic","Precipitation of CaCO₃ hardness"],"c":0,"e":"High BOD means microorganisms consume dissolved O₂ while decomposing organic waste, lowering the dissolved-oxygen level and suffocating fish and other aerobic organisms."},
  {"i":"chem-b3-0776","g":12,"u":"Polymers","d":"hard","t":"calculation","q":"Polyethene is made from ethene (CH₂=CH₂, Mr = 28). A sample of polyethene has an average molar mass of 56000 g/mol. Its average degree of polymerisation (number of monomer units) is:","o":["2000","1000","56000","28000"],"c":0,"e":"Degree of polymerisation = (polymer molar mass)/(monomer molar mass) = 56000/28 = 2000."},
  {"i":"chem-b3-0777","g":12,"u":"Polymers","d":"hard","t":"conceptual","q":"Which statement correctly classifies these polymers and their formation mechanism?","o":["Nylon-6,6 forms by condensation (releasing H₂O); polyethene forms by addition","Both nylon-6,6 and polyethene form by addition","Nylon-6,6 forms by addition; polyethene forms by condensation","Both form by condensation releasing CO₂"],"c":0,"e":"Nylon-6,6 forms by condensation of a diamine with a dicarboxylic acid, eliminating water at each amide link, whereas polyethene forms by addition across C=C double bonds with no by-product."},
  {"i":"chem-b3-0778","g":12,"u":"Industrial Chemistry","d":"hard","t":"calculation","q":"Propane (C₃H₈) used in household cylinders burns completely: C₃H₈ + 5O₂ → 3CO₂ + 4H₂O. Burning 0.50 mol of propane produces a volume of CO₂ at STP (molar volume 22.4 L/mol) of:","o":["33.6 L","11.2 L","22.4 L","44.8 L"],"c":0,"e":"mol CO₂ = 3 × 0.50 = 1.5 mol; volume = 1.5 × 22.4 = 33.6 L at STP."},
  {"i":"chem-b3-0779","g":12,"u":"Introduction to Environmental Chemistry","d":"hard","t":"calculation","q":"In K₂Cr₂O₇, a common oxidant used in water-quality testing, the oxidation number of chromium is (K = +1, O = −2):","o":["+6","+7","+3","+2"],"c":0,"e":"For K₂Cr₂O₇: 2(+1) + 2x + 7(−2) = 0 → 2 + 2x − 14 = 0 → 2x = 12 → x = +6."},
  {"i":"chem-b3-0780","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"A 0.20 mol/L solution of a weak monoprotic acid HA has a measured pH of 2.85. What is the Ka of HA?","o":["1.0 × 10⁻⁵","1.0 × 10⁻⁶","2.0 × 10⁻⁵","9.9 × 10⁻⁶"],"c":0,"e":"[H⁺] = 10⁻²·⁸⁵ = 1.41×10⁻³ mol/L. Ka = (1.41×10⁻³)²/(0.20 − 1.41×10⁻³) ≈ 1.99×10⁻⁶/0.1986 ≈ 1.0×10⁻⁵."},
  {"i":"chem-b3-0781","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"What volume of 0.10 mol/L NaOH must be added to 50.0 mL of 0.10 mol/L CH₃COOH (Ka = 1.8×10⁻⁵) to make a buffer of pH 4.74?","o":["12.5 mL","25.0 mL","37.5 mL","50.0 mL"],"c":1,"e":"pKa = −log(1.8×10⁻⁵) = 4.74, so pH = pKa requires [A⁻]=[HA], i.e. half neutralisation. Half of 5.0 mmol acid = 2.5 mmol OH⁻ needs 25.0 mL of 0.10 mol/L NaOH."},
  {"i":"chem-b3-0782","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"The pH of a 0.050 mol/L solution of the weak base methylamine is 11.80. What is its Kb?","o":["8.0 × 10⁻⁴","3.2 × 10⁻³","8.0 × 10⁻⁵","1.3 × 10⁻³"],"c":0,"e":"pOH = 14 − 11.80 = 2.20, [OH⁻] = 10⁻²·²⁰ = 6.31×10⁻³. Using the approximation Kb = (6.31×10⁻³)²/0.050 = 3.98×10⁻⁵/0.050 ≈ 8.0×10⁻⁴."},
  {"i":"chem-b3-0783","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"50.0 mL of 0.10 mol/L HCl is mixed with 50.0 mL of 0.10 mol/L NH₃ (Kb = 1.8×10⁻⁵). What is the pH of the resulting solution at 25 °C?","o":["5.28","7.00","8.72","5.13"],"c":0,"e":"Reaction forms 5.0 mmol NH₄⁺ in 100 mL → 0.050 mol/L. Ka(NH₄⁺) = 1.0×10⁻¹⁴/1.8×10⁻⁵ = 5.56×10⁻¹⁰. [H⁺] = √(5.56×10⁻¹⁰×0.050) = 5.27×10⁻⁶, pH = 5.28."},
  {"i":"chem-b3-0784","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"conceptual","q":"For the equilibrium 2SO₂(g) + O₂(g) ⇌ 2SO₃(g), ΔH < 0, which change increases the equilibrium yield of SO₃?","o":["Raising the temperature","Decreasing the total pressure","Increasing the pressure at constant temperature","Adding a catalyst"],"c":2,"e":"The forward reaction reduces gas moles (3→2), so higher pressure shifts equilibrium right. Higher T (exothermic) and lower P shift left; a catalyst only changes rate, not yield."},
  {"i":"chem-b3-0785","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"For N₂O₄(g) ⇌ 2NO₂(g), 0.100 mol N₂O₄ is placed in a 1.00 L vessel and 40.0% dissociates at equilibrium. What is Kc?","o":["0.107","0.0267","0.213","0.0533"],"c":0,"e":"Dissociated N₂O₄ = 0.040, leaving 0.060; NO₂ = 0.080. Kc = (0.080)²/0.060 = 0.0064/0.060 = 0.107."},
  {"i":"chem-b3-0786","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"What is the molar solubility of Mg(OH)₂ (Ksp = 5.6×10⁻¹²) in pure water?","o":["1.1 × 10⁻⁴ mol/L","2.4 × 10⁻⁴ mol/L","1.7 × 10⁻⁶ mol/L","2.8 × 10⁻⁶ mol/L"],"c":0,"e":"Ksp = (s)(2s)² = 4s³ = 5.6×10⁻¹². s³ = 1.4×10⁻¹², s = 1.12×10⁻⁴ mol/L."},
  {"i":"chem-b3-0787","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"A buffer contains 0.30 mol/L NH₃ and 0.20 mol/L NH₄Cl. Given Kb(NH₃) = 1.8×10⁻⁵, what is the pH?","o":["9.43","9.08","4.57","9.26"],"c":0,"e":"pKb = 4.74, pKa(NH₄⁺) = 9.26. pH = 9.26 + log(0.30/0.20) = 9.26 + 0.176 = 9.43."},
  {"i":"chem-b3-0788","g":12,"u":"Electrochemistry","d":"hard","t":"calculation","q":"A current of 2.00 A is passed through molten AlCl₃ for 1.00 hour. What mass of aluminium is deposited? (Al = 27 g/mol, F = 96500 C/mol)","o":["0.671 g","2.01 g","0.224 g","1.34 g"],"c":0,"e":"Q = 2.00×3600 = 7200 C. mol e⁻ = 7200/96500 = 0.0746. Al³⁺ + 3e⁻ → Al, so mol Al = 0.0746/3 = 0.02487; mass = 0.02487×27 = 0.671 g."},
  {"i":"chem-b3-0789","g":12,"u":"Electrochemistry","d":"hard","t":"calculation","q":"For the cell Zn|Zn²⁺(1.0 M)||Cu²⁺(1.0 M)|Cu, E°(Zn²⁺/Zn) = −0.76 V and E°(Cu²⁺/Cu) = +0.34 V. What is ΔG° for the cell reaction? (F = 96500 C/mol)","o":["−212 kJ","−106 kJ","+212 kJ","−424 kJ"],"c":0,"e":"E°cell = 0.34 − (−0.76) = 1.10 V; n = 2. ΔG° = −nFE° = −(2)(96500)(1.10) = −212300 J ≈ −212 kJ."},
  {"i":"chem-b3-0790","g":12,"u":"Electrochemistry","d":"hard","t":"calculation","q":"Using the Nernst equation at 25 °C, what is the cell potential of Zn|Zn²⁺(0.10 M)||Cu²⁺(0.0010 M)|Cu? (E°cell = 1.10 V)","o":["1.04 V","1.16 V","1.07 V","1.10 V"],"c":0,"e":"Q = [Zn²⁺]/[Cu²⁺] = 0.10/0.0010 = 100. E = 1.10 − (0.0592/2)log(100) = 1.10 − 0.0296×2 = 1.10 − 0.0592 = 1.04 V."},
  {"i":"chem-b3-0791","g":12,"u":"Electrochemistry","d":"hard","t":"calculation","q":"In the electrolysis of aqueous CuSO₄ with inert electrodes, a charge of 0.50 F is passed. What volume of O₂ gas (at STP, 22.4 L/mol) is produced at the anode?","o":["2.80 L","5.60 L","1.40 L","11.2 L"],"c":0,"e":"Anode: 2H₂O → O₂ + 4H⁺ + 4e⁻. mol O₂ = 0.50/4 = 0.125. Volume = 0.125×22.4 = 2.80 L."},
  {"i":"chem-b3-0792","g":12,"u":"Electrochemistry","d":"hard","t":"conceptual","q":"In a galvanic cell, why does the salt bridge prevent the cell potential from dropping to zero?","o":["It supplies extra electrons to the cathode","It maintains electrical neutrality by ion migration into each half-cell","It increases the standard electrode potentials","It catalyses the electrode reactions"],"c":1,"e":"As the reaction proceeds, the anode compartment accumulates positive charge and the cathode negative charge; the salt bridge lets ions migrate to neutralise these, sustaining current."},
  {"i":"chem-b3-0793","g":12,"u":"Electrochemistry","d":"hard","t":"calculation","q":"The same quantity of electricity deposits 0.54 g of Ag (108 g/mol) and x g of Cr from Cr³⁺ (52 g/mol) in series cells. What is x?","o":["0.0867 g","0.260 g","0.0289 g","0.156 g"],"c":0,"e":"mol e⁻ = 0.54/108 = 0.00500. Ag⁺+e⁻→Ag uses 0.00500 mol e⁻. Cr³⁺+3e⁻→Cr: mol Cr = 0.00500/3 = 0.001667; mass = 0.001667×52 = 0.0867 g."},
  {"i":"chem-b3-0794","g":12,"u":"Electrochemistry","d":"hard","t":"application","q":"Iron is protected from rusting by attaching blocks of magnesium. Which statement correctly describes this sacrificial protection? E°(Mg²⁺/Mg) = −2.37 V, E°(Fe²⁺/Fe) = −0.44 V.","o":["Mg is more easily oxidised, so it acts as the anode and is consumed instead of Fe","Fe acts as the anode because it has the lower reduction potential","Mg coats the iron and physically blocks oxygen only","Both metals are reduced simultaneously"],"c":0,"e":"Mg has the more negative reduction potential, so it is oxidised preferentially (the anode) and corrodes in place of the iron, which becomes the protected cathode."},
  {"i":"chem-b3-0795","g":12,"u":"Industrial Chemistry","d":"hard","t":"calculation","q":"In the Haber process N₂ + 3H₂ → 2NH₃, what mass of NH₃ (17 g/mol) can be made from 28 kg of N₂ (28 g/mol) assuming H₂ is in excess and 60% yield?","o":["20.4 kg","34.0 kg","17.0 kg","12.0 kg"],"c":0,"e":"mol N₂ = 28000/28 = 1000 mol → theoretical NH₃ = 2000 mol = 34.0 kg. At 60% yield: 0.60×34.0 = 20.4 kg."},
  {"i":"chem-b3-0796","g":12,"u":"Industrial Chemistry","d":"hard","t":"calculation","q":"The Ostwald process oxidises NH₃: 4NH₃ + 5O₂ → 4NO + 6H₂O. What volume of O₂ at STP is needed to oxidise 2.0 mol NH₃ completely?","o":["56.0 L","44.8 L","22.4 L","112 L"],"c":0,"e":"Mole ratio NH₃:O₂ = 4:5, so 2.0 mol NH₃ needs 2.5 mol O₂. Volume = 2.5×22.4 = 56.0 L."},
  {"i":"chem-b3-0797","g":12,"u":"Industrial Chemistry","d":"hard","t":"conceptual","q":"In the Contact process the catalytic step 2SO₂ + O₂ ⇌ 2SO₃ is run at about 450 °C rather than a lower temperature. Why is this compromise temperature chosen?","o":["Lower T gives higher yield but too slow a rate, so 450 °C balances yield and rate","Higher T increases the equilibrium yield of SO₃","450 °C is the only temperature where V₂O₅ is solid","The reaction is endothermic so heat raises yield"],"c":0,"e":"The forward reaction is exothermic, so a low temperature favours high SO₃ yield but the rate is impractically slow; 450 °C is a compromise giving an acceptable rate with still-good yield over V₂O₅."},
  {"i":"chem-b3-0798","g":12,"u":"Industrial Chemistry","d":"hard","t":"calculation","q":"A sample of haematite ore is 80% Fe₂O₃ by mass. What mass of iron (Fe = 56, Fe₂O₃ = 160 g/mol) can be extracted from 1.00 tonne of this ore at 100% efficiency?","o":["560 kg","700 kg","448 kg","800 kg"],"c":0,"e":"Fe₂O₃ mass = 0.80×1000 = 800 kg → mol Fe₂O₃ = 800/160 (kmol) = 5.0 kmol → Fe = 10.0 kmol × 56 = 560 kg."},
  {"i":"chem-b3-0799","g":12,"u":"Polymers","d":"hard","t":"definition","q":"Which pairing correctly classifies the polymerisation type and a matching monomer feature?","o":["Addition polymerisation — monomers contain C=C double bonds, no small molecule lost","Condensation polymerisation — monomers must contain C=C bonds only","Addition polymerisation — always releases water as a by-product","Condensation polymerisation — no functional groups are required"],"c":0,"e":"Addition polymers (e.g. polyethene) form from unsaturated monomers adding across C=C with no by-product; condensation polymers form from monomers with two functional groups, releasing a small molecule such as water."},
  {"i":"chem-b3-0800","g":12,"u":"Polymers","d":"hard","t":"calculation","q":"Ethene (C₂H₄, 28 g/mol) is polymerised to polyethene. How many ethene monomer units are present in one polyethene chain of molar mass 1.40 × 10⁵ g/mol?","o":["5000","2800","10000","3500"],"c":0,"e":"Each repeat unit is −CH₂CH₂− of mass 28 g/mol. Number of units = 1.40×10⁵ / 28 = 5000."},
  {"i":"chem-b3-0801","g":12,"u":"Introduction to Environmental Chemistry","d":"hard","t":"application","q":"Acid rain forms when SO₂ dissolves and is oxidised in the atmosphere. A rainwater sample has pH 4.0. Compared with neutral water (pH 7.0), how many times greater is its [H⁺]?","o":["1000 times","3 times","100 times","30 times"],"c":0,"e":"[H⁺] at pH 4.0 = 10⁻⁴ mol/L; at pH 7.0 = 10⁻⁷ mol/L. Ratio = 10⁻⁴/10⁻⁷ = 10³ = 1000 times greater."},
  {"i":"chem-b3-0802","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"A buffer is prepared by dissolving 0.20 mol CH₃COOH and 0.30 mol CH₃COONa in water to make 1.0 L of solution. Given Ka(CH₃COOH) = 1.8 × 10⁻⁵, what is the pH? (log 1.5 ≈ 0.18)","o":["4.39","4.74","4.92","5.05"],"c":2,"e":"pH = pKa + log([salt]/[acid]) = 4.74 + log(0.30/0.20) = 4.74 + log 1.5 = 4.74 + 0.18 = 4.92."},
  {"i":"chem-b3-0803","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"25.0 mL of 0.100 M CH₃COOH (Ka = 1.8 × 10⁻⁵) is titrated with 0.100 M NaOH. What is the pH exactly at the half-equivalence point? (log 1.8 ≈ 0.26)","o":["4.74","2.87","7.00","8.72"],"c":0,"e":"At half-equivalence [acid] = [conjugate base], so pH = pKa = −log(1.8 × 10⁻⁵) = 5 − 0.26 = 4.74."},
  {"i":"chem-b3-0804","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"calculation","q":"A 0.0500 M solution of a weak base B has pH = 10.94. What is Kb of B? (Take 10⁻³·⁰⁶ ≈ 8.7 × 10⁻⁴)","o":["1.5 × 10⁻⁵","7.6 × 10⁻⁶","3.0 × 10⁻⁵","1.5 × 10⁻⁴"],"c":0,"e":"pOH = 14 − 10.94 = 3.06, so [OH⁻] = 8.7 × 10⁻⁴ M. Kb = [OH⁻]²/(C − [OH⁻]) ≈ (8.7 × 10⁻⁴)²/0.0491 ≈ 1.5 × 10⁻⁵."},
  {"i":"chem-b3-0805","g":12,"u":"Acid–Base Equilibria","d":"hard","t":"conceptual","q":"For the equilibrium 2SO₂(g) + O₂(g) ⇌ 2SO₃(g), ΔH = −198 kJ. Which single change increases both the rate of reaction AND the equilibrium yield of SO₃?","o":["Raising the temperature","Adding a catalyst","Increasing the total pressure","Removing some O₂"],"c":2,"e":"Higher pressure favours the side with fewer gas moles (3 → 2), raising yield, and increases collision frequency, raising rate. Higher T speeds rate but lowers yield (exothermic); a catalyst does not shift equilibrium."},
  {"i":"chem-b3-0806","g":12,"u":"Electrochemistry","d":"hard","t":"calculation","q":"A current of 5.00 A is passed through molten AlCl₃ for 1.93 hours. What mass of aluminium is deposited at the cathode? (Al = 27, F = 96500 C/mol)","o":["3.24 g","9.72 g","2.43 g","1.62 g"],"c":0,"e":"Q = 5.00 × 1.93 × 3600 = 34740 C; mol e⁻ = 34740/96500 = 0.360. Al³⁺ + 3e⁻ → Al, so mol Al = 0.360/3 = 0.120; mass = 0.120 × 27 = 3.24 g."},
  {"i":"chem-b3-0807","g":12,"u":"Electrochemistry","d":"hard","t":"calculation","q":"Given E°(Zn²⁺/Zn) = −0.76 V and E°(Cu²⁺/Cu) = +0.34 V, what is the cell EMF when [Zn²⁺] = 0.0100 M and [Cu²⁺] = 1.00 M at 298 K? (Use 0.0592/n log Q; log 0.01 = −2)","o":["1.16 V","1.04 V","1.10 V","0.99 V"],"c":0,"e":"E°cell = 0.34 − (−0.76) = 1.10 V; n = 2, Q = [Zn²⁺]/[Cu²⁺] = 0.01. E = 1.10 − (0.0592/2)(−2) = 1.10 + 0.0592 = 1.16 V."},
  {"i":"chem-b3-0808","g":12,"u":"Electrochemistry","d":"hard","t":"calculation","q":"The same quantity of charge is passed through cells containing AgNO₃ and CuSO₄ in series. If 1.08 g of silver is deposited, what mass of copper is deposited? (Ag = 108, Cu = 63.5)","o":["0.318 g","0.635 g","0.159 g","1.27 g"],"c":0,"e":"mol e⁻ = 1.08/108 = 0.0100 (Ag⁺ + e⁻ → Ag). Cu²⁺ + 2e⁻ → Cu, so mol Cu = 0.0100/2 = 0.00500; mass = 0.00500 × 63.5 = 0.318 g."},
  {"i":"chem-b3-0809","g":12,"u":"Electrochemistry","d":"hard","t":"conceptual","q":"During the electrolysis of dilute aqueous Na₂SO₄ using inert electrodes, which products form at the cathode and anode respectively?","o":["Na metal and SO₂","H₂ and O₂","H₂ and SO₂","O₂ and H₂"],"c":1,"e":"Water is reduced at the cathode (2H₂O + 2e⁻ → H₂ + 2OH⁻) since Na⁺ is too hard to reduce, and water is oxidised at the anode (2H₂O → O₂ + 4H⁺ + 4e⁻) since SO₄²⁻ resists oxidation."},
  {"i":"chem-b3-0810","g":12,"u":"Industrial Chemistry","d":"hard","t":"calculation","q":"In the Haber process N₂ + 3H₂ ⇌ 2NH₃, 28.0 kg of N₂ reacts with excess H₂ at 60% yield. What mass of NH₃ is produced? (N = 14, H = 1)","o":["20.4 kg","34.0 kg","17.0 kg","28.0 kg"],"c":0,"e":"mol N₂ = 28000/28 = 1000 mol; theoretical NH₃ = 2000 mol = 34.0 kg; at 60% yield = 0.60 × 34.0 = 20.4 kg."},
  {"i":"chem-b3-0811","g":12,"u":"Industrial Chemistry","d":"hard","t":"application","q":"In the Contact process, SO₃ is absorbed into concentrated H₂SO₄ to form oleum rather than directly into water. The main reason is that:","o":["SO₃ is insoluble in water","Direct absorption in water produces a dense corrosive acid mist that is hard to condense","Water lowers the yield of SO₃","Oleum is cheaper to transport than SO₃ gas"],"c":1,"e":"Adding SO₃ straight to water releases so much heat that it forms a fine, persistent H₂SO₄ mist that is difficult to collect; dissolving in concentrated H₂SO₄ as oleum avoids this."},
  {"i":"chem-b3-0812","g":12,"u":"Industrial Chemistry","d":"hard","t":"calculation","q":"Limestone is decomposed: CaCO₃ → CaO + CO₂. To obtain 1.40 t of CaO (Ca = 40, C = 12, O = 16), what mass of pure CaCO₃ is needed?","o":["2.50 t","2.00 t","1.75 t","2.25 t"],"c":0,"e":"M(CaO) = 56, M(CaCO₃) = 100. mol CaO = 1.40 × 10⁶/56 = 2.50 × 10⁴ mol = mol CaCO₃; mass = 2.50 × 10⁴ × 100 = 2.50 × 10⁶ g = 2.50 t."},
  {"i":"chem-b3-0813","g":12,"u":"Polymers","d":"hard","t":"calculation","q":"Polythene is made from ethene, CH₂=CH₂ (C = 12, H = 1). If a polythene chain has a molar mass of 56000 g/mol, how many ethene monomer units does it contain?","o":["1000","2000","4000","500"],"c":1,"e":"Monomer repeat unit –CH₂CH₂– has mass 28 g/mol. Number of units = 56000/28 = 2000."},
  {"i":"chem-b3-0814","g":12,"u":"Polymers","d":"hard","t":"conceptual","q":"Which pair correctly classifies the polymers? Terylene (a polyester) and nylon-6,6 versus polythene and PVC.","o":["Terylene and nylon-6,6 are condensation polymers; polythene and PVC are addition polymers","All four are addition polymers","Terylene and nylon-6,6 are addition; polythene and PVC are condensation","Only PVC is a condensation polymer"],"c":0,"e":"Terylene and nylon-6,6 form by condensation (eliminating small molecules like H₂O), while polythene and PVC form by addition across C=C double bonds with no loss of atoms."},
  {"i":"chem-b3-0815","g":12,"u":"Introduction to Environmental Chemistry","d":"hard","t":"application","q":"Acid rain forms when NO₂ and SO₂ dissolve and are oxidised in the atmosphere. Which equation correctly represents acid-rain formation from sulfur dioxide?","o":["SO₂ + H₂O → H₂SO₄","2SO₂ + O₂ + 2H₂O → 2H₂SO₄","SO₂ + 2H₂O → H₂SO₃ + H₂","SO₂ + H₂ → H₂SO₃"],"c":1,"e":"SO₂ is oxidised and hydrated to sulfuric acid: 2SO₂ + O₂ + 2H₂O → 2H₂SO₄, which is balanced in S, O and H. SO₂ + H₂O → H₂SO₃ only gives the weaker sulfurous acid; the option shown for H₂SO₄ directly is unbalanced in oxygen."},
  {"i":"chem-b3-0816","g":12,"u":"Introduction to Environmental Chemistry","d":"hard","t":"calculation","q":"Complete combustion of octane: 2C₈H₁₈ + 25O₂ → 16CO₂ + 18H₂O. What mass of CO₂ is released when 1.14 kg of octane is fully burned? (C₈H₁₈ = 114, CO₂ = 44)","o":["3.52 kg","1.76 kg","4.40 kg","0.44 kg"],"c":0,"e":"mol octane = 1140/114 = 10 mol; mol CO₂ = 10 × 8 = 80 mol; mass = 80 × 44 = 3520 g = 3.52 kg."},
  {"i":"chem-b3-0817","g":12,"u":"Acid–Base Equilibria","d":"impossible","t":"calculation","q":"At 25 °C, 50.0 mL of 0.100 M CH₃COOH (Ka = 1.8×10⁻⁵) is titrated with 0.100 M NaOH. What is the pH after adding exactly 25.0 mL of base?","o":["4.74","4.44","5.04","7.00"],"c":0,"e":"At half-neutralisation [CH₃COOH] = [CH₃COO⁻], so pH = pKa = −log(1.8×10⁻⁵) = 4.74."},
  {"i":"chem-b3-0818","g":12,"u":"Acid–Base Equilibria","d":"impossible","t":"calculation","q":"A 0.0100 M solution of a weak monoprotic acid HA is found to be 4.0% ionised at 25 °C. What is its Ka?","o":["1.7×10⁻⁵","1.6×10⁻⁴","4.0×10⁻⁴","6.4×10⁻⁶"],"c":0,"e":"[H⁺] = 0.040×0.0100 = 4.0×10⁻⁴; Ka = (4.0×10⁻⁴)²/(0.0100−4.0×10⁻⁴) = 1.6×10⁻⁷/9.6×10⁻³ ≈ 1.7×10⁻⁵."},
  {"i":"chem-b3-0819","g":12,"u":"Acid–Base Equilibria","d":"impossible","t":"calculation","q":"What mass of solid CH₃COONa (M = 82 g/mol) must be dissolved in 500 mL of 0.200 M CH₃COOH (Ka = 1.8×10⁻⁵) to give a buffer of pH 5.00? (Ignore volume change.)","o":["15.0 g","4.7 g","9.4 g","23.6 g"],"c":0,"e":"pH = pKa + log([A⁻]/[HA]); 5.00 = 4.74 + log(x/0.200) ⇒ x = 0.200×10^0.26 = 0.364 M; n = 0.364×0.5 = 0.182 mol; mass = 0.182×82 ≈ 15.0 g."},
  {"i":"chem-b3-0820","g":12,"u":"Acid–Base Equilibria","d":"impossible","t":"calculation","q":"At 25 °C the pH of 0.10 M NH₄Cl is closest to which value? (Kb of NH₃ = 1.8×10⁻⁵)","o":["5.13","8.87","7.00","4.87"],"c":0,"e":"Ka(NH₄⁺) = Kw/Kb = 1.0×10⁻¹⁴/1.8×10⁻⁵ = 5.6×10⁻¹⁰; [H⁺] = √(5.6×10⁻¹⁰×0.10) = 7.5×10⁻⁶; pH = 5.13."},
  {"i":"chem-b3-0821","g":12,"u":"Electrochemistry","d":"impossible","t":"calculation","q":"A current of 5.00 A is passed through molten AlCl₃ for 1.00 hour. What mass of aluminium (M = 27 g/mol) is deposited? (F = 96500 C/mol)","o":["1.68 g","5.03 g","0.560 g","3.36 g"],"c":0,"e":"Q = 5.00×3600 = 18000 C; mol e⁻ = 18000/96500 = 0.1865; Al³⁺ + 3e⁻ → Al, mol Al = 0.1865/3 = 0.0622; mass = 0.0622×27 = 1.68 g."},
  {"i":"chem-b3-0822","g":12,"u":"Electrochemistry","d":"impossible","t":"calculation","q":"For the cell Zn|Zn²⁺(1 M)||Cu²⁺(1 M)|Cu, E°(Zn²⁺/Zn) = −0.76 V and E°(Cu²⁺/Cu) = +0.34 V. What is ΔG° for the cell reaction? (F = 96500 C/mol)","o":["−212 kJ","−106 kJ","+212 kJ","−424 kJ"],"c":0,"e":"E°cell = 0.34 − (−0.76) = 1.10 V; n = 2; ΔG° = −nFE° = −2×96500×1.10 = −212300 J ≈ −212 kJ."},
  {"i":"chem-b3-0823","g":12,"u":"Electrochemistry","d":"impossible","t":"calculation","q":"The same quantity of charge is passed through cells of AgNO₃ and CuSO₄ in series. If 1.08 g of Ag (M = 108) is deposited, what mass of Cu (M = 63.5) deposits?","o":["0.318 g","0.635 g","0.159 g","1.27 g"],"c":0,"e":"mol e⁻ = 1.08/108 = 0.0100 (Ag⁺ + e⁻ → Ag); Cu²⁺ + 2e⁻ → Cu, mol Cu = 0.0100/2 = 0.00500; mass = 0.00500×63.5 = 0.318 g."},
  {"i":"chem-b3-0824","g":12,"u":"Industrial Chemistry","d":"impossible","t":"calculation","q":"In the Contact process sulfur is converted via SO₂ and SO₃ to H₂SO₄ (M = 98). To produce 8.0 tonnes of pure H₂SO₄ at complete conversion, what minimum mass of sulfur (M = 32) is needed?","o":["2.6 t","8.0 t","5.2 t","3.2 t"],"c":0,"e":"Sulfur is conserved 1:1 (S→SO₂→SO₃→H₂SO₄); mol H₂SO₄ = 8.0×10⁶/98 = 8.16×10⁴; mass S = 8.16×10⁴×32 = 2.61×10⁶ g ≈ 2.6 t."},
  {"i":"chem-b3-0825","g":12,"u":"Industrial Chemistry","d":"impossible","t":"conceptual","q":"In the Haber process the conditions (~450 °C, ~200 atm, Fe catalyst) are a compromise. Which statement best explains choosing 450 °C despite the reaction being exothermic?","o":["Lower temperature gives higher equilibrium yield but too slow a rate, so 450 °C balances yield against acceptable rate","Higher temperature increases the equilibrium yield of ammonia directly","The catalyst only functions above 450 °C and is destroyed below it","450 °C maximises the equilibrium constant Kc for the forward reaction"],"c":0,"e":"The exothermic forward reaction is favoured at low T (Le Chatelier), but the rate then becomes impractical; 450 °C is the kinetics-versus-yield compromise. The catalyst raises rate, not equilibrium position."},
  {"i":"chem-b3-0826","g":12,"u":"Industrial Chemistry","d":"impossible","t":"calculation","q":"In steam reforming CH₄ + 2H₂O → CO₂ + 4H₂, what volume of H₂ at STP (22.4 L/mol) is obtained from 4.0 kg of CH₄ (M = 16) at 100% conversion?","o":["2.24×10⁴ L","5.6×10³ L","1.12×10⁴ L","8.96×10⁴ L"],"c":0,"e":"mol CH₄ = 4000/16 = 250; mol H₂ = 4×250 = 1000; V = 1000×22.4 = 2.24×10⁴ L."},
  {"i":"chem-b3-0827","g":12,"u":"Polymers","d":"impossible","t":"calculation","q":"Polyethene from ethene (C₂H₄, M = 28) has a number-average molar mass of 70000 g/mol. How many monomer units (degree of polymerisation) make up one average chain?","o":["2500","5000","1250","70000"],"c":0,"e":"Degree of polymerisation n = M(chain)/M(monomer) = 70000/28 = 2500 repeat units per chain."},
  {"i":"chem-b3-0828","g":12,"u":"Polymers","d":"impossible","t":"conceptual","q":"Which pairing correctly matches a polymer with its formation type and characteristic small-molecule by-product?","o":["Nylon-6,6 — condensation — water eliminated","Polyethene — condensation — water eliminated","Nylon-6,6 — addition — no by-product","PVC — condensation — HCl eliminated"],"c":0,"e":"Nylon-6,6 forms by condensation of a diamine with a diacid, eliminating water; polyethene and PVC form by addition with no small-molecule by-product."},
  {"i":"chem-b3-0829","g":12,"u":"Polymers","d":"impossible","t":"application","q":"A polymer is made from the monomer CH₂=CH–CN (acrylonitrile). What is the repeat-unit structure and the polymerisation type?","o":["–CH₂–CH(CN)– ; addition","–CH₂–CH(CN)– ; condensation","–CH=C(CN)– ; addition","–CH₂–CH₂–CN ; condensation"],"c":0,"e":"Addition polymerisation opens the C=C bond, giving the saturated repeat unit –CH₂–CH(CN)– with no atoms lost (polyacrylonitrile)."},
  {"i":"chem-b3-0830","g":12,"u":"Introduction to Environmental Chemistry","d":"impossible","t":"calculation","q":"A sample of acid rain has [H⁺] = 2.0×10⁻⁵ M. What is its pH, and is it more acidic than 'natural' rain (pH ≈ 5.6)?","o":["pH 4.70, more acidic than natural rain","pH 5.30, less acidic than natural rain","pH 4.70, less acidic than natural rain","pH 9.30, more acidic"],"c":0,"e":"pH = −log(2.0×10⁻⁵) = 5 − 0.30 = 4.70; since 4.70 < 5.6, it is more acidic than natural rain."},
  {"i":"chem-b3-0831","g":12,"u":"Introduction to Environmental Chemistry","d":"impossible","t":"calculation","q":"The dissolved O₂ in a river is 8.0 mg/L. Expressed as molarity (O₂, M = 32 g/mol), this is closest to:","o":["2.5×10⁻⁴ M","8.0×10⁻³ M","2.5×10⁻⁶ M","2.6×10⁻² M"],"c":0,"e":"8.0 mg/L = 8.0×10⁻³ g/L; divide by 32 g/mol = 2.5×10⁻⁴ mol/L."},
  {"i":"chem-b3-0832","g":12,"u":"Introduction to Environmental Chemistry","d":"impossible","t":"conceptual","q":"Photochemical smog over a city involves NOₓ and hydrocarbons in sunlight. Which species is the key secondary pollutant whose build-up characterises this smog?","o":["Ground-level ozone (O₃)","Carbon dioxide (CO₂)","Sulfur dioxide (SO₂)","Methane (CH₄)"],"c":0,"e":"Photochemical smog is marked by build-up of ground-level ozone formed from NOₓ and volatile hydrocarbons under sunlight; CO₂, SO₂ and CH₄ are not the defining secondary oxidant."},
  {"i":"chem-b3-0833","g":12,"u":"Acid–Base Equilibria","d":"impossible","t":"calculation","q":"What is the pH of the solution formed by mixing 30.0 mL of 0.10 M HCl with 20.0 mL of 0.10 M NaOH at 25 °C?","o":["1.70","2.00","12.30","1.30"],"c":0,"e":"mol H⁺ = 0.0030, mol OH⁻ = 0.0020; excess H⁺ = 0.0010 mol in 0.0500 L = 0.020 M; pH = −log0.020 = 1.70."},
  {"i":"chem-b3-0834","g":12,"u":"Electrochemistry","d":"impossible","t":"application","q":"In the electrolysis of concentrated aqueous NaCl (brine), what forms at the cathode and anode, and why is Cl₂ favoured over O₂ at the anode?","o":["H₂ and Cl₂; high Cl⁻ concentration plus O₂ overpotential gives Cl₂ the kinetic advantage","Na and Cl₂; sodium plates out before hydrogen","H₂ and O₂; chloride is a spectator ion","O₂ and Cl₂; water is preferentially reduced at the cathode to O₂"],"c":0,"e":"At the cathode water is reduced to H₂ (Na⁺ too hard to reduce in water); at the anode, despite O₂ being thermodynamically marginally favoured, the high Cl⁻ concentration and O₂ overpotential make Cl₂ the actual product."},
  {"i":"chem-b3-0835","g":12,"u":"Industrial Chemistry","d":"impossible","t":"calculation","q":"In the Ostwald process 4NH₃ + 5O₂ → 4NO + 6H₂O. What mass of O₂ (M = 32) is required to oxidise 68 g of NH₃ (M = 17) completely?","o":["160 g","80 g","200 g","128 g"],"c":0,"e":"mol NH₃ = 68/17 = 4.0; mol O₂ = (5/4)×4.0 = 5.0; mass = 5.0×32 = 160 g."},
  {"i":"chem-b3-0836","g":12,"u":"Acid–Base Equilibria","d":"impossible","t":"calculation","q":"Carbonic acid is diprotic: Ka₁ = 4.3×10⁻⁷, Ka₂ = 4.8×10⁻¹¹. For a 0.020 M H₂CO₃ solution at 25 °C, [CO₃²⁻] is approximately:","o":["4.8×10⁻¹¹ M","9.3×10⁻⁵ M","2.0×10⁻² M","4.3×10⁻⁷ M"],"c":0,"e":"For a diprotic acid with Ka₂ ≪ Ka₁, [HCO₃⁻] ≈ [H⁺] from the first step, so [CO₃²⁻] = Ka₂[HCO₃⁻]/[H⁺] ≈ Ka₂ = 4.8×10⁻¹¹ M, independent of concentration."},
  {"i":"chem-b3-0837","g":12,"u":"Acid–Base Equilibria","d":"impossible","t":"calculation","q":"A buffer is prepared by dissolving 0.20 mol of CH₃COOH and 0.10 mol of NaOH in water and diluting to 1.00 L (Ka of CH₃COOH = 1.8×10⁻⁵). What is the pH?","o":["4.74","4.44","5.04","4.04"],"c":0,"e":"NaOH converts 0.10 mol acid to 0.10 mol acetate, leaving 0.10 mol acid and 0.10 mol acetate (equal amounts). pH = pKa = −log(1.8×10⁻⁵) = 4.74."},
  {"i":"chem-b3-0838","g":12,"u":"Acid–Base Equilibria","d":"impossible","t":"calculation","q":"25.0 mL of 0.100 M CH₃COOH (Ka = 1.8×10⁻⁵) is titrated with 0.100 M NaOH. What is the pH after adding exactly 25.0 mL of NaOH (the equivalence point)?","o":["8.72","7.00","5.28","9.26"],"c":0,"e":"At equivalence all acid becomes 0.0500 M acetate (50 mL total). Kb = 1.0×10⁻¹⁴/1.8×10⁻⁵ = 5.56×10⁻¹⁰; [OH⁻] = √(5.56×10⁻¹⁰×0.0500) = 5.3×10⁻⁶; pOH = 5.28, pH = 8.72."},
  {"i":"chem-b3-0839","g":12,"u":"Acid–Base Equilibria","d":"impossible","t":"calculation","q":"For N₂(g) + 3H₂(g) ⇌ 2NH₃(g), Kc = 0.250 at a certain temperature. At equilibrium [N₂] = 2.00 M and [NH₃] = 2.00 M. What is the equilibrium [H₂]?","o":["2.00 M","1.59 M","4.00 M","0.500 M"],"c":0,"e":"Kc = [NH₃]²/([N₂][H₂]³); [H₂]³ = (2.00)²/(0.250×2.00) = 4.00/0.500 = 8.00; [H₂] = ∛8.00 = 2.00 M."},
  {"i":"chem-b3-0840","g":12,"u":"Electrochemistry","d":"impossible","t":"calculation","q":"In the molten-state electrolysis of NaCl in a Down's cell, a current of 9650 A flows for 5.00 minutes. What mass of sodium (Ar = 23.0) is deposited at the cathode? (F = 96500 C/mol)","o":["690 g","345 g","23.0 g","1380 g"],"c":0,"e":"Q = 9650×300 = 2.895×10⁶ C; mol e⁻ = 2.895×10⁶/96500 = 30.0; Na⁺ + e⁻ → Na, so mol Na = 30.0; mass = 30.0×23.0 = 690 g."},
  {"i":"chem-b3-0841","g":12,"u":"Electrochemistry","d":"impossible","t":"calculation","q":"For the cell Zn|Zn²⁺(0.0100 M)||Cu²⁺(1.00 M)|Cu with E°cell = 1.10 V, what is the cell potential at 25 °C? (E = E° − (0.0592/n)logQ)","o":["1.16 V","1.04 V","1.10 V","1.22 V"],"c":0,"e":"n = 2, Q = [Zn²⁺]/[Cu²⁺] = 0.0100; E = 1.10 − (0.0592/2)log(0.0100) = 1.10 − 0.0296×(−2) = 1.10 + 0.0592 = 1.16 V."},
  {"i":"chem-b3-0842","g":12,"u":"Electrochemistry","d":"impossible","t":"calculation","q":"A constant current electroplates copper from CuSO₄ solution, depositing 1.27 g of Cu (Ar = 63.5) in 30.0 minutes. What current was used? (F = 96500 C/mol)","o":["2.14 A","1.07 A","4.29 A","0.536 A"],"c":0,"e":"mol Cu = 1.27/63.5 = 0.0200; Cu²⁺ + 2e⁻ → Cu so mol e⁻ = 0.0400; Q = 0.0400×96500 = 3860 C; I = 3860/1800 s = 2.14 A."},
  {"i":"chem-b3-0843","g":12,"u":"Industrial Chemistry","d":"impossible","t":"calculation","q":"In the Haber process N₂ + 3H₂ → 2NH₃, if 56.0 kg of N₂ reacts with excess H₂ at 40.0% yield, what mass of NH₃ is produced? (N = 14.0, H = 1.0)","o":["27.2 kg","68.0 kg","34.0 kg","17.0 kg"],"c":0,"e":"mol N₂ = 56.0/28.0 = 2.00 kmol; theoretical NH₃ = 2×2.00 = 4.00 kmol = 68.0 kg; at 40.0% yield = 0.400×68.0 = 27.2 kg."},
  {"i":"chem-b3-0844","g":12,"u":"Industrial Chemistry","d":"impossible","t":"conceptual","q":"In the Contact process the key step is 2SO₂ + O₂ ⇌ 2SO₃ (ΔH < 0), run over V₂O₅ at about 450 °C and 1–2 atm. Which statement best justifies the moderate temperature rather than a very low one?","o":["Low T gives a high equilibrium yield but an impractically slow rate, so 450 °C balances yield and rate","High T raises both rate and equilibrium yield at the same time","The V₂O₅ catalyst only functions above 800 °C, forcing a high temperature","Pressure is irrelevant because the moles of gas do not change"],"c":0,"e":"The forward reaction is exothermic, so low T favors yield but kinetics become too slow; ~450 °C is the kinetic–thermodynamic compromise. Moles fall (3→2) so pressure does matter, making the other options wrong."},
  {"i":"chem-b3-0845","g":12,"u":"Polymers","d":"impossible","t":"calculation","q":"Ethene (C₂H₄, Mr = 28.0) undergoes addition polymerization to polyethene. If one polymer chain has a relative molecular mass of 1.40×10⁵, how many repeat (monomer) units does it contain?","o":["5.00×10³","2.50×10³","1.00×10⁴","7.00×10³"],"c":0,"e":"In addition polymerization no atoms are lost, so the repeat-unit mass equals the monomer mass (28.0). n = 1.40×10⁵/28.0 = 5.00×10³ units."},
  {"i":"chem-b3-0846","g":12,"u":"Introduction to Environmental Chemistry","d":"impossible","t":"calculation","q":"Effluent entering Lake Hawassa has a dissolved oxygen of 6.0 mg/L (permissible minimum 5.0 mg/L). If 1.0 mg/L of glucose (C₆H₁₂O₆, Mr = 180) is fully oxidized by C₆H₁₂O₆ + 6O₂ → 6CO₂ + 6H₂O, how much O₂ is consumed and is the DO still acceptable?","o":["1.07 mg/L consumed; DO = 4.93 mg/L, below the limit","0.53 mg/L consumed; DO = 5.47 mg/L, above the limit","1.07 mg/L consumed; DO = 4.93 mg/L, above the limit","6.0 mg/L consumed; DO = 0 mg/L, below the limit"],"c":0,"e":"mol glucose = 1.0/180 = 5.56×10⁻³ mmol/L; O₂ = 6×5.56×10⁻³ = 3.33×10⁻² mmol/L ×32 = 1.07 mg/L; DO = 6.0 − 1.07 = 4.93 mg/L, which falls below the 5.0 mg/L limit."}
];
